INSERT INTO core.text(id, content)
VALUES ('ad777c41-80fd-4937-b177-c8988ec62ea5',
        'Tänapäeval on probleemiks see, et noorte lugemus on palju väiksem. See ei tähenda seda, et noored ei loeks üldse, vaid seda, et nad ei loe piisavalt. Leidub neid, kes väga naudivad lugemist ja nad loevad lausa iga päev. Siiski leidub rohkem neid, kes ei loe, kui neid, kes loevad.\nNoortel ei ole harjumust lugeda. Seda tuleks harjutada juba väiksest peale, kuid tihti ei ole vanematel aega või ei näita ka laps selle vastu just suurt huvi üles. Nii ei hakata last sundima, kuid noorelt lugemisega alustamine võib kaasa tuua nii mõnegi eelise. Tiit Hennoste leiab, et harjumus võiks tekkida koolis. Harjumuse tekitamiseks tuleb lugeda järjekindlalt ja pidevalt. Tänapäeval noored aga ei taha ühe asjaga pikalt tegeleda ja seetõttu võib harjumuse tekitamine osutuda raskeks. Õpetajad üritavad koolis seda harjumust tekitada, aga noor peaks ka ise sellest huvitatud olema. Kui aga lõpuks sellega ära harjuda, võivad mõned leida, et lugemine on väga meeldiv tegevus.\nKindlasti ei saa väita, et noorte lugemus oleks olematu. Loetakse küll, aga seda ei tehta eesti keeles. Noored eelistavad lugeda inglise keeles. Tauno Vahteri atriklis „Peame leppida, noored lihtsalt ei loe“ ütles Tauno: „Poepidajate sõnul on ingliskeelse pealkirjaga raamatud pea ainsad, mida noored ostavad.“ Inglise keeles lugemine ei ole halb, kuid peame mõtlema ka eesti keele peale. See on eesti ühiskonnas murekoht, sest kultuur ei arene, kui inimestel puudub oskuskeel. Eesti keel ei saa edasi areneda ja võib väita, et keele kadumisega kaoks ka Eesti riik. Seetõttu peame me oma emakeelt väga hoidma ja lugema rohkem eesti keelseid tekste.\nKuna loetakse ikkagi pigem vähe, siis sellel võivad olla negatiivsed tagajärjed. Tiit Hennoste tõi oma artiklis „Lugemise harjumuse harjutus“ välja selle, et kuna ei saada tekstist aru, siis on raske ka elus hakkama saada. Inimesed ei mõista riiki ega ühiskonda ning nad ei saa aru, millele nad nõusoleku annavad või mis võimalusest nad ilma võivad jääda. See võib kaasa tuua suuri probleeme nii inimeste kui ka riikide vahel. Samuti võib vähene lugemus kaasa tuua hea vaimse tervise. Tiit Hennoste sõnul on mitmeid uurimusi, kus seda tõestatakse. Inimese elu on kindlasti kergem, kui ta saab aru, mis ümberringi toimub. \nLugemine võib osutuda eesti keele koha pealt veelgi suuremaks probleemiks, kui noored jäävadki lugema inglise keelseid raamatuid. Siiski ei saa väita, et olukord hetkel veel nii halb oleks, sest leidub ka neid noori, kellele väga meeldib eestikeelseid tekste lugeda. Just neil võib olla see tahtmine tulevikus eesti keelt edasi arendada.');
