INSERT INTO core.text(id, content)
VALUES ('e0f95dd3-3f0d-4d90-a1fa-3d9362b20f45',
        'Interneti kiire ja laialdase levikuka tekkis sotsiaalmeedia. Tänapäeval kasutavad enamus maailma rahvast sotsiaalmeediat meelelahutuseks või info otsimiseks. Isegi eelmise põlvkonna inimesed ja lapsed on sellega kokku puutunud. Kuidas sotsiaalmeedia tegelased mõjutavad isikute iseloomu ja arvamust?\nSotsiaalmeedia on alati olnud ja jääbki peamiselt meelelahutusvahendiks. Sellega saab leida suunamudijate videoid, filme ja saateid, mis leevendab tuju, aga mõjutab käitumist. Meelelahutajate tegevused ja iseloom köidab inimesi kergelt, eriti lapsi. Nad proovivad imiteerida nende tegevusi, kõnekeelt, sõnavara, aktsenti ja iseloomu. Crystal Abidin tõi välja nelja omadust, mida suunamudijad kasutavad tähelepanu köitmiseks: eksootilisust, eksklusiivsust elulisust ja erakordsust. Tänapäeval on palju noori mõjutanud ameerika suunamudija IShowSpeed, kes on tuntud hüperaktiivsena ja omandab kõik nelja omadust. Lapsed ja teismelised on tihti üritanud tema moodi käituda, tehes tagurpidi saltosid, karjudes ja eelistades portugali jalgpallurit Cristiano Ronaldot, mis on ameerika suunamudija omapärad.\nSotsiaalmeediat kasutatakse informatsiooni saamiseks. Loetakse faktilisi artikleid, vaadatakse videoid, milles üks või mitu tegelast avaldavad oma arvamust millegist. Rahvas jälgib tihti kuulsate suunamudijate arvamust. Nad arvavad, et mida populaarsem on isik, seda valiidsem on tema arvamus. Näiteks Eesti kampaanias, #loomadesilmis, mis kutsus kokku inimesi mitte soetama karusnahka, osalesid suunamudijad Hanna Martinson, Liis Velsker, Liina Ariadne Pedanik, Martti Hallik, Mick Pedaja, Alina Tsitseronova ja Juhani Särglep. Nad levitasid karusnaha soetamise kahjusid noortele ja julgustasid neid seda lõpetama. Kampaania tägajärjeks sai rahvusvaheline petitsioon tohutult palju signatuure. Ilma nendeta ei oleks kampaania nii edukalt läinud. Samas, arvamusi ei saa täielikult usaldada. Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill järeldas: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid ‘’kuulajatele meeldib’’, siis see on probleem. Halvemal juhul võib see tulemusel kuskil suuremaks kakluseks ja rüüstamiseks minna.“\nTänapäeva noored on tihti teadvuseta ja otsivad kellegilt või millegilt nõu. Neil kas puudub enesekindlus või tahavad paremaks saada. Sotsiaalmeedia laialdane levik ja ääretult suur mitmekesisus võimaldab leida igale murele konkreetse lahenduse. Inimesed, kes tarbivad sotsiaalmeediat pruugivad olla ebatervisliku elustiiliga, aga nad ei tea mida teha selle vastu. Füüsilise tervise arenguks on olemas suunamudijad nagu ameerika kergejõustiklane Chris Heria ja raskejõustiklane Jesse James West, kes pidevalt julgustavad teisi treeeninguga tegeleda, soovitades harjutusi, dieeti ja rutiini.\nSotsiaalmeedia on tänapäeva kõige suurem norm, mis mõjutab inimeste käitumist, iseloomu ja tegevusi mitmel erineval viisil, kas video või saate kaudu. Selle mõju levib laialdaselt ja pruugib olla kas hea või halb. Kiiresti arenevas keskkonnas peab muutust vastu võtma. Ei tohi keelata suunamudijate arvamusi ega nõud, aga ei tohi lasta neil mõjutada oma iseloomu. Tähtis on enda omapära väärtustamine.​​​​​​​');
