INSERT INTO core.text(id, content)
VALUES ('1bee2749-f3b1-43cb-937d-4bc7152702aa',
        'Võib arvata, et lugemisoskus on üks tähtsamatest inimeste oskustest. See võimaldab teha igapäevaseid tegevusi ja hakkama saada arenenud ühiskonnas. Kui lugemine on nii oluline igapäevasees elus, miks on muutunud noorte lugemisharjumused nii palju halvema suunas ja milliseid tagajärgesid saab see tuua?\nLugemisharjumused on olnud läbi aegade väga erinevad. On olnud aegu, kus lugemise õppimine oli raskendatud, aga samas oli võimalik hakkama saada ilma selleta. Siis kui haridus muutus kättesaadavamaks, muutus lugemisoskus veelgi olulisemaks. Lugemisoskuse laienemisega hakkas levima meelelahutus raamatute moel. See oli see hetk, kui lugemisharjumused hakkasid arenema ja paranema, keele oskus ja arusaam olid kõrgel tasemel. Võrreldes tänase päevaga, võib märgata et lugemine on muutunud vähem oluliseks, eriti nooremate silmis. Lugemisharjumuste halvenemine võib kaasa tuua ühiskondlikke probleeme. \nLugemisoskus paneb aluse kõigele mida teeb inimene igapäevaselt: toidu ostmine, uudiste lugemine, seaduse järgimine, meelelahutuse tarvitamine ja muud. Lugemisoskus on nagu iga muu, seda tuleb õppida ja pidevalt kasutada, et meelest ei läheks. Kõiksugused lugemisharjumused nagu raamatute lugemine ja lugemisülessanete lahendamine on tõhusad viisid, et arendada ja ülal hoida antud oskust. Probleem seisneb selles, et noored loevad kõik vähem ja vähem, võib tekkida hirm, et noorte keeleoskus võib tunduvalt halveneda. Selle tulemusena võib tekkida inimesi, kes saavad ühiskonnas halvemini hakkama, enamus tegevusi on ikkagi seotud lugemisoskusega. Tiit Hennoste mõte artikklis „Lugemise harjumuse harjutus“ võtab hästi kokku selle, mis võib juhtuda siis, kui unustatakse tegeleda lugemisoskuse arendamisega: „Lugemisoskuse allakäiguga aina kasvab inimeste hulk, kes ei saa enam üiskonnas hakkama: ei suuda läbi lugeda tekste, millele nad alla kirjutavad; ei saa aru sellest, mida riik ja ühiskond neile teada annab.“ \nLugemisharjumuste halvenemist ei saa põhjendada vaid tehnoloogia arenguga, tegu on mitme erineva hoogu andva teguri koostööga. Lugemisharjumuste pidev allakäik pole ainult selle sajandi probleem, nähtus on esinenud juba pikemat aega. Soomlased on välja pakkunud idee, et olu halvenemine algas kusagil 1990. aastatel. Ühiskond areneb ülikiiresti, osa tegevustest muutuvad nii-öelda kiiruse põhisteks, rahuldust põhjustavate hormoonide kättesaadavus on tänases ajastus üli lihtne. Seda fenomenit sõnastab hästi T. Hennoste artikklis „Lugemise harjumuste harjutus“: „Teine on kiirmaailma valitsus: kiirtoit, kiirteadus, kiirseks, kiirlugemine.“ Inimese aju reastab tegevuste tähtsust läbi positiivse hormonaalse tagasiside, mina usun, et see on üks peamistest teguritest lugemisharjumuste halvenemises. Lugemine on aeglane tegevus mis vajab palju keskendumist, lugemine ei anna kasu kiiresti. Selle sama omaduse pärast kujuneb lugemine raskeks tegevuseks praeguses kiirusele põhinevas ühiskonnas. \nLugemine oskusena on tegelikult päris oluline inimestele, sest see on oskus, mis teeb meid inimesteks ja seob ühiskonnaks. See on kui vundament igapäevaste tegevustega hakkama saamiseks. Lugemisharjumuste halvenemine tekkis mitmel erineval põhjusel ja see nähtus on miski, mis võib tulevikus probleeme tekitada.');
