INSERT INTO core.text(id, content)
VALUES ('3633ef69-9bca-403c-804e-91173493a80b',
        'Suunamudijad on tegutsenud sotsiaalmeedias pikkaaega ja paljud on ka endale kogunud suure jälgijaskonna. Enamus nendest jälgijatest on noored, kellele meeldib selle suunamudija poolt edasi antud info. Aga paljud noored ei saa aru kui tõsiselt nende lemmik suunamudija neid mõjutab.\nEnamus noortele ei meeldi õppida, veel vähem raamatuid lugeda. See on liiga aeganõudev, igav ja lihtsalt mõtetu. Sotsiaalmeedias, näiteks kui nende lemmik juutuuber räägib, et keda tulevastel valimistel tuleks valida ja siis ütleb selle inimese kohta paar head asja, noore inimese aju on kergelt veendav, et ta hakkabki seda inimest kaitsma kui keegi teine peaks ütlema, et valib hoopis vastas kandidaadi. Kui noor ei tea poliitika kohta mitte põrmugi, aga ta lemmik juutuuber tuleb ekraani ette ja hakkab oma vaatajatele seletama mida tema arvab pliitikast, siis see mõjutab ka noore vaadet poliitikal kuna suure jälgijaskonnaga inimene ütles seda. Alati tuleks teha faktide kontroll enne enda arvamuse avaldamist eriti kui sa ei ole antud teemaga kurisis.\nSuunamudijatel on päris palju võimu nende jälgijaskonna üle. Noortel tuleks üldse reguleerida, et mida on sobilik vaadata ja mida mitte. Ei saa piirduda ainult sellega, et suunamudijad ütlevad oma vaadajatele kelle pool hääletada ja kuidas mõelda. Paljudel juutuuberid tänapäeval teevad noorte jaoks videosi, et kuidas saada rikkaks. Pinna pealt tundub nagu hea ja õpetlik video mida enamused tahaks vaadata, aga endamus sääraseid videosi on lihtsalt püramiidi skeemid mis suunatud noorte jaoks kelle aju pole veel lõpuni arenend. Videode mõte on lasta noortel osta juutuuberi kuuliselt maksav kursus mis õpetab raha tegema, aga ainus asi mis see teeb on,  et see võtab ostja raha ja läheb otse juutuuberi tasku ja ostja saab vastutasuks video, et kuidas naabri hoovist õunu varastada ja neid müüa, et kasumit teenida.\nKõige targem oleks piirata kas aega või infot mida noored sotsiaalmeedias näevad ja kasutavad. Suunamudijad mõjutavad ja jäävadki mõjutama noori kuna noored ei viitsi faktiliselt kõike kontrollida ja lasevad endale kõike pähe määrida.');
