INSERT INTO core.text(id, content)
VALUES ('a57cdb7a-2ced-4f77-8550-3fb84d61df09',
        'Sotsiaalmeedia laialdase ja kiire levikuga on tekkinud üha rohkem suunamudijaid, kes oma kuulsusega inimese käitumist ja tegevust mõjutavad. Suunamudijade mõju võib inimesi mõjutada nendele teadmata ja tahtmata. Suunamudijate mõju ühiskonnale ja inimesle on võimeline ühiskonnale kahju tegema, aga samas suudab see ka palju head teha.\nPaljud suunamudijad ei ole tahtlikult selleks saanud, vaid on hoopis saanud kuulsaks lihtsalt oma elu ja tegevuste jagamisega, ilma et nad sellest mingisugust kasu ootaksid. Sellised suunamudijad võimaldavad inimestel jälgida kuidas nendega sarnased inimesed elavad ja kuidas nendega sarnase elustiiliga inimesed mõtlevad ja käituvad. Kuna inimesed enamasti seostuvad endale sarnaste inimestega, võivad sellised elulised suunamudijad tahtmata oma järgijaid mõjutada. Näiteks võivad sellise suunamudija järgijad osta samu tooteid mida suunamudija kasutab, teades et see pole reklaam ja et see toode on tõesti tavalisele inimesele mõeldud.\nMõned suunamudijad on mõned suunamudijad saanud tuntuks oma eksootilisuse ja kõrge staatuse tõttu. Näiteks kellegi rikkus võib tuua vaatajaid sisse nägema ja kogema elustiili, mis on neile kättesaamatu. Sellised suunamudijad tihti avaldavad oma mõju müües elustiili, mida pole tegelikult võimalik kätte saada nende meetodite kasutamisega. Paljud nende järgijad ihaldavad sellist elustiili nagu suunamudijal on ning on nõus ostma nende reklaamitud tooteid ja kursuseid lootes saavutada samale tasemele nagu suunamudija kujutab. Sageli on ka sellise suunamudija kujutatud elustiil võltsitud, kasutades ära oma võimalust kujutada sellist elustiili mis nad tahavad, ilma oma tegelikku elu vaatajatele näitamata. Sellised suunamudijad võivad oma võtetega lõpuks saavutada sellise elustiili mida nad reklaamivad, mis aina tõstab nende populaarsust ja võimet inimesi mõjutada.\nSamas on ka paljusi heatahtlikke suunamudijaid, kes on nõus kasutama oma kuulsust selleks, et toetada organisatsioone ja liikumisi mis tahavad ühiskonnas head teha. Näiteks on tuntud Eesti suunamudijad Hanna Martinson, Liis Velsker, Martti Hallik, Mick Pedaja, Juhani Särglep, Alisa Tsitseronova ja Liina Ariadne Pedanik kes on avalikult näitanud oma toetust organistatsiooni Loomus poolt. Sellistel suundamudijatel on suur võimalus ühiskonda positiiivselt mõjutada, kasutades oma laia järgijaskonda erinevatele organisatsioonidele ja liikumistele hoo andmiseks. Paljud suunamudijad kasutavad oma kuulsust, et ise algatada mingisugune liikumine, näiteks selleks, et suurendada teadlikust haiguse kohta mis neil endal on.\nSuunamudijatel on suur roll tänapäeva digiühiskonnas, kus enamus inimesi kasutavad sotsiaalmeediat. Enamusel neil ei ole suurt mõju kui nad just seda tahtlikult ei avalda. Mõned proovivad enda kasuks kujutada ebareaalset elustiili ja reklaamida tooteid mida nad ise tegelikuses ei kasuta ning petta oma järgijaid neid ostma. Samas on ka palju selliseid, kes proovivad tähelepanu tuua ühiskondlikele probleemidele nagu looduskaitse ilma, et nad ise sellest mingisugust kasu ootaksid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
