INSERT INTO core.text(id, content)
VALUES ('be7ad329-5c2b-44df-8228-efdd859712fe',
        'Maria Murumaa Mengel on oma artiklis öelnud: „Uuringutest on selgunud, et tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida ihaldada, mida põlastava pilguga vaadata, kuidas kellegagi suhelda“. Arvatavasti kõik tänapäeva noored ja lapsed nõustuvad selle väitega, kuid influencer’ ite mõjuga on omad eripärad ja probleemid, mis kaasnevad. Kõik oleneb inimesest ja ka sellest, et millist juutuuberit, tiktokkerit või muud sotsiaalmeediakuulsust jälgitakse.\nJuhan Hellerma on oma tekstis öelnud „Samas on aina raskem eristada, kas sisuloojale endale tõepoolest meeldib mõni film ja toode, või ta teeb seda reklaamina mingisuguse rahalise tasu või mõne hüve eest“ – see lause kehtib ühe tuntuma ja kuulsama suunamudija kohta, kelleks on MrBeast. Ta on saab enamasti vaatamisi noortelt, kuid tähtsamini lastelt. Ta teeb annetus ja võistlus videoid, kus peamiseks teemaks on suure raha ära andmine, aga see suur raha peab kuskilt tulema ning see tuleb tema toodetest, mida ta toob välja ja reklaamib igas videos, kuid vaadates MrBeas’i reaktsiooni ise oma toodet proovides ei ole tal erilist meeldivust selle maitsele. Feastables, Lunchly ja Prime – on tooted, mida ta on kooskõlas reklaaminud suunamudijate Ksi ja Logan Pauliga, kes on samuti kuulsad laste seas. Toode Prime ja Feastables on liigset suhkurt sisaldavad tooted ning Lunchly on koopia varemast produktist nimega Lunchables, mis on söögi komplekt. Olles suure nimega Youtube’ i maailmas ei imestata, et tal läheb rahaliselt hästi kuna lapsed ostavad tema ülehinnatud tooteid ülemaailma. Selliseid suunamudijaid, kes teevad oma tööd ainult rahalise edukuse pärast on palju, kuid mitte kõik influencer’id ei ole sellised.\nSuunamudijate maailmas on ka neid, kes teevad oma tööd, sest neile meeldib see ning selles võib kaks isikut näiteks tuua. Luke Korns on juutuuber, kes oli algselt tähelepanu otsija noorte tüdrukute seas. Ta sai kuulsust tänu oma välimusele, kuid tänaseks on temast saanud Youtube’s lühifilmi tegija. Tema videod tänapäeval keskenduvad reisimisele, kuid mitte nii nagu tava influencer’id seda teevad, ta teeb seda minimaalse rahaga. Ta ei käi populaarsetes linnades ja riikides, kus on ainult head näidata ega eputa oma rahalist edukust, vaid just vastupidi. Ta reisib vaesematesse riikidesse, et näidata kuidas tegelik elu näeb maailmas välja ning käib näiteks Itaalia mitte turistlikutes kohtades. Samal ajal oma videotes ta räägib süngematest teemadest ja probleemidest ja toob neile tähelepanu – näiteks depressioon, suitsiidi mõtted ja laiskus. Selline juutuuber näitab elulisust ning aitab nii noortel ja lastel kui ka täiskasvanutel oma silmaringi avada ja tuua tagasi realsusesse.\nTeiseks suunamudijaks on Sam Sulek, kes on tuntud nii noorte jõusaalis käijate kui ka tavainimeste seas kuna ta peamiselt postitab oma videod Youtube ja Tiktok’i. Tema videotes ta teeb trenni ja motiveerib noori oma keha eest hoolitsema, õpetab kuidas õigesti teha jõuharjutusi ning ka vahest räägib ka tõsisematel teemadel näiteks lahkuminekud ja depressioon. Ta kasutab steroide, kuid on sellega avatud ning ei proovi vääralt ära kasutada noorte arvamusi inimese tavakehast. Selliseid influencer’e on palju, kes kasutavad välist abi, et oma keha ilusaks teha ning proovivad müüa kursuseid, väites, et pärast saavad näha samasugused välja. Samuti tehakse seda ilutoodetega, kus naissuunamudijad, kes on käinud operatsioonidel mõjutavad noori tüdrukuid oma produkte ostma.\nSuunamudijad on sotsiaalmeedias suur osa ning ilma nendeta sotsiaalmeedia platvormid kaoksid kuna ei oleks nendel platvormidel rahalist kasu. On halbu suunamudijaid ning on ka häid, kuid sotsiaalmeedias peab olema ettevaatlik, sest võidakse silmaringi avada tahtvat noort ära kasutada, seetõttu ei tohi uskuda kõike, mida näed ja kuuled influencer’itelt.');
