INSERT INTO core.text(id, content)
VALUES ('d4bb3beb-453b-4327-80a1-b249b2908d9c',
        'Tänapäeva maailmas me ei saa üle ega ümber faktist, et sotsiaalmeedia mõjutab meid suuresti isegi kui pole sotsiaalmeedia kontot. Sotsiaalmeedias toimuvat kajastavad ka paljud uudised mida kas tarbime või lihtsalt mööda kerime ajalehes kui ka televisioonis kajastatu. Tuntust on kogumas nii noorte kui ka vanemate seas sisulooja amet, mis suuresti hõlmab postituste tegemist sotsiaalmeediasse, populaarsemad neist – Instagram, Youtube ja Tiktok. Kui palju saab sisulooja meid mõjutada ja palju võimu neil tegelikkuses ikkagi on?\nSisuloojate maailm tundub ilmselt enamikele pealtvaatajate ja jälgijatele üsna lihtne, iseeneset ei tohikski seal midagi rasket olla -teed pildi, kirjutad pealkirja ja postitad ning saavutad sellega endale jälgijaskonna ja kuulsuse. Suur osa sisuloojatest on kas oma elu näitajad või neil on mingi kindel eriala millest rääkida. Oma elunäitajatel on ka omad katekooriad millesse nad jagunevad, üheks neist on enda luksusliku ja rikka elu näitamine Eesti üheks näiteks on tekkinud Anita Sibul kes on saanud oma alguse youtube-ist ja tänaseks on läinud üle rohkem instagrammi. Anita sisu instagrammis on põhiliselt luksus reisi või luksus brändide omamisest. Anita on tunnistanud ka intervjudes, et on kasutanud näiteks koti rentimist.Rentinud endale soiva luksus brändi koti ja siis sellega postituse teind kus eksponeerib seda. Millest võib järeldada, et kõik mis sotsiaalmeedias näidatakse ei pruugi üldse päriselu olla.\nSisuloojad teevad ka palju reklaam postitusi ja koostöid brändidega, kus nad kas reklaamivad kindlat toodet oma postituses või annavad koos toote välja. Reklaamidega mõjutamist teevad paljud sisuloojad, osad kes päriselt kasutavad enda reklaamitud teenust või toodet ja osad kes teevad reklaami ära ja hiljem ei kasuta seda vaid tegid reklaami sissetuleku eesmärgil. Esimene varjant võib olla lihtsalt väga veenvalt tehtud reklaam, et inimesed jäävad uskuma ja, et sisulooja päriselt kasutavab seda ning sellele sisulooja suhtes tekib jälgijal oma usaldus. Teise varjandi puhul on jälgijad ise teinud märkamise mitte kasutamisest, see tõttu võib ka sisulooja kaotada oma usutatuvuse. Üheks selliseks näiteks võib tuua Eesti sisulooja Brigitte Susanne Hundi, kes on oma jälgijatele lihtsalt reklaami teinud ning hiljem neid tooteid mitte kasutatanud. Enamus tähelepanekuid on teinud teine sisulooja, kes toodab oma sisu  youtube-is nimega Andrei Zevakin. Sealsed tähelepanekud olid seotud Go3, OHO! ja samsungi reklaamdega.\nSellest järeldades peaksid olema sisutarbijad aina skeptilisemad, mitte vaid üksnes kodumaiste sisuloojate osas vaid ka välismaa sisuloojate osas. Sisuloojad on suur osa meie ühiskonna pildi loomisest, mille tõttu tasub ise ka uurida tarbitava sisu tõestust. Kõike mida võib sotsiaalmeedias näha on ei pruugi alati tõene olla ja ei tasu tänu sellele luua maailmapilti mis on just nii ilus kui meedias paistab. Tuleb meeles pidada, et sisuloojad ei postita alati kui midagi on halvasti vaid suur enamus postitab vaid head külge.');
