INSERT INTO core.text(id, content)
VALUES ('92256d25-2456-49b1-8ba8-8884e084df4d',
        'Tänapäeval on tänu tehnoloogia arengule välja kujunenud uued viisid, kuidas jõuda noore publikuni. Sotsiaalmeedia juurdumine inimeste igapäevaeludesse on loonud uusi karjäärivõimalusi ning üha levinumaks on saanud avaliku elu tegelase amet, teisisõnu ka sisulooja või suunamudija amet. Kuna sotsiaalmeedia on muutunud noorte peamiseks meelelahutuse ja info otsimise allikaks, on ka avaliku elu tegelastel suurenenud roll noorte arvamuse ja hoiakute kujundamises.\nNoor publik on väga vastuvõtlik neid ümbritseva maailma suhtes. Eesti väikese rahvaarvu ja eesti keele kitsa kasutusala tõttu pole siin influencer’i kärjäär nii levinud kui näiteks Ameerika Ühendriikides, mistõttu noored leiavad meelelahutust pigem välismaistelt suunamudijatelt. Teiste maade suunamudijad oskavad oma huvitava väljendusviisiga köita nii noore kui ka täiskasvanu publiku. Maria Murumaa Mengeli artiklis „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?“ on kirjutatud, et Crystal Abidin on uurinud internetikuulsust ning jõudnud järeldusele, et eksklusiivsus, eksootilisus, erakordsus ja elulähedus on need omadused, mille abil suunamudijad köidavad oma publiku tähelepanu ja mõjutavad nende hoiakuid. Suunamudijad kasutavad seda oskuslikult ära ning seetõttu on neil väga mõjuv roll noorte hoiakute ja arusaamade kujundamisel.\nNoore inimese jaoks on olulisel kohal ühtekuuluvustunne ning praeguses tarbeühiskonnas saab seda saavutada omandades neid asju, mida tema sõber või mõni lemmiksisulooja kasutab. Kahjuks ei ole kõik inimesed internetis heatahtlikud ning leidub neid sisuloojaid, kes on valmis petma oma publikut. Tuginedes Maria Murumaa Mengeli sõnadele, võivad inimesel kujuneda välja meediastaariga parasotsiaalsed suhted ja inimesel võib tekkida illusioon, et sisulooja on nende lähedane tuttav, keda tasub kuulata. Kuna paljud tendentsid tulevad välismaalt, on Eesti noorel raske kontrollida välismaa sisuloojate sõnade õigsust ja ta võib sattuda petturi kätte. Petmine ei pruugi alati olla materiaalne. Petmine võib peituda sisulooja esmapiglult sõbralikus soovituses, mis tegelikkuses võib osutuda varjatud reklaamiks. Kristjan Kikerpilli sõnul „on aina raskem eristada, kas sisuloojale endale tõepoolest meeldib mõni film või toode, või ta teeb seda reklaamina.“ Suunamudijad-petturid teavad oma noore publiku nõrkustest ja kasutavad nende usalduse ära. Selliste olukordade vältimiseks tuletab Kikerpill meelde, et võimalusel tuleks alati kasutada faktikontrolli.\nVaatamata kõigile ohtudele pole õige arvata, et kõik avaliku elu tegelased mõjuvad noortele halvustavalt. On ka neid, kes avaldavad noortele positiivset mõju ja panevad neid mõtlema ühiskondlike probleemide üle. Oranisatsioon Loovus on alustanud kampaania #loomadesilmis, mis kutsub inimesi üles mitte soetama karusnahka ning mis on eelkõige suunatud noortele tarbijatele. Kampaania eestvedaja Hanna Martinson peab oluliseks, et noorte seas kasvaks teadlikkus karusloomafarmide kulissidetagusest elust ja nad teaksid, mis peitub mütsituti valmistamise taga. Tänu sellele, et kampaanias osalevad ka kuulsad Eesti suunamudijad, on suurem tõenäosus, et kampaania sõnum jõuab noorteni ning tulevikus aitab neil teha ühiksonnasõbralikke otsuseid.\nAvaliku elu tegelastel on suur osatähtsus noorte vaadete kujunemisel. Võrreldes varasemaga jõuavad sisuloojate mõtted noore publikuni palju kergemini ja kiiremini, mistõttu mõlemad pooled peavad vastutama oma tegevuste eest ja olema ettevaatlikud sellega, mis informatsiooni nad levitavad või tarbivad. Sisuloojatel tuleks arvestada, et nende tegevusalast on saanud informatsiooni ja mõtete hankimise allikas ning noored peavad mõistma, et sisuloojad on tavalised inimesed, kelle sõnu ei tasu alati kuulata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('92256d25-2456-49b1-8ba8-8884e084df4d', 'title', 'Avaliku elu tegelaste osatähtsus noorte igapäevaelus');
