INSERT INTO core.text(id, content)
VALUES ('be8fff16-14e4-42a1-8caf-4a74b4007148',
        'Tänapäeva sotsiaalmeedias saab leida palju erinevaid asju, eriti palju on praegu populaarseid inimesi, kes räägivad avalikult oma elust ning üritavad seda ka mõnedele noortele külge panna. Populaarsemad teemad, millest räägitakse on jõusaal, lisandid või dieedid jõusaali jaoks ning lisandite mõju.\nPaljud inimesed hakkasid tegelema oma tervisega ning rääkima ja näitama seda internetis, hakati müüma erinevaid kursusi, kuidas saada kehamassi juurde või teha üht või teist harjutust jõusaalis. Selleks inimeseks sai üks kuulus Eesti tiktokker nimega Rasmuskel. Paar aastat tagasi hakkas ta suunama noori minema jõusaali, sest tema sõnul aitab see hakkama saada muredega ja lihtsalt vabastada oma pea paariks tunniks. Üllatavalt hästi töötas motivatsioon ning tõesti paljud noored hakkasid jõusaalis käima. Teine tiktokker on Martin Rätasepp, kes väga mõjutas oma praegust auditooriumi oma looga. Martini minevik oli väga raske, koolis teda alati kiusati tema keha pärast ning kui ta sai 15, hakkas ta jõusaalis käima ja praeguseks momendiks on Martin 20 ning tema tulemus on imeline, paljud noored võtavad teda nagu ideaali ja ka paljud noored võtavad temast eeskuju.\nTihti täiskasvanutel tekkivad probleemid tervisega lapsepõlve tõttu, ka tänapäeva noored tarvitavad erinevaid lisandeid jõusaali jaoks, mida soovitavad sotsiaalmeedia isikud. Paljud inimesed jõusaali minnes hakkavad lisaks tarbima kreatiini, proteiini või vastupidi istuma dieedil. Eelnevalt nimetatud Rasmuskel räägib oma TikTokis, et kreatiin ja proteiin on väga kasulik, nende jaoks, kes hakkasid jõusaalis käima, kuid noored tänapäeval ei mõtle tagajärgedele. Kreatiini ja proteiini tagajärgedeks võivad olla punnid igalpool, soolapõletikud, ei saa rasedaks ja palju muid probleeme. Noored on väga ära mõjutatud sotsiaalmeedia influencer´itest ja seega unustavad kontrollida üle, kas influencer´ite jutt on üldse tõsi. Dieedid võivad samuti ohtlikud tervise jaoks olla, võivad tekkida probleemid soolestikuga või alakaaluga. On olnud väga palju juhtumeid, kui internetis kirjutatakse erinevatest dieetidest ning hiljem inimestel tekkivad probleemid tervisega.\nTiktokker Roosabanaanike just hiljuti pani oma Youtube´i video, kus räägib sellisest vitamiinist nagu ashwaghanda. Internetis on kirjas palju erinevaid asju sellest vitamiinist, noortele meeldib, et see hoiab immuunsüsteemi ning lihased kasvavad kiiremini, kuid nad panevad silmad kinni negatiivsetele mõjudele. Roosabanaanike küsis mitmete inimeste käest, kuidas on ashwaghanda nende elu ja enesetunnet mõjutanud ning kõikidel oli üks vastus. ,, Ma ei tunne end õnnelikuna ega kurvana`` ütles üks tüdruk sellest videost, peale ashwaghanda tarvitamist. Roosabanaanike üritas näidata selle videoga, et ei tohi panna silmad kinni kõikidele kõrvalmõjudele. Ning tõesti ashwaghanda müük Eestis läks väiksemaks, sest noored istusid depressioonis nende vitamiinide pärast.\nInfluencer´id, tiktokkerid ja muud populaarsed isikud väga mõjutavad meie elu, otsusi ning vajadusi, mõned mõjutavad hästi, on ka neid , kes mõjutavad halvasti. Lõppude lõpuks me kõik oleme inimesed, me võime mõjuda teistest, kuid see ongi meie otsus. Seega küsimus ei ole selles, kuidas sotsiaalmeedia meid mõjutab, vaid kas me laseme tal ennast mõjutada.');
