INSERT INTO core.text(id, content)
VALUES ('6d587c81-c6c8-4d54-a78a-0501826c9a1a',
        'Inimesed on alati, läbi aegade lugenud raamatuid ja oli ka alati inimesi, kes ei suutnud raamatute lugemisega hakkama. Tänapaeva noored on sammuti nagu tolleaegsed inimesed, sest mõned nendest lugevad palju, mõned aga vähem või üldse ei loe ja sellega kaasneb probleem millega on väga raske toime tulla ehk keeleoskuse probleem. Siin proovin seletada ja leida välja probleemi mis puudutab kõike tänapäeva noori, raamatute mitte lugemise pärast.\nRaamatute lugemine on isegi minu arust väga igav aktiivsus tänapäeval ja paljud noored nõustuvad minuga, sest varasemal ajal ei olnud nii palju aktiivsust kui praegu. Tauno Vahter näiteks ütles, et raamatute lugemise harjumus tuleb kodust ja koolist aga mina ei nõustu tema ütlemisega, sest isegi koolis ja kodus, inimesel ei pruugi olla vaba aega, et lihtsalt lugeda paar lehekülge. Jälle tuleb see aktiivsuse teema ette, mis ei anna lihtsalt võimalust lugeda, sest noored on harjunud sellega, et peab valima elus seda, mida sa ise tahad teha.\nTauno Vahter ütles: ,,Poisid niikuinii loevad vähe, loevad ainult tüdrukud ning nemad enamasti Tiktokis ja Instas nähtud ingliskeelseid romantilise ja fantaasiakirjanduse raamatuid’’. Sellise väide põhjal me võime väita, et poisid tegelevad rohkem teiste asjadega ja nendel on vähem aega kui tüdrukutel, keda ei huvita teised asjad kuid ainult Tiktok ja Instagram mille kaudu nad leiavad need fantaasiakirjanduse juttud ja minu arust see ei ole kõige halvem asi mis saab olla, sest tüdrukut ja poisid arenevad väga erinevalt ja see väide ei pruugi olla ka tõene mida Tauno Vahter oma tekstis mainis, sest on ka poisid mis tegelevad raamatute lugemisega rohkem kui tüdrukut.\nAusalt öeldes ma saan aru miks paljud inimesed on häiritud sellega, et tänapäeval noored ei loe oma riigikirjandust. See on ikka osa meie kultuurist ja me peame seda teadma ja sellega tegelevad paljud õpetajad õppeainete kaudu. A. H. Tammsaare, raamat ,,Tõde ja õigus’’ näitas meile talupoegade rasket elu ja Tammsaare näitas meile kõike seda läbi raamatu. Noored praegu ei väärtusta seda kirjandust mida kirjutati aastaid tagasi, sest nad ei ole õppinud tundma neid vanu emotsioone mida proovisid kirjanikud meile läbi raamatute näidata.\nProoblem on selles, et noortel ei ole lihtsalt huvitav raamatuid lugeda ja kui isegi on, siis nendel ei ole aega. Mina arvan, et inimesel või noorel ei pea olema harjumus, et lugeda raamatuid. Noored peavad lihtsalt leidma raatatutes seda mida neile meeldiks lugeda välja ja kui see ei ole isegi ,,Tõde ja õigus’’ siis ikka, noored harjuvad lugemisega kiiremini kui nad loevad raamatuid mis nendel meeldiks lugeda, mitte need mida nad peavad lugema.');
