INSERT INTO core.text(id, content)
VALUES ('87dc3bd6-c2b1-4269-b1c5-cc21ab3cc1d8',
        'Eesti ühiskonnas on paljude probleemiks sotsiaalmeedia sõltuvus. Inimesed, eriti noorem rahvas, kasutab sotsiaalmeediat koguaeg. Nende päeva suurema osa ajast võtab ära netis ringi surfamine. Suureks osaks meedias on inimesed, kes räägivad ja näitavad enda elu ning keda peetakse arvamusliidriteks. Tekib aga küsimus, et kuidas mõjutab sotsiaalmeedia ja avaliku elu tegelased inimeste igapäeva elu.\nSotsiaalmeedia on üüratult suur digiplatvorm, kus võib leida igasuguseid videoid, pilte, õpetusi, jutte, ja kus saab inimene vabalt teistega suhelda. Kuna sellisel platvormil on palju inimesi siis on võimalus end teha kellekski keda paljud fännaksid. Nendest inimestest kujunevad välja erinevad suunamudijad. Mõjutama hakkab see teisi igatipidi, nii positiivselt kui ka negatiivselt. Saame öelda, et mõned suunamudijad annavad palju õpetust erinevates tegevusalades. Saame olla ka kindlad, et need on usaldusväärsed kuna  Maria Murumaa Mengeli artikilis on toodud välja, et ,,Kõige populaarsemad suunamudijad on tihti oma ala meistrid ja eksperdid´´. Näiteks kui inimene tahab midagi küpsetada, aga tal pole varasemat kogemust sellise retseptiga on tal lihtne leida video, kus näidatakse samm-sammult etappe, et jõuda välja lõpptulemuseni. Selliseid videoid või isegi pilte ja tekste võib leida igasugustel kategooriatel. \nKõik ei ole alati ka nii positiivne kui paistab. Toome näiteks noored tütarlapsed, kes jälgivad kuulsaid influencer´eid. Võiks ju öelda, et neile meeldib see kontekst mida nad pakuvad, kuid reaalsus on näidanud, et valdavalt influencer´ite jälgimine toob kaasa enda haletsemise. Selline probleem võib viia suurematesse tüsistutesse ehk võivad kaasneda depressioon, söömishäired jne. Suurteks probleemideks pole sotsiaalmeedias mitte ainult suunamudijad ja muud avaliku elu tegelased, vaid ka petturid. Petturid võivad teha palju erinevaid vägitükke netiavarustes. Nad võivad petta välja inimestelt raha või nende andmeid, nad võivad varastada kellegi identiteedi ja saata korda suuri äpardusi. Selleks, et kõigest sellest pääseda saavad inimesed väga palju ise teha. Juhan Hellerma on oma tekstis maininud ,,...tasub kodutöö ära teha ja mitte jälgida teatud mõjukuse saavutanud suunamudijate nõuandeid pimesi.´´ Selle väitega on J.Hellerma tahtnud tähelepanu pöörata kõiksugu vahenditele, mida saab kasutada enda kaitsmiseks.\nSotsiaalmeediat kasutatakse ka väga palju reklaamimiseks ja erinevate tarvete müügiks. Kui võtta lahti instagram ja hakata ringi skrollima siis umbes iga kolmas postitus on mingi toote või teenuse reklaam. Kuna need reklaamid näevad inimese jaoks väga atraktiivsed välja, ning nende toodete või teenuste tellimine on ainult ühe klõpsu kaugusel, tekib suur himu need ka kohe endale tellida. Selliste reklaamide kaudu tellimine võib tekitada aga probleeme teadmatusega. Kui tegu pole mingi tuntuma või suurema brändi poolt pandud reklaamiga ei saa olla kindel tellimuse kohale saabumises või kvaliteedis. Sellega on tulnud ka ette juhtumeid, kus inimesi petetakse nende tellimustega. \nSaame öelda, et sotsiaalmeedia ja selles tegutsevate avalike elu tegelaste mõju inimestele võib olla nii posiivne kui ka negatiivne. Selliste mõjude põhjuseid on väga palju, aga ka enamuste jaoks on lihtsad võimalused neid ära hoida. Inimesed peaksid hakkama hoiduma sotsiaalmeedias olemist nii kaua, vähendada seda aega tervelt päevalt tunniks või kaheks.');
