INSERT INTO core.text(id, content)
VALUES ('a678dc09-192b-4237-a9c2-9b70b9aa5e35',
        'Tänapäeva maailmas on laialt levinud sotsiaalmeedia, kus peaaegu kõik, mida inimene tahab, on ainult mõne nupu vajutuse kaugusel. Sotsiaalmeedias leiab tänapäeval kõike, mida inimene soovib, kuid peab oskama otsida. Inimesed postitavad endast väga palju asju internetti üles, kuid kõik ei pruugi teada, et see, mis läheb internetti, see ka sinna jääb. Tihti peale on ka neid inimesi, kes on väga suured oma arvamuse avaldajad ja, kes käituvad nii, nagu teeb mõni suunamudija. Eesti suurimateks suunamudijateks on näiteks: Andrei Zewakin, Kris Kärner (Istoprocent), Mallukas, Maria Rannaväli. \nTänapäeva sotsiaalmeedia kohta võib väita, et seal kehtib üks kuldreegel, et mida rohkem on ühel inimesel jälgijaskonda, seda rohkem seda inimest kuulatakse, ning seda rohkem aksepteeritakse selle inimese arvamust. Need suurte jälgijaskonnaga tegelased on tavaliselt suunamudijad. Suunamudijad on tavaliselt need, kes avaldavad oma arvamust kõike rohkem ja nende jälgijad käituvad ja arvavad ka täpselt nii, nagu suunamudija, sest nad tahavad olla nagu nemad, kuna neile tundub, et nii ongi normaalne käituda. Neid inimesi ei kõikuta enam see, kas see kõik vastab üldse tõele või mida tunneb see teine inimene, kelle kohta arvamust avaldatakse. Kui ühiskonnas on mingi probleem, millega ei suudeta inimesi kaasata selle lahendamisel, siis kaasatakse näiteks suunamudijaid, kellel on palju vaadajaid, sest vaatajad kuulavad tavaliselt oma lemmikut suunamudijat ja aksepteerivad seda ja hakkavad ka nii arvama, sest jälgijad tahavad ka sellised olla, nagu on näiteks Istoprocent.\nTegelikkuses ei ole see suunamudijate eesmärk, sest nad avaldavad ainult oma enda arvamust, ja nad ei käse oma jälgijaskonnal nii arvata, vaid nad küsivad ka oma vaatajate kohta arvamust, näiteks Eesti kuulsam striimer Istoprocent, kes striimib nädalas 5 päeva ja ta avaldab oma arvamust mõne asja kohta, mis talle ei meeldi või millega ta on on nõus, kui ta on oma arvamuse ära avaldanud, siis ta tavaliselt küsib ka oma jälgijate käest, mida nemad arvavad, ning ta aksepteerib neid ja kui ta päris nõus nendega ei ole, siis ta põhjendab ära, mis talle ei sobi või küsib täpsustavaid küsimusi.\nSellega on suunamudijatel suur roll ühiskonnas, sest enamus nende jälgijaskonnal on samad maailmavaated, mis on suunamudijal endal, sest iga inimene älgib ainult seda inimest, kellega tal on väga sarnased maailmavaated. Kuid tulles nüüd tagasi suunamudijate mõju juurde ühiskonnas, siis saab öelda ka, et nende jälgijad hakkavad samamoodi rääkima ja samu väljendeid kasutama, sest see tundub jälgijatele, et see on äge ja inimesele võib tunduda, et kui ta räägib samamoodi, nagu mõni suunamudija, siis kõik inimesed arvavad, et see on sama äge, kui on see suunamudija, kelle väljendeid kasutatakse.\nSuunamudijate mõju ühiskonnas on üsna suur ja see on nii negatiivne mõju kui ka positiivne, sest kui on vaja kaasata suurem osa ühiskonnas, et teha ära midagi, siis on mõistlik kaasata suunamudijaid, kellel on palju jälgijaid, sest kui suunamudijad avaldavad oma avamust ja hakkavad midagi tegema, siis suur tõenäosus, et ka nende jälgijad on ka nõus nii tegema. Sellega tuleb ka ettevaatlik olla, sest kõik see, mida arvab suunamudija, siis see kõik ei pruugi hea olla. Alati peab olema ka enda arvamus, mis ei pea minema kokku suunamudija omaga.');
