INSERT INTO core.text(id, content)
VALUES ('4ee6cdc4-485a-4fe5-87cf-0452c3ef3650',
        'Enamus tänapäeva noori ei kujuta enda elu ilma nutiseadmeta. Kas on seal midagi sellist, mis nõuab igapäevselt tähelepanu. Või äkki miskit sellist, kust noored saavad vastused kõikidele oma küsimustele ning mis mõjutab nende enda arvamuse ja maailmavaate. Vaadates ilustat elu pildil on ka oht, et hiljem inimene saab aru, päriselus kahjuks kõik ei ole nii ilus ja lihtne nagu seda näidatakse meedias. \nPaljud tänapäeva noored kasvavad päris kiiresti, sama kiiresti nagu muutuvad ka nende mõtteviisid ja maailmavated. Nendeks kiirendavateks teguriteks on suunamudijad või nagu nüüd öeldakse „trendilooja“ või ka „sisulooja“. Neis on miskit sellist, mis köidab rohkem tähelepanu ning mida eriti teismelised on nõus tundide kaupa vaatama. Muidugi on ka see, et suunamudijate jälgijad tahavadki rohkem nende moodi olla, kas välimuselt või eluviisi poolest. Kuid paljud sisuloojad ei mõtle sellele, et noor inimene kuulab nende mõtteid, nõuandeid ja võtavad tõsiselt neid kasutusele. Nemad aga ei saa aru sellest, et noorte iidol ei pruugi alati rääkida asjadest nii nagu on, selletõttu võivadki kaasneda erinevad juhtumid.\nOn tehtud kindlaks, et suunamudijad mõjutavad inimesi tervisega seotud valikuid tehes. Tiktoki platvormil on kaua olnud üks vene suunamudija, kes rääkis tervisele kasulikest huultepalsamitest ning kes ise väidetavalt kasutas neid. Hiljem tuli välja, et sisulooja on kasutanud enda tuntust toodete reklaamimiseks. Tegelikult kõik tooted on valmistatud kellegi kodus antisanitaarsetes tingimustes, mitte tehastes. Samuti on ka leitud neis toodetes palju baktereid, mis just vastupidi võivad olla kahjulikud inimese tervisele. On olnud ka „maagiliste“ vitamiinide kampaaniaid, mis kohe teevad nende ostja kõhnaks ja ilusaks, ausalt öeldes ei teinud need absoluutselt mitte midagi\nUuringutest on selgunud, et tihti saavad noored suunamudijatelt nõu mida normaalseks või ebanormaalseks pidada. On olnud olukordi, kus suunamudijad on propageerinud oma enesearenduse kursusi, eriti naistele ja neidudele, mille ostes inimene saab sama kuulsaks või veel kuulsamakski kui sisulooja ise. On räägitud ka sellest, et tavalisel tööl käia ei ole enam moes ning elu toimib läbi sotsiaalmeedia. Inimesed, kes on olnud tõesti hädas on neid kursuseid ostnud ja lootnud parema tuleviku peale ja hakati häbenema oma töökohti, kuna palgad ei ole nii uhked nagu sisuloojatel. \nTänapäeval peaks olema ettevaatlik sotsiaaalmeedias oleva infoga ja nõuandmistega, kuna on avaliku elu tegelasi, kes tegutsevad peamiselt enda kasuks. Kahjustades noorte inimeste usaldust ja veel tõsisem kui kahjustatakse nende tervist. Eriti noor inimene usub suunamudijate öeldusse ning tegutsebki nii, nagu nemad  tahavad. Eelkõige peab kuulama ennast ning tegutsema nii, nagu sulle tundub õieti, mitte nagu seda tahavad meedias olevad inimesed.');
