INSERT INTO core.text(id, content)
VALUES ('21d6d063-eedb-4b7f-ab27-9c8fcacfb008',
        'Eestis on ühaenam aktuaalseks muutunud, et sotsiaalmeedia platvormidel tegutsevad sisuloojad, kes on oma vaadete või tegemistega sattunud vaatajate jaoks arvamusliidriteks. Suunamudijateks pärjatud sisuloojad avavad sotsiaalmeedia platvormidel, nagu instagram, tiktok, twitch, oma elu kõikidele, kes suvatsevad neid vaadata. Enamasti jälgivad sisuloojaid just nooremapoolsed inimesed, keda on lihtne veenda ja kujundada.\nSuunamudijate arvamused, mida pidada normaalseks või ebanormaalseks, kuidas suhelda, mida soovida ning mida põlastava pilguga vaadata, on noorte jaoks saanud kui baasteadmised. Noored, kes jälgivad sisuloojaid, võtavad iga päevaga järjest rohkem omaks arvamusliidrite hoiakuid, olgu see, kas hoiakute endi pärast või, et ise rohkem samastuda sisuloojaga. See ei pruugi alati olla halb olukord, aga siiski on Eestis sotsiaalmeedia platvormidel kuulsust kogunud ka asotsiaasete eluviisidega sisuloojad, kes avavad kõikidele vaatajatele, eestkätt noortele oma igapäeva elu, mis sageli on üsna depresiivne, ropp ning alaväärtuslik. Selliste sisuloojate jälgimisega kaasneb olukord, kus noored võtavad kasutusele sõnavara, mida nad kuulevad, või ülbeid ja ennastkahjustavaid eluviise.\nSuunamudijad on paljuski nagu müügimehed. Nad teenivad peamiselt elatist toodete või teenuste reklaamimisega ning selle tulemuse eelduseks on siirasus. Tartu ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill on oma uurimustöös tähendanud järgmist „Populaarsemate suunamudijate sõnumid jõuavad väga paljude inimesteni. Kui see on siiras ja võib-olla inimene lihtsalt arvab midagi, millega me ei nõustu, siis on tegemist mõtte- ja sõnavabaduse alla kuuluvaga. Kui aga mängus on varjatud hüved, siis on põhjust olla rohkem murelik.“. Sellega taotleb lektor seda, et üha raskem on teha vahet, kas sisuloojale päriselt meeldib mingi reklaamitav toode, või teeb ta seda hüve saamise eesmärgil.\nAktuaalne on ka teema, et suunamudijad proovivad noorte arvamust muuta maailmaparandamise alustel, näiteks informeerida inimesi rohepöörde olulisusest, metsade liigsest mahalõikamisest ning karusnahkadest tarbeesemete soetamisest. Näiteks on loomade eestkoste organisatsioon Loomus kaasanud Eestis mitmeid tuntuid sisuloojaid, nagu Hanna Martinson, Martti Hallik, Mick Pedaja, jt. et kutsuda üles inimesi mitte ostma karusnahka. Sisuloojate abiga jõuab sõnum, mida organisatsioon levitab, kaugemale ja rohkemate noorte kõrvu. Konkreetse üritusega proovivad maailmamuutjad vähendada karusnahakde tarbijaid, mille tulemusel peaks karusnahku vähem tootma ning vähem loomi surema. Läbi suunamudijate saab taoline ettevõtmine rohkem kajastust, kui seda oleks saanud organisatsioon Loomus ise. \nSuunamudija nimetusele omaselt mudivad sisuloojad oma jälgijate otsuseid, vaateid, valikuid ja igapäevaelu, olgu see siis paremuse või halvemuse poole. Suunamudijad on võtnud endale tähtsa rolli tänapäeva noore inimese elus ning, et kaitsta noort inimest, on vaja, et keegi kontrolliks sisuloojaid ning seda, mida noor jälgib. Noortele on vaja selgitada, et igasugu arvamust on vaja võtta teatud kriitilisusega ja eluotsused ei sõltu kellegi arvamusliidri arvamusest.');
