INSERT INTO core.text(id, content)
VALUES ('5650b685-1b3d-4200-bfc1-2fc761400c10',
        'Meie elu jooksul on meid mõjutavaid faktoreid lugematu arv. Sellisteks teguriteks võime lugeda meie sünnilinna, ümbruskonda ning pisidetaile meie kogemustest. Sotsiaalmeedia ja interneti sünniga on kergenenud informatsiooni kättesaamine ning tekkinud ka mõjutava loomuga sotsiaalmeedia suunamudijad, kellel on Crystal Abidini sõnul neli peamist omadust, milleks on eksklusiivsus, eksootilisus, erakordsus ja elulähedus ja keda võib käsitleda ka kui virtuaalmaailma avaliku elu tegelasi. Kuidas sellised figuurid mõjutavad meie tuleviku põlvkonda?\nSuunamudijad edendavad meie noorte mõtlemisvõimet ning algne pilt sotisaalmeedia mõjust tundub päris optimistlik: Sukeldudes uue kasutajana populaarsetesse meediaplatformidesse kohtame värvilisi pilte rõõmsatest peredest ja rikkadest investeerijatest, kes kõik rõhutavad punkte, mida nemad järgisid, et jõuda enda positsiooni. Noortele edukate inimeste kajastamine on täpselt õige töörist, mis arendaks neid vabal ajal ning hoiaks ära võimalikud vead tulevikus. Seega saab väita, et suunamudijad motiveerivad ja inspireerivad meie noori kirglikeks eestvedajateks, kes on varustatud ainult kõige puhtamate tarkusteradega ning läbimõeldud plaanidega.\nSuunamudijad on ka just need isikud, kes vabatahtlikult kasutavad oma vaba aega teiste inimeste aitamiseks. Müügi- ja ostufoorumites leiame videoteoseid, mis on ülesehitatud ausa ja konstruktiivse tagasisidega toodete kohta. Suunamudijateks on ka tehnikud ning põllutöölised, kes jagavad oma teadmisi seadmetest, millest tavainimene ei tea ning millest informatsiooni leidmine oleks kallis või aeganõudev. Lisaks kajastatakse meeidas erinevaid heatahtlikke kampaaniaid näiteks Eesti enda #loomadesilmis, mis kutsub inimesi üles mitte soetama karusnahka. Sellisel viisil aitavad suunamudijad suuresti ühiskonna arengut ja heaolu ning säästavad noorte aega ja raha kiirete ja läbimõeldud lahenduste pakkumisega.\nInternerikuulsused ei ole kõik heatahtlikud ning suur mõju nende poolt osutub ka pahatahtlikuks. Sügavamale navigeerides näeme, et kogu internet ei ole ainult informatsioonirikas abistav tehiskeha ning esile kerkib aina süngem toon: populaarsed finantsgurud müüvad peidetult kuulajatele ja vaatajatele oma brändi ja naiivsemad inimesed usaldavad oma virtuaalset „sõpra“ ning näevad teda kui lähedast, kuigi tegelikkuses kuritarvitavad sellised persoonid just neid noori ning oma kuulsust suurema ja mõjukama meediavõimu omandamiseks.\nSotsiaalmeedias mõjutatakse inimesi ka poliitiliselt. Tänapäeval on poliitikasse kasutusse tulnud uus võte: nimelt loovad poliitikud endale kasutaja, millega kajastavad nad positiivseid sõnumeid ning tühju lubadusi, et võita üle noored, kes ei oska vahet teha tõese ja väära vahel. Selline mõjutamine kaotab poliitiku tegeliku motiivi ning loob särava näo muidu unustatavale kandidaadile. Kuna noored valivad tulevikus demokraatilises riigis endale juhid, siis on selline võte pigem pikaajaline ning tõhus, kuna internetis on jälgijaid kaotada raske.\nMeie tänapäevase elu mõjutavatest faktoritest on suur osa virtuaalmaailmas. Interneti suunamudijate mõjul on mitmeid erinevaid külgi, millest mõned on positiivsed ning teised negatiivsed. Sotsiaalmeedia mõju noortele on mitmekülgne ning ainult aeg näitab, kuidas järgmised põlvkonnad sellega toime tulevad.');
