INSERT INTO core.text(id, content)
VALUES ('63277358-83a0-44a4-a81b-16292c17f997',
        'Inimene pole ammu enam metsikus looduses võitlev imetaja, kes peab ellujäämise tõenäosuse suurendamiseks järgima liidrit ja kuuluma karja. Tänapäeva nn „heaoluühiskonas“ on võimalik varasest east saati langetada otsuseid lähtudes puhtalt oma sisemisest kutsumusest, peaasi, et see jääb legaalsuse piiridesse. Siiski on enamike noorte ühiskonnaliigete igapäevane võitlus pideva ühtekuuluvustunde jahtimise ja heidikuks muutumise kartusega. Vastupidiselt levinud arvamusele, otsivad isegi ühiskonnas erilised ja silmapaistvad inimesed sidet ja heakskiitu teistelt, lihtsalt erinevate tunnustega isikutelt. Vaatleme kasvõi Vene ajal Eestisse jõudnud punk subkultuuri järgijad. Pealtnäha protestivaimulised tavaühiskonna taunijad kuuluvad ju ka siiski oma karja, kus nad saavad üksteiselt pidevat heakskiitu. Iseenesest polegi sellel midagi viga, kuid probleem hakkab esinema kui massi mõjutatakse maailmavaateliste tõekspidamiste kujunemisel ning inimene kaotab kontakti oma moraalide ja pürgimustega. Nii ongi aga juba juhtunud tänapäeva noorte ja neid juhtivate avaliku elu tegelaste ja suunamudijatega.\nÜha levinumaks saanud mõiste „suunamudja“ on juba oma nimelt mingis mõttes problemaatiline. Kui üksikisiku käes on võim panna kedagi, eriti noort, muutma oma elu trajektoori, kaasneb sellega ka oht langetada kusagil ostus, millest enam tagasi astuda ei saa. Maria Murumaa Mengeli sõnul on tehtud kindlaks, et suundamudijad mõjutavad inimesi ka tervisega seotud valikuid tehes (dieedid, iluoperatsioonid, vaktsieerimine jne), parteide ja poliitikute toetamisel, maailmavaateliste tõekspidamiste kujunemisel jm. Näiteks on ajakirjanduses avalikustatud viimaste aastatega mitmeid lugusid iluoperatsioonidega liialdanud sageli alaealistest isikutest, kes nüüd kannatavad tõsiste terviseprobleemide all. Ükski noor ei oleks tõenäoliselt oma valikuga nii kaugele suutnud minna, kui poleks olnud mingit mõjuisikut, kes neid veendis operatsiooni ohutuses ja vajalikkuses. Peaks olema imperatiivne, et mõjuisikutelt nõutaks tervist mõjutavates küsimustes koostööd objektiivsete eriala spetsialistidega, kes veenduvad, et suunamudija levitatavad hoiakud ei põhjustaks noortele järgijatele valearusaamu. \nArvamusliidritel on ka võim teha palju head, mida kahjuks tihti ei kasutata. Kui sageli alustatakse influenceri teekonda üllastel eesmärkidel nagu inimeste eluprobleemide leevenduseks toreda meelelahutuse pakkumine, on ebaausus kiire tulema esimesel kokkupuutel sponsorite rahastusega. Hakkatakse reklaamima tooteid, mille ohutuses ja tarbeväärtuses tegelikult kindel ei saa olla ning noorel jälgijal polegi muud teha, kui oma lemmikisiku soovitatud toode soetada. Ka Juhan Hellerma on väitnud, et aina raskem on eristada, kas suunamudijate reklaam ja soovitused on tehtud mingisuguse rahalise tasu või hüve eest, või meeldib antud film või toode neile päriselt. Näiteks kiitis hiljuti maailmas kõige suurema  jälgimiskonnaga juutuber MrBeast äärmiselt madala toiteväärtusega lõunaeine komplekti oma noortele jälgijatele, kes seejärel suurtes kogustes seda ka endile soetasid. Seega on suunamudijad juba piisavalt mõjuvõimsad, et nad suudavad mõjutada isegi laste söömisharjumusi, milles tegelikult peaksid kaasatud olema vanemad, kelle erapooletus ja heatahtlikkus oma lapsele on vastandlikult suunamudijatele garanteeritud.\nKuigi ühtekuuluvustunde jahtimine pole ühiskonnas suguli haruldane ega otseselt kahjulik nähtus, on noorte suhtes mõjuvõimsate suunamudijate soovitused sageli kallutatud või ei anna noorele jälgijale edasi kaasnevaid ohte, mis tekitab üha enam muret. Nende soovitused on viinud mitmed isikud nii kaugele, et lastakse teha elumuutev iloperatsioon või hakkatakse igapäevaselt tarbima influenceri reklaamitud tarbeväärtusetut toodet. Seega on ilmselge, et noore juhendamise roll võiks jääda siiski vanemate ja haritumate ühiskonnaliikmete õlule, sest muidu võivad tulevikuväljavaated muutuda kiiresti üpris täbaraks.');
