INSERT INTO core.text(id, content)
VALUES ('f664f165-db5a-48e7-a05d-ed0aafc5e1ea',
        'Lugemisoskus ja lugemisharjumusete kujundamine on oluline teema 21. sajandi ühiskonnas. Tänapäeva noored ei loe enam niipalju kui seda on tehtud varasemate sajandite jooksul. Üheltpoolt ärgitatakse õpilasi ja noori lugema, kuid selline tegevus ei ole veel vilja kandnud. Sellele tuuakse mitmeid põhjendusi ning mõnda käsitletakse ka siinses arutluses. Miks on noorte lugemisharjumused vähenenud ning mis tagajärgi see toob?\nTavaliselt on noorte lugemisharjumuste vähenemises süüdi nutiseadmete kasutus. Paljud noored kasutavad nii koolis kui ka kodus pidevalt nutiseadmseid ning tänu sellisele tegevusele jääb neil vähe aega raamatute lugemiseks. Vähene raamatute lugemine vähendab noorte silmaringi ja tähelepanuvõimet. Alles hiljuti oli näide Pealtnägijas kuidas õpilased ei suuda isegi tunnis ilma nutiseadmeta istuda. Veel toob hea näite sellest Tiit Hennoste oma artiklis „Lugemise harjumuse harjutus“, kus ta võtab kokku mida funktsionaalse lugemisoskuse puudumine võib kaasa tuua. Lugemisharjumuse üheks vähendajaks võib tuua nutiseadmeid, mis röövivad niigi väärtusliku aja noorte inimeste elust ning vähendavad soovi lugeda mõnda huvitavat raamatut.\nVeel  vähendab noorte huvi lugemise vastu kohustatud kirjandus, kus sunnitakse ühte kindlat raamatut või raamatute ajastut lugema. Mõne raamatu või isegi raamatuajastu, näiteks romantismi, klassitsismi või muu taolise puhul ei sobitu selline stiil õpilase enda raamatu maitsega ning võib ära rikkuda tükiks ajaks lugemissoovi ära võtta. Teisest küljest on vahel probleem ka siis kui noor pole lugemishuviline ning kohustus lugeda võib ära rikkuda ka täiskasvanu eas lugemissoovi. Näite sellisest probleemist  saab tuua minu enda klassist kus on kindlasti õpilasi kes armastavad lugeda, kuid kui ollakse kohustatud midagi kindlat lugema pigem tunnevad seda kui ebameeldiva tegevusena. Veel on hea näide jällegi Tiit Hennoste artikel „Lugemise harjumuse harjutus“, kus ta räägib oma kogemustest raamatutega. Samas aitab just lugemine paremini arusaada erinevatest tekstidest, näiteks artiklitest, luuletustest või isegi töölepingust. Ühe kindla raamatu lugemine võib vähendada huvi mõneks ajaks raamatu kättevõtmist. \nLugemisharjumuse kujundamine on oluline teema eriti kui just noored ei loe enam nii palju kui vanasti. Luhgemisharjumuse vähenemisel on mitmeid erinevaid põhjusi: eelistus kasutada nutitelefone, vähene huvi kindlate raamatute või üldiselt kõigi raamatute vastu. Huvi taandumisel kaasnevad mitmed probleemid, näiteks keeleoskuse kahanemine, tähelepanuvõime ja silmaringi vähenemine, teksditest arusaamine. Kokkuvõtteks on see suur probleem, mis vajaks lahendamist.');
