INSERT INTO core.text(id, content)
VALUES ('34f6ca7a-f3c4-425f-8690-07c1b23a3936',
        'Sotsiaalmeedias sisu loomine on üks kõige populaarsemaid viise kuidas raha teenida. Sisulooja on justkui uus ametinimetus. Hea sissetulek ning üldiselt üsna lihtsad tööülesanded. Tänu lihtsusele selles töös, tehakse ka palju nalja suunamudijate üle, teadmata kui suur mõjuvõim suunamudijatel tegelikult on. Suuna mudimine on olnud olemas sostiaalmeedia loomisest saati. Kuulsad lauljad, näitlejad ja muud netikuulsused tegelevad pidevalt sisuloominguga. Praegusel hetkel on lihtsalt igal ühel võimalus alustada sisulooja karjääri ning teenida raha erinevate videote või piltide postitamisega. \nSisuloojate sisu on kõigil enam vähem sama. Postitatakse videoid oma päevategemistest,  elustiilist,  jagatakse nippe ja nõuandeid näiteks moe või ilu kohta. Palju on ka õpetlikku sisu, näiteks matemaatika ülesannete lahendamine, uudiste ette lugemine natuke lõbusamas võtmes jne. Tavaks on saanud sotsiaalmeedias perfektse elu jagamine. Enamus sisu keskendub n.ö unistuste maailmale, kus kõik on 10/10 ilusad, meeletult rikkad  ja suudavad elada murevaba elu ning kui tekib tunne, et ei olda piisavalt ilus, siis selleks jagatakse (vahel ka absurdseid) nippe ja nõuandeid. Sisuloojatel on suur võim eriti noorte maailmapildi kujunemise üle. See on loomulik, et võetakse kuulda kellegi kuulsa mõtteid ja ütlemisi. Kui inimesele meeldib, mida ta näeb siis automatselt tekib usaldus inimese vastu, kes seda meeldivat sisu loob. Suunamudijad teevad oma videod võimalikult esteetiliseks, sest just esteetika ja perfektsus on see, mis noortele peale läheb ning jälgijaskonda kasvatab. \nPerfektse elu propageerimine aga alandab enesehinnangut eriti teismeliste seas. Liialt sotsiaalmeediast eeskuju võtmine kaotab reaalsustaju. Noored ei luba endal olla muud, kui perfektsed, tekitamaks sostiaalsetele normidele vastamise survet. Ei julgeta olla nemad ise. Suunamudijad on peamised sotsiaalsete normide loojad. See ei pruugi olla isegi tahtlik. Jagatakse lihtsalt oma arvamust millegi osas, kuid palju on ka pahatahtlikku sisu. Ilma aru saamatagi võivad olla noored mõjutatud erinevate sisuloojate arvamustest või tõekspidamistest. Noored võtavad sisuloojaid kui eeskujusid . \nSisuloome pole ka läbi ja lõhki halb. Paljud sisuloojad jagavad õpetlikku informatsiooni. Näiteks on TikTokis populaarseks saanud õhtulehe konto, kus üks eesti sisuloojatest loeb ette nädala uudised. Vähesed noored tunnevad huvi poliitika või üleüldse maailmauudiste vastu. Kui aga need videod tulevad ette TikTokis, siis nii mõnigi jääb neid huviga kuulama ja vaatama ning isegi kommentaariumides kaasa rääkima. Samamoodi postitatakse sotsiaalmeedias ka motivatsioonivideoid, jagades oma teekonda fitnessimaastikul või motiveerides noori õppima jne.\nKokkuvõtteks- Suunamudijate mõju noorte üle on meeletult suur. Kasutatakse jälgijaskonna kasvatamiseks mõjuvahendeid. See mõju ei ole ka alati halb. Iga noor peaks tegelikult ise aru saama, kas mõjutamine on pahatahtlik või heatahtlik. Sotsiaalmeediat tuleks ära kasutada targalt, mitte otsida igas halvas asjas põhjust, miks sisuloome üle nalja teha või selle vastu olla.');
