INSERT INTO core.text(id, content)
VALUES ('6702bbd8-905b-41e7-a38a-2a053559a5f1',
        'Tänapäeva ühiskonnas on suur roll avaliku elu ja sotsiaalmeedia tegelastel. Nende roll on tihti mõjutada inimesi, eriti noori, tegema teatud valikuid või panna neid ostma teatud tooteid või teenuseid. Nende isikute mõju on viimastel aastatel üha enam kasvanud, sest maailm digitaliseerub pidevalt ning enamus infot saavad noored tihti just sotsiaalmeediast.  Kuidas on mõjuiskiute roll noorte igapäevaelule kasulik ning millised on selle negatiivsed küljed?\nNoored võtavad tihti tuntud isikud või meediastaarid endale eeskujuks ning hakkavad jälgima kõke mida nad teevad, milliseid tooteid nad kasutavad või kuidas nad toituvad. Kuna tegu on isikuga, kes on niivõrd tuntud ja meeldib miljonitele, võibgi tekkida arusaam, et see mida tema teeb on õige ja toimib. Inimesed võivad olla ühte isikusse nii kiindunud, et kui nad tema tegevusi pidevalt jälgivad, tekib tunne justkui oleks tegu mõne sõbraga, kelle nõu tasub kuulata. Juba 1956. aastast päri parasotsiaalsete suhete teooria järgi tekib inimestel meedia vahendusel illusioon, et meediastaar on nende lähedane tuttav ( Maria Muramaa Mengel ,,Mõjutamine (4): kuidas suunamudijad meid mõjutavad?’’). Selline suhtumine noorte puhul ei pruugi alati olla tervislik, sest tegelikku inimest nad ei tea ning nad näevad ainult seda poolt, mida tuntud isik endast jagab. See võib viia valearusaamadeni täislikust elust ja panna noori oma enesehinnangus kahtlema.\nKuna influencer’ite puhul on siiski üldiselt tegemist inimestega, kes vajavad raha, et ära elada ning see ongi nende ainus sissetulekuallikas, võivad suunamudijad tihti asju ilustada või näidata paremast küljest. Nende eesmärk on koguda jälgijaskonda ja selleks võivad mõned isegi meelega tekitada meediaskandaale. Näiteks suunamudija Brigite Susanne Hunt jagab tihti oma treeniguid ja toitumist. Sellest on aga tekkind meedias mitmeid skandaale, kuna influencer’it jälgivad noored hakkasid õhtusöögiks samuti sööma nii-öelda tervislikke riisigalette või madala kalorsusega jäätist, mis üksi ei ole tegelikult kasvavale organismile piisavalt toiteväärtuslikud. Tihti reklaamitkse tooteid, mis ei toimi või, mis endale tegelikult ei meeldi lihtsalt sellepärast, et selle eest saab head tasu. Hiljuti olid pildil mitmed suunamudijad, kes soovitasid toidulisandit nimega Aschwaganda, kuid hiljem tuli välja, et see on hoopis tervisele kahjulik. Kõik suunamudijad ei pruugi olla usaldusväärsed ning seetõttu tasub enne millegi ostmist või tarvitamist ka fakte usaldusväärsematest allikatest kontrollida.\nSuunamudijad teevad ka palju, et inimesi positiivselt mõjutada ning panna neid tegema paremaid valikuid. Tegu võib olla keskkonnasõbraliku eluviisi näitamisega, taimse toitumise pooldamisega või mõne muu ühiskonnas olulise probleemi tõstatamisega. Näiteks korraldab organisatsioon Loomus kampaaniat, mis kutsub inimesi üles mitte karusnahka soetama (,,Seitse populaarset suunamudijat kutsuvad inimesi üles mitte karusnahka soetama’’, Hea Kodanik). Kampaanias osalevad mitmed tuntud Eesti inimesed, tänu kellele on kogutud allkirju karusloomakasvanduste keelustamiseks Eestis. Paljudele tänapäeva noortele on oluline keskkond ja loomade aitamine ja kui suunamudijad aitavad sõnumi viia rohkemate inimesteni saab tänu neile maailma parandada.\nMõjuisikud saavad suunata noori tegema paremaid valikuid keskonna, iseenda või ühiskonna jaoks, kuid tihti on meediapilt ilustatud ning see, mis tundub tõde võib olla hoopis vastupidine. Tuntud inimesed, kes näitavad vaid oma elu ilusaid külgi võivad muuta noored ebakindlamaks. Ka ei saa usaldada reklaamitud tooteid, sest motiivid võivad olla omakasupüüdlikud. Influencer’id ei kao ilmselt niipea, seega peab olema lihtsat ettevaatlik, keda jälgida ja usaldada ning kasutada teadmiste kogumiseks ka muid allikaid.');
