INSERT INTO core.text(id, content)
VALUES ('691de7e2-e21e-474d-ba06-05063ebe30f2',
        'Me elame ühiskonnas, kus on paratamatult tekkinud tele ja meedia tõttu isikuid, kes on pälvinud suurema tähelepanu ja kelle tegevustest ja arvamustest inimesed rohkem huvituvad. Suunamudijad ja ka paljud teised avaliku elu tegelased on paistnud silma mõne erilise ande või väljaütlemisega. Sellega koguvad nad endale teatud jälgijaskonna, kes ka hiljem kuulavad, mis nende lemmikul netikuulsusel öelda on ning selle kaudu on lihtne inimesi mõjutada. Eriti tugevalt on mõjutatud nooremad inimesed, kes on üles kasvanud internetis ja kellel ka päris elu suhtlusringkondades on tihti teemadeks see, mida meediategelased on öelnud.\nNoortel inimestel, kes kasutavad pidevalt sotsiaalmeediat, on enamasti välja kujunenud oma lemmikud sisuloojad, keda nad mõnel sotsiaalmeediaplatvormil jälgivad. Kui aga mõni suunamudija on kogunud tohutult populaarsust on neil lihtne mõjutada oma jälgijaid enda tegevuste või arvamustega. Paljud suunamudijad teevad oma kanalitel pidevalt postitusi, kus räägivad mõnest tootest, mida nad on kasutanud ja mis peaks töötama imehästi. See ei ole alati halb, sest vahest leiavadki inimesed endale sobiva toote läbi kellegi teise soovituse. Väga tihti aga ei saada isegi aru, et tegemist on hoopis reklaamiga, mille eest on meediastaarile raha makstud ning tegeligult võib tegemist olla täiesti mõttetu asjaga. Seetõttu ongi oluline olla kriitiline selle suhtes, mida sotsiaalmeedias näeb, sest mitte iga influencer ei ole oma jälgijatega aus ja tihti tehakse seda just raha pärast. Selle kohta on ka näide teisest alustekstist, kus mainitakse, et on aina raskem eristada, kas sisuloojale päriselt meeldib see film ja toode, või teeb ta seda vaid reklaamina raha eest.\nSisuloojate mõju ei pruugi aga alati negatiivne olla. Paljud meediakuulsused tegelevad ka asjadega, mis on päriselt olulised ja toovad päevakajale teemad, millele igaüks tähelepanu ei pööraks. Siia võiks tuua näite kolmandast alustekstist, kus räägitakse kampaaniast, mis kutsus inimesi üles mitte soetama karusnahka ja milles osales mitmeid Eesti suunamudijaid. Selle kaudu, et sisuloojad või muud avaliku elu tegelased oma kanalitel postitavad taolistest kampaaniatest toob sellele ka suurema tähelepanu, sest nii see jõuab rohkemate erinevate inimesteni. Paljud influencer’id postitavad ka oma sotsiaalmeediakanalitele erinevaid uudiseid, selle kohta, mis maailmas toimub. Nii saavad ka inimesed, kes tavaliselt uudiseid ei loe natuke teada selle kohta, mis nende ümber toimub.\nAvaliku elu tegelased võivad noorte igapäevaelu ning valikuid mõjutada mitmet moodi. Palju saab mõjutada positiivselt, kuid kahjuks ka negatiivselt. Alati ei pruugi noored aru saada, kui sisuloojad ei ole oma jälgijatega ausad ja sattuda nende reklaami lõksu ostes mõne asjatu toote. Samas on ka paljud suunamudijad selle poolt, et nad peaksid andma endast kõik, et nad saaksid maailma ka kuidagi positiivselt mõjutada. Näiteks osaledes mõnes kampaanias või informeerides oma jälgijaskonda oluliste teemadega. Seega peaks noored olema rohkem kriitilised selle suhtes, mida nad sotsiaalmeedias näevad ja jääma iseendaks mitte lastes ennast liialt mõjutada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('691de7e2-e21e-474d-ba06-05063ebe30f2', 'title', 'Sisuloojate positiivne ja negatiivne mõju');
