INSERT INTO core.text(id, content)
VALUES ('5ee035a0-508b-4085-b74b-a691e884e170',
        'Üha enam on teemaks, kuidas tänapäeva noortel puudub lugemisharjumus ja neil on raskusi teksti mõistmisega. Sellest räägitakse koolides, kirjutatakse ajalehtedes ning arutatakse teadlastega probleemi pikaajalisest mõjust ja tagajärgedest. Probleem pole küll eile sündinud, kuid tundub, et aina kiiremini areneval internetiajastul kasvab lugemispuudulikkus lausa epideemiaks. \nNagu kirjutas Tiit Hennoste oma arvamusloos „Lugemise harjumuse harjutus“, et inimeste lugemisharjumused saavad alguse lapseeast. Lapse lugemus saab alguse unejuttudega, mida talle loevad vanemad. Sealt edasi tulevad lasteraamatud, mida peaks laps ise mõistma ning lugema, ja hiljem kooli kohustuslik kirjandus, mida peaksid innustama õpetajad lugema. Algus tuleb siiski teha vanemate poolt, kes julgustavad oma lapsi lugema, tekitavad selle vastu huvi ja teevad seda isegi. See harjumus peab peituma juba vanemates, kuna teisele inimesele harjumust harjutada, mida endal ei ole, on peaaegu võimatu. Lugemisharjumusega tekib lapsele uudishimu ja silmaring, mis tahab ühe rohkem laienemist mida vanemaks laps saab. Seetõttu on lugemisharjumusega lapsel ka lihtsam kooli kohustusliku kirjandusega, sest kui talle tekitada piisav huvi raamatu kohta, kust on taaskord võimalik midagi uut õppida, ei näe laps seda kui kohustust ning loeb raamatu õhinal läbi.\nHennoste väitis ka oma artiklis, et mõttega lugemine on aeglane töö, milleks tänapäeva kiirmaailmas meie ajud enam valmis ei ole. Tänapäeval on nutiseadmed kui aken tervesse maailma ja seda vaid mõne sekundiga. Sotsiaalmeedias on võimalik mõne klikiga avastada uudiseid, arvamusi, kultuure või keeli igast maailma nurgast, kuid raamatust nende leidmiseks kulub tunde või päevi. Raamatute mõistmiseks tuleb keskenduda üheselt ainult enda eesolevale tekstile, sellesse süveneda ja seda analüüsida. Noored tihti ei taipa, et informatsioon mis internetis leidub, on olemas ka raamatus ja tõenäoliselt veelgi täpsemalt. Nad on oma keskendumisvõimet rikkunud nutiseadmetega juba nii kaua, et selle kahju taastamine on ilmselt võimatu. Raamatu kätte võtmine on nende jaoks täiesti tabu idee ja reeglina lausa välistatud. Seetõttu näeme üha enam, kuidas ilukirjandus, teatmeteosed ning ka kõik muud raamatužanrid raamatukogude riiulitel ainult tolmu koguvad.\nSelle epideemina tagajärjel kaob üsnapea funktsionaalne lugemisoskus üldse ära. Hennoste sõnul on aga just see tänapäeva maailmas elu alus ja eeldus. Funktsionaalset lugemist on vaja igas eluetappis: koolis, tööl, huviringides ja vabal ajal. Kõige lihtsama teksti mõistmine on siin maailmas kõige alus. Mis aga saab juhul kui need noored, kes on üles kasvanud digiajastul, kel puuudub lugemisharjumus, ja primitiivne ilukirjandustekst käib üle jõu, kasvavad suureks ning peavad oma elu iseseisvalt elama? Meie ühiskond kukub kokku. Kui vanemad ja õpetajad on tänapäeva noori nii rängalt alt vedanud, et lihtne lugemisharjumuse ja -oskuse omandamine on tegemata jäänud, saavad selle tagajärjega tegeleda vaid nemad ise, sest suureks kasvanud noored selleks võimelised ei ole.\nTänapäeva noorte lugemisharjumused võivad olla kehvad või isegi olematud, kuid kõik saab alguse lapse kodust. Vanemad on need, kes lastele peavad looma tee heale lugemusele ning õpetajad seda noorukieas innustama. Noortele tuleb mõista anda, et raamatud on informatsiooni otsimiseks väärtuslikumad kui internett. Kõige olulisemana tuleb selgeks teha, et keskendumisvõime ja lugemisoskus on igapäeva eluks esmatähtsad, muidu kukub kõik meie ümber kokku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
