INSERT INTO core.text(id, content)
VALUES ('67cc69a8-6db6-4430-ab68-f9c97d76d8ac',
        'On öeldud, et tänapäevainimene ei suuda enam ise mõelda, vaid mõtleb ja käitub lihtsalt nii, nagu teevad seda inimesed, keda ta austab. Räägitakse, et enam ei suudeta olla originaalne, vaid kõik mida tehakse ja kuidas käitutakse on teiste kopeerimine. Kuid kas tõesti on juhtunud nii, et polegi enam ühtegi originaalset ideed kellelgi välja öelda? Suunamudijad mõjutavad elu tõsisel määral ainult nendel inimestel, kes lasevad ennast nende poolt mõjutada. Kui ei jälgita kellege tegevust internetis, siis ei saa ka jäljendada nende tegevusi. \nSuurimaks negatiiseks mõjuks suunamudijatel ja interneti populaarsusel viimase kümne aasta jooksul võib tuua igasugused sotsiaalmeedias leiduvad challenge’id, mis kutsuvad esile inimesi tegema igasugu lollusi, et kogda internetis popuaarsust. Üks varasemaid näited sellest minu eluajal oli cinnamon challenge, inimesed võtsid eesmärgiks süüa suur supilusikatäis puhast kaneeli ilma vee ega mingite muude abivahenditeta. Teadagi ei lõppenud see paljudele hästi, paljud said tõsised hingamisteede kahjustused ning mõni isegi suri. Üks hiljutisemaid samalaadseid tegevusi oli Tide Pod challenge, mis kutsus esile inimesi sööma kapslitena leiduvat pesuvahendit. Jällegi kohutavalt rumal idee, kuid kuna see sai internetis popuaarseks, siis paljud seda ka jäljendasid. \nSuunamudimine pole küll mingi ebamäärane kurjus, mis lapsi ja noori oma lõbu eesmärgil tapab. Sellel on ka häid külgi, nagu näiteks on see toonud palju rohkem tähelepanu siiani rohkem varjus olnud ühiskonnaprobleemidele. Üks nendest probleemidest on tedavasti olnud juba mitmeid aastaid aina hullem kliimamuutumine ning sellega kaasnevad tagajärjed. Veel üks viimase aja suurimaid probleeme, hindade tohutu tõus, on toodud aina rohkem avalikkuse ette. On toodud välja, et seda ei põhjusta mitte inflatsioon, sõjad ega muud säärased tegurid, vaid hoopis ühiskonna rikkaima kihi aina kasvav ahnus ja vajadus tõsta numbrit nende pangakontol. Praeguseks omab ühiskonna tipp kokku juba nii palju raha, et isegi kõik koos ei suudaks nad seda kõike väga mitme eluaja jooksul ära kulutada, mis ilmselgelt on liiga palju. Sotsiaalmeedias on toodud ka viise kuidas võidelda ühiskonna tipu kurjuse ja ahnuse vaastu, mis tulenevad igast spektrumi otsast ja erinevad väga oma ekstreemsustes. Näiteks hiljutine Ameerikas asetleidnud tervisekindlustuse firma juhataja tapmine, mida ülemaailmselt sügavalt austatakse ning kangelaslikuks peetakse.\nSuunamudijatega puutume me kõik kokku kas varem või hilje, vähem või rohkem. Infoühiskonnas lihtsalt pole sellest pääsu. Läbi interneti levitavad nad väga erinevat informatsiooni, mis võib olla kasulik kui ka kahjulik. See on inimese loomuses üritada jäljendada seda mida teevad need, kes meile meeldivad, kuid alati peaks meeles pidama, et oma tegude eest vastutad üksnes sina ise. Seega tuleks alati oma suured otsused tõsiselt läbi mõelda ning võtta teistelt vaid inspiratsiooni. Jääge originaalseks kui vaid võimalik.');
