INSERT INTO core.text(id, content)
VALUES ('e4586600-6a88-41b6-a94b-78861ef9ab41',
        'Üha rohkem räägitakse ühiskonnas sellest, et noored ei loe piisavalt raamatuid. Probleem on reaalne ja see tekitab muret ja palju pinget just vanemale generatsioonile, kes on ühiskonna tuleviku pärast mures. Aga, kas asi on tõesti nii hull, et sellega tuleks koheselt tegeleda või on ka alternatiive?                                                                                                              Noorte lugemishuvi vähenemisele on mitmeid põhjuseid. Kindlasti üks peamistest on nutitelefonide ajastu ja nende liigne kasutamine. Noortel on palju lihtsam ja kergem leida meelelahutust ja rahuldust nutiseadmetest, sest populaarsust koguvad lühivideod annavad põneva info palju kiiremini edasi kui raamatud. Asjale süvenemata mõeldes ei tundugi probleem eriti suur, kuid tegelikult on asi tõsine. Nutiseadmetes pidev olemine on justkui narkootikum, see tekitab väga kergelt ja suurel määral sõltuvust, mistõttu raamatud lihtsalt ei kutsu enam inimesi. Tiit Hennoste arvamusloos on argumenti kinnitav lause „Nutitelefon on suurel osa inimestest pidevalt käes, pidevalt aktsioonis“- see ütleb, et noored on leidnud endale kergema viisi meelelahutuse saamiseks.                                                                                                                 Lisaks nutimonomaaniale on suureks teguriks ka kiire elustiil. Me kõik oleme kuulnud oma vanemaid rääkimas, et kui nemad veel noored olid, siis nad lugesid raamatuid vabatahtlikult. Muidugi see on tõsi, aga aeg on edasi liikunud ja elu on kiiremaks läinud. Noortel on rohkem võimalusi enesearenguks, näiteks: interneti teel kursused, suur valik trenne ja meelelahutusasutused. Noortel on nii palju rohkem ja kiiremaid valikuid vabaks ajaks, et raamatud lihtsalt ei ole enam parim viis selleks. Tiit Hennoste ütleb oma arvamusloos sarnast: „Mõttega lugemine on aeglane tegevus“. See ongi reaalsus, noortel on tänapäeval palju rohkem kohustusi ja ülesandeid, mis teevadki tavalisest argipäevast väga pika päeva, peale mida ei olegi võimalik, et esimene soov on raamatu lugemine.                                                                                     Tänu nendele põhjustele on huvi raamatute vastu märgatavalt langenud. Ühiskond justkui ootaks lahendust probleemi lahendamiseks, sest senini katsetatud lahendused pole ilmselgelt toiminud, näiteks minu koolis pandi sügisel igasse klassi „telefonihoidla“, tänaseni pole ma ühtegi telefoni seal veel näinud. Kindlasti lugemisharjumuse puudumine ei ole kooli põhjustatud ja üldiselt süüdlase otsimine on äärmiselt vale. Lugemine ei alga lasteaias ega koolis, isegi mitte kodus! Kõik, mida kasvatajad, õpetajad ja vanemad saavad teha on näidata lugemise positiivseid külgi, milleks on: sõnavara laiendamine, puhkus ajule ning ootusärevust tekitav põnevus lugemises.                                                                         On inimesi, kellele absoluutselt raamatud ei meeldi ja seda ei saagi pahaks panna. Aga kindlasti leidub ka neid, keda on lugemisest eemale viinud keskkonna muutus. Nutitelefonid ja kiire elustiil ei ole andnud palju võimalusi raamatute jaoks, kuid need pole ainsad põhjused. Noortel on meelest läinud raamatute positiivsed küljed. Ma usun, et neid meelde tuletades, kui mitte inimest sundides, on võimalik huvi raamatute vastu taas elustada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
