INSERT INTO core.text(id, content)
VALUES ('67acd52d-70fb-49d4-b502-ff1d3670c7e9',
        'Nii eesti kodudes, kui ka koolides on juba pikemat aega olnud probleemne küsimus selles, et kas lapsed veel raamatuid loevad. On teada, et igas koolis on kohustuslik kirjandus, et iga noor vähemalt mingil määral oleks tuttav eesti ja ka välismaiste teostega. Kuid on see efektiivne ja kas pole mitte võimalik, et see pigem just pärsib kui soodustab noorte huvi lugemise vastu?\nMõeldes kohustusliku kirjanduse peale, tuleb mõelda meie endi kooliajale ja sellele, kuidas mõne teose lugemine ei läinud sugugi ladusalt. Siit tuleneb nii mõnelgi noorel koheselt mõte, et kui see üks raamat juba kuhugi ei kõlvanud, mis siis veel nende järgmistega saab. Paljud noored nii mõtlevadki ja nii saabki, just nagu Tiit Hennoste on öelnud, vabatahtlikust lugemisest kohustuslik lugemine. Just sellel põhjusel peavad õpetajad olema äärmiselt ettenägelikud kohustusliku kirjanduse valimisel. Õpetajad peavad oskama näha, kas nende valitud raamatud ka õpilastele sobivad ja kui hästi. Ning sellega tuleb aktiivselt tegeleda just algklassides, kus õpilased pole veel oma esimestes raamatutes pettunud. Ilmselgelt peab iga noor lugema eesti kirjanduse klassikat nagu näiteks Tammsaare ,,Tõde ja õigus’’ ja Kreutzvaldi ,,Kalevipoeg’’, sest need raamatud peaksid olema elementaarsed iga eestlase jaoks ja sellest ei tohiks kindlasti mööda hiilida. \nKuid kohustuslik kirjandus pole mitte ainus viis noori lugema saada. Enamik noori, kes loevad, on selle harjumuse endale kodust kaasa saanud juba varajases eas. Üldjuhul on nad näinud enda vanemaid või vanavanemaid raamatuid lugemas ning lastel on kombeks käituda oma vanemate eeskujule vastavalt. Lisaks aitavad laste lugema saamisele kaasa ka vanemate loetud unejutud, sest siis hakkab laps juba ise mõtlema, et mis nendes raamatutes veel peidus on. Sellele viitavad ka Tiit Hennoste laused: ,,Kus lugema õpitakse? Kindlasti kodus.’’ Nii mõnigi laps hakkas juba väiksena oma vanematega koos lugema just nimetatud eeskuju tõttu ja on näiteid, kus peredes kestavad koos lugemise traditsioonid ka siis kui laps on juba täisealiseks saanud. \nKui rääkida lugemise vajalikkusest või lugemata jätmise tagajärgedest tuleb tõdeda, et on silmaga nähtav, kui mõni noor raamatuid lugenud ei ole. Seda on näha nende hoiakust, keelekasutusest, maailmavaatest ja arusaamadest. On öeldud, et intelligentne on see inimene, kes loeb. Viimasel ajal on seda ka märgata. Kuid mõned noored tasakaalustavad enda lugematuse näiteks audioraamatute kuulamisega ning seegi on positiivne nähtus. Võib öelda, et raamatute lugemine on siiski vajalik juba pelgalt aju treenimiseks, kuid samas saab sellegi välja vahetada näiteks ristsõnade lahendamisega. \nLugemisharjumused tulenevad noortel kodust ja koolist, kus olulist rolli nende lugema saamises mängivad vanemad eeskuju näitel ja õpetajad raamatute valimise poole pealt. Raamatud on kasulikud ja vajalikud, et laiendada inimeste sõnavara ja maailmavaadet.');
