INSERT INTO core.text(id, content)
VALUES ('e85bb3d4-f97f-4e2c-8d31-08bc881b7155',
        'Tänapäeva noorte lugemisharjumused on palju muutunud viimaste põlvkondade jooksul. Tegu ei ole väikesete kõrvalekalletega. Tegu on suure, aina laieneva probleemiga. Aga, millest on see probleem tingitud ja kuidas mõjutavad kehvad lugemisharjumused noorte tulevikku?\n Noorte lugemisharjumused hakkasid halvenema juba ammu, aga probleem on hoogsalt kasvamist jätkanud. Nüüd on juba uueks normaalsuseks muutunud laste nutisõltuvus. Lapsed on kasvanud väikesest saati koos tehnika vidinaga, olgu see siis tahvelarvuti või nutitelefon, sest vanemad on muutunud laisaks ja harjunud mugavusega, et neil justkui puudukski kohustus oma lapsi kasvatada. Samuti on õhtused unejutud asendatud mingi videoklipi või filmiga. Aga lugemise huvi ei tule ühelgi lapsel iseenesest, selle peavad vanemad talle tekitama. Samuti ei paista raamatud sugugi huvitavad, kui laps näeb, et vanemad ei loe ka raamatuid vaid istuvad koguaeg ninapidi telefonis. Ka Tiit Hennoste mainis oma artiklis ,,Lugemis harjumuse harjutus“, et nutimonomaania ja kiire elutempo ei ole otsesed põhjused, miks noortel pole erilisi lugemisharjumusi. Nutimonomaania ja kiire elutempo lihtsalt andsid sellele hoogu juurde.\n Noortel puudub huvi lugemise vastu, sest neil on palju muid võimalusi, kuidas oma vaba aega sisustada. Varem ei olnud võimalust lihtsalt lahedat arvutimängu mängida või oma sõbrale helistada. Nüüd on noored harjunud kõigega, mida nutitelefon neile koguaeg pakub. Miks neil siis üldse peakski paistma, et raamatud ja lugemine on huvitav? Tegelikult ei pruugi see sugugi huvitav olla, kuna raamatu lugemine on aeganõudev ja tüütu. Igavaid kohti ei saa edasi kerida ja ägedaid videomängulisi klippe ka ei ole. Ainus kord, kui noored raamatu kätte suvatsevad võtta on siis kui koolis sunnitakse ja lugemine muudetakse kohustuseks. See ei ärata samuti mingitki huvi raamatute vastu, sest tihtipeale on kohustusliku kirjanduse raamatud igavad või täiesti vale žanr. Tänu sellele jääb noortele mulje, et lugemine on nõme kohustus ja sellest pole võimalik rõõmu tunda. Tiit Hennoste mainis oma artiklis ,,Lugemis harjumuse harjutus“, et koolis oli ka neil kohustuslik kirjandus, enam jaolt see pahameelt ei valmistanud aga kui tuli paks raamat ülikoolis, siis selle lugemine tappis tal küll lugemisisu mõneks aastaks ära.\n Lugemisharjumuste halvenemisega võib kaasneda paljusi erinevaid negatiivseid tagajärgi, mis noori tulevikus sügavalt mõjutada võivad. Noortel ei pruugi olla piisavalt lai sõnavara, et väljendada teistele oma tundeid. Võimetus enda tundeid väljendada, võib tekitada neile edasises elus erinevaid konflikte. Samuti on neil täiskasvanuna limiteeritud silmaring, sest nad ei lugenud raamatuid, eriti just klassikalisi teoseid. Klassikaliste teoste lugemine aitab ka samastuda meie esivanematega ja mõista eestlaste mõttemaailma paremini. Täiskasvanuna ei pruugi noored mõista metafoore, kõnekäände ega vanasõnu, mis on osa meie keelest ja kultuurist.\n Me peaksime kõik panustama tulevikus oma lastesse. Me peame harjutama neid lugema ja eemaldama nad nutimaailmast, sest muidu kaob ära nende lapselik kujutlusvõime, hea sõnavara ja oskus ennast korrektselt ja arusaadvalt väljendada. Kuigi on väike tõenäosus, et me oleme suutelised lugemisharjumuste parandamiseks siis me võiksime seda üritada sellegipoolest.');
