INSERT INTO core.text(id, content)
VALUES ('b1f17140-f572-4d3d-9d08-96b962635657',
        'Suunamudijad on kuulsused, kes kajastavad oma elu ja arvamusi. Nad võivad tegutsed erinevatel sotsiaalmeedia platvormidel nagu näiteks Youtube, Instagram, Snapchat jne. Sõna „suunamudija“ on suhteliselt uus sõna eesti keeles. Uue sõnade võistlusel olid lapsed selle väljapakkunud ja aktuaalseks muutnud. Aga kuidas mõjutavad „suunamudijad“ meie elu? Ja miks nad ültse nii erilised on?\nSuunamudijate pakkuvad meie ellu nelja erinevat asja. Esimeseks on eksklusiivsus, mis pakub inimestele infot asjade kohta, mis ei ole jälgijatele muidu kättesaadav, näiteks kallid riided, aksesuaarid või eksklusiivsed üritused. Teiseks on nende erakordsus. Kõige populaarsemad suunamudijad on tihti oma ala meistrid või eksperdid. Nad võivad olla – tantsijad, trummarid, kunstnikud, õpetajad, käsitöömeistrid ja nii edasi. Nende võlu on selles, mida „tavainimene“ teha ei oska. Kolmandaks on nende eksootilisus. Eksootilisuse alla lähevad „suunamudijad“ kelle välimus on omapärane. Neil võib olla füüsiline või vaimne defekt, millest nad üritavad rohkem infot jagada teistele. Näiteks Downi sündroom, Vertigo, albinism jt. Neljandaks on elulisus ehk kus nad rääkivad oma elust ausalt, et samastuda oma jälgijatega. Parimaks näiteks saaks siia tuua Malluka, kes on kuulus „suunamudija“ emade seas. Mallukas pakkub oma vaatajatele ome pereelu ja varasemaid kogemusi. \nKui me nüüd paremini arusaame, kes on „suunamudijad“ on ka kergem näha nende võimu meie arvamustes ja tegemistes. Neil on võimalus meile asju pähe määrida kui ka maha teha brände kelle vaated ei sobi ühiskonnaga. Just alles juhtus midagi sellist, kus osalesid: Hanna Martinson, Liis Velsker, Liina Adriadne Pedanik, Martti Hallik, Mick Pedaja jt. Nad kasutasid #loomadesilmis ,mis kutsub inimesi mitte karusnahka soetama. Nad soovivad oma nooremaid vaatajaid informeerida karusnahafarmide kulissidetagusest elust. \nKuid peale heade külgede on ka „suunamudijatel“ võimalus ära kasutada oma platvormi. Ajades ringi valesid, kasutades oma populaarsust, et kriminaalseid asju teha.\nKokkuvõttes arvan, et „suunamudijatel“ on palju võimalusi meie elusid muuta. Kas hea või halva poole oleneb sellest keda jälgid. Neil on võimalus meile asju müüa kui ka vastu reklaamida halbadele firmadele. Nende mõju on täna päeval ainult kasvamas.');
