INSERT INTO core.text(id, content)
VALUES ('191e3544-b236-405a-8bca-fcb462908190',
        'Tänapäeval kasutavad noored ja ka ülejäänud teised inimesed aina rohkem internetti ja sotsiaalmeediat. Sellega kaasnevad ka erinevad suured mõjutused, mis võivad muuta noorte elu kardinaalselt. Mõne oma positiivselt, kuid sotsiaalmeedial ja sellel, mida seal näidatakse võivad olla ka negatiivsed mõjud. Suunamudijad üritavad tavaliselt rääkida ja jagada sotsiaalmeedias head ja laialdast sisu, mis köidaks võimalikult palju inimesi ning selletõttu ei pruugi kõik alati tõsi olla ja selles suhtes peab inimesel olemas olema kriitiline mõtlemine, et mitte uskuda kõike, mida loeb ja näeb.\nSellepärast kaasnebki sotsiaalmeedia sisuga elulisus ja samastumise võimalus. Osad suunamudijad koguvad endale jälgijaskonda sellega, et jagavad oma elu nii nagu see on ja ei lisa juurde mingit mõtetut juttu, mis ei ole tegelikult tõsi. Nende jaoks on kõige tähtsam jääda autentseks ja mitte valetada või välja mõelda mingit lugu oma enda elu või kellegi teise oma kohta puhtalt selleks, et koguda suuremat jälgijaskonda. Mida elulisem ja reaalsem suunamudija on seda rohkem võib olla ka inimesi, kes nõustuvad ja samastavad ennast temaga.\nEelmisele lõigule vastupidiselt on ka neid suunamudijaid, kes jagavad ja näitavad oma elu eksklusiivsemalt kui see tegelikult on, näiteks uhkustavad mingite kallite ehete, riiete, majade ja muude selliste asjadega. Kahjuks ei ole see reaalsus ja sellega on tavainimestel raske samastuda, sest suuremal osast ühiskonnast ei ole võimalusi endale lubada selliseid uhkeid ja kalleid asju. Selliseid suunamudijaid ei tasu ka alati uskuda, sest suurem osa ajast ei ole tegelikult need kallid esemed isegi päriselt nende omad, vaid nad lihtsalt brändide poolt neile laenatud, et teha reklaami, sest nad on populaarsed ja selletõttu jõuab info paljude inimesteni.\nAsi, mis võib veel inimeste tähelepanu köita on suunamudijad, kes näevad välja teistsugused, näiteks teine nahavärv või mingi haigus või erinevus väljanägemises teistest, sellega kaasneb tavaliselt ka palju negatiivsust, sest alati on inimesi, kellel on midagi halba öelda teiste kohta, see võib tuleneda lihtsalt sellest, et nad ei ole ise oma eluga rahul ja väljendavad seda negatiivsusega teiste inimeste vastu. Vaatajatele läheb peale ka see, kui kellelgi on mingi talent või oskus teha midagi sellist, mis on ebatavaline ja milleks kõik ei ole võimelised.\nSotsiaalmeedias on ka inimesi ja nii öelda pettureid, kellel on halvad kavatsused jälgijaid hirmutada ja meelitada ning tekitada neis mingi reaktsioon. Näiteks kui keegi näeb sotsiialmeedias mingit videot, kus kellelgi juhtus midagi halba, siis loomuliklt tekib vaatajal mingisugune reaktsioon sellele ja ta tahab kohe selle kohta rohkem infot saada, et kas sellel kannatajal on kõik korras või saada teada mis täpsemalt juhtus ning sellega saab video postitaja kohe oma kontole vaatamisi juurde.\nKokkuvõttes võib öelda, et sotsiaalmeedial on jälgijate eludele väga suur mõju, sest kui midagi seal näidatakse, siis loomulikult tahavad vaatajad ka endale sellist elu, et nad saaksid olla võimalikult sarnased ja samastuda võimalikult palju näiteks oma lemmik suunamudijaga. Kuid sotsiaalmeediat kasutades peab olema ka alati ettevaatlik ja mitte uskuda päris kõike mida loed ja näed. Isegi kui mõni jälgitav suunamudija võib olla reaalne ja võib tunduda, et ta räägib kõigest nii nagu see päriselt on tema jaoks peab jälgijal olemas olema kriitiline mõtlemine.');
