INSERT INTO core.text(id, content)
VALUES ('59f31e4e-6d5f-4765-8157-f0d71e3afbca',
        'Tehnoloogia arenguga saavad aina suuremat tähelepanu ka suunamudijad. Kui kunagi kutsuti auhinna tseremooniatele ja punase vaiba üritustele vaid filmistaare ning maailmakuulsaid muusikuid, siis nüüd näeb nendel üritustel aina rohkem ka inimesi, kes on oma tuntuse saanud luues sisu sotsiaalmeediasse. Selle põhjal saame öelda, et suunamudijate tähtsus ühiskonnas on suurenenud ning nende arvamus loeb noortele. Kuid tekib ka küsimus kas nende otsused ning see, mida nad oma kontodel esitavad on hea eeskuju noortele või mitte.\nSuunamudijate tõusuga on tõusnud ka kriitika nende vastu. Enamasti kritiseeritakse just seda, mida nad oma jälgiaskonnale maha müüvad ning mida nad propageerivad. Eriti on muutunud see, kuidas nähtakse naise keha. Kuna sotsiaalmeediaga on võimlaik teenida päris suuri summasid, siis tihtipeale on suunamudijad lasknud oma keha muuta. See omaette ei oleks probleem, kui seda ei varjataks. Tõsiasi on aga see, et paljud mikrokuulusued räägivad, et nemad ei ole oma kehaga muud teinud, kui trenni ning toitunud tervislikult. Sellistel valedel on aga väga suured tagajärjed, sest neid videoid näevad noored tüdrukud, kes hakkavad ennast sellise jutu peale näljutama ning ennast üle treenima. Kuna noore inimese aju ei ole veel täielikult välja arenenud, siis tihti ei nähta läbi valedest, usutakse pimesi, mida neile räägitakse. Nad teevad kõik, et näha välja nagu oma lemmikstaar. Selline käitumine viib meeleheiteni, kui ei saada soovitud tulemust ning leidub tohutult juhtumeid noortest, kelle meeleheide viis söömishäirete või isegi suitsiidini.\nKuid mitte kõik suunamudijad ei ose sellised. On ka neid, kes näiavad ka oma halvemaid päevi ning viskavad aknast välja väite, et suunamudija elu on perfektne. Eestlane Maria Rannaväli on hiljuti sattunud tagasi noorte orbiidile oma jõusaali treeningutega. Ta meelidb noortele just seetõttu, et ta on küllaltki uus jõusaali külastaja ning areneb koos oma vaatajaskonnaga. Ta ei valeta oma videotes ning ei räägi, et kõik tema treening sessioonid on perfektsed, vaid jagab ka motivatsioonipuuduse muresid ning mis juhtub, kui jõusaalis käimine ning füüsilise koormuse saamine mõneks ajaks lõpetada. See on otseloomulikult noortele hea, sest nad näevad teda, kui inimest. Ka tema ei ole perfektne ning ka tema piinleb samade murede all, mis „tavainimene“.\nArvan, et suunamudijad ei ole noortele ja ühiskonnale raudkindlalt halb eeskuju. Küll aga tuleb õppida, keda internetis jälgid milliseid nõuandeid kuulad. Kui suudame sotsiaalmeediast välja tõrjuda inimesed, kes pidevalt iseenda kohta valetavad ning suunavad teisi ebatervislikule teele, ning õpime kuidas armastada ennast ning kuidas iseenda armastust ilma valetamata teistega jagada, ei näe mina põhjust, miks suunamudijaid tagakiusata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
