INSERT INTO core.text(id, content)
VALUES ('026d85f3-40ba-4d6e-98fd-2aa439f937d1',
        'Tänapäeval ütlevad paljud, et noored ei loe piisavalt ja ei saa keelest piisavalt hästi aru, sest nad istuvad kogu aeg ekraani taga. Selline arusaam peab mõnes mõttes paika, kuid selles ei saa süüdistada ainult nutiseadmeid. Asi on ka inimestes endas. \nÜhiskonnas kehtib väärarusaam, et noored ei loe kas piisavalt või üldse. See aga pole tõsi, sest noored loevad pidevalt, isegi kui nad ise seda ei teadvusta. Näiteks on uuringutas välja toodud, et kuigi noored on pidevalt ekraanide taga, siis nad ikkagi loevad. Loetakse mängujuhiseid, sõnumeid ja tekste postituste all. Sellega võib ümber lükata väite, et noored ei loe, kuid ega arvutimängu juhised noorte sõnavara ei arenda ning sellepärast käib siiski noorte funktsionaalse lugemise oskus pikkamisi alla. Sellepärast arvab Tauno Vahter, et noorte lugemisharjumuse suurendamist ei tule. „Tõsiselt häid tulemusi noorte lugemisharjumuse suurendamisel ei ole ja pigem ka ei tule.“ Tauno Vahteri arvamust kinnitab Tiit Hennoste väitega: „Kokkuvõttes tundub mulle, et suur osa lugemise harjumusest algab iseendast.“ Kui noored leiavad suuremat huvi internetis olemisest, kui raamatu lugemisest, siis nad raamatut ka läbi ei loe. Noored küll loevad, aga nad loevad pigem mõttetut teksit kui neid arendavat teksti ning sellepärast ei teki nendes lugemisharjumust.\nTänapäeva noored ei ole harjunud lugema pikki tekste ja see viib keele oskuse allakäiguni. Eriti ei ole nad harjunud lugema erinevaid bürokraatiatekste, kuid samas ei ole nad harjunud lugema ka ilukirjanduslikke tekste, mis panevad aluse funktsionaalse lugemise oskuse tekkele ning tänu millele on võimalik bürokraatiatekste mõista. Sama väidab Tiit Hennoste oma arvamusloos: „Tegelikult on kõige keerukam keel hoopis ilukirjanduses.“ Kui noortel ei ole harjumust lugeda raamatuid, siis on loogiline, et nende sõnavara ja maailmapilt ei ole nii avar, kui teistel, kes veedavad oma vaba aja lugedes. Ka Helin Puksand on uurinud korrelatsiooni õpilaste lugemise harjumuse ja funktsionaalse lugemise oskuse vahel. Ta tõi välja, et õpilased, kelle peres on lugemise armastajaid ja kellel on rohkem raamatuid kodus, loevad ka ise rohkem ning PISA testide alusel on ka just nende õpilaste funktsionaalse lugemise oskus märksa parem kui teistel. Keerulise teksti mõistmise olulisust kinnitab Tiit Hennoste arvamus: „Keerukas keel on olemas ja jääb alatiseks olema. Seda peab valdama, et maailmas hakkama saada, mõista keerulist, ebatavalist sõnavara, mõista pikki, keerukaid lauseid.“ Tänapäeva noored ei ole harjunud lugema keerulisi ja pikki tekste ning see võib neile tulevikus palju kahju teha. \nTänapäeva noored loevad pidevalt, kuid nad loevad tihti tekste, mis ei aita kaasa nende keele oskusele. Samuti ei ole nad harjunud lugema pikki tekste. See kõik aitab kaasa funktsionaalse lugemise oskuse allakäigule ning keele oskamatusele.');
