INSERT INTO core.text(id, content)
VALUES ('879ba5f9-4e99-479e-910d-bcd15d4dc44f',
        'Mida aeg edasi, seda rohkem on hakanud avaliku elu tegelased ning sotsiaalmeedia mõjuisikud noorte igapäeva elu ning valikuid rohkem suunama. Nad mõjutavad nii meie tarbimisharjumusi, poliitilisi vaateid, tervisega seotud valikuid kui ka maailmavaateid. Kuigi see võib inimestele mõjuda positiivselt on selles ka palju negatiivseid külgi. Kuidas suunavad meedia mõjuisikud noorte igapäevaelu?\nAvaliku elu tegelased suunavad noori nende maailmavaateid uskuma. Sotsiaalmeedias tegutsevad sisuloojad kasutavad ära oma platvorme, et jagada teistega oma poliitilisi vaateid ning üldiselt uskumusi, mis neil elus on. Samal ajal mõjutades sellega ka oma jälgijaskonda. Kuna vaateid ja maailmapilte on väga palju erinevaid, tekitab see ka jälgijates erinevaid arvamusi. Nii ka näiteks poliitikas. 2024. aastal toimusid Ameerika Ühendriikides presidendi valimised, mis sotsiaalmeedias tekitas kirglikke eriarvamusi. Sellest võtsid meedias sõna mitte ainult ameeriklased, vaid ka Euroopa ja Eesti sisuloojad, sest nad tundsid, et tulemus mõjutab ka nende elusid. Nii toimuski sotsiaalmeedia platvormidel mõnda aega justkui võitlus mõjutada inimesi valima just enda lemmiku poolt. See toob aga kaasa probleemi, kus noored kipuvad uskuma ja järgima ka võhikuid, kes olenemata teemast ei pruugi teada, millest nad räägivad, sest nende allikaks on teiste inimeste arvamus. Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill on öelnud: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid „kuulajatele meeldib“, siis see on probleem“. Seega suunavad meedia mõjuisikud noorte poliitilisi vaateid.\nLisaks poliitilistele maailmavaadetele suunavad avaliku elu tegelased noori ka nende tarbimisharjumuste poolest. Viimasel ajal on populaarseks teemaks just taaskasutamine ning keskkonnasäästlik tarbimine. Sotsiaalmeedia mõjuisikud kutsuvad oma platvormidel inimesi üles tarbima keskkonnasõbralikumalt. Samuti võetakse osa ka erinevates teemaga seonduvates kampaaniates. Nii teevad erinevad ettevõtted paljude sisuloojatega ka koostööd. Nii saavad inimesed oma seisukohti ka teistega jagada ning mõjutada ka neid keskkonnasäästlikumalt tarbima. Näiteks tegi loomade eestkoste organisatsioon Loomus koostööd erinevate sisuloojatega kampaania #loomadesilmis raames, kus nad kutsusid üles inimesi mitte soetama karusnahka. Loomuse kommunikatsioonijuht Annika Lepp on öelnud: „Kuigi teeme Loomuses igapäevaselt tööd selle nimel, et Eesti keelustaks karusloomafarmid, on oluline jõud ka tarbijatel, kel on igapäevaseid otsuseid tehes võimalik valida looma- ja keskkonnasõbralik toode“. Seega üritavad sotsiaalmeedija mõjuisikud ning avaliku elu tegelased panna inimesi tarbima nii nagu nende maailmavaated ette näevad ja see mõjutab noorte tarbimisharjumusi.\nTänapäeval on vaieldamatult suureks mõjuallikaks noorte seas sotsiaalmeedia. Sisuloojad kasutavad ära oma platvorme oma maailmavaadete jagamiseks ning oma jälgijaskonda neid uskuma pannes. Olgugi siis teemaks maailmavaated, poliitika või elustiil ja tarbimisharjumused, igal juhul võib väita, et avaliku elu tegelased mõjutavad noorte elusid suurel määral.');
