INSERT INTO core.text(id, content)
VALUES ('3df27079-d128-4eed-9196-98a5a9c16de1',
        'Elame arenevas riigis, kus sotsiaalmeedia kättesaadavus ja mõju on pidevalt kasvamas. Igapäev näeme noori tõmbamas oma taskust välja nutitelefoni ja sirvimas läbi tuhandete artiklite, blogipostituste ja lühivideote, käsitlemas, mida algoritm neile ette toob. Kõige selle meedia taga on isik, kes selle tegi ja sotsiaalmeediasse minimaalse kuluga üles pani. Nii on võimalik igaühel midagi oma elust või arvamusest teiste tähelepanu ette tuua, eriti kui sa juhtud sellest kuulsaks saama. \nRohkem kui kunagi varem on võimalik eestlasel mõjutada oma rahva noori, olgu see trendide alustamine või poliitiliste suundade arvukuse mõjutamine. Üks suur põhjus, miks suunamudijad saavad kergelt noori mõjutada on ettevaatlikult välja arendatud tugev parasotsiaalne suhe oma vaatajatega. Artikli autor kirjeldab suhet: ,,..tekib meedia vahendusel inimestel illusioon, et meediastaar on nende lähedane tuttav, keda tasub kuulata.“ Eriti on seda võimalik näha laste seas, kuidas nad selgelt võtavad eeskuju oma lemmikutelt suunamudijatelt ja on nõus tegema seda, mida nad ütlevad. Näiteks poiste seas nimekas Eesti tiktokker Bonex on sattunud omadega skandaalidesse seoses trendidega, mida ta on alustanud, nt purskkaevu hüppamine. \nLisaks trendidele, mis paneb noori tegema ebasobilikke asju on ja mure nende arvamuste ja vaadete arengus. Maria Murumaa Mengel toob oma artiklis välja: „Suunamudijate kaudu jõuab noorteni ja mitmeid baasteadmisi ja tüvitekste,..“ Paljud noored võtavad oma uudiseid sotsiaalmeediast, millega on mitmed suunamudijad endale vaatajaid ligi tõmmanud pideva uudiste käsitlemisega lihtsustatud ja arutlevas vormis. Noortele on see mugavam, sest ei pea läbi lugema pikki artikkleid, kus tihtipeale on kõige tähtsamad osad jäetud rahanõudva paketi taha. See võib tuua häid ja halbu tagajärge, nt tagada sõnavabadust juhul kui meedia üritab midagi ära katta või hoopis olla kasvamiskoht kahjulikele poliitilistele liikumistele, mis eriti tõmbab endale ligi kergesti mõjutatavaid noori. Hea puhul võib see kasvatada tolerantsust, näiteks teiste rahvuste vastu. Hea näide on just Eestis kuulsaks saanud Yiling „Kaspar“ Wang, kes on oma usina eesti keele õppimisega toonud positiivsema vaate eesti keelt õppivate immigrantide ja Hiina kultuuri vastu. \nKättesaadav internet on toonud inimestel ellu palju karjääri-, õppimis- ja meelelahutus võimalusi. Siiski peame mõtisklema küsimuse üle, kui hea on sotsiaalmeedia meie riigi noortele? Trendidega on võimalik inimestel tunda kogukonna tunnet ja uudiste filtrita jagamine ning arutlemine tagab sõnavabadust, aga samuti on neil omad halvad küljed. Tähtis on olla tähelepanelik nende noorte elus ja õpetada neile kriitilist mõtlemist, et mitte minna nii kergesti antud mõjudega lihtsameelselt kaasa. Nagu üks poliitik kunagi ütles: „Eesti suurim probleem on see, et meil on liiga palju lolle.“ ja mis selle lahendus on? Hea kasvatus ja haridus.');
