INSERT INTO core.text(id, content)
VALUES ('bfd75057-3576-489a-8444-2ef5559e056e',
        'Tänapäeval süüdistatakse ikka noori selles, et ei loeta üldse raamatuid ning ollakse hoopis telefonis. Seda teevad põhiliselt täiskasvanud lapsevanemad ning õpetajad, kuid nemad on ometi need, kes noori üles kasvatavad, harivad ja loovad neid inimesteks. Seega tuleb võib-olla hoopis neid süüdistada?\nVanemad on need, kes õpetavad ja harivad lapsi kõige rohkem enne kui nad kooli lähevad. Tänapäeval aina rohkem kipuvad vanemad arvama, et enne kooli minemist peavad nad õpetama nad lihtsalt sööma, kõndima ja rääkima ning ülejäänud õpetab kool. Selle asemel, et õpetada oma lapsi õigeaegselt lugema, antakse neile lihtsalt telefon kätte ning pannakse käima mõtetu värviline laste video, et lapse tähelepanu oleks mujal ja ta vaikselt oleks. Isiklikult näen ja imestan pidevalt, kuidas igalpool: restoranides, lõbustusparkides, mänguväljakutel ja isegi pargis jalutades on vanemad andnud lapsele nutiseadme, kus nad on nagu kinni naelutatud ja pole mingit huvi välise maailma vastu.\nVanemad loodavad siis, et kui nad lapse kooli saadavad hakkavad nad järsku innukalt õppima ja lugema. Lastel puudub juba iseenesest eeldus selle jaoks ning ega kool sellega otseselt kaasa aita, kui pannakse koolikirjandusse raamatuid, mis lastele huvi ei paku. Loomulikult peab laskma lastel lugeda klassikalisi Eesti raamatuid, mis õpetaksid neile kultuuri, ajalugu ja eesti keelt, kuid tõsiasi on see, et nad on harjunud telefonides tarbima kiiret värvilist inglispärast meediat. Seda kinnitab Tiit Hennoste oma artiklis mainides kiirmaailma valitsus ja nutiseadmete sõltuvust ühiskonnas.\nSamuti väidab Hennoste ka seda, kuidas lugemisharjumus algab kindlasti kodust ning mainib oma kogemust raamatute ettelugemisest, mis temale tundub väga iseenesestmõistetavana. See võib  tunduda nagu midagi loomulikku ja väikest, kuid see on midagi, mida vanemad peaksid hakkama tänapäeval rohkem tegema. Mitte ainult ette lugeda, vaid ka õpetada, näidates lapsele neid sõnu, mida parasjagu ette loetakse. Veel parem kui osta või laenutada laste aabits ja lasta lapsel näiteks lugeda iga päev pool tundi enne kui nad võivad nutiseadet kasutada. See on midagi, mis minu lapsepõlves tehtis ja see mõjutas mu lugemisharjumusi väga positiivselt.\nKoolid see eest peaksid kohustuslikku kirjandusse panema kergemaid ja rohkem huvitavamaid raamatuid, isegi välismaiseid, et saada lapsi lugema ning tekitada neis huvi. See on tähtis, et algatada lugemisharjumust lastes ning siis hiljem saab anda neile raskemaid, tähtsamaid ja n-ö igavamaid raamatuid. Algklassides andis minu kirjanduse õpetaja meile huvitavat välismaist kirjandust ning minu teisest koolist pärit sõbra kohstustlik kirjandus, mis oli rohkem klassikalisem, kõlas ka jube igavalt.\nKokkuvõttes tuleneb üldine noorsoo lugemisharjumuste langus ikkagi kasvatusest ja haridusest ning vanema generatsiooni öeldu ja tegude vahel on mõningaid konflikte. Kui me tõesti tahame, et olukord paraneks peame hakkama panema rohkem fookust noorte kasvatusse.');
