INSERT INTO core.text(id, content)
VALUES ('ab142535-df3c-45ef-a3db-1f410eaa293c',
        'Tänapäeva inimest ümbritseb tehnoloogia maailm, mis annab meile palju võimalusi arendamiseks ja aja veetmiseks. Meie harjumused ja huvid muutuvad ning meie oskused kaovad. Noored ei näe enam vajadust lugeda raamatud ja nende lugemisharjumused kehvenevad. Kas kasaaegses mailmas lugemise olulise puudus mõjutab noorte elu?\nPeamiseks lugemise olulise puuduse põhjuseks on nutiseadmed. Tänapäeva tehnoloogiat muudavad meid „loomadeks“, kes keegi ei soovi enam arendada ja õppida. Lugemise tähtsus ning tahe liikuda edasi kaob. Noored unustavad peamistest asjadest, mis meid igapäeva elus ümbritsevad ning ei näe tähtsust koos aega viibimisest ja raamatute lugemisest. Meie sõltuvus telefonist, tahvelarvutitest või arvutitest mõjutavad meie üldist arusaam reaal mailma olemise olulisust ning toob kaasa erinevaid vaimse tervise probleemid nagu depressioon. Tiit Hennoste artiklis „Lugemise harjumuse harjutus“ ütleb, et inimised on harjunud sellega, et telefon või teised nutisedmad sunnitavad meid vaatamata teisele poole kõndima ninaga ekraanis – see näitab, et noored enam ei märka, mis juhtub nende näo ees. Samuti Hennoste nimetab neil juhtumid nutimonomaaniaks, mis annab mõtte sellest, et nutiseadmed on pigem haigus kui ravi.\nTänapäeva inimesed soovivad rohkem elada kiirmaailmas, kus saab kõige vajaliku saada kiire tempoga. Sellega kaasneb ka tahe raamatute lugemises, kuna teose mõte arusaamiseks on vaja rohkem aega, mis on kasaaegses elus kõige kallim valuuta. Tiit Hennoste ütleb sellest, et maailmaga valitseb kiirus, kus on kiirtoit, kiirkeel, kiirteadus, kiirseks, kiirlugemine – noored ei taha enam raiskata oma elu selleks, et ühele tegule anda kogu oma tähelepanu. Nad ei väärtusta enam selle töö ja tähtsust, kui keegi teeb midagi hingega ning kuulutab selleks palju tundi. Kaob visioon sellest, kuidas peab välja näema Homo sapiens oma võimega liikuda edasi.\nRaamatud kaotasid oma peamist tähtsust ja mõtet. Tänapäeval kirjanikuks võib saada igaüks, vaatamata, kui õigesti või korrektselt oskab keegi kirjutada. Tulemusena, poodide riiulitel me näeme erinevaid dark romance raamatuid, mis ei anna põlvkondadele midagi, vaid meelelahutuseks ideed. Tauno Vahter artiklis „Peame leppima, noored lihtsalt ei ole“  arvab, et raamatud kaotasid oma tähtsust ning neile pakkub rohkem huvi kiirmailmaga seotud tegureid. Kuigi viimasel ajal tüdrukut hakkasid huvitavama romaanidega ja fantaasikirjandusega – need teosed annavad lootust, et järgmised põlvkonnad ei unusta lugemisharjumusest ning jätkuvad hea meelega lugemist.\nLugemise olulise puudus mõjutab noorte elu, kuna nende sõltuvused tänapäeva tehnoloogiast, kiirmaailmast ning dark romaanidest ei anna neile aluse enesearendamiseks. Inimene on ajaga muutunud abituteks, mis seisab ühel kohal  ja elab ühel hetkel, kuid lugemine annab meile võimalus laiendada oma vaatepilti ja arendada oma mõtteviisi.');
