INSERT INTO core.text(id, content)
VALUES ('ad5e7a22-0225-4f5f-a96f-e1b88d5f299d',
        'Sotsiaalmeedia on viimase kümne aasta jooksul läbinud hiiglasliku kasvutrendi. Interneti kättesadavuse kiire levik noorte seas on tõstatanud uusi küsimusi ning arutelusid seoses noorukitele interneti poolt avaldatava mõjuga. Kuigi noored võivad internetist leida ka kasulikku ning toetavat infot, veedavad lapseohtu, teismelised nutitelefoni kasutajad üha rohkem aega sotsiaalmeedias, seda ka siis, kui peaks tegelema kooli- või kodutöödega või tekib võimalus perega maha istuda ja aega veeta. Kuid mis need mõjutavad tegurid siiski on ning kuidas need meie kõige värskemat generatsiooni mõjutavad? \nSotsiaalmeedia suures maailmas on paratamatu, et tänu liikuva info koguse hoomamatusele levib internetis suur hulk eksitavat teavet. Noored inimesed, kellel puudub lai elukogemus ning kelle aju pole veel lõplikult välja arenenudki, on valeinfo talletamise osas eriti haavatavad. Selle sama väärteabe tarvitamine võib noori panna tegema enesele laastavaid asju, olgugi, et nende endi arust on see tegevus õigustatud ning põhjendatud. Veel tänapäevalgi on laialdaselt levinud probleem söömishäiretega, eriti noorukite seas. Probleemile lisas õli veelgi tulle sotsiaalmeediaplatformi TikTok`i levik alaealiste seas. Platformil on palju isehakanud tervisliku elustiili nõustajaid, kes ütlevad rahumeeli noortele, kelle jaoks kehaline väljanägemine on eriti tähtis, et parim viis kaalulangetamiseks on vähem süüa või isegi ennast näljutada. Noored, kes seda infot tarbivad ning selle järgi elavad, teevad endile karuteene tulevikuks, sellest ise arusaamata.\nOn tõsiasi, et teismeeas isikutele omavad sõbrad ja tuttavad koolis suuremat tähtsust, kui nende endi pere. Igavate ning kurnavate pereõhtute asemel valitakse tihtipeale kas sõpradega väljas hängimine või nendega restorani sööma minek. Kuna sõbrad ja tuttavad omavad noorte jaoks enim tähtsust, on nendel ka suurem mõjuvõim noorukite elu mõjutamise osas. Kui aga nooruk ei saa piisavalt kontakti enda kamraadidega, liigub ta sotsiaalset ühtekuuluvustunnet otsima tänapäeval äärmiselt kättesaadavast sotsiaalmeediast. Just täpselt sellise, noortega suhestumis meetodiga on palju kuulsust teeninud Eesti suunamudija Maria Rannaväli. Rannaväli toodab interneti sisu, kus räägib enamjaolt oma igapäevastest tegemistest ning arutleb noorukitega erinevatel, nende jaoks päevakajaliselt teemadel. Kuna Rannaväli on ka ise alles enda kahekümnendates eluaastates, suudavad noored temaga suhestuda ning vastupidi, tema noortega. Seetõttu on Maria Rannaväljal suur kontroll lapseohtu inimeste harjumuste kujundamise ja mudimise üle.\nTeismelised on oma elu kui avastusretke alguses ning neil on veel palju kogeda ja näha. Uhked ja kiired sportautod on eriti pilkupüüdvad just noortele, kellele see suurt elevust tekitab. Seda eriti Eestis, kus helikopteritega ringi lendamine ning luksusautodega sõitmine pole päris igapäevane nähtus ja tekitab noortes veel suuremat huvi. Piiritu kujutusvõime tekitab noorukitele tihtipeale suured ambitsioonid, teenida palju raha ning elada 21. sajandi stiilis aristokraatliku eluviisiga. Seetõttu on teismelistele eriti meelepärased sotsiaalmeedia sisuloojad, kes püüavad pilku sätendavate kalliskividega ja eksootiliste mootorsõidukitega. Samat põhimõtet jälgides sai endale eriti suure lapseohtu vaatajaskonna sisulooja Andrew Tate, kes noored oma pilli järgi tantsima sai uhke elustiili eksponeerimisega. Tate kasutas noorte kergemeelsust ära, reklaamides neile oma krõbeda hinnaga veebikursust, mis pidi neil väidetavalt aitama samale elujärjele tema endaga. Tate on kogunud hinnanguliselt kümneid miljoneid USA dollareid noorte manipuleerimise ning edundamisega.\nSotsiaalmeedia on hoomamatu ning äärmiselt keeruline võrgustik, kus noortel võib orienteerumine kohati keeruliseks minna. Haavatavus valeinfo suhtes ning noorukitele omapärane kergemeelsus võib neid kergesti eksitada valele teele või mõjuda neile suisa laastavalt. Samas on lapseohtu inimestel sotsiaalmeediast leida ka tuge ning seltsi teiste noorte sisuloojate kaudu, kellega nad suhestuda saavad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ad5e7a22-0225-4f5f-a96f-e1b88d5f299d', 'title', 'Noored – sotsiaalmeedia ohvrid või kasulõikajad?');
