INSERT INTO core.text(id, content)
VALUES ('60c6d8e0-bc94-456c-9c91-25b734b6cec8',
        'Tänapäeval veedavad noored suure osa oma ajast sotsiaalmeedias, vaadates erinevaid videosi. Paratamatult satutakse kokku ka suunamudijatega, keda väga tihti jälgitakse ka edaspidi. Noorte tähelepanu köidavad suunamudijad kallite esemete, hämmastava talendi, ilusa välimuse ja oma elu probleemidega. Noored saavad suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida põlastava pilguga vaadata, kuidas kellegagi suhelda.\nUuringutes on selgunud, et suunamudijate kaudu jõuab noorteni mitmeid baasteadmisi ja tüvitekste.  ehkki suunamudijate otsest ja kiiret mõju on keeruline mõõta, on et suunamudijad mõjutavad inimesi konkreetsete toodete ostmisel. Paljud suunamudijad teevad koostööd erinevate toodete loojatega, saades neile reklaami tehes soodustusi või isegi tasuta kaupa. Tihti on just noored, kes lähevad sellise müügi kampaaniaga kaasa, sest nende jaoks on teisel pool ekraani olev isik täiesti usaldusväärne. Eesti tegutsev tiktokker Bonex, kes müüb Hiinast tellituid tooteid edasi märksa kallimalt kui ise neid soetas. Tema turg on suunatud Eesti noortele, kes ei taju seda, et tiktokker teenib nende pealt lihtsat raha, vaid kujutavad teda ette kellegi tähtsa isikuna. See on probleem, sest noored ei taju internetist tulevaid ohte.\nLoomade eestkoste organisatsioon Loomus alustab tänasel rahvusvahelisel karusnahavabal reedel ja ostuvabal päeval kampaaniat #loomadesilmis, mis kutsub inimesi üles mitte soetama karusnahka. Kampaanias osalevad kuulsad Eesti suunamudijad Hanna Martinson, Liis Velsker, Liina Ariadne Pedanik, Martti Hallik, Mick Pedaja, Alisa Tsitseronova ja Juhani Särglep. Läbi selle, et on kaasatud nii palju suunamudijad on võimalik saavuitada enda tahtmine, sest igal suunamudijal on erinev jälgijaskond. see kampaania on suunatud just noortele tarbijatele, et tõsta karusloomafarmide kulissidetagusest elust, mis on kõike muud kui ilus mütsitutt või kohev jopekrae. Antud kampaaniaga tehakse tööd, et Eestis keelustataks karusloomafarmid. Aastate jooksul on karusloomakasvanduste keelustamisele Eestis toetust avaldanud pea 70 erinevate valdkondade ettevõtet. Keeldu aiatavd toetada suunamudijad ja sellest on väga palju kasu olnud, kuna inimestele läheb korda nende tegemine ja selletõttu võetakse ka nende arvamusi kuulda. \nMõjukad sotsiaalmeedia tegelased Andrei Zevakin, Robin Valting ja ansabelt 5MIINUST liikmed Kristjan Jakobson ja Priit Tomson, kes teevad mitmesuguseid reisisaateid ja jagavad seda sisu vaatajatega juutuubi platvormil. Lisaks reisi tegevustele reklaamitakse ka vaatajate seas hasartmängu. Ise nad teevad enda panuseid kasiino rahade eest, sest nendel on sponsorlepingud, kuid tava vaataja ei tea seda ja nende jaoks tundub see hea viis raha teenida. Kuid tegelikult see nii lihtne ei ole ja suure võidu asemel on ka suur võimalus saada suur kaotus. Videotes kajastatakse ainult suuri võite ja kaotuste seeria jääb kaamera taha. 2024 aasta andmetel kuulub Eestis hasartmängusõltuvuse riskirühma 112000 inimest ehk 11 protsenti elanikkonnast. See o nprobleem, et mõjuvõimsad inimesed suudavad sotsiaalmeedias rahvast mõjutada erinevate otsustega.\nSotsiaalmeedia tegelased saavad mõjutada enda vaatajaskonda nii positiivsete kui ka negatiivsete asjadega. Nende mõju võib ulatuda alates pisikestest asjadest kuni suurte otsusteni välja.');
