INSERT INTO core.text(id, content)
VALUES ('675e5e74-a4b8-4ffb-abe6-5bce5f285cc5',
        'Sotsiaalmeedia mõjuisikud suunavad noorte igapäevaelu, otsuseid ja valikuid. Tänapäeva sotsiaalmeedias on nii positiivsust kui ka negatiivsust. Suunamudijad saavad postitada asju, mis nende jägijate mõtteviisi ning otsuseid muudavad, nad saavad panna neid võtma osa asjadest, mis toovad ühiskonnale head ning muuta inimeste heaolu.\nTänapäeval on inimeste tähelepannu tõmmata väga lihtne: pakutakse infot asjade kohta, mida tavainimesel on raskem kätte saada, näidatakse oskusi, mis omakorda üllatab vaatajaid või räägitakse lihtsalt oma elust. Uuringus, mille viis läbi Crystal Abidin, oli küsitud  internetikuulsuselt neli peamist omadust, mille abil suunamudijad oma publiku tähelepanu köidavad ja selle kaudu nende hoiakuid ja arusaama kujundavad: eksklusiivsus, eksootilisus, erakordsus ning elutähendus. Tänapäeval on loodud mitu äppi, kus saab enda asju ning elu jagada. Neist kõige rohkem populaarsust on kogunud TikTok. Just sealt saavad paljud inimesed, eriti noored nõu, mida saab normaaseks pidad ning milline stiil on hetkel päevakajane. Kuid igal asjal on ka oma negatiivne pool.\nSuunamudijad võivad tuua positiivset tagasisidet, kuid on ka olukordi, kus asi on hoopis vastupidine. Eesti kuulus suunamudija Maria Rannaväli rääkis saates „Laser“, kuidas TikTok on rikkunud tema vaimset tervist. TikTokis on väga palju negatiivsust ning seetõttu on ka paljude noorte mentaalne tervis kannatada saanud. Tänapäeva standardid on väga kõrged ning inimesi hakatakse tegema maha, kui ei nähta välja selline nagu kõik teised. Paljud muudavad ennast just selle pärast, et sobituda teistega, kuid ajapikku see kõik hakkab lihtsalt vaimsele tervsele. Kuid on ka palju suunamudijaid, kes toovad üles just mentaalset tervist ja positiivsust ning tänu sellele ei ole olukord nii hull. Postitatakse asju, mis panevad ühiskonda palju headust ning näitavad, et igast asjast saab lõpuks leida positiivsust.\nSotsiaalmeedias on palju organisatsioone, mis postitavad asju, et tuua tähelepanu aspektidele, mis on jäänud tahapilti. Näiteks on olemas kampaania #loomadesilmis, mis kutsub üles mitte soetama karusnahka. Eesti suunamudijatest osalevad seal kaks inimest, kes on nii Eestis kui ka Ameerikas populaarsed: Liina Ariadne Pedanik ning Martti Hallik. Sotsiaalmeedias võib kohata palju kaadreid, kus nähtakse, kuidas koheldakse neid loomi, kelle nahast asju inimesed pärast kannavad. Kuulsad suunamudijad, kes sellistest kampaaniadest osa võtavad, saavad muuta ka oma jägijate mõtteviisi, et ka nemad sellest osa saaksid ning loomade elu ning saatust muutaksid.\nSotsiaalmeedia kujuneb välja nii, milliseks inimesed selle ise teevad. Jagades rohkem positiivsust, jääks kõik negatiivne tahaplaanile ning ka inimeste enda heaolu oleks parem. On vaja aru saada, millisetele suunamudijatele antakse kuulsust ning milliseid asju nemad postitavad.');
