INSERT INTO core.text(id, content)
VALUES ('f00e1a63-9651-4597-a30d-30421dd7caef',
        'Tänapäeva ühiskonnas tuleb tihti arutluse alla noorte vähene lugemus. Sageli selgitatakse trendi suurenenus nutiseadmate kasutamisega. Sellised arengud on olnud märgatavad juba palju enne telefonide turule tulekut. Võõrkeelte pealetung soodustav noorte abitust tulevikus. Lugemuse vähenemine vaesustab ühiskonda, kogu elu kolib järjest enam internetti.\nÜhiskonnas on raamatud noorte seas minetanud oma kunagise hiilguse. Tiit Hennoste on öelnud artiklis „Lugemise harjumuse harjutus“: „Tänapäeval on liiga palju eri võimalusi vaba aega veeta ilma lugemata.“ Modernses ühiskonnas on raamatute kasutus asendunud nutiseadmes olemisega. Telefonis on kättesaadav tohutu hulk informatsiooni ilma lugemata. Raamatud on varasemalt olnud ühed tähtsamad informatsiooniallikad igas vanuses inimeste seas. Mõtteterade kogumise lugemise teel on arendav tegevus, mis suurendab lisaks silmaringile ka keelekasutuse oskust. Mugavus on nakatanud inimesi pidevalt, nüüd ähvardab see muute tervet inimkonda. Praegune  suundumus muudab noori abitumaks ning vähendab nende võimekust iseseisvas elus hakkama saamiseks. Laste tahe kogeda alatasa uut ja huvitavat on olnud teada juba varem.\nLugemisharjumise kadumist noorte seas on täheldatud juba pikki aastaid enne nutiajastu saabumist. Juba esimese vabariigi ajal ilmus ajalehes Kaja artikkel nimega „Noorte lugemisoskus läheb taguspidi“. Järeltulevate põlvkondade lugemus langus peab olema seotud muuga kui ainult nutiseadmete tulekuga. Inimkond on läbi aegade järgemööda arenanud ning ühe uusi leiutisi valmistanud. Kätte on jõudnud olukord, kus uued avastused muudavad ühiskonda järjest mugavamaks. Järjest vähem on vaja teha elus püsimiseks. Noored on rahva peegel: laste seas toimuvad muutused kanduvad suuremal või vähemal määral üle vanematesse kihtidesse. Selline olukord muudab inimesed varem või hiljem abitumaks ja havatavamaks, sest elamiseks ei pea enam ränka tööd tegema.\nGlobaliseerunud maailmas on järjest enam kanda kinnitanud inglise keel, mis suunab paratamatult lugema võõrkeelseid tekste. Tauno Vahter on artiklis „Peame leppima, noored lihtaslt ei loe“ välja toonud, et lisaks noortele on ka täiskasvanute hulgas suurenenud inglise keelsete väljentite kasutamine. Ka täiskasvanud inimesed on kunagi olnud noored, nende mõttemaailma arengu ajal on inglise keel tugevnenud üle planeedi. Täiskasvanudte kõnepruuk kandub pidevalt üle nooremale seltskonnale. Võõrkeeltest mõjutatud noored tekitavad olukorra, kus kõne  kandumine toimub mõlemas suunas. Kohalikud väiksemad keeled võivad sattuda ootamatu löögi alla, mis võib lõppeda keele osatähtsuse vähenemisega.\nPraeguses maailmas on järjest rohkem noori, kelle lugemus jätab soovida. Trend on edasi kandunud ka vanematele inimestele, kes omakorda kannavad seda oma järglestele. Noored peelgeldavad ühiskonnas toimuvaid muutuseid. Sured muutused võivad ohtu seda väiksemad keeled.');
