INSERT INTO core.text(id, content)
VALUES ('33770fd7-195e-4b42-a00d-0295bbe40b24',
        'Tänapäeva nutimaailmas on paljude noorte suureks elu osaks sotsiaalmeedia kanalid nagu Instagram, TikTok, Snapchat ja Youtube. 20.sajandil oli sirguvate noorte eeskujudeks nende vanemad, sõbrad või sugulased. Generatsioon Z-st on näha, kuidas noored ei soovi olla mitte oma vanemate, vaid hoopis sotsiaalmeedias laineid löövate netikuulsuste moodi. See kuidas keegi võhivõõras mõjutab sirguvaid maimukesi on vanemale generatsioonile nii arusaamatu, kuid nad ise on samuti alateadlikult sellest mõjutatud. Tekib küsimus, kuidas meid mõjutatakse?\nÜleüldiselt internet on praeguse seisuga oma parimas olemuses, igapäevaselt tehakse seda aina paremaks, kuid vanasti seda polnud. Noorem põlvkond on sellega kogu oma elu elanud ning ei oskaks ilma selleta midagi teha. Tänu sisuloojatele ja blogijatele saavad paljudki inimesed oma muredele lahendusi. Blogija Mallukas ja sisulooja Kristina Pärtelpoeg otsustasid teha podcast`i nimega „Salajutud“, kuhu inimesed saavad anonüümselt kirju saata. Enamuselt räägitakse seal inimeste piinlikest olukordadest või siis suhte probleemidest. Paljudki noored on saanud sealt abi oma murede lahendamisele, kuna teistele ei julgeta näost näkku seda rääkida ning teatakse, et keegi ei saa sellest kunagi teada. Tänapäeval on palju veebikiusamist, mille all paljud noorukid kannatavad. Oma muredest mitte rääkimine tekitab omakorda aga mentaalseid probleeme, mida on palju raskem lahendada. Seega tänu kahele naisele, kelle algne plaan oli lihtsalt lõbu pärast ühe podcast`i tegemine, on aidanud paljusid Eesti inimesi oma suurte murede lahendamisel või kartustest üle saamisel.\nKartus on siinses ühiskonnas selline, mida keegi eriti välja näidata ei taha. Paljude mureks on oma mugavustsoonist välja tulemine, kuna inimesed kardavad, et võivad oma elus sellepärast läbi põleda. Seepärast ongi hea, kui meil on inimesed, keda vaadata, kes motiveerivad meid tegema midagi uut. Eesti teleseriaali „Ühikarotid“ näitleja Liina Raud rääkis oma TikToki kanalil, kuidas tema suureks abiks oli Tuuli Roosmaa, kes kutsus teda seriaali näitlema. Naine, kes keskkooli ajal põlastas näitlemist, tunnistas, et see oli tema elu muutepunkt ja kus ta sai aru, et soovib oma elus, midagi enamat. Liina Raud motiveeris inimesi, tegema asju, milleks nad pole valmis. Lisaks jagas ta oma kogemust Ameerika Ühendriikidesse immigreerumisest, mis kõitis paljusid üle saamaks oma hirmust reisimise üle ja tegema asju ristirästi vastupidi oma elustiilile. Inimesed oleksid teadmatuses, kuidas asjad käivad, kui meil ei oleks netikuulsusi, kes räägiksid oma enda kogemustest ja vigadest.\nVanemad inimesed võivad väita, et tänapäeva noorus on hukkas, kuid nad ei tea sotsiaalmeedia suurtegijate mõjust noorukide elule. Nad on aidanud lahendada piinlikuid hetki ja probleeme, kui ka inimestel üle saada erinevatest hirmudest. Meie vanemad ja vanavanemad ei tohiks olla nii kriitilised, kui nad on, sest nad ei tea, mis nende lapsi võib aidata.');
