INSERT INTO core.text(id, content)
VALUES ('ea616a2b-e171-4672-a9ce-970b9e6d9116',
        'Tänapäevases maailmas, kus enamus meie kõigi tähelepanust, eriti just noorte omast, on suunatud just internetimaailma. Maailmas, kus on võimalik jälgida inimesi, südmusi ja muud, kas või teisel pool maakera, on selge et tuleb välja sorteerida, mis on tõsi ja mis mitte. Internetimaailmas varitseb erinevaid ohte: kelmused, röövid, vale info levik ja veel palju muud. Samuti on seal pesitsevatel suunamudijatel väga suur võim inimeste üle. Kui sulle meeldib keegi siis hakkad alateadlikult tema järgi erinevaid asju tegema, olgu selleks siis mingi asja soetamine, filmi vaatamine või hoopis kuhugi reisimine.\nNoorte tähelepanu on väga suurel hulgal suunatud just internetti ja seal toimetavatele influencer´itele. Nende tegevus paneb noori, kes neid jälgivad tegema asju, mida nad muidu iial ei teeks. 28-aastane Eesti sisulooja Andrei Zevakin kandis pikka aega pikki lokkis juukseid. Selle tagajärjel tegid paljud Eesti noored poisid läbi tugeva stiili muutuse oma juustega. Nad kõik tahtsid välja näha nagu Zevakin ja nii lastigi oma juuksed lokki keerutada. See on ehe näide sellest, kuidas üks inimene suudab panna väga suure rahva hulga enda välimust muutma. Selles muutuses pole midagi halba aga paraku on ka neid muutusi, mis ei mõju noorte tervisele hästi.\nSuunamudijatel on väga suur võim muuta inimeste käitumismustreid ja nende eluviise. Enamasti on need muutused head aga paraku on teada tuntud, et kui on head siis peab olema ka halba. 39-aastane Eesti mees, kes esines youtube´s kasutajanimega HD Tanel, tegi videoid sellest, kuidas mängis erinevaid arvutimänge. Paljud noored said just nendest videotest huvi arvutimängude vastu. Kahjuks ei olnud ka kõik arvutimängud sobilikud igale vanuseastmele. Nii hakkasidki palju noored mängima erinevaid tapmis- ja tulistamismänge, nagu call of duty ja fortnite. Tulistamismängud toovad endaga kaasa erinevaid häireid, kõige levinum on ärevushäire, sest mängides ei tea sa iial, kust nurga tagant vastane tuleb ja sind üritab tappa.\nSamuti osalevad mitmed tuntud suunamudijad ja avalikuelu tegelased erinevates kampaaniates. Nendel kampaaniatel on üldjuhul hea tagamõte. Organisatsioon Loomus lõi kampaania #loomadesilmis, mille patroonideks olid Eestis hästi tuntud sisuloojad ja avalikuelu tegelased, nagu Hanna Martinson, Liina Ariadne Pedanik, Martti Hallik ja mitmed teised. Selle kampaania eemärgiks oli kutsuda rahvast üles mitte ostma karusnahkseid tooteid, ja tõsta rahva teadlikust karusnahafarmide telgitagustest. See ongi super näide sellest, kuidas firmad kasutavad tuntud nägusid oma reklaamides ja kampaaniates, et rahvas tuleks sellega kaasa. \nEesti noorte ja samuti ka täiskasvanute maailm on suurel määral suundunud internetti. Inimesed peavad olema targad ja suutma sorteerida terad sõkaldest. Väga suur mõju on suunamudijatel just lihtsate noorte üle, kes tahavad olla nagu nemad. Seepärast peamegi olema valvsad, et see mis jõuab meie noorte silme ette, oleks turvaline ja usaldusväärne. Noored ise ei suuda veel selgelt aru saada, mis on tõde ja, mis on väär.');
