INSERT INTO core.text(id, content)
VALUES ('9e36a488-065d-4cac-a8c5-52bc30dcf3d0',
        'Tänapäeval on tuuakse Eestis esile mitmeid probleeme. Üks nendest probleem on noorte lugemine, kas lugeda või mitte lugeda. Mis on need tegurit, mis takistavad noortel lugemist harrastamas? Noored veel ei tea, mis neid huvitab ja kuhu suunda oma teekonda alustada, aga se, et tahetakse lugemist peale suruda ka ei ole vastus.\nLugemine on harrastus, mida paljud naudivad. Nagu Tauno Vahter on oma artiklis peame leppima, noored lihtsalt ei loe, et puudub noorte seas huvi lugemise vastu. Muidugi noorte seas esineb ka noori, kes naudivad lugemist, kuid on ka palju, ke ei loe. Lugemine võtab aega ja see on iga inimese jaoks erinev. Mida vanemaks noorukit saavad on nad juba ka leidnud osa endast ja teaved oma huvisi täpsemalt. Lugemist saab noortele huvitavaks teha vaid suunamisega, parim näide meie ühiskonnas on see kooli kirjalik lugemine. Kuid selleski ei piisa, et seda parandada tuleks kohustusliku kirjandust muuta. Tuleks tuua kohustuslikku lugemisse erinevate zanridega raamatuid, et noor leiaks omale meelepärase raamatu, et talle tekitada lugemise vastu huvi. Niimoodi saaks noortele panna ka aluse lugemisele.\nMe elame tänapäeval ka kiires ühiskonnas, kus meil ongi kiire, Tiit Hennoste on ka välja toonud, et meile on normiks tulnud kiirmaiilm: kiirtoit, kiirkeel, kiirteadus, kiirlugemine jne. Lisaks on ta oonud ka välja, et lisaks kiirele maailmale on tulnud esile ka nutimonomaania. Kuna meie teadus on arenenud väga kiiresti on meil raske sellega kaasas püsida, sest aina rohkem innovaatilisi tehnoloogiaid ja avastusi on tulemas. Kuid selles maratonis me ei saa ka ainult kiirendada, sest kui me ainult kiirendame kukume lõppude lõpuks kokku. Kiires maailmas peame ka leidma hetke, et hetkeski hinge tõmmata, oma mõtteid koguda ja ennast arendada. Sellepärast osutubki oluliseks korraks üks kord päevas raamatud lugeda mõttega. Vaid nii saad oma mõtteid puhata ja uusi mõtteid vastu võtta ja kooskõlastada neid enda maailmaga.\nPaljud ei võta ka koheselt lugemise vastu kuna on juba nutimaailmaga ära harjunud. Peame algul saama välja oma harjumusest skrollimisest ja raamatu kätte võtma, ning ennast üles otsida. Selleks ongi vaja omale treenida lugemise harjumus. Tuleb leida aeg, kus loed raamatust 10 lehekülge ja kui oled harjunud, siis lisad lehekülgi juurde. Algul võibki tunduda, et sunnime ennast lugema, kuid kui harjutad ja teed seda tegevust piisavalt kaua ongi meil kujunenud harjumus. Kui harjumus ja oma meelele leidnud raamatu old leidnud, võib lausa unustada ära oma sundlugemise ja harrastada raamatut. \nLugemine on meiega olnud sajandeid ja see jääb ka tulevikus samaks, isegi siis kui raamatud kaovad ei lõpeta me ka lugemist internetis. Lugemisega saame maandada oma stressi ja laiendada oma maailmapilti. Läbi ramatute suudame ennast seostada ka teiste maailmapildiga jaoma probleemidele lahendused leida.');
