INSERT INTO core.text(id, content)
VALUES ('213f7e3f-2fff-498f-8469-2ebab5d613b5',
        'Noored ei loe, kas see on häving või uus reaalsus, millega tuleb õppida elama? Mitte lugemine ise ei ole midagi uut aga mõte selle ümber on küll. Enda kaotamine sellises maailmas on lihtne. Kas noorte tahtmist raamatuid lugeda suurendamine aitaks?\nNoored ei loe ning see pole midagi uut. Lugemisharjumuse vähenemine on toimunud aastate jooksul. Tauno Vahteri arvamusloos on toodud näide 1932.aastal ilmunud artiklist ajalehes Kaja, pealkirjaga „Noorte lugemisoskus läheb tagurpidi“. Antud artikkli olemas olu tõestab, et lugemisharjumuse vähenemine ei ole alanud tänapäeval, nutiajastul. Samas näitab artikkel ka seda, et noorte kallal kirutakse alati. Olgu ta siis stiili, muusikamaitse või iseloomu poolest.  Noored on alati omapärased olnud isegi mässulised. See ei minu jaoks üldse ime, et noored ei loe. Lugemine ei ole nende esimeseks priooriteediks. Kõik vast ikka mäletavad enda nooruspõlve, kus nad tahtsid ainult lõbutseda ja sõpradega väljas käia. Enamus noorte jaoks vajub lugemine just sinna mitte lõbusasse ajaviitmis katekooriasse. Isegi, kui präegu nutiseadmeid ei eksisteeriks, leiaksin et see oleks siisk mingil määral probleem. Kool ja ka kodu, kust kõik algab, on kaotanud oskuse teha lugemine noorte jaoks lõbusaks. Kuigi mitte lugemine on noorte seas toimunud koguaeg, võib öelda, et tänapäeval on see siiski süvenenud tänu nutimaailmale.\nLugemise vähenemine on tingitud maailma muutumisest. Alustame selllega et, mida meile õigupoolest lugemine annab? Kas iga raamat, mida me loeme on lihtsalt tühine ajaviide või annab ta meile midagi enamat? Lugemine just kui kujundab inimest. Kõik lood või artiklid, mida me loeme kujundavad meid ennast. Kõik need loetud õhtud, mil sa istud raamatu taga ja loed annavad sulle uudse kogemuse ja tunded, mida sa mujalt ei saa, arvamused, mis kujundavad sinu mõttemaailma. Tiit Hennoste on enda arvamusloos „Lugemise harjumuse harjutus“ toonud välja, et „Mina kasvasin raamatutega“. Tema nooruses 1960. ja 1970. aastatel oli lugemine vaba aja täitmine. Tänapäeval on raamatu asenduseks tulnud nutiseade. Kas see on tõesti nii halb? Nutiseadme olemas olu on andnud meile võimaluse saada informatsiooni kõik ühest kohast. Isegi raamatuid ei pea enam füüsilisel kujul laenutama vaid võib lugeda sõrme liigutuse kauguselt. Iseenesest see on ju tore, aga kaasneb ka negatiivseid mõjusid. Raamatuid võib küll internetist lugeda, aga seda tunnet mis sa saad lehte keerates ilma et sa peaks mitu tundi ekraani vahtima on ikkagi midagi muud. Sellest tulenevalt võib öelda, et loetakse küll, lihtsalt vähem füüsilisel kujul.\nNoored ei loe, see on meie uus reaalsus. Arvutid on ülevõtnud meie vaba aja veetmis viisid ja sinna ei ole iseenesest midagi teha. Uue maailmaga tuleb lihtsalt kaasas käia. Et ennast mitte kaotada siia nutimaailma, tuleb lugeda ning hoida raamatuid, millest kõik alguse sai.');
