INSERT INTO core.text(id, content)
VALUES ('29eff616-ae73-4bfa-bb0f-983b0a0a5f34',
        'Viimasel ajal on päevakorda kerkinud üks aastaid täheldatud ja ajapikku süvenenud probleem. Selleks on lugeda armastavate noorte suurearvuline vähenemine. Kuidas taastada noorte huvi raamatute vastu? Mis on need lugemist mõjutavad tegurid ja mis rolli mängib see noore inimese elus ning ühiskonnas?\nLugemine ja oskus oma sõnu seada on üha rohkemate noorte jaoks kujunenud igapäevaseks probleemiks. Ei osata suhelda teistega ega ka ise mõista, mida täpselt temalt tahetakse. See on suur probleem, sest funktisonaalset lugemisoskust tuleb ette igas eluvaldkonnas. Ka paljud uuringud toovad välja, et hea lugemisoskus loob ellduse parematele hinnetele, paremale haridusele, paremale sissetulekule ja paremale vaimsele tervisele. Kui funktisonaalselt lugeda oskavate inimeste osakaal järsult väheneb, põhjustab see terves ühiskonnas taandarengu. Seega on areneva ühiskonna eelduseks lugemisoskus ja soov ennast arendada. Mida varem alustada enese arendamisega, seda suurem on selle positiivne mõju elukvaliteedile. \nHarjumus lugeda tuleb tihtipeale kodust. Vanemad utsitavad oma lapsi veerides lasteraamatuid lugema ja innustavad neid öeldes, et lugemine on vajalik oskus. Kahjuks on aga aeg näidanud, et vanematel ei ole enam viitsimist ega ka aega lastele lugemist õpetada. Kordades lihtsam on anda neile kätte nutitelefon või tahvelarvuti, et nad saaks seal mängida ja multifilme vaadata. Vanemad peavad seda loogiliseks variandiks ise adumata, et see pärsib lapse loomingulisust ja õppimisvõimet. Ka Tiit Hennoste on öelnud, et nutimonomaania on üks lugemise hääbumise põhjuseid. Kogu maailma info on sealt kättesaadav ja raamatute lugemine tundub mõttetu. Filmidest ja videotest saab aju dopamiini palju kiiremini ja efektiivemalt. Siiski ei arenda see laste loovust, fantaasiat ega kujutlusvõimet nii, nagu seda teeb raamat. Jääb tunne, et raamatutel ei ole võimalust nutiseadmetega konkureerida ja on ainult aja küsimus, millal raamatud igaveseks ajalukku jäävad.\nKas tuleks midagi ette võtta, et noori rohkem lugema saada? Tauno Vahter on öelnud, et võitlus noorte lugemisharjumuste pärast on kõigest pidurdav kaitselahing. Ei ole võimalik kedagi vägisi ja ilma omapooolse tahteta lugema sundida. Ta rõhutab, et alati on ka lugejaid noori ja tõsiselt häid tulemusi noorte lugemisharjumuste suurendamisel ei ole ja pigem ka ei tule. Tahe lugeda peab tulema ikka iseenesest ja selle mõjutamine on kõigest viljatu püüdlus. Ainus viis neid raamatuid lugema juhtida on teha need kättesaadavamaks ja aktaktiivsemaks. Sellisel juhul suureneb tõenäosus, et raamat oma enda vabast tahtest pihku haaratakse. \nRaamatute lugemine on tänapäeval kaduv nähtus. Koos lugejate arvu vähenemisega kaovad ka intelligentsed inimesed. Kuna jõuga kedagi lugema sundida ei saa, jääb üle vaid loota, et üha rohkem noori valib ise raamatute lugemise tee ja kindlsutab sellega targa ühiskonna püsimise.');
