INSERT INTO core.text(id, content)
VALUES ('f97f8fa4-a854-45ac-80fd-6f4259a6d3dd',
        'Igapäevaelus saadavad inimesi kõikjal reklaamid. Kui seade on ühendatud internetiga on seal automaatselt kuulutused soodusmüükidest ja uudistoodetest ning teenustest. See on tüütu, ning enamus inimestest ei keskendu nendele, vaid otsivad kiiresti seda x-märki, kust reklaam sulgeda. Aga mis siis, kui reklaamist saab sõber?\n„Juba 1956. aastast päris parasotiaalsete suhete teooria kohaselt tekib meedia vahendusel inimestel illusioon, et meediastaar on nende lähedane tuttav, keda tasub kuulata“ kirjutab Maria Murumaa Mengel artiklis „Mõjutamine (4): kuidas suunamudijad meid mõjutavad?“. Noorte elud on kolinud TikToki, Instagrami, Snapchati ja igasse muusse sotsiaalmeedia platvormi, mis kättesaadav on. Ühismeedia algusaegadel oli selle eesmärgiks sõpradega suhelda ja uusi tutvusi sobitada. Ajaga on asjad aga arenenud sinnamaale, et enamus sisust mida tarbitakse on täielike võõraste poolt suurele vaatajaskonnale kasumi teenimise eesmärgil loodud. Kasutatakse väljendeid nagu viral, must have, essential, et tekitada tunne, et kõik kasutavad antud tooteid ja ka vaatajal on seda kohe vaja. Ühe nooremad tüdrukud ostavad endale kalleid meigitooteid, parfüüme ja riideid, sest need on trendikad ja tahetud. Suunamudijad mängivad tarbijate emotsioonidega, tekitades FOMO (fear of missing out), sest inimestes on kaasasündinud tung kuuluda gruppi. Ja sa ei saa kuuluda gruppi, kui sul pole kõige uuemaid ja trendikamaid asju.\n2016. aastal lasi Kylie Jenner, ameerika influencer ja üks Kardashianitest välja oma huulepulkade komplektid, mis koosnesid huulepulgast ja huulepliiatsist. See toode, nagu kõik, mida Kardashianid välja lasevad osutus väga populaarseks ja inimesed ostsid neid kokku nagu poleks homset. Kas inimestel oli tõesti nii suur vajadus huulepulga järgi? Jenner reklaamis oma toodet ise, ning ostja sai läbi selle ostmise kogeda vähemalt midagi, mida Kardashianid, sest nende eluviis on tavalisele inimesele kättesaamatu. Üha rohkem tuleb välja kuulsuste brände, kui jätkata Kardashianitega siis näiteks Skims, 818 Tequila. KKW beauty ja muud. Need brändid on kallimad, kui nende konkurendid, kuid siiski millegi pärast edukamad, vähemalt sotsiaalmeedias. Ostes kuulsuse toote saab inimene temaga samastuda, tarbida seda mida ka tema iidol. Paljud kuulsuste brändid on saanud vastukaja halva kvaliteedi või ebaoriginaalsete ideede tõttu, kuid see ei takista ostjaid rahakotti avamast, sest kõik tahavd oma argipäeva veidi Kardashianite glamuuri.\nNoored on mõjutatavad, kuna neil on pooleli raske üleminekuaeg, kus kõige oluisemaks on kuuluvustunne. Kui kõikidel sõbrannadel on hetkel kõige trendikamad tooted ja sinul pole, on see kui maailma lõpp. Suunamudijad üritavad meile igal ärkveloldud hetkel müüa enda maailma, mida me tegelikult kunagi kätte ei saa, vaid jääme ise vaesemaks. Lohutuseks võib öelda, et vähemalt sai kogust sellest jamast ühe keskpärase huulepulga.');
