INSERT INTO core.text(id, content)
VALUES ('8a12170a-1c34-452b-b83e-2b224aaaa58a',
        'variant II\nFunktsionaalne lugemine on vajalik oskus, et edukalt elus hakkama saada. Lugedes on võimalik ammutada vajalikke teadmisi, edastada informatsiooni ning mõista ümbritsevat maailma. Seepärast on tähtis harjutada lugemist, et mõista ka kõige keerukamaid lauseid ning nende nüansse, kuid kahjuks on viimastel aastatel lugemine, kui harjumus nooremate põlvkondade seas vähenenud.\nTänapäevases kiirusel põhinevas ühiskonnas on inimesel raske leida aega, et süveneda ning kannatlikult lugeda raamatut. Tegevus on küll kasulik, kuid paljude tehnoloogiliste võimaluste ja sotsiaalmeedia tõttu on ühiskond harjumas kiire eluviisiga, kus rahulolutunnet on lihtne saavutada. Noored ei loe enam raamatuid, kuna rahulolutunde saavutamiseks kulub rohkem aega ning pingutust, võrreldes näiteks TikToki või Instagrami kasutamisega. Näiteks kirjutab Tiit Hennoste artiklis „Lugemise harjumuse harjutus“, kuidas nutiseadmetest tulenev kiirmaailm ei mõjuta mitte ainult lugemist, vaid ka toidutööstust, teadust, keelekultuuri, seksuaalseid harjumusi ja nii edasi. On palju põhjuseid, miks noored tänapäeval ei loe, ning üheks peamiseks põhjuseks on ühiskonna kiireloomulisus.\nLugemise vähenemisega väheneb ka oskus mõista keerukamaid tekste. Tekstide mittemõistmisest võivad tuleneda elus märkimisväärsed raskused, mistõttu noored ei mõista neile edastatavat informatsiooni, allkirjastatavaid finantslepinguid ning ühiskonna poliitilist maastikku. Noored, kes ei ole võimelised mõistma keerukaid tekste ning nende põhjal oma järeldusi tegema, on vähem võimelised kui teised, kes seda suudavad, tulenevalt nende oskamatusest märgata keelelisi nüansse ja võimalikke loogikavigu informatsioonis, mida nad loevad. Artiklis väidab Hennoste, et lugemisoskuse vähenemisega väheneb ühtlasi inimeste hulk, kes suudavad iseseisvalt ühiskonnas hakkama saada, mistõttu oleks tähtis lugeda, et olla võimeline mõistma maailma enda ümber.\nÜhiskondlikul tasemel on vähe, mida oleks võimalik teha, et noori lugema panna. Hennoste artiklis väljendub olukord, kus 1990. aastatel vähenes Soomes vabatahtlik lugemine justkui vastureaktsioonina kohustuslikule lugemisele. Seega võiks järeldada, et üks väheseid võimalusi lugemist soodustada, oleks anda inimesele vaba valik, kas ja mida lugeda. Lugemine ei ole tegevus, mida saab sundida inimest tegema. Selleks on vaja isiklikku tahet, et olla võimeline tekstile keskenduma ning sellest maksimumi võtma. Seega on lugemine ja selle arendamine täielikult inimese enda vastutada, sest keegi teine tema eest seda teha ei saa.\nLugemine on kasulik oskus, mis on kahjuks noorte seas vähenemas, tulenevalt ühiskondlikest mõjutustest ning kiireloomulisest elustiilist. Siiski peaksid noored mõnikord lugema, et arendada oma funktsionaalset lugemisoskust, mis aitaks neil tulevikus hakkama saada. Olgugi, et püüdlused noori lugema saada on hea eesmärgiga, kipuvad need siiski ebaõnnestuma ning tagajärjena noori veel rohkem lugemisest võõrutama. Seetõttu peaks lugemine olema vabatahtlik, et selle atraktsioon noorte seas taastuks.');
