INSERT INTO core.text(id, content)
VALUES ('0b0fb466-61d7-42d1-8e80-ef4b0af46d56',
        'Sotsiaalmeedias tegutsevatel persoonidel on suur mõjuvõim noorte üle. Peaaegu kõigil noortel on mingisugune sotsiaalmeedia rakendus, seega mängivad suunamudijad suurt rolli enamuste noorte eludes. Seda mõju inimeste üle saavad suunamudijad ära kasutada mitmetel eri viisidel nii maailma muutmiseks, kuid ka ainult isiklikuks hüvanguks. \nAvaliku elu tegelased saavad tänu sotsiaalmeediale muuta maailma paremaks kohaks. Suunamudijatel on suur mõju eriti just noorte üle, kes on ühiskonna tulevik. Noorte ettevõtmiste kaudu saab korda saata väga suuri tegusid kogu ühiskonna hüvanguks. Näiteks #loomadesilmis kampaaniat viib läbi noorte seas populaarne Hanna Martinson ja sellest võtavad osa ka teised suunamudijad. Hea Kodaniku artiklis räägib Martison, et usub noorte huvi maailma muuta paremaks. Seega tänu sellele näevad palju rohkem arv noori seda kampaaniat ning ka võtavad ise sellest osa, sest suunamudijate roll muudab kampaania turunduse aktraktiivsemaks just noorte seas. Järelikult suunamudijate abiga saab noori harida erinevate ühiskondlike probleemidega ning panna noori aktiivsemalt nendega tegelema. \nNoored jäljendavad sotsiaalmeedias nähtud ja kuuldut väga palju, mille tõttu oma enda mõtted ja arvamused jäävad tihtipeale tahaplaanile. Nad võtavad oma igapäevaeludes valikuid tehes väga palju inspiratsiooni influencer`itelt, kes saavad väga drastiliselt kujundada noore inimese maailmavaadet. Õpetajate Lehe artiklis kinnitab seda juba 1956. aastal tehtud uuring, milles tuuakse välja, et nimesed võtavad kuulsusi nagu nende lähedasi tuttavaid, kelle nõu tuleb kuulda võtta. Seega saavad influenecer´id mõjutada nii noorte poliitilisi maailmavaateid, arvamusi ning suhtumisi oma sotsiaalmeedia sisuga kui ka panna neid kedagi või midagi idoliseerima või hoopis vihkama. Ei saa öelda, et selline mõjutamine ainult halb on, kuid noored peaksid meeles pidama ja hoidma ka enda arvamust ning mitte laskma mõjutada ennast ülenisti. Kõik inimsed peaksid vaatama sotsiaalmeedias nähtut või räägitut kriitilise pilguga.\nInimesed, eriti noored, peavad sotsiaalmeedias olema ettevaatlikud, et nad ei satuks suunamudija asemel petturi otsa. Influencer´itele on eetiline käitumine reklaamida toodet või teenust, millega nad ise ka rahul on. Nad peaksid jääma enda vaatajatega ausaks, kuna sotsiaalmeedias on jälgijatel kõige suurem roll. Kahjuks leidub neid, kes kasutavad ära inimeste naiivsust sotsiaalmeedias reklaamitu suhtes ning teevad palju koostöid ainult brändi poolt pakutava tasu pärast, kuigi see toode või teenus ei pruugi olla üldsegi kvaliteetne või tõhus. Kristjan Kikerpill toob välja, et see on probleemiks saanud, kuna inimeste arvamus on vaba, kuid keegi ei saa tõestada, kas suunamudijad arvavad seda päriselt või tulu pärast. Paljud Eesti suunamudijad reklaamivad Aswha Ghandat, kui imerohtu, mis aitab kõige vastu. Seejärel paljud inimesed soetasid seda ning neil ei mõjunud see ravim nii nagu sotsiaalmeedias räägiti. Alles peale seda nad uurisid päriselt läbi viidud teadusuuringuid selle kohta ja said teada, millised kõrvalnähud sellel päriselt on. Seega on sotsiaalmeedias reklaamitu tihtipeale kaheldava väärtusega ning inimesed peaksid tegema faktikontrolle, mis põhinevad teadusel.\nAvaliku elu tegelased avaldavad noorte elule väga suurt mõju. Nii noored kui ka suunamudijad ise peaksid enda tegusid ja öeldut läbi mõtlema, kuna see tagajärg võib olla ootamatult suur. Noored peavad olema ettevaatlikud ning kriitilise pilguga reklaamide suhtes, kuid ka olema tähelepanelikud ühiskonnas toimuva suhtes ning kasulike projektidega kaasa lööma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
