INSERT INTO core.text(id, content)
VALUES ('1af735d8-4c22-4c2d-9e59-0e430ef33a02',
        'Iga 31. detsember, läbivad aastad meie kalendris ja koos aastatega vahelduvad ka huvid inimestel. Varem inimesed pühendasid enda vabaaega põlluharimisele ja küttimisele, aga hiljem oma oskuste arendamisele. Viimased sajandid nii noorem kui ka vanem põlvkond vabal ajal pühendasid end raamatute lugemisele, aga mida rohkem arenesid tehnoloogiad, seda rohkem inimestel kadus huvi raamatute vastu. \nKohustuslik kirjandus koolides ei pakku huvi lastele, kuna enamasti noored soovivad lugeda kirjandust, mis on nende jaoks põnev. Tehnoloogia ajastul noored võivad võrrelda, kus nende jaoks oleks parem olla ja kahjuks, kuna praegu on suur  populaarsus USA’l ja Inglismaal paljud noored on huvitatud nendes kultuurides ja riikides. Teadlased on uurinud, et raamatud inglise keelse pealkirja ja sisuga laenatakse ja ostetakse palju rohkem, kui teisi raamatuid. Samuti mängib olulist rolli see faktor, et paljudest raamatutest teismelised saavad teada Tiktokist või Instagrammist, kus neid soovitavad välismaalt blogijad. Selleks, et noortel tõuseks huvi raamatute lugemise vastu see peab muutuma populaarseks, kuna kõik teismelised tahavad olla ajaga kaasas. Seetõttu on vaja alustada internetis propagandad, et raamatud muutuksid populaarseks nagu spinnerit, kendamad jt. Samuti peab muuta meie haridus süsteemi selleks, et lapsed loeks seda, mida tahavad, kuna see aitab tagastada huvi lugemise vastu.\nÜks olulistest probleemidest 21. sajandil on see, et inimesed harjusid elama kiirmailmas. Võttes kätte telefoni ja avades Tiktoki, Instagrami või Youtube shortsi vaataja saab kiire dopamiini, kuna vaadates maksimum viie minutilist videot ta arvab, et areneb. Kiirmaailma valitsuses peamine probleem on selles, et suur osa informatsioonist säilitatakse lühimälusse, mis une ajal meie organism unustab, seetõttu peamine info, mis oli saadud terve päeva jooksul kaob. Tiit Hennoste oma artiklis „Lugemise harjumuse harjutus“ kirjutas, et „mõttega lugemine on aeglane tegevus“, aga kiirmaailma valitsuses inimeste jaoks see on suur katastroof. Seda globaalset probleemi peab kontrollima riik, kuna vahetundide ajal lapsed istuvad telefonides. Seega koolides, kus noored peavad arendama oma sotsiaalset ja vaimset tervist võiks keelata telefoni kasutamist. Nende asemel võiks koolis lisada lugemis tundi, kus lapsed ise valivad endale raamatu ja loevad, see jätaks nende kiirelu tagaplaanile.\nKõik inimesed maalimas on oma moodi laisad ja sellega kaasneb ka lugemise tahtmine, kuna paljud tahavad lugeda, aga ei ole valmis raiskama sellele aega. Kõik harjumused elus tulevad distsipliinist, kuna kui inimesel puudub distsipliin, siis isegi kui on tugev soov ta ei suuda end kokku võtta. Seega, et arendada soovi lastel lugemisele võiks neile anda mingi motivatsioon lugemiseks, näiteks maiustus, mäng jne. Täiskasvanud, aga peavad arendama distsipliini, näiteks nagu tegi Tiit Hennoste „Otsustasin, et loen igal õhtul pool tundi. Alguses on raske, aga paari kuu pärast on asi selmaal, et vajan oma igaõhtust lugemise annust.“ \nLugemine on väga tähtis oskus, mida inimesed peavad arendama, aga mitte unustama, kuna see on üks inimeste omadustest, mis eristab meid loomadest. Kõik inimesed, kes elavad tsiviil ühiskonnas ja on elus saavutanud oma sihtpunkte räägivad, et lugemine on üks peamisi elu kvaliteete. Lugemine suurendab inimeste sõnavara ja paljudel arendab distsipliini.');
