INSERT INTO core.text(id, content)
VALUES ('c1d22b4e-9d9b-42ff-b58f-a2c6227b0129',
        'Tänapäevases ühiskonnas on tekkinud probleem, et noored ei loe enam nii palju raamatuid. Siiski leidub veel noori lugejaid, aga ka neil on omad eelistused teose valikul. Vähene lugemine ning igasugused eelistused ei ole väga ühiskonna arengut soodustavad tegurid. Tekibki küsimus, mis on noorte lugemisharjumused ja nende tagajärg Eestis.\nInglise keel on võtnud üle noorte lugemise, sest selliste raamatute tegevus viib tavaliselt lugeja välismaale. See tähendab, et nad on hakanud eelistama välismaa kirjandust üle kodumaise. Kõige populaarsemateks raamatuteks osutuvad need, millel on kaanel pealkiri inglise keeles. Seepärast on hakatud isegi müüma ja avaldama ainult selliseid teoseid, sest teistel ei lähe müümine nii edukalt. Näiteks vene kirjastused avaldavad peamiselt selliseid noorteromaane, sest need on pea ainsad raamatud, mida noored ostavad ja loevad. Sellisel lugemisharjumusel ka tagajärg – noored on rohkem seotud välismaa kultuuriga kui isamaa kultuuriga. See tekitab muret, sest meil on vaja tulevikus kedagi, kes annab ka oma järglastele meie kultuurilist pärandit edasi ning selleks on vaja, et nad ikka mõnda asja teaksid ka oma kodumaast. Üheks võimalikuks lahenduseks sellisele probleemile olla võib see, et hakatakse eestimaiset kirjandust tõlkima rohkem inglise keelseteks. Seega tänapäevases eesti ühiskonnas on noortele rohkem peale hakanud välismaine kirjandus ning selle tagajärg ühiskonnale on see, et nad ei pruugi mõista enam isamaa kultuuri omandamise ja edasiandmise olulisust. \nNoored ei loe tänapäeval nii palju kui varem, sest seda pigem nähakse kohustusena kui vaba aja täitmisena. Teosed on tihtipeale keerulises, bürokraatlikus keeles, mis noortele enam nii hästi peale ei lähe. On tulnud nende ellu nutitelefon, milles on kiire ja lihtsasti haaratav info olemas. On tehtud oma eelistused ning pigem ollakse oma seadmes kui pead pööritavas arusaamatus tekstis. Aga sellel on karm tagajärg – kõik ülesanded nii tulevikus kui ka olevikus nõuavad keerukate sõnade ja tekstide mõistmist. See tähendab, et kui ei loeta ega harjutata sellist mõtlemist võib noortel väga keeruliseks elu minna. On olemas uurimusi, mis tõestavad, et ilma hea lugemisoskuseta on noorel paremad hinded, parem sissetulek ja ka parem vaimne tervis. Kõige parem lahendus sellisele probleemile ongi sisestada neile, et see on neile kasulik. Kuna harjumus algab üldiselt iseendast tuleks see noortele esimese asjana selgeks teha. Eesmärgiks võiks neil olla, et nad treenivad ennast ning harjutavad endale parema tuleviku nimel. Seega Eesti ühiskonnas on probleemiks see, et paljudel noortel üldse puudub lugemisharjumus. Selle tagajärg ühiskonnale on, et tulevikus ei pruugi mõista nad bürokraatlikke tekste, mis on näiteks nende töökohale olulised. Lahenduseks on neile sisestada idee, et see on nende enda heaolu nimel, sest harjumus algab iseendast.\nLugemisharjumused on noortel erinevad, kuid kõige populaarsemateks osutuvad nende puudumine või inglise keelse kirjdanduse eelistamine. Need preagu küll suurt rolli ühiskonnas ei mängi, aga tulevikus võib olla neil karm tagajärg. Õnneks on olemas lahendusi sellisele probleemile, mis võivad päästa meie ühiskonna noorte lugemisharjumuste jagajärgedest.\nTeine variant');
