INSERT INTO core.text(id, content)
VALUES ('a5ac7fe7-d6d3-47be-8f6f-90d1c2723f0f',
        'Tänapäeva Eesti ühiskonnas on noorte lugemisharjumused võrreldes varasemaga kiirenevas allakäigutrendis. Kirjandus on küll laialdaselt kättesaadav nii paberkujul kui ka internetis, kuid siiski ei leia noored sellest enam samasugust meelelahutust kui varem. Raamatute lugemisel on aga palju olulisi lisaväärtusi, mis ei arenda inimest mitte ainult keeleliselt, vaid vormivad ka mõttemaailma ja aitavad ümbritsevat maailma paremini mõista. Lisaks kaugenevad noored järjest enam emakeelsest kirjandusest. Kuidas mõjutavad noorte lugemisharjumused Eesti ühiskonna tulevikku?\nNoorte lugemuse vähenemine raskendab neil ühiskonnas orienteerumist ning hakkama saamist. Selleks, et maailma paremini mõista on igapäevaelus tihti vajalik kasutada funktsionaalset lugemisoskust. Noortel, kes seda oskust ei treeni,  on üha enam raskusi keerukatest tekstidest aru saamisega ning nende tõlgendamisega. Näiteks kirjutatakse Eesti Vabariigi seadused rohkeid juriidilisi termineid sisaldavas bürokraatilises keeles, millest arusaamiseks on vaja süveneda ja vaeva näha. Paljud täiskasvanud inimesed, rääkimata noortest, ei valda seda keelt ning see tekitab lõhe Eesti riigi kodanike ja juhtorganite vahel. Sellest saab järeldada, et ilma funktsionaalse lugemisoskuse arendamiseta on noortel raske riigi teadaandeid ja suunitlusi mõista ja enda jaoks tõlgendada. Selline konflikt võib tulevikus viia noorte ja riigi üksteisest kaugenemiseni.\nVõõrkeelsete raamatute lugemine vähendab noorte võimet väljendada end emakeeles. Tänapäeval on noorte põhilisteks lugemisallikateks internetis laialdaselt levivad inglise keelsed teosed, mille peamine eesmärk on tekitada naudingut. Neid raamatuid lugedes ei pea noored eriti mõtlema ega juurdlema lausete või sõnade tähenduse üle, sest sõnavara on niivõrd lihtsustatud. Näiteks levib sotsiaalmeedia rakenduses TikTok selline liikumine nagu BookTok, mille vahendusel tutvustatakse uusi peamiselt romantika – ja fantaasiateemalisi raamatuid ning meelitatakse noori neid ostma. Kuna rakenduses toimub arutelu inglise keeles, eelistavad noored võõrkeelset raamatut eesti keelsele tõlkele ja integreerivad teoses kasutatud fraase oma sõnavarasse. Sellest saab järeldada, et võõrkeelsete teoste lugemuse kasv noorte seas võib tulevikus kaasa tuua emakeelse kirjanduse hääbumise ja eesti keele arengu pidurdumise.\nNoortel pole enam harjumust vabal ajal lugeda ja see pärsib nii individuaalset kui ka ühiskondlikku arengut. Tänapäeval antakse kodudes lastele juba varajases eas kätte raamatu asemel nutitelefon. Sellisel viisil on lugemisharjumuse kujunemine keeruline, kuid koolis on raamatute lugemine kohustuslik ja see toobki kaasa nn käsu peale lugemise. Näiteks on Soomlased pakkunud, et neil on käsu peale lugejaid umbes pool 9. klassi õpilastest. Noortel ei teki motivatsiooni ise enda lugemust suurendada ja koolitööle lisaks enda teadmisi ka kodus täiendada. Sellest saab järeldada, et vabal ajal lugemise harjumuse puudumine võib põhjustada tulevikus Eesti ühiskonna üldise intelligentsustaseme languse. \nNoorte lugemisharjumuse muutused on paratamatud ja käivad ajaga kaasas, kuid neil on siiski suur mõju ühiskonna tulevikule. Et kindlustada emakeele püsimine ja ühiskonna areng, on vajalik suunata tähelepanu eelkõige noortele ning propageerida nende seas raamatute lugemist. Sellisel viisil areneb eesti keel koos inimestega edasi ja Eesti riik on tulevikus heades kätes. \n\n\n\n\n\nTees: \nSelgitus:');
