INSERT INTO core.text(id, content)
VALUES ('4d45bcfc-84ec-45a1-b50a-3ee5c6a985f8',
        'Tänapäeval on väga menukaks ametiks kujunenud suunamudimine. See on lihtne elatusviis, kus peamine töö on teha sotsiaalmeediasse postitusi. Samas on vaja koguaeg olla oma ideedega innovatiivne, et jälgijaskonda säilitada.\nNoored näevad suunamudijaid eeskujudena. Sisulooja töö on teha põnevat loomingut, mida oleks jälgijatel huvitav vaadata ning millega neil oleks lihtne samastuda. Samuti suunavad nad oma loodut erinevatele sihtgruppidele, näiteks Ameerika Ühendriikide nooruk Sam Sulek teeb peamiselt videosid jõutõstja elustiili kohta. Tihtipeale võib tema kommentaarides näha teisi noori, kes tänavad netikuulsust inspiratsooni eest trenni teha. Samuti liigub erinevatel sotsiaalmeedia platvormidel blogijaid, kes räägivad niisama oma igapäevaelust: mis nad päeva jooksul teevad, mis tooteid nad kasutavad, kellega nad suhtlevad. On ka kindlaks tehtud, et sotsiaalmeediakuulsustel on mõju inimeste tervisega seotud valikutes ning ka poliitküsimustes ja maailmavaadete kujunemisel. Seega, on influencer`itel mõju tänapäeva noorte üle.\nSisuloojate reklaamitud toodete ostmist tuleks põhjalikult läbi mõelda. Suunamudijate peamine sissetuleku allikas on erinevad tehingud firmade ja brändidega. Influencer`i töö on teha tootest video või postitus seda kiites ning selle eest saab ta raha. Kahjuks ei saa kunagi kindlaks teha, kas sisulooja seda toodet päriselt ise ka kasutab. Seda juhtub palju jumestajate kogukonnas, kus tehakse video, mis reklaamib mõnda meigitoodet. Hiljem aga ütleb sama suunamudija, et tegelikult kaup ei meeldinud. Samuti turundatakse erinevaid ravimeid või operatsioone enda muutmiseks. Viimasel ajal pildis olnud ravim on Ozempic, mis on kaalulangetuse kiirendaja. Kristina Pärtelpoeg räägib tihti oma sotsiaalmeedias, kuidas ta on käinud mitmel erioperatsioonil nagu rinnasuurendus ja rasvaimu. Alati ei pruugi need operatsioonid või ravimid olla tervisele head, aga otsus tehakse mõtlematult. Seetõttu tuleks iga reklamitud toode või ost läbi mõelda.\nSisuloojad suunavad oma jälgijaid ka heategevusele. Eesti ühed kuulsaimad sisuloojad korraldavad kampaaniat, mis innustab inimesi karusnahka mitte soetama. Selle kampaania eestvedaja on Hanna Martinson, kes arvab, et noored hoolivad loomadest ja maailmast, mistõttu on see suunatud neile. Samal probleemil maailmatasandil tegutseb organisatsioon Fur Free Retailer. Sellega liitunud moeketid ei kasuta oma toodetes karusnahka. Samuti reklaamivad suunamudijad ka teisi organisatsioone, näiteks abiorganisatsioonid ukrainlastele ning seal toimuvale sõjale, Eesti Vähihaigete Laste fondi ning Toidupanka. Selliseid reklaame tehes saab jälgijaid suunata abivajajaid aitama ning seetõttu nende elu kergendada. \nSeega on suunamudijad noortele eeskujuks nii üksikisku tasandil, aga ka ühiskondlikus pildis. Nad aitavad esile tuua tooteid ning ideid, mille peale kõik ei pruugi tulla. Samas tuleb ka reklaamitud toodetes olla kriitiline, sest internetis on raske mõista, kas keegi on päriselt siiras või on see näitemäng. Igal tööl on oma hea ja halb pool, mistõttu tuleb sisuloojaid kuulates säilitada kaine mõistus ning teha kaalutletud otsuseid.');
