INSERT INTO core.text(id, content)
VALUES ('84a901a8-cc5a-488e-8cff-aace5351ae8d',
        'Käes olev aasta on meil kirjandus aasta, kus püstitame üles küsimusi, kas noored loevad piisavalt. Võib välja tuua, kuidas vanem põlvkond paneb tähele, kuidas noored loevad vähe ja eriti just eesti kirjanduse klassikuid. Kardetakse noorte vähese lugemisharjumustega võib kaduda lugemis oskus täielikult. Meediaga oleme suutnud noorte lugemisharjumustest tekitada suure probleemi, mis ausalt öeldes ei ole nii suur ega oluline probleem millele peaksime keskenduma.\nVanem põlvkond on arvamusel, et noored eelistavad lugeda inglise keelset kirjandust, mille tagajärel kaob eesti keel ära. Vale on väita noored ei loe, kuna leidub noori, kes loevad ja samuti loovad ka ise oma lugusi. Tauno Vahter on öelnud, et vanaunumesed hädaldavad noorsoo ja aegade muutumise üle, kuna nende ajal oli kõik teistmoodi. Vanematel inimestel ei olnud nutiseadmeid, millega vaba aega seostada, kuid nemad samuti käisid parema meelega õues mängimas teiste lastega, kui olla kodus nina raamatus. Seega ma usun raamatute lugemiseharjumused on olnud mõlemal põlvkonnal sarnased. Kindlasi nende ajal oli noori, kes lugesi hea meelega raamatuid hommikust õhtusse, kuid alati leidi parem ja lõbusam lahendus, kuidas oma vaba aega veeta. \nTänapäeval me ei saa elada ilma, et oskaks lugeda. Ülesande tekstist kuni erinevate lepingute läbi lugemine sõltub funktsionaalsest lugemisoskusest. Ja seda oskust on võimalik omandada erinevatel viisidel. Üks võimalustest on erinevate raamatute lugemine. Kuid samuti arendab noor oma funktsionaalset lugemist läbi erinevate tekstide info otsimist. Tiit Hennoste oma arvamusloos tõi välja, et kui kasvab inimeste hulk, kelle lugemisoskused muutuvad kehvemaks, ei suudaks nad enam ühiskonnas hakkama saada. Võib olla peaks vaatama noorte lugemisharjumuste probleemi teisest nurgast. Kas on oht, et tulevased põlvkonnad ei suuda lugeda läbi tekste, millele allakirjutavad? Kui noorte lugemisoskus on halb ei suudaks nad lugeda läbi keerukaid tekste ja raamatuid, mille tekstid nõuavad kaasa mõtlemist. \nKas siis noorte üle viriseda, et nad ei loe piisavalt ja sundida neid lugema parandaks midagi? Olen suurelt kindel see teeks asja hullemaks ning muudaks probleemi päriseks. Tuleb mõista noor on ka inimene, kellel on omad mõtted ja soovid. Selle asemel, et neid karistada või neid maha teha tuleks hoopis ise muuta enda lähenemist. Üks häid näiteid on laste riidesse panek. Selle asemel, et hommikul lapsega kakelda riietamise üle ning rikkuda selle käigus oma tuju ja lapse võiks proovida õhtul lapsega riided enne välja valida. Sama saaks teha ka lugemisega näiteks nii vanem kui ka noor võtavad selle aja, et lugeda koos raamatud. Samuti ei tohiks teha noort maha, et loeb inglise keelset teost kuna lihtsaks põhjuseks võib olla see, et seda raamatud, mida noor lugeda tahaks ei ole tõlgitud eesti keelde või eesti keelne tõlge ei ole kõige parem.\nOlen arvamusel, et ei tasu teha suurt probleemi ega kurta noorte lugemisharjumuse üle. Ei tasu karta, et eesti keel võõrkeelse kirjanduse kõrvalt ära peaks kaduma, vaid hoopis vastupidi. Võõrkeelne kirjandus rikastab ning arendab eesti keelt. Parem tuleks tegeleda nende probleemidega, mis on tõeliselt olulisemad ning vajad meie tähelepanu.');
