INSERT INTO core.text(id, content)
VALUES ('d081d8fd-497e-422b-9585-47b6b9fd121e',
        'Internetile on ligipääs igal ajal ja kohas peaaegu üle kogu maailma. Selle tulemusena jälgime veebi teel populaarseid inimesi, nende nõuandeid, soovitusi ja elusitiili. See mida näeme, mõjutab vältimatult igapäevaelu harjumusi ja otsuseid, sest paratamatult seovad nad toetajaid maailmaga, mida nad ei tea ja millega saavad samastuda.\nSuurema pooldajaskonnaga sisulooja on võimeline suunama otsuseid. Nähes nutiseadmes, mida juutuuber parasjagu arvab millestki, hakkab meile paistma, et on ebanormaalne minegid toiminguid teha, kuigi see tegelikult nii ei ole. Märkame, kuidas suunamudijad reklaamivad teatud dieeti, eset või sööki, näib, et just see ongi õige, sest tal on ju suur fännibaas, mis ei teki lihtsalt iseenesest. Digi-arvamusliider tundub meile sõbrana, kuna ta meeldib paljudele. Maria Murumaa Mengel on oma artiklis väitnud, et „juba 1956. aastast pärit parasotsiaalsete suhete teooria kohaselt tekib meedia vahendusel inimestel illusioon, et meediastaar on nende lähedane tuttav, keda tasub kuulata“. Nõnda ilmneb liigne usaldus võhivõõra netikuulsuse vastu. Nende arvamus kujundam meie oma ja asume jälgima dieeti ja kasutama brändide kalleid tooteid, kuigi tegelikult selline elustiil meile ei meeldi. Seepärast tuleks hoolega mõelda, kas võtta ühe inimese eeldusi tõsiselt, lähtuda tuleks rohkem enda seisukohtadest ja jääda iseendaks, sest nõnda kujneb värvikate persoonidega inimkond. \nInfluencer´id on tavaliselt täiesti tüüpilised kodanikud nagu meiegi, mitte professorid ja arstid, neile lihtsalt meeldib oma elu jagada ning seeläbi raha teenida. Turundades erinevaid tooteid oma platvormil, maksavad reklaami tellijad neile päris kopsakaid summasid. Kahjuks peabki tõdema, et piisavalt suure rahasumma eest ollakse nõus esitlema tooteid, mida nad ise kunagi ei kasutaks. Kristjan Kikerpill, Tartu Ülikooli ühiskonnateaduste lektor, on öelnud: „Sõnavabadus on vaba ja arvamuse avaldamine ei ole keelatud, kuid kui mängu tulevad varjatud hüved, siis tuleks olla eriti ettevaatli.“ Pöörata tuleks kriitiliselt tähelepanu, mida trendiloojad üritavad maha müüa, sest nad ei ole arstid, kes on teadlikud, kuidas tooted päriselt mõjuvad. Seetõttu peame tegema faktikontrolli, kas antud ese vastab reklaamis lubatule või mitte. Nõnda väldime pettust, pettumust ja liigseid mõttetuid väljaminekuid.\nTuntud nime kaasamine ürituse reklaamimisel viib selleni, et tarbija pöörab sündmusele rohkem tähelepanu, sest sisulooja tekitab neis usaldustunnet. Uritakse aktsiooni kohta, mida varem poleks teiste sarnaste ettevõtmiste vahel märganud. Hea Kodaniku poolt avaldatud uudises „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“ selgub, et vastava liikumise käigus on kogutud juba 54 000 allkirja, mis on suur number, kuid kui sellises projekts poleks kaasa löönud digi-arvamusliidrid, poleks informatsioon nii paljude inimesteni jõudnud ning kogutud allkirjade arv oleks palju väiksem. Seetõttu, kui on vaja reklaamida olilisemat ettevõtmist või juhtida tähelepanu ühiskonnaprobleemile, aitaks sellele kaasa mõne blogija veenmine projektis osalema.\nÜhiskonnas on paratamatult nii, et mõned kodanikud omavad suuremat võimu kui teised ning seeläbi suudavad veenda enda arvamuses ja heakspidamistes nende pooldajaid. Tuleb olla kriitiline ja valida hoolikalt kõike, mida nad soovitavad, sest olgugi, et nad tunduvad meile kui lähedased, on nad tegelikult võhivõõrad ja kasuteenimise eesmärgil võivad välja pakkuda mõne mure lahendamiseks kaheldavaid esemeid.');
