INSERT INTO core.text(id, content)
VALUES ('2b0567af-52f3-42ed-b517-e8f330ed6536',
        'Tänapäeva ühiskonnas on väga suur osa suunamudijatel ja influenceritel, sest nende elustiili ja valikute järgi teevad nende vaatajad otsuseid. Eriti mõjutatav grupp on noored, kes vaatavad enda iidoleid ja ei saa veel aru, kuidas need samad sisuloojad muudavad noorte elu. Siiski jääb küsimus, kuidas suunavad sisuloojad enda jälgijaid?\nMõjuisikute positiivne suunamine on harv nähtus, sest pigem reklaamitakse raha ja uute võimaluste pärast, mitte põhjusel, et toode on siiralt hea. Üheks ühiskonnale kasulikuks suunajaks on juutuuber nimega Tavakodanikust Naine, kelle videod räägivad peamiselt Eesti meedias räägitavatest teemadest juriidilises võtmes. Selliste videote taustal hakkavad noored rohkem huvi tundma õiguste, seaduste ning ka Eestis toimuva kohta. Kuna videote koostaja on juurat õppinud on tal baasi, kus oma teadmised ammutada ning seletada teistele eestlastele keeruliste seaduste sisu ilma kanseliiti mõistmata. Sellist isikut, kes teeb oma sisu just selle nimel, et teisi harida ilma reklaami tegemata, on erakordne, mis muudab ta vaadatavaks ning aitab kinnitada reeglit.\nJägijate suunamiseks saab kasutada heategevust, sellega on noored ja ka jõukamad täiskasvanud nõus aitama, et muuta elukeskkond paremaks. Heategevuse alla võib minna, kas vähiravifondi tutvustamine või karusnahafarmide keelustamine. Viimase puhul tehti Eestis väga palju tööd, et selline tegevus lõpetada. Üheks reklaamnäoks oli Hanna Martinson, kes on varasemast tuntud, kui glamuurne ning väga särtsakas sisulooja, ta on ka tahes- tahtmata kandnud suuri kasukaid. Vaatamata eelnevatele tegudele oli Martinson organisatsiooni Loomus eestvedaja ja rääkis teemast väga südamlikult ja usutavalt märgib Hea Kodanik 2019.aastal uudises „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“. Ta suutis teiste toodete propageerimisega ning teadmiste levitamisega saada toetusi tuhandelt inimeselt. Sellise heategevus tööga suudavad influencerid muuta maailma ja suunata noori paremate valikute ning helgema tuleviku poole.\nInimeste tähelepanu saamiseks ja sellega kaaasnevalt nende suunamisel on abiks sisuloojatel näiteks eksulusiivsus, sest selliseid tooted, teenuseid ja elu ei suuda tavainimene elada. Sellist võtet, mis pärineb Crystal Abidini uurimustest, kasutab näiteks Brigite Susanne Hunt, kelle kuulsus algas draamadest, kuid nüüd on tegemist juuratudengi, sisulooja ja bikinifitnessiga tegelajaga. Tänu enda iganädalastele iluprotseduuridele ja dieetidele ei suuda tavakodanik temaga enam samastuda, mis muudabki ta ainulaadseks ning vaatajal tekib tunne, et teda peab kuulama. Sellise võtte kasutamine ei ole kesk- ja alamklassile aus, sest nemad ei saa aru, et naine saab selle kõige pealt raha ja kuulsust juurde.\nSotsiaalmeedia ja seal tegutsevad sisuloojad võivad olla ausad ja propageerivad aiunult neid tooteid, millesse nad ise usuvad kuid mõned teevad seda raha ja rikkuse pärast. Noori saab suunata tarbeid, teenuseid ostma või igapäeva otsuseid tegema mõjutuste, motiveerimise või teadmiste teel, olenemata, kas need välenduvad hiljem positiivselt või negatiivselt.');
