INSERT INTO core.text(id, content)
VALUES ('50db32c5-5dda-4ab8-b65a-a7e85de37b01',
        'Enne kui internet igaühele kättesaadav oli, soovisid lapsed olla ikka astronaudid, politseid või tuletõrjujad. Tänapäeval aga tahavad enamus noored saada just suunamudijateks, keda nad tänu internetile idoliseerivad, mistõttu ka noorus usaldab neid. Tekib küsimus, kui palju siis suunamudijad mõjutavad noorust ja kuidas?\nNoored, kes on vähese elukogemusega ei ole endale veel maailmast mingit terviklikku pilti loonud. Niisiis proovitakse seda kokkupanna internetis, kus on tihti enesekasupüüdlikud influencerid, kes proovivad maha parseldada erinvevaid produkte . \nKes tahavad olla trendikad ja ajaga kaasas käija, pöörduvad netikuulsuste poole, et leida milline telefon osta, mis riietus on moes ja palju muud, ning sisuloojad saavad tihtipeale raha toodete esiletõstmise ja soovitamise eest oma videotes.\nBrigitte Susanne Hunt soovitas oma videotes kõigile brändi Samsung ja kui hea see on, aga sarjas mis rääkis ta enda elust oli tal alati kasutuses teise brändi telefon.Probleem seisneb selles, et need trendiloojad ei soovita seda toodet kuna see on hea, vaid seetõttu, et raha sisse voolaks.\nRaske on arusaada, kas produkt on tõesti hea või seda räägitakse paremaks, et raha saada, seetõttu tulebki teha faktikontroll enne ostmist.\nNoored pidevalt võrdlevad ennast teistega ja proovivad sisse sulanduda, ning see on täiesti normaalne, mis aga ei ole normaalne on need ilustandardid mis neile ettepannakse\ninternetiavarustes on mehed, kelle kõhulihased näevad välja nagu ehitusklotsid ja nende biitsepsid on neist vaesetest puberteedi eelsestest poistest neli korda suuremad. Neil samul influiencerittel  veel jultumust öelda neile noortele, et nad ostaksid nende vitamiine või mõnda muud produkti ja küll nad varsti näevad välja nagu tema. Kunagi ole juutuubi kanal Liver King, kes soovitas kõigil süüa toorest liha ja osta tema produkte, et olla lihases. Hiljem tuli sellel teemal skandaal, kuna tuli välja, et ta oli lihtsalt tarbinud suurtes kogustes testosterooni.\nTüdrukutega samamoodi koguaeg soovitavad erinevad suunamudijad erinevaid kaalulangetus tablette, mis paneb noored arvama, et kõhn olemine on normaalsus.Saja aasta eest ei usuks keegi, et on inimesi kes vabatahtlikult näljutavad endeid, aga nüüd on haiguseid nagu anoreksia, boliimia ja taolisi rohkem kui kunagi varem.\nÕnneks on siiski ka mikrokuulsusi, kes kasutavad oma kuulsust ära, et teha head.\nNäiteks kaks tuhat kakskümmend kolm osalesid kampaanias karusnahkade kasutamise vaste seitse eesti kuulsat netikuulsust. Nimelt oli kampaania, mis oli suunatud just noortele tarbijatele, et tõsta teadlikkust karusloomafarmide tumedamatest külgedest.\nSuunamudijad on omal moel noortele nagu lisa vanemad, nad õpetavad neile erinevaid asju, võibolla lohutavad neid rääkides oma kogemustest ja palju muud. Seetõttu on suunamudijatel suur mõju noorusele.\nSelleasemel, et noortel interneti kasutus ära keelata, tuleks neid harida ohtude osas.');
