INSERT INTO core.text(id, content)
VALUES ('721fd424-24eb-4dfe-9fc2-2be8f05cc5ec',
        'Maailma pidev areng muudab mitmekesisemaks kõikvõimalikud tegevusvaldkonnad. 20. sajand ja 21. sajand on väga erinevad inimese elustiili ning harjumuste poolest. Kõik muutub ja nii on ka muutunud nutiajastu noorte lugemisharjumused. Kuidas täpselt mõjutab vabatahtliku huvi puudumine lugemise vastu noorte funktsionaalse lugemise oskust?\nNoorte lugemisharjumus on viimase sajandi jooksul märgatavalt muutunud. Varasemalt üks peamine vabaaja meelelahutus, lugemine, on pidevalt areneva maailma kõrval jäänud noorte seas üha enam vähepopulaarsemaks valikuks. Aastaid tagasi ei olnud kättesaadaval väga palju teisi vabaajaveetmise võimalusi, mida oleks saanud üksi läbi viia, peale lugemise. Kui kunagi valiti raamatu žanrite vahel, siis tänu pidevale arengule on juurde loodud tohutult palju meelelahutusvorme, millest iga inimene saab valida just endale sobiva ja vähesed valivad selleks tegevuseks lugemise. Tiit Hennoste on oma arvamusloos kirjutanud, et soomlaste üheksanda klassi õppuritest on vabatahtlikud lugejad vaid pool klassi õpilastest. Maailma kiire areng, eriti tehnoloogia areng, toob endaga kaasa märgatavaid muudatusi inimeste käitumisharjumustes. Üheks näiteks saab tuua noorte lugemisharjumuse languse tänu nutiajastu lihtsasti tarbitavatele meelelahutusvormidele.\nLugemisharjumuse langus ja ainult kohustuslikus korras lugemine vastu noorte vabat tahet pärsib nende funktsionaalset lugemisoskust. Noored on harjunud 21. sajandi kiire elustiiliga ja seepärast ei ole harjunud võtma aega, et lugeda rahulikult raamatut, samal ajal olla mõttega kohal ja keskenduda teose sisule. Raamatuid loeb enamik noori koolis, ainult kohustuslikus korras ja seda selleks, et tunnistusele läheks kirja positiivne hinne. Selline kiire elustiis sunnib kõik tekstid kiiruga läbi lugema ja mõttega kohaolu teoses on vähe. Kõigel on oma tagajärg. Minimaalne lugemine ei arenda noore funktsionaalse lugemise oskust, mis tähendab, et tekstist täpselt arusaamine muutub raskemaks. Selline oskus on eluks vajalik, eriti praegu, kui kõik kokkulepped, nagu laenud või liisingud, on paberil kirjas keerulises sõnastuses, mille mittemõistmine võib kaasa tuua suuremaid riske. Tiit Hennoste viitas oma arvamusloo artiklis uuringutele, mis näitavad, et kui lapsel on hea lugemisoskus ja loeb vabatahtlikult ka vabal ajal, on ta hinded, karjäär ja sissetulek paremad, kui nendel lastel, kes vabal ajal ei loe. Funktsionaalne lugemisoskus, mis omandatakse vaid hea lugemisharjumuse teel, on hea elu alus ja annab eelise elada kvaliteetsemat ning riskivabamat elu. \nNutiajastu noorte harjumus lugeda väheneb kiiresti. Lugemise asemel eelistavad noored tarbida kiiresti kättesaadavat infot rohkem kui mõttega raamatut lugeda. Selline tegevus ei arenda funktsionaalset lugemisoskust ja edaspidi võivad infotekstid lugejale arusaamatuks jääda. Noore tulevikus on see oskus aga tähtsal kohal, sest olulised lepingud on kirjutatud keeruliselt ning kui nendest aru ei saa, võivad tagajärjed olla riskantsed.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('721fd424-24eb-4dfe-9fc2-2be8f05cc5ec', 'title', 'Noorte lugemisharjumus ja tagajärjed');
