INSERT INTO core.text(id, content)
VALUES ('b1635287-7702-4fae-8016-7259fadc77ca',
        'Meie uudses digimaailas jääb kõlama väide, et noorukid üha rohkem seostavad oma elu digiseadmetega, mis on tänapäeval kõige suurem probleem meie ühiskonnale. Lapsed elavad virtuaalmaailmas ning raamatute lugemine on saanud neile kohustuseks. Selline käitumine meie järgmisel põlvkonnal on ohtlik ning sellel on oma halbu tagajärgi.\nEesti teismelistest on saanud inglise keelne lugeja.  Noorukite mõtlemine on täiesti üle viidud inglise keelde, nemad mõtlevad, räägivad ning loevad inglise keeles. Milles siiski seisneb probleem? Probleem on selles, et Eesti on väiksema rahvaarvuga riik. Suurem osa filmidest, raamatutest ei ole lihtsalt tõlgitud eesti keelde, lastel ei ole muud võimalust enesearendamiseks. Tauno Vahteri sõnul teismeliste hulgast loevad enamasti tüdrukud ning sellistes platvormides nagu TikTok ja Instagram, kus on väga vähe eesti keelse kontenti olemas. Probleem on sügavamal, kui esmapilgul võiks tunduda. See seisneb mitte ainult teismeliste väärtushinnagutest, vaid ka võimalustest, mis Eesti tänapäeva ühiskonnal olemas. \nEelmise aasta riigieksamite tulemusi vaadates võib aru saada, et suurem osa Eesti teismelistest ei oska ennast sulliselt ega kirjalikult väljendada. Tiit Hennoste oma arvamusloos ütles: „Funktsionaalne lugemisoskus on põhiline tänapäeva maailmas elamise eeldus ja alus.“ On tehtud palju uuringuid, kus selgub, et laste parimad tulemused koolis on tingitud ka tema vabaaja veetmisest ning lugemisoskusest. Kõige rohkem on seda näha Ida-Virumaal, kus eesti keele teise keelena õppijad tihti ütlevad, et ei oska ennast väljendada isegi omas ehk vene keeles. Selline olukord ei ole tingitud ainult õppija eesti keele oskusest ning omandamisest, vaid ka tema lugemisharjumustest. Mida rohkem inimene loeb, seda lihtsam on tal elus edaspidi osata ennast väljendada nii suuliselt kui ka kirjalikult. Tulevikus see võib tuua Eesti ühiskonnale suuri probleeme, sest sellised inimesed ei suuda täiskasvanuna maailmas hakkama saada.\nEesti noorte seast on saamas digi-zombid.  Tänapäeval on kõikidel, isegi täiskasvanu inimestel alati telefon kaasas, alati pöial on peal. See probleem on tekkinud juba ammu, aga tänaseks on see ületanud ome piire. Eesti, nagu teada, on üks suurimaid digiriike, kus kõik töö, õppimine ning vaba aeg käib nutiseadme kaudu. Tiit Hennoste arvamusel on praegune ühiskond – kiirühiskond, kus valitseb ainult kiirus. Lugemisega nii olla ei saa, see on aeglane tegevus, mis nõuab püüdlikkust. Lapsed peaksid oskama ennast välja lülitada vähemalt tunniks ja näha ilu enda ümber, mitte ainult digimaailmas.\nMeie infoühiskonna suurim probleem on nutisõltuvus. Kõigepealt see algab täisealistest, kes on pika aja vältel näidanud oma lastele just selliseid väärtushinnanguid. Selleks, et kõik see peatuks me peaks alustama kõigepealt iseendast ning mõelda oma väärtuste peale, mida meie näitame ja transleerime järgmisele põlvkonnale.');
