INSERT INTO core.text(id, content)
VALUES ('e9f970b2-e197-43c3-9ae3-d2f1ece16097',
        'Lugemisharjumused aina vähenevad, kuigi seda ei saa öelda ainult tänapäevaseks probleemiks. Need on juba aastakümneid langenud.\nTänapäevane lugemisharjumuste puudus on nutitelefonite süü. Noored loevad raamatuid tänapäeval aina vähem ja vähem, paljud ei loe väljaspool kohustusliku kirjandust midagi ja paljud ei loe kohustusliku kirjandust isegi. Raamatud on paljude meelest igavad, seda sellepärast, et nutitelefonid on ära rikkunud paljude ajud. On raske leida kedagi kelle telefon ei oleks osa nende igapäevasest elust. Me veedame aina rohkem aega nina kinni oma telefonides ja mida rohkem aega möödub siis seda rohkem leiavad firmad viise hoida meid seal. Viimaste aastate jooksul, pärast TikToki platsile saabumist on aina rohkemates sotsiaalmeediates leida Tiktoki stiilis lühivideoid. Meie ajud on nii ära harjunud selle kohese dopamiini laksuga mida telefonist leida saab, et paljudele on lugemini ka raske, sest nad ei suuda oma tähelepanu ühes kohas piisavalt kaua hoida. Seda kohest dopamiini laksu on leida ka mujal, Tiit Hennoste on öelnud seoses tänapäevase lugemisharjumustega et inimesed on pidevalt oma telefonides kinni, isegi tänaval kõndides ja et me oleme hakkanud elama kiirmaailmas, meil on kiirtoit, kiirkeel, kiirlugemine jne. See kiirmaailm teeb juba praegu probleemiks olevat tähelepanu puudust ainult hullemaks. Inimesed ei pea keskendume isegi toidu tegemisele enam, sa saad sama hästi oma telefonist tellida toitu. Tähelepanu puudus on tänapäeval asi millega paljud kokku puutuvad igapäevaselt.\nLugemisharjumuste puuduse tagajärjed on jubedad. Kui inimestel puudub lugemisoskus, on neil palju raskem uudiseid mõista. Uudiseid peaks iga inimene ise lugema ja ka mitmest allikast, sest valeinfo maailmas ei saa ainult ühte allikat usaldada. Kui inimesed ei oska ise uurida uudiseid järgi, ei tea nad ka mis maailmas toimub, nii et neid oleks väga lihtne mõne riigi poolt kontrollida ja neile propogandat sööta. Veel toob lugemise allakäik kaasa langevaid koolihindeid, mis küll ei ole iseenesest intelligentsi näitaja mingil viisil, aga näitab inimeste töövõimekust. Tiit Hennoste on väitnud et lugemisoskus ja vabal ajal lugemine on uuringute põhjal näidatud andma paremaid hindeid, paremat haridust, paremat sissetulekut ja paremat vaimset tervist.\nInimeste lugemisharjumused halvenevad ja lugemise populaarsus aina langeb, see on mitmekesine probleem, kuid selle üheks mõjukaks põhjuseks võib määrata nutitelefonite ja kiirmaailma tõusu. Lugemisharjumuste langusega kaasneb väga palju ühiskondliku probleeme, on selge et midagi paeb tegema et parandada tänapäeva noorte lugemisharjumusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
