INSERT INTO core.text(id, content)
VALUES ('fb7308ce-5780-4748-97e2-754dddec7b92',
        'Üha suurem on sotsiaalmeedia ja seal tegutsevate suunamudijate roll ühiskonnas. Leidub väheseid inimesi, kes igapäevaselt ei külastaks erinevaid veebisaite, olgu see siis seotud tööga või niismama meelelahutusega. Teadmised, faktid või hoopis valed, mida nad sotsiaalmeediaplatvormidel propageerivad ja jagavad, mõjutavad inimeste otsuseid, valikuid ning igapäevaelu.\nKuna suunamudijad teevad tihti koostööd erinevate firmadega ja jagavad sellest postitusi enda sotsiaalmeediakanalil, siis mõjutavad nad inimesi ostma kindla firma tooteid või teenuseid. Tihti ei suuda noored ise otsustada, kas mingi asja soetamine on hea idee, seega tahavad nad teada arvamust nende meelest usaldusväärseltelt inimestelt ning pöörduvad sotsiaalmeedia poole. Kindlasti ei uslada nad kõiki, nad leiavad influencer´id, kes tunduvad nende meelest usaldusväärsed, ausad ning sarnase mõttemaailmaga nagu nad ise. Katkendis, mis on kokku pandud Maria Murumaa Mengeli ja Juhan Hllermaa artiklitest on välja toodud, et on läbi viidud uuring, kust on selgunud, et väga tihti saavad noored nõu just sotsiaalmeediast, näitkes mida pidada normaalseks, mida pidada ebanormaalseks ja mida ihaldada. Suunamudijad aitavad tavalistel noortel teha valikuid, millega nad ise hakkama ei saa või ei proovigi saada.\nNetikuulsuste vaba arvamuse või vale informatsiooni avaldamine sotsiaalmeedias võib viia noortevahelise konfliktini. Kuna suunamudijad ei räägi alati faktipõhiselt või avaldavad arvamust, mis kõigile ei pruugi meeldida, võib see tekitada sotsiaalmeedia platvormidel sõnavõtte ning võib lõppeda veebikiusamise ja halvemal juhul ka veebisisese vägivallaga. Tartu Ülikooli ühiskonnateaduste lektor Kristjan Kikerpill on oma uurimistöös öelnud: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid “kuulajatele meeldib“, siis see on probleem. Halvemal juhul võib selle tulemusel kuskil suuremaks kakluseks ja rüüstamiseks minna.“ Suunamudijad peaksid rohkem jälgima, mida oma vaatajaskonnale räägivad ning kuidas enda loomesisu teistega jagavad.\nAvaliku elu tegelastel on võim kallutada noori rohkem hoolima neid ümbritsevast keskkonnast, suunates noortele erinevaid kampaaniaid ja üleskutseid. Hanna Martinson algatas Eestis kampaania #loomadesilmis, et tõsta nii noorte kui ka vanade inimeste teadlikkust karusloomafarmide kulissidetagusest elust. Projekti on kaasatud nii näitlejad, muusikud, kirjanikud, ajakirjanikud, arstid kui ka moekunstnikud ja zooloogid. Rahvusvaheliseks kujunenud petitsioon on kogunud juba 54 000 allkirja. Kuulsustel, kellest inimesed lugu peavad, on soodsad võimalused muuta ühiskonda paremaks, sest nad saavad kaasata projektidesse noori, kes neid jälgivad, ja seega saavad nad aidata muuta paremaks meid ümbritseva õhkkonna.\nSuunamudijate tähtsus meie elus väiksemaks ei muutu, aga me saame ise valida, kui suurel määral end sellest mõjutada laseme. Tuleb kriitiliselt hinnata, milline informatsioon tundub adekvaatne ning milline tuleks kohe enda mälust pühkida. Kindlasti ei tähenda see seda, et peaksime üdini skeptilised olema, internetis leidub palju teadmiseid, millest päriselt ka kasu on.');
