INSERT INTO core.text(id, content)
VALUES ('de585bac-e635-49fe-a9fc-90d968a1b754',
        'Tänapäeval on intellektuaalide seas populaarne jututeema noorte vähene lugemisharjumus. On toodud välja palju mõtteid selle põhjuste osas, aga kust see siis ikkagi alguse sai, mis on selle tagajärjed ja kuidas on see seotud üha suureneva inglise keele kasutusega? \nViimastel aastatel on noored hakanud üha vähem lugema. Vanemate inimestega vesteldes võib pidevalt kuulda, et tänapäeval loevad noored nii vähe ning et aastaid tagasi lugesid nad salaja raamatuid, mitte ei näppinud õhtul teki all telefoniekraani. Ning alati on süüdi nutiseadmed. Lugu pole aga nii lihtne. Nutiseadmed on küll osaliselt süüdi, aga probleem algas juba enne nende kasutusele võmist. Üks lugemise populaarsuse vähenemise põhjuseid seisneb filminduse arengus, kuna filmid lubavad sarnaselt raamatutele teise maailma süveneda, aga teevad seda lihtsamal kujul. On arvatud ka, et süüdi on raamatude prežtiisikuse vähenemine. Aja jooksul on raamatud odavamaks ja levinumaks muutunud ning enam pole lugemine auasi, vaid vastupidi. Lugejaid võidakse nohikuteks või tuupuriteks nimetada. Tiit Hennoste väidab oma arvamusloos „Lugemise harjumuse harjutus“, et umbes pool üheksanda klassi õpilastest loevad ainult käsu peale ning et probleem algas 1990ndatel. Põhjuseks on tänapäevane kiirmaailm ja lähedaste inimeste eeskuju, mitte nutitelefonid. Noored loevad tänapäeval üha vähem raamatuid, aga süüdi pole ainult nutiseadmed.\nNoored eelistavad ingliskeelset kirjandust eestikeelsele. Need vähesed raamatud, mida noored tänapäeval loevad, kipuvad olema inglise keeles kirjutatud või siis vähemalt inglise keelest tõlgitud. Põhjus seisneb selles, et raamatusoovitusi saadakse ennekõike sotsiaalmeediast ning populaarseim on tihti just välismaine, peamiselt ingliskeelne kirjandus. Tulemus on kurb – noorte emakeelne sõnavara seguneb inglise keelega. Kannatada võivad ka kodumaised autorid, kelle raamatuid ei osteta, sest need on noorte silmis igavas vanas eesti keeles. Seda toetab Tauno Vahteri arvamuslugu „Peame leppima, noored lihtsalt ei loe“, kus ta toob välja, et inglise keel on võtnud noorte lugemise üle ning saksamaal ostetakse peamiselt ingliskeelse pealkirjaga raamatuid, mis tähendab, et noored tunnevad kõige rohkem huvi välismaise kirjanduse vastu. Tulemusena võibki areneda rohkem nende inglise keele oskus emakeele oskuse asemel. Noorte lugemiseelistused on ingliskeelsed ning selle tõttu seguneb inglise keel emakeelega.\nTänapäeval loevad noored erinevatel põhjustel üha vähem raamatuid ning loetav kirjanus on tihti inglikeelne, mille tõttu voolab emakeelde üha rohkem ingliskeelseid sõnu.');
