INSERT INTO core.text(id, content)
VALUES ('f537601c-4b6a-41ba-85ff-fd50c0dc7546',
        'Tihti seisame silmitsi olukordadega, mis on nii enesest mõistetavad, kuid raske on neid teadvustada. Nimelt on lugemine niiöelda ebapopulaarseks muutunud, ning kaotanud oma lugejaskonna. Lugemine, kui vaba aja veetmise võimalus, on kaotanud oma tähenduse. See aga toob kaasa erinevaid probleeme nii ühiskonnale kui ka indiviidile. \nLugemine, kui meelelahutus on muutunud tööks. Kuigi lugemine on hariv, ning vanasti peeti seda kui vabaaja veetmise võimaluseks, on nüüd aga seda hakatud seostama justkui kohustusega. Raske on panna näpu peale sellele, kust selline arusaam võis alguse saada, sest me oleme pidevas muutuvas keskkonnas. Kuid mis on siiski selle põhjus? Kohati võib arvata, et see tuleneb inglise keele mõjust. Inglise keel kui globaalne keel mõjutab eestlaste kõnepruuki. Palju laenusõnu on tulnud eesti keelde just inglise keelest, see aga avaldab suurt mõju meie endi keele oskusele. Eesti keel muutub arusaamatuks inglise keele kõrval, ning olud, mis on keerulised või rasked seostatakse tihtipeale tööga. Tauno Vahteri artikel „Peame leppima, noored lihtsalt ei loe“ kajastab, kuidas inglise keel on üle võtnud noorte lugemise. Paljude kirjastuste pealkirjad on muutunud inglise keelseks, vaatamata sellele, et tõlge on teises keeles. Inglise keele mõjul on eesti keele oskus vähenenud, ning seetõttu tekitanud probleeme eestikeelse kirjanduse lugemise juures. Keelest arusaamine on muutunud justkui üleasandeks, mis vajab lahendamist, mitte meelelahutuseks. \nNutiseadmed on uus alternatiiv klassikale lugemisele. Tänapäeval kohtame tihti inimesi, kellel on kogu aeg nuttiseade näppude vahel, lehitsedes seal erinevaid sotsiaalmeedia platvorme ja  sirvates lühivideosid. Ajad on muutunud, ning nüüd saab kogu vajaliku informatsiooni või meelelahutuse vaid kliki kauguselt. Selline muutus on aga jätnud rängad tagajärjed meie endi intelligentsile. Paljud oskused, nagu funktsionaalne lugemine, on muutunud järjest halvemaks. Lugemine ja sellest arusaamine on tänapäeval hakkama saamise alus, ning selle puudumisel kasvab aina inimeste hulk, kelle toime tulek elus on raskendatud. Lugeminsel on tähtis roll meie elus, ning tihtipeale seda alahinnatakse. Inimesed enam ei pürgi lugema raamatuid, vaid selle asemel lähevad interneti, kus sealne keelekasutus on segunenud teiste keeltega või pole grammatiliselt korrektsed. Artiklis „Lugemise harjumuse harjutus“ kajastab Tiit Hennoste seda, kuidas mitmed uuringud on tõestanud seda, et hea lugemisoskus tagab parema hariduse ja sissetuleku. Kui vanasti olid raamatud peamised info allikad, siis nüüd on informatsiooni kättesaamine muutunud kordades kergemaks, mis on aga halvendanud meie teksti mõistmist. See on omakorda ebaeetiline pikemas perspektiivis. \nLugemine, vanasti kui vabaja veetmise võimalus, nüüd aga kohustus, on muutunud märgatavalt ning kaotanud oma populaarsuse. Lugemise roll nii ühiskonnale kui indiviidile on olulisel kohal, kuid selle vähenemine toob endaga kaasa mitmeid probleeme, mõjutades meie keelelist oskust ning funktsionaalset lugemist.');
