INSERT INTO core.text(id, content)
VALUES ('b54a9f69-ee2b-4261-93b1-72cb4499d93b',
        'Juba aastaid on räägitud, et tänapäeva noored ei loe piisavalt, aga on ka neid, kes veedavad palju aega raamatuid lugedes. Mis mõjutab noorte lugemisharjumusi ning mis on selle võimalikud tagajärjed?\nPaljud noored eelistavad lugeda inglise keeles. Inglise keel on maailmas üks enam kasutatavaid keeli ja selle oskamine annab inimesele elus eeliseid. See ongi üks põhjus, miks osad noored eelistavad lugeda inglise keeles. Neid raamatuid on lihtne paari klikiga internetist alla laadida ja kohe lugeda. Lisaks saab inglise keelseid raamatuid kiiremine kätte ning noored ei pea ootama kuni raamat nende emakeelde tõlgitakse. Tauno Vahteri arvamusloos „Peame leppima, noored lihtsalt ei loe“ räägib autor sellest, kuidas vene kirjastused avaldavad peamiselt inglisekeelse pealkirjaga raamatuid, sest need lähevad noortele rohkem peale. Inglise keel on suunanud noori lugema, kuid mitte oma emakeeles.\nTänapäeva noored ei soovi lugeda, sest see on neile vastumeeleseks muutunud. Koolis on lapsed kohustatud lugema kohustuslikku kirjandust ning see mõjutab laste lugemisharjumusi. Paljudele noortele ei meeldi need raamatud, mida nad koolis lugema peavad, ja kui noori sunnitakse neid lugema, tekib lastel lõpuks negatiivne arvamus lugemise suhtes. Kui raamat, mida nad loevad, on liiga paks siis kaob neil ka huvi selle vastu ära, sest nad teavad, et peavad selle lugemiseks palju aega kulutama. Tiit Hennoste ilmunud artikklis „Lugemise harjumuse harjutus“ on autor rääkinud, kuidas ülikooli ajal pidi ta tuhandete lehekülgede kaupa lugema ning see võttis talt mõneks ajaks huvi lugemise vastu ära. Mida rohkem sunnitakse noori lugema raamatuid, mida nad lugeda ei soovi, sest rohkem kaotavad nad üldse huvi raamatute vastu.\nSamas on lugemine noortele vajalik ning aitab neid elus edasi. Lugemise käigus õpivad noored eluks vajalikke funktsioone, mitte ainult lugemist, vaid ka sõnavara ja kogu maailma mõistmist. Ilma nende oskusteta ei arene noortest eluks valmis isikud ning neil võib tulevikus raskusi tekkida. Sellepärast ongi oluline, et nii kool, pere kui ka kogu ühiskond teeks noorte jaoks lugemise meeldivaks. Tiit Hennoste mainis oma artikklis „Lugemise harjumuse harjutus“, kuidas on tehtud piisavalt uuringuid, mis tõestavad, et laste jaoks on lugemine vajalik ning see arendab neid. Noorte jaoks tuleb lugemine teha meeldivaks, sest lugemise mõju nende elus mängib suurt rolli.\nLugemise tähtsus on juba ammu kindlaks tehtud ja on oluline, et ka noored sellest aru saaksid, sest see toob neile elus plusse juurde. Kuigi mõnel juhul on sellel ka negatiivseid pooli, näiteks siis, kui noored loevad inglise keeles ja jätavad selle käigus oma emakeele tagaplaanile. Kuid siiski on parem, kui nad loevad inglise keeles, selle asemel, et mitte üldse lugeda.');
