INSERT INTO core.text(id, content)
VALUES ('aeb83bea-8e3a-436b-bd3d-1931841a9143',
        'Ajad muutuvad, samamoodi muutuvad ka noorte lugemisharjumused. Areneb tehnoloogia, tulevad uued õpetamisviisid. Uued viisid ja sotsiaalne keskkond mõjutab noort lugejat ning kujundab tema eelistusi. Kuigi lugemise muutub noorte seas aina vähem populaarsemaks, seda siiski proovitakse ennetada, eelkõige inimese väiksest east: kodus ning koolis. Aga kuidas mõjub see ühiskonnale ja inimesele endale?\nTänapäeva noored eelistavad ingliskeelseid autoreid. Kiire tehnoloogia arenguga tuli kaasa ka kiirem infovahetus, maailm muutus digitaalsemaks. See aga kõvasti mõjutas inglise keele igapäevast kasutust inimeste seas. Noortele, kes on kasvanud tehnoloogiaga käsi käes, muidugi on inglise keel hästi lähedane, mistõttu ingliskeelsed autorid ongi nende seas populaarsed. Üheks teiseks ning kurvemaks põhjuseks võib olla see, et noortele ei meeldi justnimelt emakeelsed autorid, nende stiil, teoste teemad. Veel on võimalik, et noortel pole midagi eestikeelsete teoste vastu, aga lihtsalt nende lemmikute välismaisete autorite raamatuid ei tõlgita, mistõttu neil pole muud valikut kui lugeda inglise keeles. Tano Vahter on oma arvamusloos isegi öelnud, et „Poepidajate sõnul on ingliskeelse pealkirjaga raamatud pea ainsad, mida noored ostavad või loevad“. Inglise keele leviku tulemust on hästi näha näiteks Venemaal,  kus kirjastused avaldavad peamiselt teoseid, kus tegevus toimub välismaal ning autori nimi on ingliskeelne. Sellega kaasneb tõde, et kirjanikest emakeele arendajad jäävadki välismaiste kirjanike varju. Lisaks keele levikule mõjutas tehnoloogia areng ka noorte lugemiseelistusi, muutes nende raamatute keele eelistust.\nSundlugemine ei arenda noort inimest kui lugejat, vaid hoopis vastupidi. Suurel osal inimestest tekkivad positiivsed seosed asjadega, mida nad tahavad teha ise, negatiivsed aga nendega, mida neid sunnitakse tegema. Nende asjade hulka kuulub ka kohustuslik kirjandus või igasugune sundlugemine, mis on väga laialt levinud.  Sundides noori lugema, pantakse neid tahes tahtmata raamatutesse vaenulikult suhtuma. Mõnel võivad need negatiivsed emotsioonid seostuda just kohustuslikus kirjanduses loetavate emakeeles kirjutatud raamatutega, sest võõrkeeles keegi kedagi lugema ei sunni. Isegi Tiit Hennoste on öelnud oma arvamusloos, et pärast seda, kui ülikoolis pidi tuhandete lehekülgede kaupa lugema, kadus tal lugemisisu päris mitmeks aastaks ära. Vanemad põlvkonnad kipuvad ütlema, et lugemishuvi langeb nutivahendite pärast, kuigi lugemishuvi kadu algas pihta juba 1990-tel, seega põhjus seisnes siiski muus. Sundlugemine ei tee noortele head, vaid pigem tekitab nendes negatiivseid seoseid, mistõttu nad hakkavad lugemist koguni vältima.\nMida aeg edasi, seda rohkem muutuvad noorte lugemisharjumused. Kiire tehnoloogia areng aitas kaasa inglise keele levikule ja laialdasele kasutuselevõttule noorte seas, mis tekitas suurt huvi inglisekeelsete autorite vastu. Selle tagajärjeks oli aga kiiresti langev emakeelsete kirjanike populaarsus. Suur tagajärg on ka sundlugemisel, mistõttu tekkis paljudel noortel lugemisega väga ebameeldiv seos. Tauno Vahter ütles, et „võitlus noorte lugemisharjumuse pärast on kõigest pidurdav kaitselahing“, tuleb välja, et tal on kahjuks õigus.');
