INSERT INTO core.text(id, content)
VALUES ('41531100-a13c-4a69-b9e6-c41c7e07ba5a',
        'Tänapäeva noorte lugemisharjumused on võrreldes minevikunoortega palju erinevad. Need on ajas läbi teinud muutuse, mis on hakanud mõju äratama nüüdse aja ühiskonna toimimisele. Kuidas on aga noorte lugemisharjumused muutunud ning mida see võib ja on endaga kaasa toonud?\nLugemus noorte seas aina väheneb. Nimelt on raamatud kui vaba aja veetmise võimalus jäämas üha rohkem tagaplaanile, sest järjest tuleb juurde teisi erinevaid vaba aja tegevusi, mis ei nõua enam pikaajalist keskendumist. Enim on noorte seas näha just kalduvust lühikese või väikese mahuga sisu tarbimisele, nagu lühivideod Tiktokis või Instagramis. Seda just seetõttu, et need pakuvad rahulolu tunnet palju kiiremini kui näiteks raamatud, mille lugemiseks tuleb panustada rohkem aega kui 30 sekundit, mis on umbes ühe lühivideo keskmine pikkus. Ka Tiit Hennoste toob enda Sirpi artiklis „Lugemise harjumuse harjutus“ välja, et üks noorte lugemisharjumuse vähenemise põhjuseks on n-ö kiirmaailma valitsus ehk kiirtoit, kiirkeel, kiirteadus, kiirseks, kiirlugemine. Noorte soov raamatuid või teisi mahukamaid tekste lugeda on aina vähenemas, sest üle on võtmas kiire ja lühike sisu.\nNoorte aina väiksem soov lugeda viib aga oluliste funktsionaalsete lugemisoskuste hääbumiseni. Mida vähem noor loeb, seda vähem ta treenib enda aju hoomama mahukaid või keerukaid tekste. See on aga oluline oskus, sest erinevate tekstide mõistmist nõuavad paljud olulised eluvaldkonnad ning seetõttu on neist arusaamine märkimisväärse tähtsusega. Artiklis „Lugemise harjumuse harjutus“ ütleb autor Tiit Hennoste, et lugemisoskuse allakäiguga kasvab inimeste hulk, kes ei saa enam ühiskonnas hakkama, sest nad ei saa enam aru kasvõi sellest, mida riik ja ühiskond neile teada annab. On suur oht, et noorte lugemuse vähenemine toob endaga kaasa suure hulga inimesi, kes ei suuda enam aru saada olulistest tekstidest ning seeläbi osaleda ühiskondlikus elus.\nSamas kui on noori, kes loevad, siis ei taha nad seda teha enam enda emakeeles. Noortel on suur tendents lugeda hoopis inglise keeles ning seda on mõjutanud suuresti just sotsiaalmeedias levivad trendid. Nimelt on näiteks sotsiaalmeedia platvormil Tiktok levima läinud n-ö raamatute lugemise liikumine ehk booktok, kus noored jagavad ja hindavad raamatuid ning selle põhijooneks on see, et loetakse kõige rohkem massidesse jõudnud teoseid, mis on sageli raamatupoodides müügiks vaid inglise keeles. Ka Tauno Vahter on oma Maalehe artiklis „Peame leppima, noored lihtsalt ei loe“ kirjutanud, et isegi kui tüdrukud loevad rohkem, siis enamasti Tiktokis ja Instagramis nähtud inglisekeelseid raamatuid. Isegi kui viimastel aastatel on raamatute lugemine taas tänu sotsiaalmeediale veidi populaarsemaks saanud, siis on see kaasa toonud aga selle, et noored eelistavad inglisekeelseid teoseid eestikeelsetele.\nVähem keskendumist nõudvad vaba aja veetmise võimalused on vähendanud noorte soovi lugeda, sest pakuvad mõnutunnet kiiremini, ning see on suurendanud ohtu, et juurde tekib aina rohkem funktsionaalsete lugemisoskusteta inimesi, kes ei saa enam ühiskonnas hakkama. Samas on sotsiaalmeedia mõjul lugemine taas populaarsemaks saanud, kuid sedagi selle arvelt, et eelistatakse lugeda emakeelsete asemel inglisekeelseid teoseid.');
