INSERT INTO core.text(id, content)
VALUES ('fd79c935-284a-4ad4-b773-b586ff12b145',
        'Praegusel ajal kogub aina enam populaarsust sotsiaalmeedia ning sisuloome ja selle abil mõjuisiku staatuse saamine. Suurem osa meedia tarbijatest on noored, kellele suunamudijad mõju avaldavad. Sellega koguvad nad endale kuulsust ning teevad endale justkui nime. Kuid kuidas nad siiski noori mõjutavad?\nSuunamudijad postitavad erinevat sisu, mille abil üritavad populaarsust koguda. Olgu selleks kas treeningvideod, retseptid või isegi naljad. Iga mõjuisik loodab kuulsaks saamisele. Sageli kasutatakse selleks loose või erinevad kampaaniaid, mis noorte tähelepanu tõmbavad. Osad brändid teevad koostöid just alustavate „influenceritega“, et olla neile justkui hüppelauaks karjääriteekonnal. Tihti tehakse loosikampaaniate postitused just sellised, et need noorte tähelepanu võidaks ja neid loosides osalema kutsuks. \nPaljud arvamusliidrid avaldavad oma arvamust sotsiaalmeedias, otsides endale justkui kaasamõtlejaid. Leidub noori, kes nende öelduga samastuvad. Leides sarnase mõtlemisega inimesi, tunnevad noored ühtekuuluvust ja mõistmist. Neil võib tekkida julgus ka ise oma mõtteid välja öelda, mitte enam endale hoida. Erinevalt kuulsustest saavad nemad oma arvamust levitada ilma selleta, et tekiks suur skandaal ajakirjanduses. \nSuunamudijad reklaamivad ka erinevaid dieete ja toitumiskavasid. Noored võivad leida, et nende praegune toitumine on halb ja kaalunumber liiga suur. Sageli võib olla tegelikkus hoopis vastupidine. Nad võivad tekitada endale söömishäired ja alatoituvust.\nSotsiaalmeedias tegutsevatel avaliku elu tegelastel on suur mõju nii noorte arvamustele, igapäevasele elule kui ka valikutele. Kas noored endale seda mõju avaldada lasevad, on juba teine küsimus.');
