INSERT INTO core.text(id, content)
VALUES ('c2843a2f-33a7-44c9-ad84-a426c35b9ebb',
        'Tänapäeva ühiskonnas leidub palju erinevaid probleeme ja raskusi, kuid üks levinumatest on noorte suhtumine kirjandusse ehk raamatu lugemisse ja sellega seotud tagajärjed. Suur meie ühiskonna noortest lihtsalt ei loe. Kindlasti leidub noori kes loevad, kui neid on tunduvalt vähem. Selleks põhjuseks võib olla kasvõi see, kuidas vanemad oma lapsi kasvatavad ja mida need vanemad iseendast kujutavad, kui ka see, milline laps omaette on ja millised on tema prioriteedid ja harjumused. Noored on just need inimesed, kes panevad aluse mingisuguse tegevustele. Nendest sõltub päris palju ning kui nende elutee läheb kaotsi, peab ikkagi vaeva nägema nende tagastamisega õigele teele. \nÜks levinumatest põhjudest, miks noored ei loe, on nende kasvatamine. Vanemad on erinevad, erinevate huvidega, hobidega, arusaamistega, harjumustega ja ka vanemad on samuti kasvatatud erinevalt. Kindlasti noor ei hakka lugema raamatuid ega erinevaid ajalehti-artikkle kui tema vanem ei hakka tal lugemise vastu alates lasteaiast harjumust tekitama. Isegi kooli kohustuslik kirjandus ei saa olla nii effektiivne kui lapsevanema soovitused. Kahjuks meie ühiskonda jäi väga vähe lapsevanemaid, kes enda lapsele soovitaksid midagi kasulikku ja meeldivat, kuid neid ikkagi on. Tihti ka kooli kohustuslik kirjandus ei ole nii huvitav ja kaasahaarav kui on kirjandus, mis noortele meeldida võib, seega selle kirjandusega noortel tekkivad ebameeldivad emotsioonid. Selleks, et neid emotsioone vältida, tuleb lasteaiast alates anda lastele lugeda mingisuguseid raamatid, mis on kergesti arusaadava ja rikkaliku sisuga, tuleb harjutada ja harjutada. See tekitaks laste sees harjumust. Ebameeldivaks tagarjärjeks oleks noorte vale suhtumine kirjandusse. Mida rohkem noor loeb, seda paindlikumaks muutub tema mõtlemisviis.\nVeel üks väga oluline põhjus miks noored ei loe, see on nende prioriteedid. Eriti need prioriteeid, mis kujutavad tema sees umbes kuueteistkümnenda eluaasta jooksul. Selle vanusega lapsed juba hakkavad endale tulevikkuplaane koostama ning arutlema kuidas, kuhu ja millal. Kindlasti noored ei hakka lugema kuni nad ise aru ei saa miks see oluline on ja miks paljud edukad inimesed ramatuid loevad. Noorte prioriteedid koosnevad rohkesti nii nende vanemate prioriteetidest kui ka neid ümbritsevast ühiskonnast ehk nende sõpruskonnast, riigist ja ka teiste noorte huvidest. Palju noori teevad seda, mida teevad noored teistest riikidest ehk siis lihtsalt kopeerivad. Kopeerivad nende käitumist, suhtlemist ja samuti prioriteete. Need võiad olla nii head kui ka halvad, sõltub noortest, kellelt nad seda kopeerivad. Kahjuks vale eeskuju kopeerimine võib viia ebameeldivate tagajärgedeni, mis on seotud põhimõtteliselt nii vaimse kui ka füüsilise tervisega.\nIgas ühiskonnas leidub noori, kes ei loe ja ka väidavad, et lugemine pole nendele vajalik. Seda saab ja peab muutma, sest igas ühiskonnas on vaja teadlikke inimesi, kes saaks aru mida ja kuidas teha. Vähemalt bürokraatiakeele teadmine võimaldaks nendel olla vähemaltki natukene targem kui suurem osa riigielanikkest. Lugemine aitaks noortel aru saada kuidas toimib meie maailm ja mis peidetud saladused võivad olla iga meie ümber.');
