INSERT INTO core.text(id, content)
VALUES ('63ee4829-5c8e-48d8-b2bc-4c273d841c50',
        'Suunamudijaid on erinevatel sotsiaalmeedia platvormidel ääretult palju. Kõigil oma erinevad žanrid ja sellest tulenevalt ka vaatajaskonnad inimestest, keda saab ühel või teisel viisil mõjutada. Olgu selleks kas siis millegi müümine soovides omakasu või lihtsalt enda elustiili õhutamine. Enamik sisuloojaid vaatavad inimesed on ka lapsed, mille tõttu on see veelgi lihtsam. Kui suurel määral mõjutavad suunamudijad oma vaatajate igapäevaelu, otsuseid ja valikuid?\nMõjuisikuid on internetis tohutult palju ja ka iga võimaliku žanri jaoks. Sellepärast jagunevad ka vaatajad tahest-tahtmata eri vanusegruppidesse. Erinevad suunamudijad sotsiaalmeedia kanalid on mõeldud juba lastele, kuid kuna nendel otsusevõime puudub on neile mõeldud sisu enamasti puhtalt raha teenimiseks neile loodud videode pealt läbi sotsiaalmeedia võrgustiku seatud reklaamide. Suunamudijad hakkavad noori hiljemas eas, kui on tekkinud arusaam materialistlikest esemetest ja hakkab arenema inimese iseloom. Just selles vanuses on kõige kergem inimest mõjutada ja talle omakasu teenimise eesmärgil teha reklaami toodetele või misiganes rahalisele väljaminekule. \nNoortele suunatud reklaame ja ebatervislikke elustiili otsuseid õhutatakse sotsiaalmeedias aina rohkem ning nendest tingitud mõju on märkimisväärne. Üks kuulsamaid ja korduvamaid sisuloojaid, kes on noori oma tegemistega pettis on Ameerika juutuber ja avaliku elu tegelane Logan Paul. Nimelt tegi ta krüptovaluuta CryptoZoo, peale mille miljonite eurode eest müümist kogutud raha endale jättis. „Eriti kui mängu tulevad rahalised kohustused, tasub kodutöö ära teha ja mitte jälgida teatud mõjutuse saavutanud suunamudijate nõuandeid pimesi.“ Skandaalist tulenevalt maksis Logan Paul varastatud raha tagasi ja pääses täielikust karjääri hävingust. Kuid poole aasta pärast suutis ta uuesti pahandustesse sattuda, kui ta tegi sõjast toimuvast video ajal reklaami enda spordijoogi firmale. Kui mõned varastavad oma vaatajatelt raha ja teevad ebaetilisi või petvaid reklaame on ka teine moodus kuidas oma mõjusfääris olevaid noori mõjutada. Aasta tagasi enda sotsiaalmeedia karjääri alustanud juutuuber ja tiktokker Togi, kes alustas enda sisu loomist kulturismi ja jõusaalis treenimisega seotud videotega sai kiiresti populaarsust tänu tema väga avalikule steroidide kasutamisele. Tema loodud sisu koosneb tänaseks hasartmängude mängimisest, suurtes kogustes uimastite ja alkoholi tarbimises. Kuna ta saavutas sellise elustiiliga ja terviseharjumustega kuulsuse ja on teeninud üle miljoni dollari viimase paari kuuga on tema noored vaatajad arusaamal, et sellise ennastsalgava ja „samuti šokeerivale sisule panustavad influencer’id „ saavad ka kuulsaks ja rikkaks.\nSuunamudijad mõjutavad noori enda iga liigutusega, kas see neile meeldiks või mitte. Mõjuisikute tegemised ja elustiilid on noorte poolt ihaldatud ning kui seda neile pakutakse haaravad nad ka sellest võimalusest mõtlemata. On ka ausaid inimesi, kes tahavad oma vaatajatele head, kuid selliseid sisuloojaid on tänapäeval vähem.');
