INSERT INTO core.text(id, content)
VALUES ('5a7af0c3-ce84-47a5-b107-af7488704aeb',
        'Tänapäeva maailmas on üha suurem mõju avaliku elu tegelastel ja suunamudijatel teiste inimeste valikute üle. Noored on kasvanud üles keskkonnas, kus nad pidevalt näevad mõnda suunamudijat oma nutiseadmes või telekas. Uus põlvkond on justkui kasvatatud nende mõjuisikute poolt, kes oma tegevusega mõjutavad laste moraale, käitumist ja eluviisi. Oluline on mõista, kuidas need kuulsad inimesed mõjutavad noori oma tegudega.\nIlmselt kõige märgatavam on see, kuidas lapsi kasvatatakse igasuguste nutiseadmetega, pannakse laps tahvelarvuti taha vahtima ja lastakse tal ise leida midagi toredat. Lapsed võtavad omaks kõik, mida nad internetis või meedias näevad ja niimoodi kujunebki nende arusaam maailmast ja moraalist, seega on interneti suunamudijatel sama suur mõju noore inimese mõttemaailma kujundamisel kui vanematel ise. Noored kasvavad üles ja käituvad nii nagu nad teised on talle näidanud, siis on oluline, et laps vaataks ikka korralikke sisuloojaid, mitte kedagi viletsat ja negatiivset.\nMaailmas on mõned päris šokeerivad netikuulsused, keda noored peaksid vältima. Hiljuti, umbes koroonaajal, on tekkinud mitmed suunamudijad, kes reklaamivad igasugust jama, peamiselt noortele, et teenida kasumit. On palju noori, kes ei tea, kuidas oma eluga toime tulla või kahtlevad oma võimetes ja neid proovitaksegi mõjutada. Kuulsused propageerivad igasugust jama just sellistele noortele, sest nad teavad, et nad saavad kasutada neid ära raha teenimiseks, näiteks on olemas sellised suunamudijad, kes proovivad poistele seletada, milline õige mees peaks olema ja müüvad selle teemalisi kursusi. Noored võivad sellest saada täitsa vale kasvatuse ja kujuneda ühiskonna heidikuteks.\nVähesed mõjuisikud teevad sisulist tööd ka, näiteks on sotsiaalmeediates kontod, mis tegelevad keskkonnaohtude, tervise ja muude probleemidega. Nende abil saab palju lihtsamini meelitada noori heategevusega tegelema või oma eluviisi muutma, sest nad usaldavad seda suunamudijat. Arvatavasti plakatid ja infovoldikud ei meelita noori tegutsema, aga see, et keegi, keda sina austad, kutsub midagi asjalikku tegema mõjub palju paremini. Tõenäoliselt on ka palju rohkem julgust tegeleda trenniga või liikumisega, kui on näha, milliseid saavutusi tuntud sportlased saavutavad.\nKuulsad isikud võivad ka mõjutada seda, kuidas noored riietuvad või mida nad tarbivad. Ilmselgelt kui kellegile väga meeldib mõni punkar, siis ta võtaks sealt eeskuju oma riietuse jaoks. Niimoodi on alati olnud, mingi muusik või kultuuri tegelane saab kuulsaks ja tekib uus mood just tema stiili põhjal. Igal suunamudijal on oma enda stiil või eripära ja tema jälgijate riietus võib muutuda vastavalt sellele milline riietus tal endal on. Ikka on põhjus, miks ettevõted rahastavad sportlasi, et saada enda logo särgi peale, sest mõjuisikutel on see võime kujundada, mida noored tahavad kanda.\nSuunamudijatel on ühiskonnas väga suur mõju noorte eluviisi ja käitumise kujundamisel. Mõjuisikud on mõnel juhul justkui vanemad nendele lastele, kes jäetakse ekraani taha istuma. Tähtis on, et noored vaataks korralikke sisuloojaid, muidu nad võivad saada kehva kasvatuse. Kuulsad inimesed saavad kasutada ära oma mõju, et noored tegeleks millegi kasulikuga. Nad saavad ka mõjutada, ühiskonna moodi, sest noored võtavad eeskujuks kuulsate isikute riietuse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
