INSERT INTO core.text(id, content)
VALUES ('c18beb52-cfdf-48ea-be44-5d6b05e82abc',
        'Tänapäeva maailmas on just noored need, kes tarbivad kõige rohkem ja kõige uuemat infot. Postitused internetis, lühiartiklid Telegrammis, pildid ja lood, mis tulevad väga kaugelt, teisel maailma poolkeralt – kõik see jõuab klikki vältel inimeseni sel samal hetkel, kui sotsiaalmeediarakendus saadab talle vastava sõnumi. Ning just noored on need, kes selle teabe esimesena kätte saavad.\nPole midagi halba selles, et olla teadlik maailmast toimuvast. Just vastupidi – kellegi teise päevajuhtumid, arutused ja lood võivad abiks olla omaenda eluga hakkama saamisel, otsuste ja valikute tegemisel. Artiklis „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?“ osutab Maria Murumaa Mengel uuringutele, millest on selgunud, et nõu ühiskonnanormide, suhtlemise, suhtumise ja teiste hindamise kohta saavad noored tihtipeale „netikuulsustelt“. Sotsiaalmeedia on kiire ja lihtne viis vahendada oma arvamust ja arusaami. Internetikuulsaid isikuid usaldatakse, nende sõnu kuulatakse ning noored inimesed võtavad nende maailmavaadet meeleldi omaks. Tihti tunnevad noored, et lemmik „juutuber“ on nendest targem ja kogenum, tekkib illusioon, et see on lähedane tuttav ja teda tasub usaldada. Suunamudijate soovitused ja nõuanded võivad aidata oma problemidega võitlemisel ja arvamuste, harjumuste, seisukohtade loomisel. Eriti siis, kui mõjuisik asub noorest vaatajast kaugel ja pakub talle uut ja tavapärasest erinevat vaatenurka. Siiski peab olema ettevaatlik sellega, keda ja mil määral kuulata. Kõik nõuanded ja soovitused, mida leidub internetis, ei ole tingimata kasulikud vaid sellepärast, et tulevad tuntud „blogijalt“. On oluline aru saada, mis on tõsi ja mis vaid kuulujutt.\nSama ettevaatusega peab suhtuma ka sotsiaalmeedia mõjuisikute truudusse ja aususse. Enamik neist on, vaidlemata, avameelsed ja väärilised inimesed, kuid leidub ka selliseid, kes loodavad oma mõjuvõimu kasutades noori tarbijaid petta. Tavaliselt postitavad need influencer’id lühikest kuid siiski provokatiivset infot, mis kogub tähelepanu ja kujutab lugejates väärarusaami. Oma artiklis kirjutab Juhan Hellermaa, et suunamudijate ja veebikelmide vahel jookseb õrn piir. Raske on vahet teha tavalisel mõte- ja sõnavahetusel ning varjatud huvisid sisaldavatel postitustel. Suunamudijad võivad otsida tähelepanu ja populaarsust – selleks avaldavad nad muundatud lugusid oma elust või täielike fantaasiajutte. Mobiiltelefoni ekraani vahendusel on peaaegu võimatu aru saada, kas vastaspool pöördub vaataja poole siiralt või valetab talle näkku. Selliste kelmidega hakkama saamisel aitab arenenud kriiitiline mõtlemine ja oskus kahtlusi tekitavat teabet järgi otsida ja üle kontrollida.\nSotsiaalmeedias leiduv info võib noorele tarbijale osutuda nii hea kui ka halb. Suunamudijate soovitused ja ettepanekud võivad olla kasulikeks uute lähenemisnurkade otsimisel ja terviklikuma maailmapidi kujundamisel. Samas võib „netikuulsustelt“ saada valelikku ja koguni välja mõeldud infot, mida noor lugeja kindlasti peab tähelepanelikult läbi vaatama. Suunamudijad võivad noort ühele või teisele poole „suunata“, aga omaenda „suuna“ paeb inimene valima ikka ise.');
