INSERT INTO core.text(id, content)
VALUES ('08dbd3a3-44ab-4720-9a0e-678d291d27f2',
        'Tänapäeva vanem põlvkond tihti tunneb muresid noorte lugemisharjumuse kohta. On palju uusi vahendeid, millega saab leida vastuseid enamikele küsimustele ja tekib tunne, et noored ei tunne enam huvi lugemises. Kas see on tõesti nii ja kuhu tänapäeva noorte suhtumine lugemisse  viib uue generatsioni?\nLugemine laiendab silmaringi ja võib tuua mõtteid, mis mitte kunagi ei külastaks inimese pead, kelle mõttemaailm on osaliselt piiratud tema keskkonnaga. Miks siis tänapäeva noored ei soovi lugeda? Meie maailm areneb geomeetrilises jadas. Soovi korral võib ükskõik mis küsimuse vastust internetis leida. Ilukirjanduse raamatuid asendasid filmid, mille keel võimaldab rääkida lugusid märkavalt kiiremini, kui seda teevad raamatud. Sellises kiirmaailmas, raamatu lugemine on liiga aeglane protsess, mis võib tunduda aju jaoks suhteliselt mõttetu. Sest aju teab, et tulemusi mida saab raamatust, võib saada kiiremini näiteks internetis otsides. Kunagi raamat oli ka oluline ajaveetmise vahend, aga nüüd selle jaoks meil on teised esed. Tänapäeva lapsed enamasti loevad raamatuid ainult kooliülesannete raames, mis tekitab negatiivse assotsiatsiooni, kuna isikule ei meeldi teiste poolt määratud kohustused.\nSellises kiirmaailmas, noorte mõtlemine ja kontsentreerumine on ka korduvalt intensiivsem kui eelmisel põlvkonnal, mis võib tegelikult ainult kõlada hästi. Ühelt poolt noored on võimelised kiiresti tarbima informatsiooni, aga samal ajal see tekitab raskusi olukordades, mis vajavad põhjalikuma ja pikema kontsentratsiooni. Neid olukordi on täiskasvanute elus üpris palju, aga noored, kelle elus selliseid hetki veel pole, eriti ei vaja põhjaliku keskendumise võimet. See võib tuua probleeme nende edasises elus ja paneb vanema põlvkonna muretsema noorte eest. Kuid noorte eest muretsemine toimus kogu aeg. Isegi Antiik-Kreekas filosoof Platon arvas, et uus generatsioon on rumalam, kuna nad hakkasid märkima kirjalikult uusi asju, näiteks õppides. Tundub, et iga uus generatsioon on rahutu uuega, kuigi areng ja muutused on inimkonna paratamatu omadus.\nKuigi ei saa öelda, et abosluutselt kõik tänapäeva noored ei loe. Tõenäoliselt räägitakse ainult nendest, kes ei loe, kuna see tundub probleemina ja probleemi tõstetakse esile. Siis tekibki arvamus, et kedagi ei huvitagi lugemine, aga see ei pruugi nii olla. Minu ümber on väga palju noori, kes loevad raamatuid, laenavad ja arutavad neid üksteisega. Lugemine muutub populaarseks trendiks, eriti klassikalise kirjanduse lugemine. Noored tunnevad ennast intelligentsem, aga samas võivad sellise põhjusega lugedes, tõesti hakkata huvi tundma. Kiire informatsioonioni tõttu noorte seas saavad populaarseks psühholoogia ja filosoofia, mille arusaamiseks nad ostavad raamatuid nendest kategooriatest. Samuti sotsiaalmeediast on võimalik leida romaani, mille süžee võib tunduda lummavana. Ma arvan, et tänapäeva kiirmaailm annab võimaluse noortele analüüsida rohkem asju ja saada aru, mida ta soovib ja vajab.\nRafineerides eelmainitud arutelu, võib arvata, et kiirmaailm, milles me praegu elame, pakub meeletult palju vahendeid info tarbimiseks vaba aja veetmiseks, mida kunagi võis lugemisega teha. See ei tähenda, et noored on täiesti unustanud lugemisest, vaid seda, et nad on saanud rohkem valivateks. See annab võimaluse noortel lugeda siis, kui neid see huvitab ning seda, mis neid huvitab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
