INSERT INTO core.text(id, content)
VALUES ('cf0cc8b4-9501-4ecb-af68-41c9991fb8d2',
        'Olen väikesest peale olnud raamatutest huvitatud. Kodus oli meil lasteraamatuid igast ajastust, igast teemast, igas pikkuses, igas formaadis.  Lugemisoskamatuna sirvisin neid, kus leidus rohkem pilte, kui olin veerimise selgeks saanud istusin ja proovisin aabitsatest aru saada, kuni suutsin pikemat sorti raamatuid lugeda. Vanemad ei sundinud mind kordagi raamatut kätte võtma – tegelikult õppisin lausa iseseisvalt lugema. Nad andsid mulle võimaluse raamatutest huvitatud olla, kindlustades, et meil on kodus erinevaid raamatuid, mis erinevas vanuses lastele sobivad, ja mind raamatukogusse vahel kaasa võttes. Kahjuks ei ole kõik elanud n-ö raamatute keskel ja seetõttu ei ole ka tekkinud huvi nende vastu.\nTänapäeval populariseerib lugemist sotsiaalmeedia. See võib tunduda paradoksaalne, arvestades, et nutiseadmeid süüdistatakse madalas lugemistasemes,  kuid rohkem lugemist ei tähenda alati head, kuna iga tekst ei ole sama väärtusega. Tauno Vahter märgib oma arvamusloos „Peame leppima, noored lihtsalt ei loe“, et noored, kes loevad, tarbivad peamiselt TikTokis või Instagrammis nähtud romantilise ja fantaasiakirjanduse raamatuid. Need raamatud on loodud eesmärgiga meelitada inimesi, kes on harjunud sotsiaalmeediaga, kus on oluline saada võimalikult palju sisu kätte lihtsasti ja kiiresti. Suur osa neist raamatutest on kirjutatud seetõttu algeliselt, puudub kompleksus, mis aju ja mõtlemisvõimet arendaks, teemad ja tegelased on stereotüüpilised ja pinnapealsed, et võimaikult kiiresti teos väljastada üha uusi lugusid nõudvale tarbijaskonnale.\nNoorte oskamatus süvendeda pikkadesse, keerulistesse ja analüüsivatesse tekstidesse, tähendab, et tulevikus ei suuda ühiskond enam samamoodi toimida, kuna inimesed ei saaks hakkama. Tiit Hennoste on öelnud: „Funktsionaalne lugemisoskus on tänapäeva maailmas elamise eeldus ja alus,“ sest seda läheb vaja kõikijal, alustades koolist kuni lepingute sõlmimiseni välja. Lugemisoskuse langemisega esimese maailma riikides nagu USA, tähendab see ühiskonnale kriisi, kus tuleb haridusreformiga taastada noorte lugemisvõime või muuta senist süsteemi, kus eeldatakse, et kõik on head kirjaoskajad.\nSäärase taandarengu tõttu võib kaduda ka meie väljendusoskus, kuna oskame ainult pinnapealselt ja lühidalt oma mõtteid teistele edastada. Raamatute abil on meil võimalik mõista ja kaasa tunda loendamatutele erinvatele inimestele, näha nende perspektiivi detailselt ja sellega oma maailmavaadet arendada. Lihtsakoeliste raamatute tarbimise ja vähese süvenemisega tekstidesse, mis on keerulisemad, aga see-eest kasulikuma sisuga, võime kaotada sõnavara ja ka oskuse ise ennast lõpuks väljendada, mistõttu kaob ka vastastikune mõistmine. Orwelli teoses „1984“ kärbiti inimeste sõnavara, et nende mõtteid piirata ja sellega luua ühtsem mass, kes iseseisvalt mõelda ei oskaks. Seetõttu on oluline säilitada oskus keerulistest ja pikkadest tekstidest aru saada.\nLapsepõlves lugemishuvi tekitamine, andes lastele ise võimaluse raamatute keskele süveneda, on ühiskonnale ülimalt oluline. See õpetab last päriselt lugema, mõistma vanuseastemle sobivaid raamatuid ning arendab tema aju.  Tänu sellele teki noortes motivatsioon lugeda ainult seda,  mida sotsiaalmeedias näidatakse, mis on tihti kehva kvaliteediga, vaid on kujundanud selle juba varem. Lugemisoskus on oluline meile terve elu vältel – me kasutame seda koolis, tööl, lepinguid sõlimides ja teistes igapäevastes tegevustes, näiteks suheldes. Raamatud aitavad meil kasvatada oma sõnavara ja -seadmisoskust, mis võimaldab meil enda tundeid sügavamalt väljendada ja seetõttu tuleb püüda sellist oskust säilitada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cf0cc8b4-9501-4ecb-af68-41c9991fb8d2', 'title', 'Miks on oluline tekitada lastel lugemisharjumus?');
