INSERT INTO core.text(id, content)
VALUES ('d0dda260-ad92-4321-8e82-e26c1dc4bab7',
        'Tänapäeval arvatakse, et noored ei loe kirjandust üldse ega pole selles huvitatud. Maailmas käib kõik läbi lugemise ning kuidas siis noored, kes ei loe, saavad veel ühiskonnas hakkama?\nSellise arvamusega, et lapsed, kes ei loe raamatuid ei saa maailmas hakkama, ei ole mina nõus. Mina ise ei loe palju raamatuid, isegi ütleksin, et loen neid väga vähe. On küll tõsi, et sellega seoses ei ole minu sõnavara nii rikkalik kui tahaks. Samas aga suudan ma lugeda läbi tekste, mõista eestlaste juttu ja mõista pikki ja keerukaid lauseid. Kas sellest piisab? Mina ei tea. Arvan, et selleks, et maailmas hakkama saada, ja, aga enda huvides võiks muidugi oma keelt ja sõnavara laiendada. Miks ma siis raamatuid ei loe? Ei viitsi. Jah, on raamtuid, mis mulle tõesti huvi pakkuvad ja ma loen neid hea meelega, aga kahjuks on nad tavaliselt vene keeles. See, et ma raamatuid ei ole, ei tähenda seda, et olen laisk vorst, kes ainult nutiseadmes on. Küll aga on mõned probleemid ka – kirjanduse tunnid. Põhikoolist on mul olnud selline tunne, et kui jõuan kirjanduse tundi, ei mõista ma enam eesti keelt üldse. Nii et sellega, et ilukirjanduses on kõige keerukam keel, olen ma täiesti nõus.\n„Poisid niikuinii loevad vähe, loevad ainult peamiselt tüdrukud ning nemad enamasti TikTokis ja Instas nähtud inglisekeelseid romantilise ja fantsaasiakijanduse raamatuid.“ – selline on Tauno Vahteri arvamus.Tundub nagu stereotüüp. Esiteks on minu jaoks tektsi pealkiri väga agressiivne ja järsk – „Peame leppima, noored lihtsalt ei loe.“ Ise mainib ta küll, ei noori lugejaid on alati, aga vist arvab, et neid on väga vähe. Minu keskkonnas, mis mind ümbritseb, on väga palju tuttavaid, kes loevad ja ma alati imestan, kust neil on nii palju aega lugemiseks ja tahet. Seda, et tüdrukud loevad rohkem, kui poisid, ei saa mina väita, sest pole näinud uuringuid selle kohta. Ise näen TikTokis alati palju noori, nii poisse kui ka tüdrukuid, kes räägivad raamatudest ning mitte ainult romantilistest või fantaasiakirjandusest. Ning tõesti neid inimesi on meeldiv kuulata, kuidas nad oma lauseid üles ehitavad ja oma mõtteid avaldavad. \nNoori lugejaid on alati ning noored, kes palju ei loe, saavad ka ühiskonnas hakkama. Kui inimene ise tahab lugeda, saab ta tõesti seda endale sisse harjutada. Võib olla hakkan mina ka rohkem lugema, et oma mõtteid väljendada ja ilusaid kirjandeid kirjutada. Arvan ka, et praegu on noori lugejaid isegi rohkem, kui täiskasvanuid. „Peame leppima, INIMESED lihtsalt ei loe.“');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d0dda260-ad92-4321-8e82-e26c1dc4bab7', 'title', 'Kui raamatuid ei loe, ei saa ka ühiskonnas hakkama');
