INSERT INTO core.text(id, content)
VALUES ('c5f9804f-2988-415c-a259-75b76dda9781',
        'Raamatutel on olnud suur roll ühiskonnas juba sajandeid. Neis antakse edasi tarkust, kogemusi, müüte, ajalugu ja palju muid. Nende lugemine on viis, kuidas arendada enda teadmisi paljudest teemadest, aega veeta ja arendada enda fantaasiavõimet. Tänapäeval on see tegevus aga muutunud järk-järgult ebapopulaarseks ja inimesed loevad väham kui kunagi enne. Populaarseks on saanud sellega seoses järgmised küsimused: miks see aga on, mis see endaga kaasa toob ja kas seda saab parandada?\n Tänapäeva maailmas, kus kõik on kättesaadavam kui kunagi varem on raamatute lugemine kaotanud enda populaarsuse. Üks põhjuks selleks, nagu Tiit Hennoste ütles on nutimonomaania. Noored on asendanud raamatu lugemise, kui aja veetmis tööriista filmide ja arvutimängude mängimisega. Samuti on noored asendanud raamatu lugemise kui enda harimise internetist leitud artiklite ja videodega. Kõik sellepärast, et need viisid on neile rohkem kättesaadavamad, nõuavad vähem aega ja teemasse süvenemist. Tänapäevases kiirmaailmas on aja väärtustamine saanud väga populaarseks noorte hulgas, isegi siis kui noortel pole selle alles jäänud ajaga midagi peale hakata. Kindlasti on ka olemas noori, kes loevad raamatuid ja naudivad seda, kuid nende osakaal on kõvasti vähenenud.\n Raamatute mittelugemine toob endaga kaasa aga väga palju negatiivseid mõjusid. Näiteks on paljudel lastel tekkinud probleemid süveneda ühesse asja korraga, mis on ka üks raamatute mittelugemise tagajärgi. Raamatut lugedes õpid sa süvenema antud jutustusse lugedes sõna-sõna haaval teksti ja see oskus peegeldub ka igapäeva elus. Samuti on noortel raske aru saada tekstidest ja neid ise ka luua, kuna nad puutuvad kirjandusega kokku liiga vähe. See tekitab probleeme neil tulevikus tulles lugeda läbi lepinguid ja saada aru sõnade tähendusest. Kannatab ka noorte fantaasiavõime olles vähe kokkupuutunud fantaasiaraamatutega, see omakorda mõjutab negatiivselt suurelt mõtlemist ja erinevate viiside, asjade leiutamist. See kõik kindlasti peegeldub ka noorte tehtud kirjandites, mida paljud noored peavad kindlasti koolis kirjutama.\n Paljud vanemad inimesed teades seda annavad endast kõik, et suunata nooremat põlve lugema rohkem, tehes selle mõjutamiseks ka erinevaid üritusi. Nagu kirjutas Tauno Vahter „Võitlus noorte lugemisharjumuse pärast on kõigest pidurdav kaitselahing.“ Maailma arenedes ainult edasi ja edasi pakkudes palju erinevaid alternatiive vaba aja veetmiseks ja lugemiseks on see paratamatu, et noorte lugejate arv läheb järjest alla poole. Kindlasti on ja jääb noori, kes loevad ja seda naudivad, kuid nende noorte osakaalu suurendamine on ülimalt keeruline.\n Kokkuvõtteks on raamatute lugemise langus paratamatu, tuues endaga kaasa palju negatiivseid mõjusid. Kahtlemata, aga toob arenev maailm juurde noortele teisi oskuseid ja isegi alternatiive, et neid negatiivseid mõjusid vähendada ja noori harida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c5f9804f-2988-415c-a259-75b76dda9781', 'title', 'Tänapäeva noored ja lugemine');
