INSERT INTO core.text(id, content)
VALUES ('efdd67c0-6569-4488-8a61-2a9d27983322',
        'Lugemine on huvitav osa inimeste elust, tänapäeval on suures osas võimatu elada ilma selleta. Lugema õpitakse tihtipeale üsna noorelt, sõltuvalt inimesest teevad osad seda ülejäänud elus väga palju, teised aga väga vähe või üldse mitte. Läbi aja muutuvad nii loetavad tekstid kui ka lugemisharjumused. Millised on noorte lugemisharjumused ja selle võimalikud tagajärjed.\nNoored veedavad üha enam vaba aega raamatute lugemise asemel hoopis muid tegevusi tehes. Võrreldes varasema ajaga on noortel tekkinud juurde palju tegevusi vaba aja sisustamiseks, neil uued võimalused nii igapäeva tegevustes kui ka digimaalimas. Lisaks uutele võimalustele on noored saanud osaks ka kiiremale elustiilile ja tehnika arengule. Raamatute lugemiseks on inimestel jäänud vähemaks aega ja motivatsiooni. Elutempo kiirenemisele on aluse pannud kiired infoedastamise viisid. Tõestuseks sellele on Tiit Hennoste lause „Lugemine oli vaba aja täitmine, mitte kohustus“, mis on pärit artiklist „Lugemise harjumuse harjutus“, Sirp. Noorte seas lugemine aina väheneb muude tegevuste tõttu.\nRaamatud on kaotanud enda algupärase eesmärgi toimida meelelahutusena. Tehnika areng on toonud kaasa palju uusi viise, kuidas saada meelelahutust kiiremalt ja efektiivsemalt. Võrreldes raamatu lugemisega, mis võtab väga palju aega ja keskendumist, on imelihtne vaadata filme, videoid või uudiseid. Noorte lugemisharjumusi on pärssinud ka värskelt saabunud videomängud, mis pakuvad rohkelt meelelahutust. Digimaailmaga käib ka tihti kaasas inglise keel, mis on hakkanud mõjutama ka noori. Meedia platformid YouTube ja Netflix võimaldavd vaadata vastavalt videod ja filme internetis. Seega raamatud on suures pildis kaotanud enda meelelahtusliku funktsiooni, mis mõjutab noorte lugemisharjumusi negatiivselt.\nVõimalikud tagajärjed lugemise vähenemisele võivad olla kirjaoskuse ja arusaamise langus ja raamatute kadumine müügilt. Lugemine annab inimesele suure osa tema kirjaoskusest ja sõnavarast. Juhul, kui noored vähem sellega tegelevad hakkavd ka kaduma lugemise positiivsed efektid. Funtsionaalne lugemine on inimeste jaoks alus, mis aitab neil mõista enda ümber toimuvat, juhul kui kaob oskus lugeda, kaob ka oskus midagi mõista. Raamatute vähese lugemise korral kaob mõte neid hoida ja toota, mis võib viia raamatute väljasuremiseni. Seda tõestab lause „Poepidajate sõnul on inglisekeelse pealkirjaga raamatud pea ainsad, mida noored ostavad või loevad“, artiklist „Peame leppima, noored lihtsalt ei loe“, Maaleht. Lugemise vähenimse võimalikud tagajärjed on kirjaoskuse ja mõistmise langus ning võimalik raamatute kadumine müügilt.\nNoorte lugemisharjumusi mõjutavad erinevad vabaaja tegevused, elutempo ja muu meelelahtus negatiivselt. Selle tagajärjed võivad olla kahjulikud, kirjaoskus ja tekstide mõistmine võivad langeda. Vähese huvi korral raamatute vastu võivad need sootuks müügilt kaduda. Sõltumata noorte huvist lugemise vastu peaksid nad säiltima seda eluliselt tähtsat oskust.');
