INSERT INTO core.text(id, content)
VALUES ('82613d7e-8718-473e-9c3e-01093e1ced28',
        'Tänapäeva noorte eludes on suurt rolli mängimas suunamudijad, keda nähakse nüüdsel ajal internetis vägagi palju. Neid on aga kahte sorti: ühtesid nimetame me sisuloojateks, teisi aga võime nimetada veebikelmideks. Nad on hakanud noori suunama nende igapäevaelus, valikutes ja ka otsustes. Olenevalt suunamudijast võib selle mõju olla nii positiivne kui ka negatiivne.\nVaadates positiivsemat poolt siis suunamudijad saavad anda head nõu tuleviku valikute osas või suunata neid asju õigesti tegema. Suunamudijad võivad tulla eriti kasuks neile noortele, kellel pole olnud vanemaid, kes neile midagi õpetaks. Kogu selle sisu ja informatsiooniga, mida näiteks toktokkerid või instagrammerid on jaganud, on võimalik noorel ise omandada neid asju, mida nad oleksid soovinud õppida. Näiteks, kui mõni tüdruk või poiss on tahtnud terve elu saada tantsijaks, siis tänu mõnele kuulsale tantsijale on tal olnud võimalus seda õppida. Seda sellepärast, et see kuulsus on jaganud oma häid nippe ja kogemusi sellel allal, mille pealt on hea õppida olnud. Lisaks võib see kuulus tantsija olla jaganud kindlasti ka palju informatsiooni selle kohta, kuhu saab tantsimist edasi õppima minna ning kus oleks hea seda teha. Tänu sellele teabele võib olnud saada selle tüdruku või poisi unistus teoks.\nTeisalt keskendudes veebikelmidele, keda on lihte sassi ajada sisuloojatega, siis nende mõju noorele võib olla vastupidiselt negatiivne. Veebikelmide peamiseks eesmärgiks on panna inimesi reageerima, neid kas meelitades või hirmutades, ning seda võivad nad teha märkamatult samuti oma sisu jagades. Selle puhul võib noor saada aga valet infot arvates, et see on õige. Selle tõttu võib ka noor teha valesid otsuseid või valikuid. Näiteks, kui mõni suunamudijast kelm on öelnud, et just sellele viidatud lingile vajutades saab tasuta esemeid, kuid mainitud link on hoopis üks arvutiviirus, siis mitmed jälgivad võivad saada seetõttu tünga ning jääda halva valiku ohvriks. Sellepärast tuleks aga olla noortel ettevaatlik ja alati kasutada faktikontrolli, nagu on öelnud Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill. Samas vaadates asja positiivsemat poolt, siis selle loo ohver sai õppida olema aga rohkem ettevaatlikum ja tähelepanelikum.\nKokkuvõtvalt võib siiski öelda, et influencer’itel on olnud positiivne mõju tänapäeva noortele. Olenemata sellest, et on olemas ka kelmid, kes kõike head ei soovi, siis ka nendest saavad noored õppida ja omandada sellest positiivse. Tänu suunamudijatele, kes on loonud selleks keskkonna, on noortel olnud võimalus kogeda ja silmaringi avardada ning teha ka rohkem otsuseid, mis tunduvad õiged.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('82613d7e-8718-473e-9c3e-01093e1ced28', 'title', 'Suunamudijate mõju noortele');
INSERT INTO core.text_property(text_id, property_name, property_value)
