INSERT INTO core.text(id, content)
VALUES ('ab9bb3ae-0ada-4ee6-82cb-758d910029e0',
        'Noorte lugemisoskust on seatud küsimärgi alla juba aastakümneid. Nutitelefonide ja interneti laialdane levik on sellele ainult hoogu andnud. Siiski ei saa väita, et nutitelefonid on ainuke põhjus, miks noored lugemisest enam ei huvitu. Kas see probleem on aga nii laialdane, kui väidetakse?\nLugemishuvi puudumine toimub koolis juba algklassidest. Õpilased, kes ei huvitu lugemisest, loevad kohustuslikku kirjandust ning sellest tekib lugemisest negatiivne eelarvamus. Selle tõttu ei pruugi noored tahta oma vabal ajal lugemist harrastada. „Selles pole midagi uut, näiteks 1932. aastal ilmus ajalehes Kaja artikkel „Noorte lugemisoskus läheb tagurpidi“ ja küllap leiaks palju vanemaid näiteid.“ Kuna lugemiseks peab pikaajaliselt pingutama, on see keerulisem ja ka igavam kui näiteks sotsiaalmeedias postituste vaatamine. Sellest võib olla tingitud ka paljude kitsas sõnavara. \nKitsas sõnavara võib olla kahjulik üksikisikule näiteks töölepingule allakirjutamisel, ilma lepingut lugemata. Tutvumata lepinguga, võib inimene teadmata nõustuda tingimustega, millega ta tegelikult nõus ei ole. Sama tulemus võib olla ka siis, kui isik luges lepingu läbi, kuid ei saanud sellest täielikult aru ning kirjutas ikkagi alla. Lepingule allakirjutamine on nõusolek lepingus kirjeldatavaga ja sellest mitte arusaamisel ei saa inimene teada, millega ta alla kirjutades nõustub. Sõnavara kitsastumisel võib tekkida ka olukord, kus keerukamad sõnad kaovad lihtsalt kasutusest, kuna nende tähendust ei teata ja ei viitsita ka välja uurida.\nKüsimusele vastamiseks tuleks arvestada ka seda, kui tähtis on inimese igapäevaelus lugemine ning loetud teksti analüüsimine. Sotsiaalmeedias kui ka päris elus liigub tihti väär informatsioon ning lugeja peab säilitama võime informatsiooni üle kontrollida. Kuna kõik liigub internetis ja maailmas nii kiiresti, on aga keeruline selle jaoks viitsimist leida. Probleem tekibki siis, kui igat postitust ja plakatit võetakse faktina ning räägitakse seda informatsiooni edasi, ilma kontrollimata, kas see üldse tõsi on. \nNoorte lugemishuvi on alla käinud juba aastakümneid ning seda muuta ei pruugi olla võimalik. Kuigi interneti laialdane levik on sellele hoogu andnud, ei ole see siiski lugemishuvi langemise põhjus. Siiski on tähtis säilitada kriitiline mõtlemine ja analüüsida loetavat informatsiooni.');
