INSERT INTO core.text(id, content)
VALUES ('2138d4e9-024d-4bf9-9481-d77d521a8a17',
        'Võime öelda, et tänapäeva maailmas polegi enam vaja mõelda oma enda peaga. Me oleme sotsiaalmeedia pideva mõjutamise all, aga kuidas seda ära tunda ning mis infot me endaga kaasa võtame, on juba iga inimese enda teha. Meil on sotsiaalmeedias tuntud staarid, kes jagavad meiega oma igapäeva tegemisi või võtavad sõna teemadest, mis võiks suuremat rahvamassi mõjutada. Neid inimesi nimedatakse suunamudijateks.\nMe oleme mõjutatud milleski, millest meil pole aimugi, mis võiks meid mõjutada. Nooremaid on lihtsam mõjutada, sest neil puudub oma mõtteviis maailmast ning just seda saavad ära kasutada suunamudijad. Rääkides noortematele oma mõtlemisviise, kuidas maailma nähakse, avaldades oma arvamusi, mis võiksid ühtida noorte omadega ning läbi selle mõjutada neid. Näiteks suure jälgijaskonnaga Ameerika Ühendriikide meesjuutuber IShowSpeed propageerib pidevalt oma videotes, kuidas jalgpallur Christiano Ronaldo on kõige parem mängija ning Ronaldo liider jalgpallur Messi on just kõige halvim. Selline mõjutamine võib noore isiklikku arvamust muuta, sest arvab, et nii ongi, sest nii ju üks kuulsamaid Ameerika juutubereid ütles kelle austaja ta on. Tõsiseks läheb siis, kui noore sõbrad jälgivad samuti sama sisuloojat ja nõustuvad sellega, mida mõjuisik räägib. Kuidas saab siis üks laps oma kaaslastest erineda oma arvamusega? \nAlati pole olemas niiöelda pahatahtlikke suunamudijaid, kes suruvad enda vaatajatele peale oma ainuõigset arvamust. Suunamudijad võivad mõjutada noori ka positiivselt. Rääkides aktuaalsetel teemadel, mis võiks noori panna vaatama maailma teise nurga alt. Heaks näiteks saab tuua, kuidas mõjuisikud Hanna Martinson, Liis Velsker, Liina Ariadne Pedanik, Martti Hallik, Mick Pedaja, Alisa Tsitseronova ja Juhani Särglep võtsid milleski suurest osa. Nad võtsid osa kampaaniast #loomadesilmis. Kampaania #loomadesilmis kutsub inimesi üles mitte soetama karusnahka, sest karusloomad võivad olla hoopis midagi muud, kui tühipaljas uhke kasukas või tutimüts. Sellisest kampaaniast rääkimine võib panna noori mõtlema sellele, mis tegelikult toimub maailmas ning  kuidas päriselt poe lettidele glamuursed kasukad ilmuvad, mida pärast ostma hakatakse. Avada noorte silmad ja näidata karmi tegelikkust, mida mitu karuslooma selleks läbi peavad elama, et keegi saaks kasukat seljas kanda ja hiljem kõlbmatuks kuulutada.\nMe peaksime arusaama, mida suunamudijad tegelikult meie mõtlemisega teevad ja kui suur mõju neil on. Meie teha, aga on suuresti see, kui palju me nendega ühel lainel oleme ning millal me aru saame, et tegemist on lihtsalt ühe isiku mõttemaailmaga, millel pole mitte mingitki pismist meie enda omaga. Noori saab jälgida nende vanemad, kes on elu kogenumad ja võiksid enda võsukesi jälgida, keda nad parasjagu sotsiaalmeedias jälgivad ja mis mõju see neile kaasa võib tuua, et laps enda isikupära ei kaotaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2138d4e9-024d-4bf9-9481-d77d521a8a17', 'title', 'Sotsiaalmeedia mõjuisikud noorte igapäeva elus');
