INSERT INTO core.text(id, content)
VALUES ('30caaa5d-a826-417e-8981-d00c0375bf4f',
        'Sotsiaalmeediaplatvormid on tugevalt mõjutanud noorte karjäärivalikuid ja igapäevaelu, mis seostub vabaaja tegevustega. Noored teenivad läbi sotsiaalmeedia raha ja koguvad kuulsust. Eriti palju populaarsust on saanud suunamudijad, kes lahutavad meelt ja pakuvad vaatajatele oma kanali sisu, teenides ise kasumit. Selle kõigega kaasnevad ka ohud, kuid peamiselt informeeritakse noori, kutsudes üles tegutsema või oma teadmiseid kuulama.\nNoored on otsustanud läbi sotsiaalmeedia mõju hakata ka ise tootma sisu, mida postitada raha teenimise eesmärgil. Erinevatest platvormidest jõuab vaatajani igast riikigist hulganisti kontenti. Postitatakse erilist ja omamoodi sisu, mis vaatajat ligi tõmbab. Noored on enamasti huvitatud rutiinidest, samuti langevad nad ka müügilõksu, kui kuulsused soovitavad erinevaid ilutooteid, mida jälgijad ka kohe ostma lähevad. Noored saavad suunamudijatelt nõu, sest on tekkinud arusaam, et nemad teavad, mis on sobilik ja mis mitte. Vaatajaskond puutub kokku sisulooja elu ja probleemidega ning võib tunda ennast samas olukorras. Loodetakse, et äkki parandab teise mure tema enda mure või üritatake läi mõistmise ja influenceri kogemuse oma elu paremini tundma õppida.\nSotsiaalmeediaplatvormides korraldatakse ka erinevaid üritusi ja kampaaniad, millest huvipakkujad osa võtavad. Jälgijatele antakse  ülevaade maailmas toimuvatest sündmustest ja tõsisema juhtumi korral julgustatakse abivajajaid toetama. Instagrami kuulsad influencerid kutsusid Los Angelese metsapõlengus inimesi annetama ja vajaminevaid esemeid hädasolijate ostma. Eestis tuntud suunamudijad jagasid allkirjade kogumiseks linke, kus jälgijad said ennast kurssi viia, et aidata kaasa karusnahafarmide keelustamisele. Noorte aktiivsusest on teada saanud ka loomakaitseorganisatsioonid, kes tõenäoliselt ka muret kuulda võtavad ja probleemile lahenduse leiavad. Inimesed tunnevad ennast rohkem teadlikumana ja tahavad sarnastuda oma jälgitavaga. Tekib küsimus, kas rahvas on tõesti huvitatud kellegi aitamisest või tehakse seda propageerimise survel.\nVäheste kogemustega ja mitte nii teadlikud noored võivad langeda ka pettuse ohvriks. Enamus sisuloojaid teevad koostööd erinevate firmadega, kus enda kasumi teenimise eesmärgil reklaamivad toodet või sarja enda jälgijaskonnale. Tartu Ülikooli ühiskonnateaduste instituudi lektro Kristjan Kikerpill soovitab ennast sellega kurssi viia, et mitte ohvriks langeda. Tuleb osata vahet teha, kas sõnum on lihtsalt arvamus või on selle taga peidus mõne teenuse hüvitamine, mis loomulikult toetajale kahju toob. Tõenäoliselt survestab sotsiaalmeedia ka tulevasi noori  karjääri tegema, kuid ekspertide seisukohalt võib selline töö tekitada ka väga erineval hulgal probleeme.\nSuunamudijate soovitused ja reklaam võivad ühsikonnas kodanikke informeerida, kui selle kõige taga võib peituda ka murettekitav koht, kui noored lõksu langevad. Alustav sotsiaalmeediategelane võiks ennast kurssi viia ohtudega ning olla aus kõigi teiste suhtes nii, et oma jälgijat rahalises mõttes mitte röövida. Muidugi on informatsiooni jagamine igatki moodi vajalik, et inimesi ennetada ja teadvustada.');
