INSERT INTO core.text(id, content)
VALUES ('a4511d6f-9024-4a69-8965-b5ced2191ee0',
        'On olemas seisukoht, et noored ei loe ning me peame sellega leppima. Kuigi see väide ei käi kõigi kohta, on ikkagi üles kasvamas suur hulk noorukeid, kes ei loe ning on tänu sellele halvemal järjel elus.\nLugemine algab juba enne kooli, kui vanemad või lasteaiakasvatajad õpetavad väikseid tasapisi lugema. Pole kummaline nähtus, kui vanem esitab oma lapsele teatud piirangud ning selle käigus õpitakse lugema – näiteks enne ei saa telefonis olla, kui on raamatust 10 lehekülge loetud. Sellest tingituna võib lapseeast juba tekkida hoiak, et lugemine on ebameeldiv ja ei anna sulle midagi.\nAlustekstis on väidetud, et harjumus luuakse harjutamisega. Kui treenida ennast vastu tahtmist, kuid järjepidevalt, siis lõpuks tunned ennast halvasti, kui ei ole trenni teinud – sama käib ka lugemise kohta. See väide ei pruugi olla vettpidav, sest vaadates noorte seisukohta, on väga raske alustada lugemist, kui sind see ei huvita ning ei saa aru mille jaoks on vaja lugeda. Lugemise harjumuse kujunemiseks on kindlasti tähtsam leida raamat, mis sind rohkem kõnetab. Kui leida selline raamat, tekib harjumus iseenesest, sest on tahtmist lugeda. Sellele lisaks saaksid tõuke kaasa anda kirjanduse õpetajad, kes suunavad õpilasi lugema midagi, mis neid huvitab. Kindlasti ei tee halba ka keerukamad tekstid, mis annavad hiljem aluse teiste keerukate tekstide arusaamale.\nÜks olulistest asjadest, mis alustekstis väidetud on see, et inimestel on vaba aja veetmiseks palju muid ja huvitavamaid tegevusi, kui raamatut lugeda, sealhulgas nutitelefoni kasutamine. Selle asemel, et lugeda, istuks tavaline noor pigem tundide kaupa pigem Tiktokis või Instagramis ning lahutaks enda meelt seal. Scrollimine ja vaatamine annab igal juhul palju rohkem dopamiini palju kiiremini, sest niimoodi on tänapäeva sotsiaalmeedia platformid üles ehitatud – võimalikult palju rõõmu võimalikult lühikese ajaga. Sellise asja puhul ei aita muu, kui enesedistsipliin. Noored peavad endale seadma mingid piirid normaalse elu tagamiseks ning selle eest pääsu pole. Vastasel juhul kui endale piire mitte seada, võid enda elu käest lasta ning järgmine hetk, kui oled gümnaasiumit lõpetamas, ei teagi kuhu edasi minna või mis sind huvitab.\nLugematuse tagajärgi on raske paika seada, sest parasjagu see ühiskonna tase, keda lugemine ei huvita ei ole suures pildis veel „elu näinudki“ ning veel ei tea, äkki võib lugematus olla hoopis üks suurimaks põhjuseks edukusele?\nKokkuvõttes võib öelda, et noori sunniviisiliselt lugema panna on üsna raske. Lõpuks peab noor ikkagi ise aru saama, et kui ta ei loe, ei saa ta ka targemaks. Iga noor peab ise selle „pisiku“ endas üles leidma, et alustada uut ja kasulikku harjumust edaspidiseks eluks.');
