INSERT INTO core.text(id, content)
VALUES ('fb5c2e7f-6230-4c65-93ce-304bdd84d0e0',
        'Ühaenam kuuleme, kuidas 21. sajandi noorte lugemise harjumused on aastakümnete jooksul muutunud järl-järgult kesisemaks, kuna suurem osa vabast ajast veedetakse kas nutitelefonide, arvutite või televiisori taga. Sellest tulenevalt on aga paljudel noortel raskusi arusaamisega komplekssetest tekstidest, ametlikest terminitest ja keerulisest sõnavarast.\nNagu paljude teiste asjade puhul, siis ka noorte lugemise harjumused saavad ennekõike alguse kodust. See, kas noor on huvitunud lugemisest, uutest teadmistest, erinevatest kirjanikest ja nende kirjutatud teostest, saab kõik alguse lapsepõlves. Mitmed uuringud on aga näidanud, et vanemad, kes oma lastele kasvõi enne magamaminekut unejutuks erinevaid raamatuid ette loevad, äratavad oma teoga lastes huvi nii lugemise kui ka uute teadmiste vastu. Ent vaatamata sellele, on Tiit Hennoste sõnul lugemise harjumuste kujundamine ning nende jätkamine ikkagi igaühe iseenda teha ja vastutada.\nKuid kui lihtne on siiski tänapäeva kiiresti liikuvas ning pidevalt arenevas maailmas võtta hetkeks aeg maha, et kasvõi üks ilukirjanduslik teos või teaduspõhine tekst otsast lõpuni süvenenult läbi lugeda? Tuleb aga välja, et sugugi mitte lihtne. Seda aga sellepärast, et enamus inimesi on harjunud kompleksset ning mahukat informatsiooni kiirkorrast ja nii-öelda möödaminnes tarbima. Elame ajastul, mis on endaga kaasa toonud nii interneti kui ka kõrgelt arenenud tehnoloogia, mille tõttu on tekkinud infoüleküllus. Inimkonda valitseb niinimetatud kiirmaailm, millega sammu pidamiseks, on mõttega lugemine paratamatult muutunud aeglaseks ning mõnes mõttes ka mõttetuks tegevuseks, sest uut informatsiooni tuleb kogu aeg juurde. Sellepärast loevad ka paljud inimesed näiteks läbi vaid uudise pealkirja ning sissejuhatuse.\nPeale selle, et tänapäeva noorte lugemise harjumus olevat drastiliselt vähenenud, on paljude inimeste arvates veel tõsisemaks murekohaks aga tänapäeva noorte harjumus ning eelistus tarbida pigem nii ingliskeelset informatsiooni kui ka kirjandust. Küllap kardetakse, et eesti keel jääb sellisel juhul kas inglise keele varju või ei kandu põliste eestlaste kultuuripärand noortele põlvkondadele edasi, sest peetakse paremaks elada ingliskeelses maailmas. Küll aga oleks mõistlikum jätta antud murekoht ennem koolide hooleks, kuna õppeasutustes töötavad pedagoogid ning filoloogid on siiski oma ala spetsialistid, mistõttu teavad nad täpselt, millstel teemadel õpilasi ning tudengeid harida.\nTeatavasti on lugemise harjumus, tekstide tõlgendamine ja ridade vahelt lugemine nüüdisaegses maailmas, kus on tahes-tahtmata liikvel nii valeinformatsiooni kui ka petised, ääretult hädavajalik oskus, mida omada. Seetõttu on siiski väga oluline olla distliplineeritud ning kohusetundlik ja arendada välja korralik lugemise harjumus.');
