INSERT INTO core.text(id, content)
VALUES ('17f8397c-174b-4ac3-a99e-407db05e664b',
        'Sotsiaalmeedias asuvad kuulsused nii eestist kui ka välismaalt, kes avaldavad Eesti noortele tugevat mõju. Noorukid jälgivad neid ja soovivad tihtipeale olla just nagu nemad, aga kuhu jääb inimese enda isiksus ja kriitiline mõtlemine, et mis on õige ja vale maailmas? Sellele suunatakse tähelepanu järjest vähem. \nMis puutub mõtlemisse, eriti noorte puhul siis on nad väga mõjutatavad, olenevalt vanusest loomulikult. Seda on näha märgatavalt poliitikas, kus iga hääl loeb ning kui poliitiku käitumine ja hoiakud on noortepärased, siis edasi see kindlalt mõjutab ka nende vanemaid ning valikut hääletamisel. Näiteks valilisealisteks saanute hulgas on populaarsust avaldanud tugevalt poliitik ja sotsiaalmeedias aktiivset Jüri Ratast, kes on rajanud endale tugeva toetuse noorte poolt, käitudes ja tehes postitusi internetis, keda noored kohtlevad nüüd kui „ägeda tüübina“ ja nagu on Maria Murumaa Mengel öelnud:„[---] on kindlaks tehtud, et suunamudijad mõjutavad inimesi[---]parteide ja poliitikute toetamisel[---]“. Eestis tihtipeale poliitikud ei täida kunagi oma lubadusi, seda noored ei kontrolli ja ei mõtlegi hetkes, et kas Jüri Ratas tõesti seisaks Eesti inimeste eest või kasutab ära neid, et koguda hääli ja pääseda riigikokku või Euroopa parlamenti. Sellise tähtsa valiku puhul ei suuna noored tähelepanu, vaid suhtuvad Jüri Ratasse kui sõbrana.\nHoiakud ja maailmavaated mida kuulsused jälgivad, ajavad inimesi üksteise vastu viha hoidma ja pidama ehk „cancel culture“ või tekitama kiusamist teiste kuulsuste või tavaliste kasutajate vastu. Sellist käitumist näeb rohkem Ameerika Ühendriikides, kus maailmas ühel laialt levinuvaima sotsiaalmeedia platvormi X-i (varem teatud kui Twitterina) peal levib pidev nõiajaht inimeste üle, kellel on „vale arvamus“ või hoiak, mis teistele ei meeldi. Täpsemalt see tähendab nagu mainitud, kellegi platvormilt maha tõukamist, põhiliselt kuulsuste ja neid jälgivate inimeste kaudu, saates neid ähvardama ja äärmuslikel juhtudel inimene keda taga kiusatakse kaotab oma töökoha või isegi võtab endalt elu. Sellisele käitumisele panid aluse inimesed, kes omavad liberalistlike väärtusi. Põhiliselt on tihti tegemist Juhan Hellerma öeldud olukordadega: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, “kuulajatele meeldib“, siis on see probleem. Halvemal juhul võib selle tulemusel kuskil suuremaks kakluseks ja rüüstamiseks minna.“ On karta, et selliste masside hulgas on ka noori, kes peab ainult selle inimese väärtusi, arvamusi ja käitumist heaks, keda ta ise on kõige rohkem jälginud ja ei anna võimalust teisele poolele end kaitsda. \nKuulsad isikud mõjutavad noorukeid rohkem kui enamus arvavad. Nende väljaütlemised ja mõtlemisviisid jätavad keskealistele tugeva jälje, mis mõjutab neid terve elu, kui nad ei omanda iseseisvaid ja põhjalike arvamusi maailma suhtes.');
