INSERT INTO core.text(id, content)
VALUES ('f2ce206d-c292-49c5-b146-640b500cba7b',
        'On vähe inimesi, kelle elu rohkemal või vähemal määral ei ole ükski suunamudija mõjutanud. Arvamusliidrid ei ole midagi uut, kuid tänu sotsiaalmeedia võidukäigule on nende lavapind suurenenud ning seega tõenäoliselt paremini nähtaval kui varasemalt.\nKõige suuremat mõju tunduvad uue aja sisuloojad omavat ennekõike noorte üle. On üpris loomulik, et teismelised ja värsked täiskasvanud otsivad endale eeskuju, ning tihtipeale seda eeskuju pakubki just suunamudija. Kuna paljud suunamudijad on ka ise pigem nooremad, siis nooredsaavad samastuvad selle pooles. Kuna aga ei saa väita, et küik noored suudavad iseseisvalt arvamust omada ja kriitiliselt neile antud infot töödelda, siis võiks olla tegemist üpris hästi manipuleeritava osaga ühiskonnast. Kristjan Kikerpill on öelnud, et eriti ettevaatlik peaks olema sisuloojate nõuannetega, mis hõlmavad endas rahalisi kohustusi. Kuigi inimese lemmik netikuulsus võib endast jätta mulje, et ta päriselt soovitab midagi, ei saa välistada, et soovitusi jagatakse kellegi kolmanda huvides. Sammuti on üsna märkimisväärsks ohuks suunamudijad, kes soosivad mingit poliitiist vaadet, kuna ei saa väita, et tegemist on just tema vaatega ja mitte tasustatud tööga. Näiteks Venemaal on kui mitte kõik, siis suurem osa sisuloojatest ning arvamusliidritest rakendatud riigi poliitilisi vaated levitama. Kuigi valimistel on paljudes kohtades reklaamid, või valitsev partei või võimuliit teeb otsuseid, siis nendest on lihtne mööda vaadata või isegi kritiseerida, küll mitte alati avaliult kuid enda teadvuses. Kui aga sama infot jagab tuttav ja endale usaldusväärne suunamudija, on tõenäoliselt risk uskuma jääda suurem.\nOlles küll arvesse võtnud noorte mõjutatuse lihtsust, võib see hea eesmärgi nimel kasutades ka kasuks tulla. Ajakirjast Hea Kodanik ilmus artikkel, kus käsitleti karusnaha farmide vastast liikumist ning seal toodi välja, et kaasatud oli ka mitmeid tuntuid suunamudijaid. Tõenäoliselt aitas nende arvamusliidrite kaasamine kaasata liikumisse ka arvestataval hulgal sisuloojate jälgijaskonnast. Kuna noored on üks aktiivsem ja häälekam pool ühiskonnast, siis nende tähelepanu juhtimine probleemidele aitab kindlasti mõjutada ka laiemat avalikust sellega tegelema.\nSuunamudijatel on mõjuvõimu mõjutada noori suurte või vähemasti suuremate valiute tegemisel, kuid mõju omatakse ka noorte igapäeva elu üle. Õpetajate lehes saab välja lugeda, et suunamudijad mõjutavad seda, mis on noorte eesmärgid, mida valida ja mida mitte, kuidas käituda jne. Ei ole ebatavaline, kui mõni tuntud influencer laseb endale teha uue ning võibolla ka ebatavalise soegu, mis muidu võibolla ei pruugiks positiivset vastukaja saada, kuid puhtalt tänu tuntusele võtab vaatajaskond selle omaks ning võib hakata ka jäljendama. Võibolla ongi just need väikesed mõjutused, kust tuleb välja suunamudijate tegelt võim, sest nõnda väikesest elukorralduse muutusest nagu oli eelnevalt välja toodud, ei sõltu just palju, seda on lihtne korraldada ning see võib juhtuda nii, et noor ei saa sellest arugi. \nKuigi suunamudijate suur mõjuvõim võib olla ohtlik, ei saa tunnistamata jätta ka selle potentsiaali midagi ühiskonnale kasulikku teha. Seega oleneb kõik sellest, kui palju noored ise enast lasevad mõjutada ning mis teemadel.');
