INSERT INTO core.text(id, content)
VALUES ('a0998b7e-a4d0-4957-8ed3-8b5150753236',
        'Noored on hakanud raamatute lugemisest järjest rohkem kaugenema. Selle põhjuseks peetakse tavaliselt infoajast probleemiks. Noored on parema hea meelega rohkem sotsiaal meedias selle asemel, et raamatut hakata lugema. Kui koolis on kohustuslik raamatu lugemine siis loetakse, kas ainult raamatu taga olevat kokkuvõtet või lastakse terve töö ära teha tehisintelektil. Kuidas mõjutab raamatute mitte lugemine noorte mõtlemist?\n Noored ei ole endale harjumust raamatute lugemise suhtes võtnud seetõttu, et milleks nad peaksid raamatut lugema, kui nad saavad terve raamatu sisu võtta internetist, kellegi teise kokkuvõttest. Noored ei pea isegi pinguta selle nimel, et raamat läbi lugeda ja sellega kaasneb ka see, et ei teki lugemis harjumust. Tänapäeva noored veedavad rohkem aega nutiseadmes, kui raamatuid lugedes, kuna seal saab kiiresti meelelahutuse kätte vaid paari vajutusega. Noored soovivad rohkem olla sotsmeedias ja suhelda enda ealistega. Nad saavad selle info mida nad vajavad interneti keskkonnast kätte ning paha tihti nad ei mõtle, kas info vastab tõele. Kui noored ei loe väga raamatuid siis nad peavad tihti peale ennast paremaks nendest, kes raiskavad oma aega raamatute lugemiseks, kuna nad on saanud selle aja millekski muuks kasutada.\n Negatiivselt mõjub raamatute mitte lugemine noore mõtlemisele sellega, et ta sõnavara on väiksem ning tihtipeale ka tema õigekirja oskus on kasina võitu. Sellest hakkavad probleemid pihta ning noorte keele tase hakkab langema juba sellepärast, et nad ei ole lugenud raamatuid ja nende sõnavara selletõttu on väike. Noored ei soovi lugeda ning nende mõtlemine võib taandareneda sellega, et ei ole raamatute lugemisega oma mõttemaailma rikastanud. Kui sõnavara on juba väike siis enda mõtete väljendamisega võib tulla probleeme, et ei suudeta ennast väljendada nii nagu soovitakse. Eneseväljendamine on kõige olulisem oskus ja kui seda ei osata siis on juba nukker seis.\n Kui noored ei ole hakanud varasemast east lugema ja on valinud endale lihtsad ja õhukesed raamatud, mida on kergem lugeda siis ei teki ka sellist tunnet, et peaks lugema midagi. Ise olen lugenud raamatuid tihedalt põhikoolis, kus ei olnud mul nii suurt võimalust kasutada nutiseadmeid ning igavuse peletamiseks sai loetud raamatuid. Nüüd kui ma olen juba gümnaasiumi astmes siis sain kokku teiste inimestega, kes väga raamatuid ei loe ja mulle on jäänud külge see, et miks ma pean lugema raamatuid, kui ma lihtsalt saan kokkuvõte lugemisega raamatu töö tehtud. Minu sõnavara on rikkalik tänu sellele, et ma põhikooli ajal üldse tahtsin raamatuid lugeda ning ka mu mõttemaailm on sellepoolest rikkalikum.\n Noorte mittelugemine mõjutab erinevalt kuna, me tarbime meediat erinevalt ja sellega kaasnevalt on meie sõnavara ka erinev. Raamatute mittelugemisega kaasneb napp sõnavara ja ka see, et fantaasia on kesisem. Mida vähem noored raamatuid loevad seda rohkem on nad keele oskamatud. Kui noorest east raamatute lugemine ei süvene sisse siis me ka ei loe neid ka tulevikus.');
