INSERT INTO core.text(id, content)
VALUES ('0ce52a98-049d-42f7-98e4-73d58f46cb01',
        'Tänapäeva noorte lugemisharjumus pole eriti kiita. Hästi palju leidub noori, kes ei loe või teevad seda ainult siis kui peavad. Osalt on ka noori, kes loevad ja teevad seda suurima hea meelega. Kui võtta eraldi poisid ja tüdrukud, siis leidub rohkem tüdrukuid, kes vabalajal võtavad raamatu kätte ja loevad. Poisid pigem veedaks selle aja sõpradega või arvutimäne mängides, kuid leidub ka vastupidist olukorda. On ka noori, kes tahaks rohkem lugeda või sellega alustada, kuid ei tea kust alustada.\nVõtame alguses ette noored, kes ei loe või loevad sunniviisiliselt. Need noored on tavaliselt harjunud olema kas oma nutiseadmes või arvutis. Mida nad seal teevad? Tavaliselt vaatavad nad seal erinevaid videoid või mängivad erinevaid mänge. Sealt võivad nad enda keeleoskust näiteks inglise keeles parandada ja isegi leida, et niimoodi on lihtsam, aga see pole ju kunagi lahendus olnud. Loomulikult nad suhtlevad seal ka oma sõprade ja pereliikmetega, aga nad ei loe sealt eriti midagi kasulikku, mis nende silmaringi ja sõnavara avardaks. Vahest harva avatakse mõni uudisteportaal, kuid see võidakse ka kiiresti sulgeda, kui lugu ei ole näiteks kahe esimese lausega huvitav nagu pildi või pealkirja järgi eeldati.\nKui nüüd mõelda nende noorte peale, kes vabatahtlikult loevad, siis neil on juba rikkalikum sõnavara kui mittelugejal. Tavaliselt need noored leiavad, et uudiste lugemine tuleb neile kasuks. Nad vaatavad neid artikleid ja loevad need lõpuni, isegi kui need pole huvitavad. Kui vaadata, mida tüdrukud loevad, siis on need tavaliselt armastuse ja fantaasia romaanid. Nagu Tauno Vahter kirjutas, et tüdrukud loevad enamasti Tiktok’is ja Instagram’is nähtud ingliskeelseid romantilise ja fantaasiakirjanduse raamatuid. Poiste poole pealt, kui midagi loetakse, siis loetakse tavaliselt autodest. Mõned loevad hoopis kosmosest või kosmosega seonduvast. Nad ei pruugi isegi aru saada, et nad endale head teevad, kuni see neile kasuks tuleb.\nTegelikult on ka noori, kes ei loe, aga tahaks lugeda. Alguses võib see väga keeruline olla, kuid suure tahtejõuga on kõik võimalik. Vahepeal kui noor võtabki endale väljakutseks hakata rohkem lugema, siis võib ta kogemata endale liiga teha, sest valib liiga pika aja kui loeb, või valib enda jaoks mitte huvitava lugemimaterijali. Niimoodi võib ta mõelda lugemisest halvemini kui alguses. Kui aga valitakse endale sobivalt väike aeg esialgu ja huvitav teema mida lugeda, siis võib juhtuda, et väga kiiresti leitakse, et rohkem aega veedetakse lugemisele kui vedelemisele. Nagu Tiit Hennoste kirjutas, et alguses on raske, aga mõne aja pärast on asi sealmaal, et noor vajab oma igaõhtust lugemise annust.\nNiisiis, tänapäeva noorte lugemisharjumus pole kiita, kuid mitte kõik noored ei ole sellised kes lugeda ei sooviks või seda ei teeks. Tegelikult leidub suhteliselt palju neid, kes loevad ja neid, kes tahavad lugeda. Kui ei teata kust lugemisega alustada, siis peab lihtsalt leidma väheke aega ja endale meeldiva teema. See jaotub veidike rohkem nii, et tüdrukud loevad parema meelega kui poisid, aga vahset võib see olla vastupidine. Tavaliselt leiavad tüdrukud varem, endale meeldiva teema. Vahepeal võib olla ka probleem, et poistele meeldivast teemast lihtsalt ei kirjutata piisavalt palju. Üldiselt loevad tüdrukud romantikat ja poisid hoopis midagi autode teemal.');
