INSERT INTO core.text(id, content)
VALUES ('7386a742-2029-4fe7-8347-c38ea2c3381c',
        'Avaliku elu tegelased ehk „influencerid“, vanematele inimestele suunamudijad, kelle tööks on enda nime kuulsamaks tegemine, nägu näidata ja teha tööd internetis, kas siis reklaamida või blogipostitused. Tänapäeval on suunamudijad päris populaarsed ja üha rohkem inimesi tahavad olla suunamudijad. Suunamudijad köidavad publiku tähelepanu nelja aspektiga, selleks on: ekslusiivus, eksootilisus, erakordus ja elulähedus.Kõige olulisem aspekt võiks olla eksklusiivus, kuna inimesed saavad sealt infot, mis muidu kättesaadavad, näiteks kallid esemed ja eksklusiivsed üritused. Kuna tänapäeva noored veedavad palju aega sotsiaalmeedias siis kindlasti avaliku elu tegelaste mõju noorte elus on. Paljud ka kinnitavad seda fakti sest influencereid tuleb järjest juurde ja rohkem nende postitusi jõuab ka noorteni.\nSotsiaalmeedia mõjuisikutele pakutakse kogu aeg uusi erinevaid tooteid, näiteks nagu naha- või kehahooldus produkte, erinevaid sööke ja jooke, palutakse reklaamida söögikohti, jõusaale ja kõike muud. Sisuloojad on tavaliselt nõus neid tooteid reklaamima, aga on räägitud, et ise nad neid produkte läbi ei proovi, vaid kohe teevad reklaami ja noored, näiteks, kes lausa ihaldavad mõnda sisuloojat ei kontrolli ega uuri midagi nende produktide kohta, lihtsalt kohe ostab. See on sama hea kui ostad põrsa kotis. Noored peaks kindlasti rohkem tähelepanu pöörama, mis nad ostavad ja mida sisaldab. Suunamudijate mõju on suur ja see võib muuta noore igapäeva elu. Näiteks blogijale pakuti pudelivett, mis pidi sisaldama kõike head. Blogija kohe reklaamis ja noored hakkasidki seda ostma ja jooma, pärast tuli välja, et polnud seal midagi. Sellest näitest oli aru saada, et mõju võib olla päris suur, kui nad suudavad isegi inimesi nii öelda sekundi pealt tundmatuid asju sööma ja jooma panna.\nUuringutest on selgunud, et tihti saavad just noored suunamudijatelt nõu, mis on normaalne ja mis ei ole, mida tahta, mida mitte ja mis on õige, mis on vale. Inimesed teevad tihtipeale influencerite üle nalja, aga nad ei saa aru, kui suur mõju neil tegelikult on. Suunamudijate kaudu jõuab noorteni mitmeid teadmisi ja tüvitekste, sisuloojad isegi kujundavad neid. Mõju võib olla ka halb, eriti noortele. Näiteks suunamudija näitab tatoveeringut, soovitab ja noorel lööb silmad särama ja teebki ära, kui vanemaks saab siis kahetseb\nKindlasti on suunamudijatel ka kindel hea mõju olemas. Nad osalevad heategevuses ja annavad enda panuse. Näiteks oli kampaania, kus kutsuti inimesi üles mitte ostma karusnahka, seal osalesid mitmed Eesti suunamudijat, tuntumad nimed on: Mick Pedaja, Martti Hallik ja Hanna Martinson. Suunamudijad kutsuvad inimesi üles heategevuseks, näiteks, et toetada rahaliselt ravifondi. Suunamudijad selle tõttu, et nende mõju võib olla suurem, kui kellelgi teisel. \nSuunamudijatel võib olla hea mõju, aga ka halb, enamasti ikka hea. Nad annavad inimestele infot, üritavad noortele teha selgeks, mis on õige käitumine, mis on hea ja mis nemad on valesti teinud, mida noored saaks paremini teha. Kindel on see, et avaliku elu tegelased kujundavad noorte valikuid, mõtlemist ja igapäevaelj Suunamudijatele peaks rohkem tähelepanu andma ja nende tööd tunnustama, kui nad on midagi hästi teinud, kindlasti see annaks neile motivatsiooni juurde.');
