INSERT INTO core.text(id, content)
VALUES ('55f4c023-5120-4691-8cd6-5a9272ceb187',
        'Tänapäeval on ühiskonnas probleem sotsiaalmeedia suunamudijatega ja inimesed ei tea keda usaldada. Interneti avarustes ei saa kunagi kindel olla, et keda saab usaldada ja keda mitte. Paljud suunamudijad kasutavad ära oma kuulsust, et teenida selle arvelt raha. On ka neid arvamusliidreid sotsiaalmeedias, kes annavad kasulikku ja tõepärast infot. Noored veedavad väga palju internetis ringi vaadates, siis võivad suunamudijad väga palju mõjutada nende teadmisi ja maailmavaateid.\nSuunamudijad on eeskujuks ja arvamuskujundajaks paljudele noortele inimestele. Nende jaoks võib tunduda sisulooja nende sõbrana, näiteks 1956. aasta suhete teooria kohaselt tekib meedias olles inimestel illusioon, et nende lemmik suunamudija on nende lähedane tuttav, keda saab uskuda. Kuna noored on palju telefonis, siis enamasti nad näevadki inimesi sotsiaalmeedias ja sealt hakkavad nad võtma nõu, millest kujundavad nad oma arvamuse või seisukoha, milles nad tegelikult ise täiesti kindlad olla ei saa. Nad võivad meediast saada kas usaldusväärset ja kontrollitud infot või siis vähe uuritud ja väärinfot. Kristjan Kikerpill on öelnud, et arvamus on küll vaba, aga kui see ei ole faktuaalne, siis tekib sellest lihtsalt probleem.\nKuna väga palju on internetis petmist, siis ei saa usaldada kõiki ja kõike mida üteldakse või üritatakse maha müüa. On palju sisuloojaid, kes kasutavadki ära inimesi, kes oska väga hästi sotsiaalmeediat kasutada, et nende pealt tulu teenida. Tähtis on uurida, millega antud suunamudija tegeleb, kellega üldse tegu on ja mis vastukaja ta on saanud teistelt inimestelt. Neil on samuti vaja teenida raha ja tihti kasutatakse tasuta poolikuid kursuseid selleks, et inimeses huvi tekitada ning hiljem hakatakse täispaketi eest ulmelisi summasid küsima. Enam ei saagi aru, kes on pettur ja kes suunamudija, sest kõigil on palju jälgijaid ning on raske seetõttu vahet teha, seega tuleb teha faktikontroll.\nÕnneks on olemas ka usaldusväärseid internetikuulsuseid, kes on oma väiteid kontrollind ja ei levita rahateenimis eesmärgil valeinfot. Suunamudjad, kes annavad infot, et inimesi päriselt aidata ja anda soovitusi on samuti olemas. Näiteks Eesti sisuloojad tegid Loomuse kampaania, inimestele karusnahkade vältimise jaoks. Loomuse liige Hanna Martinson väitis, et see kampaania on eelkõige selleks, et tõsta noorte teadlikkust karusloomafarmide tegelikusest elust. Tänu sellele ettevõtmisele hakkasid liituma suured loomakaitseorganisatsioonid, kes on märgiks usaldusväärsusele.\nKokkuvõtteks tasub kindlasti kontrollida sotsiaalmeedias ringi surfates veenduda, millega on tegu. Uurida enne inimese kohta kelle arvamust kuulda võtta ja uurida näiteks lähedastel kas antud arvamus on aktsepteeritav. Otsida usaldusväärseid pakkumisi sisuloojate poolt, millega sa ei saa petta ja teha faktikontrolle. Sotsiaalmeedias on pahatahtlikke inimesi ja heatahtlikke inimesi, seega ei tohiks rutuga kõike uskuma jääda ja teha kindlaks nende eesmärgid. Usaldada saab inimesi, kellel on mõni heatahtev suur organisatsiooniga koostööd. Tihti tava suur firmad teevad seda samuti rahateenimis eesmärgil.');
