INSERT INTO core.text(id, content)
VALUES ('54c1fa0e-bb29-4c8e-a14c-ca89abbc95c4',
        'Me elame tänapäeval tehnika ühiskonnas, kus paljudel on nutitelefonid ning järjest rohkem oskavad noored inglise keelt ning on tõmmatud inglise keelsete tekstide lähedusse. Lisaks mängib suurt rolli ka sotsiaalmeedia, kus noored eelistavad rohkem aega veeta kui lugeda. Mida peaks tegema, et tuua noori tagasi raamatute lugemise ja nautimise juurde?\nTänapäeval on tehnika suur osa paljude inimeste eludest. Kuna tehnika on niivõrd arenenud saab internetis teha väga paljusi asju. Tänapäeva noored eelistavad veeta oma vabat aega telefonis ning seal sotsiaalmeedias scrollida. Kuid ainult sotsiaalmeedias istumine ei ole nii kasulik, kui raamatute lugemine. Telefonis saab küll oma silmaringi avardada kuid palju väiksemal määral sest noored eelistavad istuda Tiktokis või Instagramis. Lisaks sotsiaalmeediale saab tänapäeval ka kuulata raamatuid. Raamatutega saab ka lõbusat aega veeta sest erinevad ilukirjandus lood on tegelikult väga huvitavad aga tihti on noorukitel raske süveneda ühte asja kauaks ajaks ning nad ei suuda lugeda mitut lehekülge. Tauno Vahter on öelnud „ Poisid loevad  vähe, loevad peamiselt tüdrukud ning nemad enamasti Tiktokis ja Instas nähtud ingliskeelseid romantilise ja fantaasiakirjanduse raamatuid“. \nElades lisaks interneti ajastule oskavad paljud noored juba inglise keelt ning eelistavad lugeda inglis keelseid tekste. Tihti loetakse tekste, mis paiknevad kuskil välismaal sest noorukid tahavad lugeda raamatuid, mis on kirjutatud inglise kirjaniku poolt ja paikneb ka kuskil välismaal. Inglise keel mõjutab noori isegi nii palju, et nad ostavad või laenutavad põhiliselt selliseid raamatuid, mille pealkiri on inglise keelne aga tekst sees on emakeeles. Kui autorid tahavad noortele raamatuid suunata siis peavad nad raamatut spetsiaalselt muutma ning ei saa kirjutada täpselt nii nagu ise tahaksid või sooviksid. Tauno Vahter on seda taibanud, et saksa noored ostavad selliseid raamatuid, mille pealkiri on inglise keelne aga tekst raamatu sees on ikkagi saksa keelne.\nLisaks keelteoskuse ja tehnoloogia arengule mõjutab lugemisharjumused ka noore vaimsettervist ning ka empaatiavõimet ja loovust. Ilukirjanduse lugemine aitab noortel paremini mõista erinevaid inimesi ja ka olukordi sest ilukirjanduse lugemine aitab noortel aru saada erinevaid vaatenurki ja lisaks aitab ka arendada intelligentsust. Kui noored peaksid lugema lühemaid või isegi pealiskaudseid tekste võib see piirata võimet süvenduda. Fantaasiaraamatud saavad avardada noorte maailmapilti ning arendada loovust. Näiteks on J.K. Rowlingu „Harry Potter“ olnud noortele esimene kokkupuude eetiliste dilemmade ja sõpruse tõlise tähendusega.\nTänapäeval on lugemisharjumus väga palju muutnud. Noored eelistavad lugeda lühemaid ja kergeid tekste, mida nad leiavad sotsiaalmeediast. Lisaks tahavad paljud noored lugeda ka inglise keelseid tekste või tekste, mis paiknevad kuskil välismaal, noored isegi tahavad lugeda selliseid romaane, mille pealkiri on teises keeles aga terve raamat on ikkagi emakeeles. Lugemisharjumus aitab ka noori vaimselt ning lugemine võib neid tutvustada uutele tunnetele, mida nad pole varem tundnud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('54c1fa0e-bb29-4c8e-a14c-ca89abbc95c4', 'title', 'Miks noored tänapäeval aina vähem loevad?');
