INSERT INTO core.text(id, content)
VALUES ('f9ba963f-0393-4bf6-8537-ef22ab4a7527',
        'Tänapäeva ühiskonnas ja noorte seas on tuttavaks saanud sõna suunamudija. Suunamudija on inimene keda teised inimesed ehk vaatajaskond jälgib läbi sotsiaalmeedia. Teda kuulatakse ja võetakse talt nõu. Neil on lihtne muuta noorte mõttemaailma ja arvamusi kuna, noored kuulavad neid. Miks see nii on ja kuidas nii on väjakujunenud?\nSuunamudijaid on tuhandeid keda igapäevaselt jälgitakse. Neid on väiksema jälgijaskonnaga ja suuremaga. Tavaliselt suurema jälgijaskonnaga suudamudijatel on rohkem noori kes neid jälgivad ja tahavad samastuda nendega. Mõjutavad nad neid noori oma väljaütlemistega, maailmavaadetega ja reklaamidega toodetele. Kõige tavalisem mis juhtub on see, et sisulooja reklaamib mingit toodet ja järsku kõik jälgijad tahavad seda toodet, kuna nende jälgitav või iidol kasutab seda. Kuid siiski inimesed ei arvesta sellega, et toode ei pruugi neile sobida ja ilma piisava taustauuringuta nad ei oleks teadnud seda et, neil pole vaja seda toodet. Nii saab sisulooja oma raha ja firmad hea revenüü oma toodetest. \nSamastumine suunamudijatega on teemakohane ja noorte seas populaarne. Kuna inimesed on tänapäeval erinevate mõtete ja iseloomudega siis igaühele sama sisulooja ei sobi jälgimiseks. Kuna inimesed samastuvad suunamudijaga siis kuulavad rohkem tema nõuandeid, sest ju tegelikult on sarnased kogemused ja arvamused. Jagatakse oma mõtteid ja kogemusi. „Uuringutest on selgunud, et tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida ihaldada, mida põlastava pilguga vaadata, kuidas kellegagi suhelda.“ See näitab, et võetakse suunamudijatelt nõu ja tahetakse samastuda nendega kuigi tegelikult võiks inimene siiski omamoodi mõelda ja enda mõtteviisiga olla mitte teise inimesega samasugune.\nMõnikord on hea kuulata avaliku elu tegelasi. Näiteks kui on mingid kampaaniad nagu loomade aitamine jne, siis täitsa tasub neid kuulata ja vaadata mis neil selle kohta öelda on. Mõned reklaamivad neid kampaaniaid teades, et see ongi heategevus ja kõik võiksid neid toetada ja suunamudija tahab ise näidata, et ta hoolib. Näiteks on toodud välja #loomadesilmis mis on heategevus kampaania, mis kutsub inimesi üles karusloomadest hoolima ja mitte nende nahku endale soetama. Need suunamudijad panevadki ka noored selliseid asju toetama tänu oma mõjuvõimule ja siis ka noored hoolivad loomadest ja nende tulevikust maailmas. \nSuunamudijad mõjutavad suurt osa noori. Toodete reklaamimine neile ja kuna noored kuulavad siis, pimedalt ostetakse esemeid ja ei mõelda kas on vaja neid või mitte. Kuulatakse ka sellepärast, et samastutakse nendega mis tekitab sideme ja mõttekäigu millepärast noored suunamudijat jälgima hakkavad. Vahepeal on suur jälgijaskond hea siis saab reklaamida kampaaniaid ja kui jägijaid on palju siis on kampaanial rohkem aitajaid ja see jõustub paremini. Suunamudijate mõjul on nii pluss külgi kui ka miinus külgi, mis tulevad välja.');
