INSERT INTO core.text(id, content)
VALUES ('961969c9-2381-4a1f-8777-6651c7a2a26e',
        'Tänapäeval leiavad noored meelelahutust peamiselt internetiavarustest. Interneti suurim haru on kahtlemata sotsiaalmeedia, kus tegutsevad inimesed, kelle töö on vähemal või rohkemal määral teiste suunamine. Sotsiaalmeediat kasutades, tekib peaaegu igal kasutajal lemmik või lemmikud suunamudijad, kes tihti on meile suureks eeskujuks.\nCrystal Abidini uuris,  mille abil suunamudijad oma publiku tähelepanu köidavad ning tõi välja neli peamist omadust. Üks omadustest, mis võidab inimeste südameid on internetikuulsuse elulisus. Elulisus ja elulähedus tähendab seda, et meediastaar on enda jälgijatega täielikult avameelne ja aus. Näitades, et ka tema ise on täiesti tavaline inimene ja tegelikult ei erine tema elu palju tavainimese omast. Suunamudija mitte ei näita enda elu häid külgi, vaid ka elu pahupoolt ja elus esinevaid probleeme. Selline läbipaistvus vaatajatega tekitab neis meelerahu samastumisega. Kui noor teab, et ta ei ole oma probleemiga üksi, annab see teadmine kindlasti lootust, et probleemile on lahendus. Kuid tuleb meeles hoida, et jälgija ei tunne sisuloojat isiklikult ja ei saa teda lõpuni usaldada. „Juba 1956. aastast pärit parasotsiaalsete suhete teooria kohaselt tekib meedia vahendusel inimestel illusioon, et meediastaar on nende lähedane tuttav, keda tasub usaldada“. Sageli juhtub, et arvamused ja väärtused kujundatakse täiel määral nähtust ja kuuldust sotsiaalmeediast. Omad vaated tuleks luua enda peaga mõeldes ja mitte lasta ennast mõjutada teiste nägemustega maailmast.\nArtikklis „Sotsiaateadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir“ mainiti, et internetipetturil ja sisuloojal võivad olla samad eesmärgid. Kelm tegutseb internetis omakasupüüdlikult inimesi kuidagi mõjutades või neilt midagi välja pettes. Tavaliselt tehtakse seda varjatud teel ning peidetakse oma identiteeti, kuna tegemist on kuritööga. Kõige sagedamini leiutatakse erinevaid skeeme raha teenimiseks ohvriks langenud inimeste arvelt. Kuid mõned suunamudijad suudavad petta ja valetada nii osavalt, et keegi ei oleks sellist tegu neilt kunagi osanud arvata. Paljud internetikujud on sotsiaalmeedias teise persoonaga erinevalt enda päris isiksusest, et inimestele rohkem meeldida. Kui see kuju suudab inimestele tõesti väga sümpatiseerida, on ka manipuleerimine lihtsam. Tuleb olla ettevaatlik ning teha alati faktikontrolli enne suunamudija jutu uskumist või kuhugi raha paigutamist. „... võimalusel tuleks alati kasutada faktikontrolli. Eriti kui mängu tulevad rahalised kohustused, tasub kodutöö ära teha ja mitte jälgida teatud mõjukuse saavutanud suunamudijate nõudeid pimesi“. Ei tasu ka arvata, et iga sotsiaalmeedia tegutseja taga on varjatud hüved, aga tuleb teada kuidas internetis turvaliselt käituda ning mida kuulda võtta.\nKokkuvõtteks hindavad suunamudijate toetajad kõige rohkem siirust ja autentsust tehtud sisu juures. Jälgijad saavad läbi selle ennast samastada sisuloojaga. Kuid ei tohi segamini ajada, keda on näha vaid väreleva pildina ja kes on päris usaldatud  sõber.');
