INSERT INTO core.text(id, content)
VALUES ('7afd31c3-8586-4c60-9fa2-98078e253d55',
        'Tänapäeva noortel puudub harjumus ja võib ka öelda, et tahe lugeda raamatuid, artikkleid, ajalehti või muid kirjanduslikke  tekste, mis ei ole kohustuslikud. Sõna ``lugemine`` tuleks igal inimesel enda jaoks lahti mõtestada, mida see tähendab üldpildis ning miks see on kasulik. Lugemisel on nii positiivseid kui ka negatiivseid tagajärgi, mida tuleks meeles pidada.\nKui rääkida lugemisest, kui selle tähendusest, siis on lugemine kõige lihtsamalt öeldes teksti või loo läbi töötamine ja selle mõistmine ning enda jaoks arusaadavalt lahti mõtestamine, mis võib osutuda arvatust keerulisemaks. Lugemine ise on kasulik inimesele mitmest vaatepunktist. ``Funktsionaalne lugemisoskus on põhiline tänapäeva maailmas elamise eeldus ja alus.`` Lugemist läheb vaja peaaegu igal pool. Koolides, töö juures, teatrites ja paljudes teistes kohtades. Koolis on vaja lugeda kohustuslikku kirjandust, matemaatika tekstülessandeid ning teatris on vaja lugeda näitlejatel teksti, et etendust läbi viia. Ilma lugemisoskuseta inimene hakkama ei saa. \nLugemine, kui negatiivne mõju inimesele. Poepidajad ütlevad, et ``ingliskeelse pealkirjaga raamatud on ainsad, mida noored ostavad või loevad``, mis võib tuua kaasa inimeste eesti keelsete tekstide väärmõistmise või isegi keele hävingu. Kui keegi enam ei loe eestikeelseid tekste võib keel ununeda või lugemine raskelt välja tulla, kuna inimene on harjunud nägema ja lugema teist keelt. Samuti ei ole piisav eesti keele lugemine enam nii sorav ning lihtsate sõnade tähendust ei teata. Inimene võib halvimal juhul muutuda kinniseks ning suhtluse enda ümber inimestega katkestada või üldse kaotada, sest raamat on justkui tema ainus sõber ja mugavustsoon, kust pole lihtne välja tulla. Noored ei ole ka harjunud lugema kirjandust lihtsalt niisama ilma kohustuseta, kuna kõik on olemas internetis, mis tähendab, et noorte aju ei pruugi olla nii mitmekülgne, kui peaks. \nLugemine, kui positiivne mõju inimesele. Kui inimene loeb iga päevaselt või isegi iga nädal ühe raamatu, siis aju areneb ja on vastuvõetavam uutele sõna kasutustele või väljenditele. Enda ümber olevatest inimestest on võimalik paremini aru saada, kui kasutada samu väljendeid, mida nemad ning selliseid ütlusi mõista, mida kuuled. Lugemine täidab ka vaba aega nagu ütleb tekstis Tiit Hennoste, sest lugedes inimene ei veeda nii palju aega ekraani ees olles ning inimese aju on pärast puhanum ja vastuvõtlikum uuele informatsioonile. Samuti ajumaht võib väheneda ning tuua kaasa inimaju arengu langemise või vähenemise.\nKokkuvõtteks võib öelda, et noored peaksid rohkem hakkama lugema, et nende keeltes püsiks nende emakeel ning oskus lugeda teksti soravalt ning mõista teksti sisu ja tuuma. Vaba aja võiks sisustada lugedes, mitte telefonis ekraani sõrmitsedes.');
