INSERT INTO core.text(id, content)
VALUES ('da685768-2e0f-4ee3-8a7a-af92718256ff',
        'Viimaste aastate jooksul on sotsiaalmeedias esinenud suunamudijate buum. Noori mõjutab nende keskkond ja sellest tulenevalt ka nende arvamused. Nad kuulavad neid, keda nad austavad ja tänapäeval on see üha rohkem keegi sotsiaalmeedias.\nJärjest rohkem on inimesi, kes jälgivad erinevaid influencereid sotsiaalmeedias. Paljud tahavad enda lemmikute tähelepanu ja seda nad vahel saavadki, aga sellega käivad kaasas probleemid. Nagu Maria Murumaa Mengeli artiklis „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?“ mainis, on sellega kaasnenud ka parasotsiaalsed suhted. Nendes suhetes näevad inimesed sisuloojad kui oma sõpru. Tihti kaitsevad ja kuulavad nad oma lemmikute arvamusi pimedalt ilma, et nad sellel teemal end hariksid. Selleks on hea näide suunamudija Andrew Tate, kes oli vahel väga tuntud just poiste seas. Ta tihti rääkis kuidas naised peaks meestele alluma ja kuidas tõeline mees olla. Oli palju noori, kes tahtsid nagu tema olla, ignoneerides ta seksismi ja kaitstesid mehe arvamusi, öeldes, et tal on õigus. Kui ainult sellist sisu tarbida,  muutuvadki aja möödudes nende noorukite mõtted ja otsused selliseks nagu nende lemmikud. \nInfluencerid on muutnud ka inimeste nägemusi ilust. Muutes oma pilte tundmatutele tasemetele ja kustutades kõik sobimatu, näitavad nad publikule ainult enda parimat. See on ka põhjus miks üha enam noori enda välimust kosmeetiliselt ja operatsioonidega muudavad. Hea näide sellise standardi kohta on Kyle Jenner, kes on aastaid iluprotseduure teinud ja näeb tundmatu välja, kui vaadata naise nooremaid pilte. Temal on aga võrreldes noorukitega, kes teda jälgivad üüratult palju raha, millega oma välimust muuta. Selline asi põhjustab noortel enesetunde langust, nähes mitterealistlike ilustandareid ja soovides nad oleksid nagu oma lemmikud sisuloojad.\nJärjest rohkem usaldatakse suunamudijaid toodete ostmises. Juhan Hellermaa tekstis „Sotsiaalteadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir“ kirjutatakse, et kui asi on rahalistes otsustes, on inimesel mõtekam ise toote kohta infot otsida ja mitte pimesi suunamudija nõuandeid jälgida. Vahel peab ka mõtlema, et kas seda asja, mida reklaamitakse inimesel tegelikult vaja on. Kuigi videos võib tunduda, et influencerile asi meeldib ei saa selles kunagi kindel olla. Nagu Juhan Hellermaa ütles: „Samas on aina raskem eristada, kas sisuloojale endale tõepoolest meeldib mõni film ja toode, või ta teeb seda reklaamina rahalise tasu või mõne muu hüvitise tõttu.“\nSuunamudijad kontrollivad noorte maailmavaateid ja oste üha enam. On tähtis olla tähelepanelik ja jätta meelde, et nende arvamus pole parem kui teiste oma. Samuti peaks noored silmas pidama, et see, mida need influencerid teevad on nende töö ja nad ei ole professionaalid, kelle sõnu kergesti usaldada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('da685768-2e0f-4ee3-8a7a-af92718256ff', 'title', '„Suunamudijate tagajärjed noorte elus“');
