INSERT INTO core.text(id, content)
VALUES ('a42cdca6-3462-4fad-8f08-2ccaf6e3165a',
        'Tänapäeva noorete lugemisharjumuste vähenemisega on seotud mitmed tegurid. Paljud noored võtavad lugemist rohekm kohustusena kui hobina või viisi, et laiendada oma silmaringi ja puudub tegelik huvi raamatute vastu. Noorte lugemisharjumusi mõjutab tugevalt ka sotsiaalmeedia, millest satutakse kiiresti sõltuvusse. Lugemishuvi kadumise tõttu vähenevad noortel funktsionaalse lugemise oskused ja nad jäävad ühiskonnas hätta. \nPaljud tänapäeva noored võtavad lugemist kui kohustust. Tiit Hennoste väitis, et tema nooruses oli lugemine pigem vaba aja täitmine, mitte kohustus. Näiteks tänapäeval loevad paljud õpilased ainult selleks, et saada positiivne hinne kirjanduse tunnis. Lugemist kohustusena võttes tekib pigem tülgastus raamatu lugemise vastu kui huvi. Sellepärast ongi väga tähtis luua endale positiivne mõtteviis. Mõelda, et tahad seda raamatut lugeda kuna see huvitab sind, mitte et see on kui kohustus. Noored ei võta lugemist kui võimalust, et avardada oma silmaringi ning arendada oma funktsionaalse lugemise oskuseid, vaid eelistavad veeta oma vaba aega pigem sotsiaalmeedias surfates. Kuna sotsiaalmeedia on suureks sõltuvuseks, võib olla noorel raske oma telefon käest panna ja pikaajaliselt keskenduda raamatu lugemisele. \nLugemisharjumuste vähenemise põhjuseks on ka sotsiaalmeedia ja nutiseadmete areng. Kuna me elame ajastul, kus kasutatakse palju nutiseadmeid, ei teki inimestel tahet oma küsimustele vastuseid saada pikki tekste lugedes. Palju kiirem ja tõhusam viis on küsimused nutiseadme otsingusse kirjutada ja saada oma vastus sekunditega. Noored proovivad leida viise, kuidas mugavamalt ja kiiremini erinevates olukordades toime tulla, aga just on tähtis seista raskuste ja väljakutsetega silmitsi, sest just nii on võimalik midagi uut õppida ja ennast proovile panna. Samuti paljud noored eelistavad e- ja audioraamatuid rohekm kui paberraamatuid. E- ja audioraamatuid on mugavam lugeda endale meelepärases kohas ja sobival ajal. \nSotisaalmeediast ja lugemist kui kohustust võtmisega tulenebki noortel lugemisoskuste allakäik. Funktsionaalse lugemise oskused järjest vähenevad, kuna ei treenita oma lugemist igapäevaselt. Noortel tuleb ette raskusi tavaliste tekstide mõistmisega ja nad jäävad ühiskonnas hätta. Väheste lugemisharjumustega ei arenda noored oma sõnavara piisavalt. Kõige raskemalt mõistetav keel on just ilukirjanduses. Seal oli väga lai ja ka raskesti mõistetav sõnavara. Aga, et seda parandada tuleb endale luua harjumus lugeda ja see algab vaid iseendast. Tuleb võtta endale kohustus, et teatud ajavahemiku jooksul lugeda läbi kindel arv raamatuid. Võimalik, et just pidev lugemine süvendab huvi ka lugemisega jätkata kui hobiga, mitte ainut kui kohustusega. \nPeamine põhjus miks noorte lugemisharjumused aina vähenevad on see, et lugemist võetakse kui kohustust ja puudub positiivne mõtteviis, et enda silmaringi avardada ja raamatute vastu huvi tunda. Tihti minnakse kergemat teed, et oleks lihtsam, kuid nii ei saa noored ennast proovile panna ja vajalikud oskused jäävad saavutamata. Sellest ongi tingitud tänapäeva noorte lugemisoskuste allakäik.');
