INSERT INTO core.text(id, content)
VALUES ('9714c2a0-72d3-4ef1-b4e7-f6bae8f5c222',
        'Harjutada noori lugema on tähtis, kuna lugemisel on palju positiivseid tagajärgi. See võib tulla suuresti kasuks tulevikus, kui on vaja aru saada keerulistest bürokraatia tekstidest, mõista dokumente millele allakiri antakse ja üleüldse laiendada maailmavaadet. Noortele aga on muutunud lugemine keerukamaks juba 1990. aastate algusest ning nutiseadmed on sellele rohkem hoogu andnud. Kui aga noored loevad, siis enamasti ei loeta Eesti keelseid raamatuid vaid Inglise keelseid, sest need on palju populaarsemad ning lähevad noortele rohkem peale.\nNoorte lugemis oskus mõjutab nende aju arengut ja kasvu ning võib juhtuda, et lugemisharjumusega inimesed on rohkem intelligentsemead ning neil võib olla vanemas eas osavama suhtlemis oskus, parem sissetulek ja üleüldse tervem vaimne tervis. Rikkalikum sõnavara aitab ka ennast väljendada paremini erinevate keerukamate sõnade abil, sest alati ei pruugi lihtsamad sõnad olla mingi asja, tegevuse või tunde väljendamiseks piisav ning midagi võib jääda puudulikuks või arusaamatuks. Kuid kui selgitada midagi sellist inimesele kelle sõnavara pole nii arenenud, võib jällegi tekkida segadus nende omavahel.\nNoorte seas on muutunud eriti vabal ajal lugemine ebapopulaarseks ning seda peetakse pigem igavaks ja vaevarikkaks tegevuseks. Kui vaadata tänapäeva aega, kus nutiseadmed on noortele palju kättesaadavamad siis võib õelda, et raamatud ongi igavamad kui nutiseadmed, sest nutiseadmed pakuvad lihtsamini ilma erilise vaevata ligipääsu huvitavale infole ja see annab palju kiiremini suurema koguse dopamiini kui raamatud. Kindlasti on ka tänapäeval teisi eri võimalusi vaba aja veetmiseks ning ei saagi öelda, et noored ei loe raamatuid ainult sellepärast, et kõik on tänapäeval nutiseadmetes. Pigem on nutiseadmed laiendanud noorte vaba aja veetmis võimalusi ning selliseid võimalusi tuleb alati juurde ja raamatute lugemine muutubki paljude noorte jaoks igavaks kui on võimalus tegeleda millegiga mis neid tõeliselt huvitab. – Tauno Vahter „Tõsiselt häid tulemusi noorte lugemisharjumuse suurendamisel ei ole ja pigem ei tule“\nPaljud noored harrastavad lugeda pigem Inglise keelseid raamatud kui Eesti keelseid, sest kogu nutimaailm on täis Inglise keelt ning see keel omandatakse tänapäeval vägagi kiiresti, tänu pideva Inglise keele vajadusele ja selle kasutusele nutiseadmetes. Inglise keelse raamatu valikud on kordades suuremad kui Eesti keelsed ning Inglise keelseid raamatuid reklaamitakse ka väga palju sotsiaalmeedias, mis paneb noori rohekm huvi tundma ja neid lugema.\nKokkuvõtteks võime öelda, et lugemine aitab ja mõjutab meie arengut, ning sellise harjumuse külge harjutamine on väga tugev enesearengu etapp. Nüüdseks aga on ühiskond muutunud ja raamatute lugemis populaarsus on langenud paljude teiste vaba aja veetmis võimaluste mõjul ja otseselt ei saa mitte keegi teine peale iseenda sundida kedagi teist lugema ükskõik mis keelseid raamatuid ja mõjutada lugejate hulka, sest ühiskond muutub pidevalt ja vahest peab leppima muutustega.');
