INSERT INTO core.text(id, content)
VALUES ('3bae89cc-09b2-4eab-92bd-2e7636fa7ebc',
        'Raamatutel on olnud määratult suur roll ühiskonnas juba mitmeid sajandeid. Lugedes saab treenida enda aju, saada uusi teadmisi laiendades silmaringi ja üldiselt aega veeta. Tänapäeval on aga raamatute populaarsus aina kahanenud ja sellel on mitmeid põhjuseid. Peamine on see, et raamatud on asendunud nutiseadmetega, ning meedias ringi surfamine on meeldivam tegevus, kui raamatu kätte võtmine. See-eest tänu nutiseadmete kompaktsusele on võimalik lugeda raamatuid peaaegu kõikjal, mis võimaldab inimestel rohkem lugeda. Lugemine on aga ikka järk-järgult ebapopulaarsem ja inimesed loevad palju vähem, kuid miks see nii on?\nViimase sajandi jooksul on tehnoloogia areng olnud meeletu, seda eriti viimase 40 aasta jooksul. Telefon, arvuti ja teised nutiseadmed on saanud osaks enamiku inimeste igapäevaseks vahendiks, ning ka selle tõttu on raamatud jäänud aina rohkem tagaplaanile. Palju lihtsam on võtta näppu telefon ja hakata sotsiaalmeedias ringi uurima, mänge mängima, artikleid lugema ja muud sellist, kui raamatut lugeda. Sellest on ka rääkinud Tiit Hennoste enda tekstis „Lugemis harjumuste harjutus“, et inimesed on juba harjunud olema pidevalt telefon käes ja kasutuses. Tema sõnul on ka lugemise asemel palju muud teha, et vaba aega veeta, kuid samas oli selleks enne nutiseadmeidki rohkem kui piisavalt tegevusi. Noored enam ei tunne erilist huvi raamatute vastu, ning on lugemisele leidnud asenduse.\nTänapäeval saab lugeda lihtsamalt, kui kunagi varem. Nutiseadmeid küll süüdistatakse lugemise kahanemises, kuid teisest küljest on erinevad rakendusi ja seadmeid spetsiaalselt loodud selleks, et saaks kõikjal lugeda. Selleks on loodud mitmeid lahendusi, nagu Kindle, mis on seade kuhu saab raamatuid alla laadida ja neid interneti vabalt lugeda. Peale selle on olemas ka audioraamatud, mida saab kuulata kus iganes, see annab võimaluse ka tutvuda raamatu sisuga näiteks autoga sõites, tööd tehes jms. Ajuteadlane Jaan Aru on rääkinud intervjuus, kuidas sellised lahendused on võimaldanud temal ka reisides raamatuid lugeda, ilma et peaks endaga kaasas kandma mitmeid raamatuid. Peale selle rääkis ta sellest kuidas on mugavam lugeda näiteks telefonist olles ise selili. Nutiseadmed võivad kahjustada lugemise populaarsust, kuid see-eest pakuvad ka häid lahendusi selleks.\nMitte lugemisega võivad kaasneda ka tagajärjed, mis mõjutavad inimese enda lugemist ja ajuvõimekust. Kui inimene ei loe raamatuid, kaob temal funktsionaalse lugemise võime. On tõestatud, et hea lugemisoskus ja vabal ajal raamatute lugemine tagab kindlama tuleviku, paremad hinded ja rohkem treenitud aju. Sellest probleemist on ka rääkinud Tiit Hennoste tekstis „Lugemis harjumuste harjutamine“, et mitte lugemisega kaob funktsionaalse lugemise võimekus, mille tõttu ei mõista inimene mida temalt küsitakse. See probleem ulatub koolis olevatest matemaatika harjutustest, kuni suurte lepinguteni ja võibolla inimene ei mõista, mida temalt küsitakse. Aju on vaja lugemisega treenida et oleks lihtsam aru saada ja mõista tekste, mida loetakse.\nTeada tuntud on see, et tänapäeval loetakse aina vähem raamatuid ja tekste, selleks on ka mitmeid põhjuseid ja ka tagajärgi, mis sellega kaasnevad. Kaob funktsionaalse lugemise võimekus, silmaring kitseneb jms. Samas aga pakutakse mitmeid lahendusi selleks, et inimesel oleks lihtsam ja mugavam lugeda oma igapäevases elus.');
INSERT INTO core.text_property(text_id, property_name, property_value)
