INSERT INTO core.text(id, content)
VALUES ('d7c13971-efc1-4d00-9cff-bedf9823cdd4',
        'Noorte tahe lugeda paberraamatuid on aina vähenemas tänapäevases ühiskonnas. See on toonud endaga kaasa palju arutelusid ning läbi viidud uuringuid noorte seas, mis võivad olla selle põhjuseks, et tänapäeva noored eelistavad tegeleda vabal ajal millegi muuga, kui raamatu lugemisega. Raamatute lugemine kaotab oma populaarsust noorte seas erinevate tegurite mõjul.\nLugemine ei ole noorte seas ära kadunud täielikult. Peale selle, et raamatute lugemine on tänapäeval kaotanud palju oma populaarsusest, leidub ikkagi väga palju noori, kelle igapäevasse tegevusse kuulubki raamatute lugemine ning seda tehakse enda vabast ajast. Tiit Hennoste tekstist ``Lugemise harjumuse harjutus`` on välja toodud läbi viidud uuringute põhjal, et need lapsed, kes tegelevad enda vabal ajal lugemisega saavad tulevikus parema hariduse, sissetuleku ja tervise. Raamatute lugemine laiendab ka noore silmaringi ja sõnavara. Sellele on võimalik tuua paralleele päris eluga, kuna tõesti tihti nii ongi. Juba need lapsed, kellele on raamat kätte antud kõigest paari aasta vanusena, neil on lihtsam alustada oma kooliteed ning edasine areng ei pruugi toimuda nii vaevaliselt võrreldes nende lastega, kes pole enne koolitee alustamist mingit algust teinud. Raamatute lugemine võib ka olla väga lõõgastav ja meeldiv tegevus. Tihti on see lõõgastav, kui loetakse endile meelepärast raamtut. Seda on välja toonud ka Jaan Aru oma intervjuus, kus räägiti et endale meelepärase raamatu lugemine võrdub kui puhkusega.\nRääkides sellest, et väga palju noori eelistavad tegeleda oma vabal ajal millegi muuga kui lugemisega, on tänapäeval üheks suurimaks teguriks aina populaarsust koguvad nutiseadmed. Juba noorest saati puutuvad lapsed kokku nutiseadmetega nagu televiisor, tahvelarvuti, mobiiltelefon jne. Selle süüdlaseks võib pidada nende laste vanemaid, kes juba noorelt harjutavad lapsi televiisori ees istuma ning lapsel ei pruugigi tekkida tahet võtta kätte lasteraamatut. Tänapäeva tehnika on nii arenenud, mis teeb võimatuks selle, et kellegil peaks kunagi igav hakkama. Nutitelefonid on täis on erinevaid mänge ja äppe, kus saab hommikust õhtuni vaadata multikaid ja filme. Olles ekraanil silamdega kinni tunde ei mõeldagi tihti raamatu lugemisele. Mugavust leitakse tihti tegevuses, kus ei pea nii palju pingutama ega analüüsima, milleks võib olla näiteks TikTokis scrollimine.\nVähenenud raamatute lugemise põhjuseks võib ka olla koolis antav kohustuslik kirjandus. Kohustuslik kirjandus ei pruugi alati tunduda kõige põnevust tekitav ning see võib tihti tekitada ebameeldivust raamatute suhtes. Kuigi kohustusliku kirjanduse lugemine on väga kasulik kuna, tihti antakse just õpetajate poolt neid teoseid, mis suurendavad silmaringi.\nKuigi lugemine noorte seas kaotab oma populaarsust on seda alati võimalik sisse harjutada. Kunagi ei ole liiga hilja tekitada huvi kirjanduse vastu ja iga õhtu mingi põnev raamat kätte võtta enne magama jäämist. Seda on võimalik teha ainult oma motivatsiooni ja tahtejõu abil.');
