INSERT INTO core.text(id, content)
VALUES ('fefbca95-9441-47a1-ad01-9e34d5c19adf',
        'Avaliku elu tegelased ja suunamudijad mõjutavad noorte igapäevaelu, otsuseid ja valikuid. Mõjuisikud köidavad publiku tähelepanu mitmete omadustega. Siiski tuleb olla tähelepanelik ja mõelda hoolikalt, keda tasub kuulata. Netikuulsused kas pakuvad kasulikku ja tõepärast sisu või maalivad endast eksitava pildi tegelikkusest.\nInternetikuulsused peavad omama midagi, mis teeb neid publiku jaoks huvitavaks. Influencer’id omavad tihti eksklusiivseid asju, mis pole tavainimesele kättesaadavad. See äratab jägijates huvi ja inspireerib neid. Näiteks räpparid Central Cee ja Playboi Carti postitavad instagramm’i pilte disainer riiete ja kallite esemetega. Noored näevad ägedaid riideid ja esemeid, mis inspireerivad nende stiili ning samuti motivatsiooni neid asju ise omada. Samuti on avaliku elu tegelased pildis seetõttu, et nad on oma ala meistrid. Noortel esineb erinevaid huvisi ja sotsiaalmeedia kujud näitavad oma ala tegemisi. Näiteks noor, kes huvitub suusatamisest võib jälgida vigursuusatajat Kelly Sildaru, kes inspireerib oma meisterlikkusega noort oma huvile pühenduma. Noorte jaoks on ka oluline samastumine sisuloojaga. Laulja Nessa Barrett on avatud oma mentaaltervisega. Tema jälgijaskond tunneb end turvaliselt, kuulates tema muusikat ja jälgides tema tegemisi sotsiaalmeedias. Sellised elulised avaliku elu tegelased annavad noortele lootust, et nad ei ole oma murega üksi.\nKuigi suunamudijad võivad luua köitvat sisu, tuleb olla ettevaatlik ja mõelda hoolikalt, kas mõjuisikut tasub kuulata. Suunamudijad võivad olla erinevate kavatsustega. Üks tahab jälgijatele soovitada toodet, mis talle tõesti meeldib, samal ajal teine soovitab toodet ainult seetõttu, et teda rahastatakse. Tegelikult on sisulooja proovinud toodet vaid korra video jaoks, kus ta seda sama toodet reklaamib. Mõni infuencer loob endast sotsiaalmeedia jaoks valeliku pildi. Videos näitab mõjuisik kui hea inimene ta on, kuid kaadrite taga paljastuvad tema mustad küljed. Sisulooja Anna Paul sattus hiljuti kriitika alla, kuna ta halvustas oma enda fänni. Anna Paul on teatud rääkimast teemal keha positiivsus. Pärast fänniga rääkimist oli ta hiljem kritiseerinud fänni keha ja välimust. Selliste juhtumite põhjal saab järeldada, et kõik sotsiaalmeedias kujutatav ei ole tegelikkus.\nSuunamudijatest võib siiski olla kasu, kuna reklaamitakse üritusi ja kampaaniaid, mis võivad pakkuda huvi noortele. Näiteks saavad noored teada oma lemmik artistide kontsertitest ja esinemistest kõige kiiremini läbi sotsiaalmeedia. Samuti teevad infuencer’id loosimisi ja jagavad sooduskoode. Sisulooja Marie-Lisete Tauts jagab oma tegemisi peamiselt instagram’is. Ta teeb koostööd erinevate brändidega ja seetõttu leiab pidevalt tema kontolt loosimisi ja sooduskoode. Samuti reklaamib ta üritusi, nagu näiteks kutsus ta noori ülesse osalema Nike jooksuüritusest. Jälgijad saavad seetõttu ideid võtta osa kasulikest üritustest nagu on õues liikumine.\nKui avaliku elu tegelased on noorte jaoks inspireerivad ja elulised, võivad nad aidata kaasa noorte motivatsioonile. Samuti saavad noored suunamudijate käest ideid osaleda kampaaniates ja üritustel. Mõjuisikute jälgimisega ei esine probleemi, kui noored on teadlikud, keda nad jälgivad ja usaldavad. Oluline on olla ettevaatlik ja jälgida ainult neid isikuid, kes on päriselt inspireerivad ja toovad ka jälgijale kasu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fefbca95-9441-47a1-ad01-9e34d5c19adf', 'title', 'Miks jälgivad noored suunamudijaid ja mida silmas pidada?');
