INSERT INTO core.text(id, content)
VALUES ('9f8accd4-cddd-443b-9969-f04216eec744',
        'Tänapäeval on internet ja sotsiaalmeedia suurem kui kunagi varem ja ajaga see aravatavasti ainult kasvab. Selle suuruse tõttu ei ole ime, et on tekkinud inimesed, kes on internetis kuulsused. Neid saab kutsuda mitut erinevat nime, aga üldiselt teatakse neid kui suunamudijaid. Nendel inimestel on suur mõju nooremate isikute elus.\nSuunamudijad mõjutavad nooremate generatsioonide elu, valikuid ja arvamusi. Suunamudijate mõju on võimalik näha üle kogu maailma, ka meil siin Eestis. Olles lihtsalt tänava peal, oodates bussijaamas bussi või jõusaalis käies ei ole harv juhus kuulda mingeid nooremaid lapsi rääkides tänapäeva meemidest või mis iganes sel hetkel internetis populaarne on. Tänapäeval on suunamudijad alustanud isegist oma firmasid, mis on eriti populaarsed noorte seas. Toodete nagu Prime või Lunchly peamised kliendid on nooremad inimesed ja on oma müükide poole pealt isegist ületanud vastas firmade müügi numbreid. See näitab, mis mõju võib olla suunamudijatel, kuigi tihti juutuuberi või instagrammeri nimi toote peal teeb seda kallimaks, eelistavad ikkagi paljud noored nende tooteid.\nSuunamudijad võivad avaldada ka negatiivset mõju noortele. Internetis võib igaüks kuulsaks saada ning selle tõttu saavad paljud inimesed võime mõjutada nooremate isikute arvamusi erinevate teemade kohta või mõjutada neid tegema halvemaid valikuid elus. See mõju võib olla neutraalne nagu lame maa uskujate arvamus, aga võib olla ka kahjulik nagu vaktsineerimis vastaste isikute mõju neile endile või nende järglastele. On ka isikuid, kes on saanud kuulsaks öeldes kahjulikke arvamusi või tehes midagi, mis võib kahjulik olla. Kuigi paljud inimesed on teadlikud, et nende isikute teod või arvamused võivad olla kahjulikud, ongi siiski mõned nooremad isikud, kes ei tea paremini ja omastab need samad arvamused või proovib sarnaseid tegusid.\nSuunamudijate mõju ei ole alati negatiivne, see võib ka väga positiivne olla. Väga kerge on internetis kuulda ainult halvast, aga tihti võib positiivne mõju olla isegist suurem kui negatiivne mõju. Internetis on võimalik leida paljusid mõjuisikuid, kes räägivad oma kogemustest, teadmistest, õpetavad või on lihtsalt meelelahutuseks. Sellised mõjuisikud saavad aidata inimestel kindlamalt oma valikuid teha või saavad neid õpetada elu kohta. Üheks selliseks allikaks on Youtube’i kanal HealthyGamerGG, mis räägib erinevatest mentaalsetest raskustest ja kuidas nendega toime tulla. Sellised kanalid lähevad Crystal Abidini välja pakutud erakordsus omadusse, kus suunamudijad on sellises alas eksperdid ja osakavad abi pakkuda.\nSuunamudijate mõju on suur ja lai, eriti nooremal generatsioonil, nende mõju võib olla nii positiivne kui ka negatiivne. Paljud noored võtavadki nõu interneti kuulsustelt ja see võib neid elus väga palju aidata või just vastupidi, kahju tuua.');
INSERT INTO core.text_property(text_id, property_name, property_value)
