INSERT INTO core.text(id, content)
VALUES ('d94af07c-78bd-459a-b973-57cffdb96576',
        'Tänapäeval on tehnoloogia ja internett tohutult arenenud ning väga paljud noored surfvavad netis ringi igapäevaselt. Internetis on kättesaadav igasugust kontenti, millest inimene võib huvituda. Selles ongi teema probleem, veebis leidub nii kasulikku kui ka kahjulikku sisu, millest noored on suuresti mõjutatud. Kuidas võivad aga sisuloojad oma noort vaatajaskonda mõjutada?\nNoored kasutavd paljusid keskkondi nagu YouTube, TikTok, Instagram jne. Nendes platvormides on neil väljakujunenud kindlad influeneceird, keda nad jälgivad. Kui mõnele tegelasele kasavb suur jälgijaskond, siis loetakse tema aravamust palju mõjukamaks, kui mõne teise isiku oma. Seetõttu kujunebki noore elu olles rohkesti mõjutatud sellest, keda ta internetis ülistab. Paljud on oma iidolidest vaimustuses ning tahavd elada ning olla nende moodi. Oma arvamsusi ja tõekspidamisi avalikult esitades mõjutatakse ka oma fänne. Paljud tuntud eestlased sealjuures ka noorte seas populaarsed juutuuberid Liina Ariadne Pedanik ja Martti Hallik osalesid kampaanias #loomadesilmis, mis kutsus inimesi üles mitte ostma karusnahkseid tooteid. Nooreamate inimeste silmaringi avardamiseks karusnaha tarbimise teemal, ning et nad kuulda võtaks ongi kampaanias kasutatud just neid isikuid, keda noored jälgivad ja kes neile päriselt korda lähevad.\nNagu on võmalik inimesi positiivelt mõjutada, saab neid ka valele teele suunata. Õpetajate Lehes artiklis „Kuidas suunamudijad meid mõjutavad?“ on öeldud järgmised laused: „Uuringutest on selgunud, et tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida ihadada, mida põlastava pilguga vaadata, kuidas kellegagi suhelda. Suunamudijate kaudu jõuab noorteni ka mitmeid baasteadmisi ja tüvikeste, sisuloojad isegi kujundavad neid.“ Avalikuelu tegelased nagu räpparid on ühed isikud, kes võivad noori negatiivselt mõjutada. Tihtipeale on räppilugude sõnad ropud ning lood räägivad ebasobivast käitumisest näiteks mõnuainete nagu alkoholi, tubakatoodete ja narkootikumide tarvitamisest. Alaealised lapsed, kes ei pruugi olla varem selliste asjadega kokkupuutnud muutuvad uudishimulikuks ja tahavd ka proovida, sest kui neile meeldiv inimene niimoodi käitub, siis miks ei võiks seda ka nemad ise teha. Ka ropendamise puhul, kui seda pidevalt kuulda, siis võib tunduda see tema jaoks normaalsena ning laps hakkab samuti ropendama, mitte pruukides aru saada, et see on tegelikult vale.\nSisul, mida individuaal internetis tarbib on väga suur tähendus, sest kõik, mida ta endale laseb sisendada mõjutab nii tema arvamusi, kui ka tema käitumist ning selle tagajärjel kogu tema elu. Võidakse mõnelt avalikuelu tegelaselt saada inspiratsiooni oma seisukohatde muutmiseks ja teha nende eeskujul otsuseid, mis muudavad isikut paremaks. Samas võivad noored olla nende poolt olla mõjutatud ka negatiivselt ning valede inimeste jälgimise tõttu oma elu untsu keerata. Sotsaalmeediat tarbides tuleb olla väga valiv, keda jälgida ja kes on kõige paremad eeskujud, et elada oma elu täisväärtuslikult. Lõppude lõpuks on ju nooruses tehtud valikud need, mis terve ülejäänud elu mõjutavad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d94af07c-78bd-459a-b973-57cffdb96576', 'title', 'Kuidas sotsiaalmeedias tarbiatv sisu mõjutab noore elu?');
