INSERT INTO core.text(id, content)
VALUES ('f11546eb-1394-4d12-a365-82c103f9ac2e',
        'Praegusel ajal on inimeste üle suur mõju sotsiaalmeedial ning seal tegutsevatel sisuloojatel. Kuidas ja milliste tegevustega nemad meie üle kontrolli saavad?\n Sisulooja on tavaline inimene, kes teeb tööd sotsiaalmeedias, nagu Youtube, Instagram ja Facebook. Nende töö on reklaamida asju või teenuseid, kellega nad juhuslikult koostööd teevad. Näiteks juutuuber teeb oma sisu Youtube platvormil. Üks tavalisemast viisist on vlogimine, näidates oma elu ning teha reklaami asjadel, mida neile saadetakse, või teenustel, mida nad kasutavad. Nad erinevad tavainimesest, kuna väga paljudel inimestel pole selliseid võimalusi, et kasutada teenuseid või asju, mida nad koostöödega endale saavad. Sisulooja on inimene, kellele meeldib tegutsemine ja loovus. Paljud sisuloojad on tantsijad ning teevad selle kõrvalt veel väga paljusid asju. Näiteks Kaisa Roon, kes on tantsutreener, ning selletõttu reisib koos oma tantsupartneriga ümber maailma, et õpetada paljudes riikides bachatat. Samuti teeb ta podcasti „Taskusõbrannad“ koos teise sisulooja Kaisaga. \n Vahepeal ei ole kõik inimesed sotsiaalmeedias hea põhimõttega. Sotsiaalmeedias on võimalik väga lihtsalt langeda petturite ohvriteks, kes esinevad sisuloojate nime alt. Näiteks kui sisulooja teeb oma platvormil loosi siis loosiõnne korral võetakse ühendust ning selleks, et oma võit kätte saada pead vajutama lingil, kuid seda linki avades võivad petturid saada nutiseadmest juba kogu vajaliku info sekunditega. Selliste võtetega saadakse enda valdustesse pangakontosid, aadresse ja muid isikuandmeid, mida pole mõistlik jagada. Kuna petturid lähevad järjest osavamateks peaks noored rääkima kindlasti sellistest asjadest oma pereliikmetega, et vältida petturite kätte sattumist.\n Samuti teevad sisuloojad väga palju heategusid. Tähtsustades looduse- ja loomadega seotud teemasid. Kuna sotsiaalmeedia pealmine sihtgrupp on noored, siis on see hea viis anda noortele teadmisi ja oskusi tuleviku päästmiseks. Loomade eestkoste organisatsioon Loomus alustab 31. jaanuaril, rahvusvahelisel karusnahavabal reedel ja ostuvabal päeval kampaaniat #loomadesilmis, mis kutsub inimesi mitte soetama endale karusnahka. Sellega on liitunud näiteks laulja Liina Ariadne Pedanik ja tema abikaasa Martti Hallik, kellel on sotsiaalmeedias väga palju jälgijaid. Keskonna teemad on ka väga levinud, ning sellega on seotud suur koristuspäev nimega „Teeme Ära“. \n Sotsiaalmeedia on tänapäeval väga suur osa inimeste maailmapildist. Inimesed saavad neilt teadmisi ja oskuseid, samuti ka soovitusi. Saadava infoga peab olema ettevaatlik ning info üle kontrollimine on vajalik. Inimeste üle saab kontrolli väga kiirelt ja lihtsalt, kuna inimesed usaldavad neid. Sisuloojad annavad väga häid pakkumisi, sooduskoode, mida kasutades võib teha liiga palju emotsioonioste.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f11546eb-1394-4d12-a365-82c103f9ac2e', 'title', 'Kuidas ja miks sisuloojad meid mõjutavad?');
