INSERT INTO core.text(id, content)
VALUES ('4365b2b0-a473-4bd2-9d47-3afb67fd601f',
        'Maailm on pidevas muutumises, sealhulgas ka ühiskond, teadus, kirjandus, inimesed ning nende harjumused, väärtushinnangud ja maailmavaated. Aegade ja ühiskonna muutumise ning tehnika arenguga muutuvad ka inimeste, eriti noorte eluviisid ja harjumused. Nagu on mainitud ka Tauno Vahteri artiklis „Peame leppima, et noored lihtsalt ei loe,“ on noorte lugemisharjumuste muutumine ja vähenemine olnud kõneaineks mitte ainult tänapäeval vaid ka mitmeid aastakümneid tagasi, näiteks 1932. aastal ajalehes Kaja ilmunud artikkel „Noorte lugemisoskus läheb tagurpidi“. \nÜheks põhjuseks, miks noorte lugemisharjumused on vähenenud, saab esile tuua ühiskonna ja koduste väärtuste muutumise. Kuna ajad muutuvad ja sellega ka inimesed, on vähenenud ka inimeste harjumus raamatuid lugeda, kodudes räägitakse raamatutest ja lugemisest vähem ning raamatutega üles kasvamine muutub järjest harvemaks. Varemal ajal, nagu Tiit Hennoste oma artiklis „Lugemise harjumuse harjutus“ ka välja tõi, oli raamatutega üleskasvamine tema nooruses ehk 1960. ja 1970. aastatel tavaline nähtus. Lugemine oli vaba aja täitmine, mitte kohustus, tänapäeval on leitud aga uuenduslikumaid viise, kuidas oma aega sisustada ning lugemine on koolides muutunud peamiselt vaid kohustuslikuks kirjanduseks. Sellega on ümber kujunenud ka noorte lugemisharjumused, sest raamatute kohta teabe saamine kodudes jääb vähemaks ning inimestel ei teki soovi või harjumust olla lugemisega ümbritsetud ka lihtsalt kodudes.\nPeale selle on toimunud ka väljapaistev areng tehnoloogia arengus. Lugemine on üheks vaba aja veetmise viisidest aga kuna on loodud nii palju erinevaid viise meelelahutuseks, on lugemine jäänud ka tagaplaanile. Tehnoloogia areng on eelkõige noortele andnud uusi alternatiive oma aja sisustamiseks peamiselt erinevate mängude, saadete ja muude kiirete tegevuste näol, mida on lihstam hallata ja mis on ka rohkem kättesaadavam. Loetakse põhiliselt just nutiseadmetes kui üldse, ning seda ka üha rohkem just lühikesi ja laialt levinud tekste. Seetõttu võib lugemine ka tulevikus muutuda just internetis tarbitavaks, mille pärast väheneb ka paberkandjal raamatute lugemine ja ostmine või üldse nende kodudes olemine muutub järjest harvemaks fenomeniks.\nTauno Vahter on välja toonud lisaks just üha populaarsemaks muutuva võõrkeelse, eriti ingliskeelse, kirjanduse tarbimise. Noored ostavad raamatuid, mis on ka tõlgitud või ongi mõnes muus keeles peale oma emakeele. Samuti on mõistlik välja tuua ka sotsiaalmeedia roll noorte lugemisharjumustes. Kuna sotsiaalmeedia on enamjaolt rahvusvaheline, toimub ka sealne suhtlus eelkõige just inglise keeles, mis toob noorte seas kaasa ka oma esmase keele kasutamise vähenemise. Sotsiaalmeediates levivad tekstid on peamiselt üksluised ning lühikesed, inimesed harjuvadki lugema lühemaid tekste ning raamatute lugemine muutub tüütuks, kuna ei saada kajastatud infot piisavalt kiiresti kätte. \nNoorte lugemisharjumuste muutumine pole vaid tänapäeval esile toodud probleem vaid seda on kajastatud läbi aegade. Kuna muutumas on ühiskond, tehnika, teadus ja kõik muu meie ümber, muutuvad ka inimeste harjumused ja tavad. Põhjuseid on mitmeid ja ka need võivad ajas järjest muutuda. Peamisteks põhjusteks võivad olla näiteks tehnika areng, ühiskonna ja inimeste koduste väärtuste muutumine ja ka kirjanduse tarbimise viisid ning keel. Inimeste eluviis muutub järjest kiiremaks ning sellest tuleneb ka vajadus info kiiremini kätte saada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4365b2b0-a473-4bd2-9d47-3afb67fd601f', 'title', 'Noorte lugemisharjumused ja nende võimalikud tagajärjed');
