INSERT INTO core.text(id, content)
VALUES ('b92e3834-e215-438d-acc2-5160e961bb9b',
        'Läbi sajandite on noortel olnud eeskujuks mingi isik, kelle sarnased nad tahaksid olla ning kelle maailmavaated huvi pakuvad. Tavaliselt on nendeks olnud lauljad, poliitikud, näitlejad ja muud kuulsused ehk teisisõnu avaliku elu tegelased. Viimaste aastatega on lisandunud nende sekka ka sotsiaalmeedia suunamudijad. Noored jälgivad õhinal nende tegemisi ning see väljendub teismeliste igapäevaelus. Kuidas siiski avaliku elu tegelased ja sotsiaalmeedia mõjuisikud suunavad noorte valikuid ja otsuseid?\nSuunamudijad seavad paika ilustandardid, mida noored valedel viisidel üritavad saavutada. Hetkel TikTokis laialt reklaamitud ravim Ozeptic aitab ülekaalulistel võtta alla ja näha välja ilus, kuid võib tuua kaasa tõsiseid terviseprobleeme, mida tihti sotsiaalmeediakuulsused ei maini. Samuti on blogijad normaalseks hakanud pidama Botoxit, mida süstitakse inimesele meelepärasesse kehapiirkonda, et see kaunim välja näeks. Noored soovivad nendega samastuda ning lasevad ka end süstida. Tegelikult on tegemist ikkagi mürgiga, mis kehas üldsegi olla ei tohiks. Paika seatud tänapäeva ilustandardid rikuvad noore keha, kuid ise nad sellest tavaliselt teadlikuid ei ole.\nAvaliku elu tegelased aitavad toetada parteide ja poliitikute populaarsust ning valimisi. Kuulsused jagavad oma mõtteid ausalt ja avatult ning näitavad üles elulisust, et inimesed nendega samastuda saaksid. Antud faktorit on oma artiklis maininud ka Maria Murumaa Mengel. 2024. aastal toimusid Ameerika Ühendriikides presidendivalimised Donald Trumpi ja Kamala Harrise vahel, mis oli laialdaselt kajastatud sotsiaalmeedias. Harrise toetaja Eminem esines debattidel ning avaldas kandidaadile avalikult toetust, mistõttu laulja austajad tema pärast ka kandidaadile oma hääle andsid. Seetõttu on avaliku elu tegelaste kaudu lihtsam noori mõjutada ja enda poolele saada.\nSotsiaalmeedia kuulsused aitavad noortel tõsta teadlikust erinevatest probleemidest ning suunavad neid õigesti käituma. Heas Kodanikus avaldatud uudises on Eesti suunamudijad kutsunud inimesi loobuma karusnahast ning tähele panema, kus materjali kasutatakse ning kuidas toodetakse. Sellisel viisil jõuab arusaam suurema lugejaskonna huvidesse ning situatsiooni hakatakse korralikult käsitlema. Samuti on laulja Selena Gomez teinud oma ilutoodete firma, mis avalikult oma sotsiaalmeedias kajastab probleemi, et ilutooteid ei tohiks katsetada loomade peal. Staaril on miljoneid jälgijaid, kes iga tema postitust tähele panevad. Sel viisil aitab ta tõsta noorte teadlikust loomakatsetuste vastu ning omakorda saavad inimesed neid teadmisi teistele edasi anda. Sotsiaalmeedia on üks lihtsamaid viise, kuidas noori suunata õigesti tegutsema.\nAvaliku elu tegelased ja suunamudijad aitavad paljugi nii probleemide kajastamisel kui ka teiste inimeste kuulsuse kasvatamisel. Läbi nende suunavad sisuloojad ka noori valikute ja otsuste tegemisel. Paremad teadmised nii loomakatsetustest kui ka karusnahast loobumisel annavad inimesele võimaluse oma teadmisi ka teistele edasi kanda. Siiski ei ole suunamudijate mõju kõige parem, kui seatakse ette ilustandardid, mida noored kangesti jälgida tahavad.');
