INSERT INTO core.text(id, content)
VALUES ('6a30a111-0bde-4998-972a-a495042ef3ef',
        'Tänapäeval on saanud väga kuulsaks trendide jälgimine. Neid algatavad ja reklaamivad igasugused kompaniid ja suunamudijad. Viimastelt võetakse eriti elus eriti palju eeskuju. \nPraeguses maailmas on palju mõjukaid tegelasi, kes saavad oma sõnade ja tegudega teisi end jäljendama panna. Üks sellistest inimestest on Andrew Tate. Tema on üks internetikuulsus, kes on tuntud oma rikkuse ja ebatavaliste hoiakute suhtes. Netis võib kohata mitmeid inimesi, kes tema sarnaselt üritavad käituda. Tema hoiakud väljanduvad keelekasutuses ja suhtumises ellu. Üks ta peamisi teemasid on rikkaks saamine, aga tema nõuanded sellel alal pole kõige paremad. Teine teda kuulaks tegev hoiak on rassism. Andrew Tate pole just kõige sobivam rollimudel, seda eriti noorte jaoks, ning tema suguste inimestega vestlemine ei ole paljude jaoks mugav tegevus, aga tema jäljendajaid on palju. Ta in üks vähestest näidetest inimesest, kes ei ole tänapäeva ühiskonnanormidele vastava käitumisviisiga.\nTate ei ole ainult sotsiaalmeedia täht, aga ta on ka oma asjade müümises väga kõrgel tasemel. Tema poolt alustatud on ka  internetiplatvorm „The Real World“. Tegu on peamiselt vestlusplatvormiga, aga seal saab ka läbida kursusi erinevate rikastumise viiside kohta. Müümise osa tuleb mängu selles, et sellise platvormile ligipääs on tasuline ning maksab mitukümmend eurot kuus. Samas sealne sisu pole väärt selliste hinda ning kõiki neid teadmisi leiab internetist tasuta. Veel üks tema ettevõtmisi oli krüptos, kus Tate üritas enda valuutat liikvele saada. See katse ebaõnnestus, sest selle väärtus langes järsult, aga ta ei kaotanud midagi, sest palju ostsid seda raha ning kõik nende kulud läksid Andrew Tate-ile. Rahalistest asjades ei ole väga soovitatav kuulata suunamudijaid, sest raha kaotamise oht on suur. \nÕnneks on ka teistsuguseid kuulsusi, kes pole tuntud ainult nende negatiivsete tunnuste tõttu. Sellised halva iseloomuga inimese moodustavad väikse osa kõigist suunamudijatest. Väga palju on inimesi, kes reaalselt tahavad teisi aidata. Nad võivad olla alates võhikust kuni oma ala eksperdini. Abi võib vaja minna ükskõik, mis eluvaldkonnas, olenemata selle tähtsusest. Tänapäeval on väga populaarseks saanud videomängud. On üks mäng nimega “League of Legends“, mis on juba ammu kuulus. Sellel mängul on väga palju mängjaid, kes tahavad paremaks saada. Paljud juutuuberid on võtnud oma südameasjaks nende aitamise. Üks neist on AloisNL, kes mängu, seletab lahti oma mõttekäigu ning miks ta midagi just nii teeb. Teda võib lugeda oma ala eksperdiks, sest ta mängib väga kõrgel tasemel. Abi pakkujaid on igal alal mitmeid ning tuleb eristada profesionaal võhikust.\nInternet on täis suunamudijaid, kes oma tegudega suunavad ka teisi. Paljud neist tahavad head, aga on ka mõningaid, kes ei tee heal ja halval vahet. Inimene peab ise otsustama, kelle sõnu ta tõena võtab ja kelle omi mitte.');
