INSERT INTO core.text(id, content)
VALUES ('24ab415e-dbb1-4a41-85d4-1b2a108ba74c',
        'Varem oli raamatute lugemine peamine tegevus ajaviitmiseks, kuid tänapäeval on märgata, et noorte lugemishuvi on vähenemas ning varsti võib see kaduda või millegi muuga asenduda. Raamatud on aasta tuhandeid olnud vahendid, millega edastada informatsiooni, levitada maailmavaateid ja säilitada kultuuri. Raamatute lugemise vähenemine võib kaasa tuua kogu inimkonda mõjutavaid probleeme. Miks tänapäeva noorte lugemisharjumus väheneb ja milliseid tagajärgi see toob?\nNoorte lugemishuvi mõjutab kõvasti ümbritsev keskkond. Juba põhikoolis antakse noortele lugeda kohustulikku kirjandust. Enamjaolt kuulub nende raamatute hulka vanemad raamatud, mis on kindlasti tähtsad Eesti kultuuriruumi tundma õppimiseks, kuid väga sisukad ja keerulised. Selliste raamatute lugema nii öelda sundimine võib noortele jätta halva mulje kõikidest raamatutest, ning seetõttu vähendada ka nende huvi lugemisse. Natuke aega tagasi ja võibolla isegi praegu kuulus põhikoolide kohustuslikku kirjandusse raamat „Meelis“. See pani mõtlema, et miks on noortel vaja lugeda  raamatuid, millel pole peaaegu mingit pistmist tänapäevaga, ning kas ei ole mõtekam panna noori lugema, midagi millega nad suhestuvad.\nSobiva raamatu leidmine võib osutuda keeruliseks. Noorte lugemishuvi vähenemise põhjuseks võib olla just see, et omale meelepärase raamatu leidmine on raske. Sellele aitab kaasa ka asjaolu, et raamatute valik aina kasvab iga aastaga. Inimestel on ka mõtteviis, et kui alustada raamatut tuleb see läbi lugeda, kuid tegelikult see nii olema ei pea. Kui sundida end läbi lugema raamatut, mis üldse huvi ei paku, võib sellega ka väheneda soov lugeda järgmisi raamatuid. Kuid kui lugeda raamatut, mis väga meeldib, võib inimene soovida lugeda veel sarnaseid raaamatuid ja nii edasi.\nNoorte lugemisharjumuste vähenemisega kaasnevad ka mõningad probleemid. Vähene lugemine kahjustab noorte keelekasutust ning halvendab ka nende eneseväljendus oskust. Lugemine on üks esimestest asjadest, mida koolis õpetatakse ja seda ka põhjusega. Lugemine aitab inimestel arendada oma sõnavara, keelekasutust ning ka mõttemaailma. Lugedes ükskõik millist teksti,  võib sellest olla tulevikus kasu mitmel erineval viisil näiteks töö leidmisel või eneseväljendamisel. Vähese lugemisega võib noore areng saada kahjustada.\nNoorte lugemishuvi on vastuvaieldamatult vähenemas iga aastaga. Põhjused, miks noortele raamatute lugemine huvi ei paku, on mitmeid. Üks põhjusteks on arvatavasti koolide ranged lugemiskohustused. Kuid noorte lugemisharjumust ei mõjuta ainult väline keskkond vaid ka noor ise. Raamatu valik on väga suur tegur noorte lugemisharjumuste mõjutamisel. Valides vale raamatu võib noore lugemishuvi kõvasti väheneda, ning sellega võib kaasneda ka mitmeid negatiivseid tagajärgi. Näiteks väheneb noore keelekasutus oskus ja üldine sõnavara. Kuigi lugemine pole veel kadumas on selle vähenemine jätnud sügavaid jälgi meie ühiskonda.');
