INSERT INTO core.text(id, content)
VALUES ('bfa08cc5-5473-4113-8b36-e43879459c1f',
        'Ühiskonnas leidub tavainimeste seast ka tuntumaid nägusid, isikud, kelle tegemistega on paljud kursis, keda kajastatakse televiisoris, internetis, ajalehtedes ja muudel meediaplatvormidel. Paratamatult peegeldub igapäevaselt meedias nende arvamus ning eelkõige mõjub see väiksematele, kes oma maailmavaadet veel kujundavad. Kuidas kuulsused noorte igapäevaelu, otsuseid ja valikuid suunavad?\nTihti näeme, kuidas mõni kuulsus on televiisorisse reklaamnäoks valitud, korraldab Instagrammis loosimänge või näitab Tiktokis, milliseid tooteid erinevad firmad talle saatnud on. Küll aga on ekraanivahendusel raske aru saada, kas toote soovitaja on siiras või eesmärgiks on siiski raha. Mõju, mis kõrvalt vaadates on ilmselge, kuid siiski on  reklaamiohvriks langemise tõenäosus suur, eriti noorte seas, kes on sageli umbusklikumad. 2019. aastal Hea Kodanikus avaldatud uudises „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“ on selgelt näha, kuidas mõtet karusnahkade negatiivsest mõjust üritatakse inimestele maha müüa kaasates kuulsuseid. Asjaolu, et reklaamimine on hästi tasustatud ning populaarne näitab, et järelikult on tarbijaid, kes selle põhjal oma otsuseid ja valikuid teevad ning sageli kasutatakse reklaamnäona suunamudijaid, et rohkem kõlapinda saada.\nInternetis leidub ka avaliku elu tegelasi, kes meeletamise või hirmutamise teel inimesi mõjutada üritavad. Just noored on sagedasemad ohvriteks langejad, sest tihtipeale, kellegi tegemisi pikalt jälgides ja tema poolehoidja olles, tunneb isik, et tegu on justkui usaldusväärse inimesega. Hetkel mil suunamudija kasutab valesid, et jälgijale meelepärane olla ning fänn samal ajal tunneb, et saab inimest usaldada, on olukord halb. Endalegi teadmata on jälgija saanud informatsiooni, mis ei vasta tõele, kuid usub seda pimesi. Kuulsuse näol on justkui tegemist arvamusliidriga, kes suudab mõjutada ka publiku mõttemaailma. Sellises olukorras on oluline fakte kontrollida, raskem on see kindlasti noortele, kellel on vähem elukogemust ning arusaama, mis võib olla tõde ja mis vale, eriti kui tegemist on niiöelda ilusa valega. Lektor Kristjan Kikerpill on öelnud: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid „kuulajatele meeldib“, siis see on probleem.“ Umbusklikuna võivad pahatahtlikud kuulsused inimest ära kasutada ning mõjutada tema otsuseid ja valikuid, kujundades tema igapäevast mõttemaailma.\nAvaliku elu tegelasi on meediaplatvormidel palju näha reklaamides, internetis, uudistes ja mujal. Pildis olles kujuneb neist arvamusliider, kes mõjutab tavainimesi. Eelkõige on mõjutatavateks noored, umbusklikumad ja väiksema kogemusega ja arusaamaga isikud. Kõige sagedamini suunavad kuulsused inimeste igapäevaelu, otsuseid ja valikuid, reklaamnäona tooteid soovitades. Lisaks kasutavad suunamudijad meelitamise või hirmutamise taktikat, millega mõjutatakse rahva mõttemaailma valedega. Nende viisidega on inimesed, pigem noored, igapäevaselt osaliselt kuulsuste mõju all ning teevad selle põjal ka oma otsuseid ja valikuid ning kujundavad enda igapäevaelu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bfa08cc5-5473-4113-8b36-e43879459c1f', 'title', 'Avaliku elu tegelased kui arvamusliidrid');
