INSERT INTO core.text(id, content)
VALUES ('73c3ce53-de88-4574-b2b1-37576b5dd3d2',
        'Viimase 50 või enamgi aasta jooksul on inimeste eludesse tekkinud aina rohkem ja rohkem viise, kuidas oma päeva sisustada mitmekülgsemalt. Mis põhjused langetavad noorte lugemisharjumusi?\nÜks põhjuseid, miks nii raamatuid kui ka teisi kirjandustekste loetakse vähe, on see, et nad näevad lugemist kui kohustust ja mitte ajaviidet. See võib tingitud olla sellest, et nad on harjunud pidevalt kasutama oma nutiseadmeid, ning nad on harjunud saama mitmekülgset infot ja seda ka mõne sõrme liigutusega. Tiit Hennoste räägib oma artikklis „Lugemise harjumuse harjutus“ ka sellest, kuidas probleemiks on tõusnud see, kuidas inimesed ei suuda enam lugeda keerulisemat teksti, võttes selleks kas teaduslikud tekstid või ilukirjanduslikud teosed. Kõik toimub kiiresti ja nuti vahendusel, lühendeid kasutades sõpradega vestlemine, erinevad keelelised lihtsustused, nagu avar, toekas, gigantne ja paljudki veel, muutuvad noortesilmades lihtsalt „suureks“. Noorte lugemisharjumused on suuresti sõltuvad noori ümbritsevast keskkonnast ning ka noorte isiklikest huvidest.\nTeine põhjus, miks loetakse vähe, on see, et raamatud ei ole mitte väikerahva keeles, nagu selleks on eesti keel, vaid üldtuntud keeles, nagu inglise keel. See põhjus on pannud erimaade kirjastusi avaldama peamiselt inglise keelse tõlkega tekste, sest nad saavad sellega rohkem tulu, kui näiteks väikekeelse tõlkega. Tauno Vahter räägib oma artikklis „Peame leppima, noored lihtsalt ei loe“ sellest, kuidas juba viimasel ajal on isegi täiskasvanud hakanud lugema inglisekeelset kirjandust. Ta on välja toonud ka head küljed, et alati on olemas lugejaid, et lugemine pole veel kadunud, kuid on näha, et raamatute sirvimine ja pikade, spetsiifiliste tekstide lugemiste arv on kahanemas. Kui saaks panna noori nutiseadmetes mahukaid ja keerulisi tekste lugema, siis ei tohiks olla probleem sellega, et inimesed ei loe.\nNutiseadmed on meie igapäevaelu üks suurimaid osasid. Lugemiste kahanemise põhjus ei ole sugugi selles, et inimesed kasutavad nutiseadmeid, vaid selles, et inimesed ei tea mida nutiseadmetest lugeda või mida otsida. Tauno Vahter on väljatoonud ka selle, et poisid ja tüdrukud veedavad suurema osa oma ajast sotsiaalmeedias ja loetakse ainult seda, mida nad seal näevad ning tekib ka siis küsimus, et miks ei ole noortele õpetatud või tutvustatud erilehekülgi, kus noor saaks lugeda endale meelepärast kirjandus, kas selleks siis ole ilu-, teadus-, või erialastkirjandust. Võib ju loota, et kui noortele näidata seda, kuidas neil on võimalik kasutada nutiseadmeid muudel viisidel, kui ainult sotsiaalmeedias sirvida ja sõbradega suhtleda, siis paraneks ka ühiskonna lugemisharjumused tervikuna mingisugusel määral.\nIseenesest ei kahjusta noorte lugemisharjumusi nende kasutuses olev nutitelefon, vaid see, kuidas sellega ringi käiakse. Kasutades seadmeid ainult enda meelepärastel viisidel, lihtsustatud keele ja slängiga vesteldes võib jäädagi mulje, et lugemiste arv on kahanemas. Parandades või muutes noorte nuti tarvidust võime loota, et paraneb ka ühiskonna lugemisharjumused vähemalt teataval määral.');
