INSERT INTO core.text(id, content)
VALUES ('a83a0ad8-5384-4087-9cb2-b20ee934549d',
        'Ühiskonna tulevik on suunamudijate kätes\nTänapäeva noorem põlvkond on väga kiindunud internetikuulsuste tegevuste jälgimisse ja nende nõu eeskujul oma identiteedi kujundamisesse. Noored võtavad õppust ja arendavad oma teadmiste pagasit igapäevaselt läbi internetis esineva informatsiooni. Ka Eesti ühiskonnas on suur roll suunamudijatel noorte arvamuste ja mõttemaailma kujundamisel. Seejuures tuleb märgata omakorda selle rolli ohtlikkust, sest uuem põlvkond kujundab tulevikus meie ühiskonna arenemist ja kunagi ei saa sisuloojate eesmärkides kindel olla.\nSisuloojatel on oluline roll noorema generatsiooni uskumuste kujunemise suunamises, sest noored idoliseerivad netikuulsusi ja kujundavad oma mõttemaailma nende nõu järgi. Eriti keeruline on netikuulsustel oma arvamuse avaldamise tagajärgi hinnata, sest puudub ülevaade vaatajaskonnast. Õpetajate lehes ilmunud artiklis kirjeldati uuringute tulemusi, mis selgitasid, et suunamudijate nõu kujundab tihti noorte arvamusi ja heakspidamisi. Läbi erinevate blogijate ja juutuberite kinnituvad teismelistele baasteadmised, mis suunavad nende kasvamist ja arenemist. Kuna noored on meie tulevik, siis on väga oluline, et nende mõttemaailmad ja identiteedid põhineksid positiivse eesmärgiga uskumustel, sest see mõjutab omakorda laiema ühiskonna arengut. Seetõttu on tähtis, et suunamudijate väljaütlemistel oleksid head kavatsused, sest halvemal juhul on nende mõjud negatiivsed.\nNoored peaksid olema kuulsuste usaldamisel ettevaatlikud, kuna nende jutt võib põhineda vääral ja negatiivsel informatsioonil. Tänapäeva ühiskonnas on teismelistel tihti keeruline enda identiteeti iseseisvalt välja kujundada ning seetõttu võetakse eeskuju oma lemmikutest sisuloojatest, kelle eetilised tõekspidmised ei pruugi olla alati kõige heatahtlikumad. 2023. aastal Novaatoris kirjutatud artiklis arutleti internetipetturite ja suunamudijate vahelistest sarnasustest ning ohust, mis sisuloojatel inimkonna mõjutamisega kaasneb. Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill on rääkinud, kuidas netikuulsuste arvamuste avaldamine on ohtlik eriti, kui need ei põhine tõestatud faktidel. Keeruline on aru saada, millal on sisuloojate eesmärk saavutada enese tarbeks rahaline kasum või muu hüvi, hoolimata tagajärgedest, mis kaasnevad väljaöeldud sõnadega. Kuna suunamudijate uskumustes ja eesmärkides ei saa alati kindel olla, siis oleks tarvilik olla nende arvamuse usaldamises ettevaatlik.\nSisuloojad peaksid oma suurt mõju suunama eesmärgile aidata ühiskonnal areneda paremaks ning teadvustada probleeme ka nooremale põlvkonnale. Kuna noorte mõttemaailma kujundamisel on roll ka netikuulsustel, siis seda on võimalik kasutada ka ühiskonnaprobleemide teadlikkuse laiendamiseks. Mitmed populaarsed Eesti suunamudijad Hanna Martinson, Liis Velsker, Liina Ariadne Pedanik ja Martti Hallik võtsid osa 2019. aastal kampaaniast #loomadesilmis, mis kutsus inimesi üles vältima karusnahka. Kampaania oli eelkõige suunatud noortele tarbijatele, et tõsta nende teadlikkust loomakasvatamise julmast tegelikkusest. Heategevuslike eesmärkidega ürituste loomine on efektiivne viis, kuidas muuta ühiskonnas esinevaid probleeme. Mõjuisikute toetuse abil on võimalik reklaamida nende olulisust ka suuremale jälgijaskonnale ning seeläbi kinnitada ka kuulsuse enda positiivseid uskumusi inimestele.\nÜhiskonna tulevik sõltub suuresti nooremast generatsioonist, mistõttu on väga oluline, et nende baasteadmised oleksid ehitatud õigetele tõekspidamistele. Seetõttu on oluline, et kõik tiktokkerid, juutuberid ja blogijad teaksid oma vastutusest noorema põlvkonna kujundajatena ning kasutaksid oma mõju ära heatahtlikel eesmärkidel ja ühiskonnaprobleemide parandamiseks. Samas peaks tänapäeva noorem põlvkond olema teadlik internetis kaasnevatest ohtudest ning seal tegutsevate isikute kavatsustest. Muuhulgas ei saa kunagi olla kindel, kas tegemist on siira ja heasüdamliku suunamudija või enese tarbeks tegutseva petturiga. Tulevik on noorte kujundada ja sellepärast peaksid meie hoiakud olema stabiilsed ja põhinema heatahtlikel uskumustel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
