INSERT INTO core.text(id, content)
VALUES ('7a293887-cd24-448e-95db-0dc092d8aaa7',
        'Tänapäeval on laialt levinud arusaam, et kõik mida internetis nähtakse on päris ning vastab ilmtingimata tõele. Sellise arusaamaga kipuvad olema just noored, kes kuulavad palju taskuhäälinguid, vaatavad filme ning jälgivad igapäevaselt sotsiaalmeedias mõnda nimekad sisuloojat. Suunamudijatel on käes võim mõjutada inimeste arvamust, soove ja tegusid nii headele kui halbadele tegudele. Noored on väga vastuvõtlikud ning haavatavad kõigele, mis internetis leidub ning tänu sellele on neile lihtsam ka mõju avaldada.\nSuunamudijad mõjutavad noori eksklusiivsuse ning erakordsusega. Crystal Abidin toob oma uurimuses välja, et noortele suunatakse infot asjade või tegude kohta, mida nad muidu endale näiteks lubada ei saaks. Näiteks erinevad luksuslikud paigad, kallid esemed või peened üritused. Sisuloojad kasutavad seda võtet ära, et tuua võimatuna näivad asjad oma jälgijateni, et neile tunduks see samamoodi osasaamisena. Paljud inimesed ei saa omale Dubai reisi lubada ning siis kasutavadki sisuloojad ära noorte soove ja tahtmisi, et mõjutada neid püüdma rohkem ning andma endast maksimumi, soovitud tulemuseni jõudmiseks. Sisuloojad on kohati oma ala meistrid või asjatundjad: tantsijad, trummarid, kunstnikud või õpetajad. Nad oskavad midagi mida teised ei oska ning see paneb neid ennast jälgima ning neid kuulama. Noori on lihtne mõjutada, kui arvatakse, et tegu on spetsialistiga, kes on elus kõike saavutanud.\nNoori on hea mõjutada pannes neid arvama, et sisulooja on nende sõber. Maria Murumaa Mengeli artiklist ,,Mõjutamine: Kuidas suunamudijad meid mõjutavad’’ loeme välja, et juba 1956. aastast pärit parasotsiaalsete suhete teooria kohaselt tekib meedia vahendusel inimestele illusioon, et meediastaar on nende lähendane tuttav, keda tasub kuulata. Selline illusioon tekitab inimestes tundeid, et nende jälgitav sisulooja räägib absoluudeslt õiget juttu, kontrollimata õhku visatud fakte. Maria Murumaa Mengeli artiklist tuleb ka veel välja, et uuringute tulemustest on näha, et tihtipeale kuulavad noored just sisuloojate nõu, mida pidada moraalseks, mida põlastava pilguga vaadata ning kellega normaalselt suhelda. Tuntakse, et suunamudijad mõistavad oma jälgijaid ning soovivad heast südamest inimesi aidata, mis mõningal juhul ka nii on, kuid suurem enamus kasutab kaastunned lihtsalt jälgijate kogumiseks ära. Sisuloojad saavad tänu sellele lihtsasti noori mõjutada, tekitades neis häid ning sooje tundeid nagu sõbrale.\nNoored on väga vastuvõtlikud ning usaldavad oma valitud sisuloojate suhtes. Noored tunnevad end kohati nagu siuloojate lähedased sõbrad kuna nendega jagatakse internetis mõnda teksti või antakse lihtsalt mõni tore soovitus. Ei kontrollita, kas suunamudija poolt õhlu visatud väide vastab tõele. vaid usutakse pimesilmi kõike mida avaldatakse. Noori on tänu sellele ka lihtne mõjutada tegema asju, mis on parasjagu just sisuloojale kasulikud. Tänapäeva noored usaldavad oma valitud sisuloojaid kohati rohkem kui oma vanemaid ning tänu sellele on neid võimalik ka lihtsamini mõjutada oma suunamudija ideid kuulama ning ka kaasa tegema.');
