INSERT INTO core.text(id, content)
VALUES ('66bce116-92bd-47a7-89d3-54d677bbe0e6',
        'Tänapäeva noored pole harjunud lugema ning see võib neile edaspidises elus saatuslik olla. Inimkond on osanud lugeda juba mõnda aega. Alguses oli lugemisoskus vaid kõrgemast soost isikutel, aja möödudes muutus lugemine hobiks ning võimaluseks pääseda reaalsusest kuskile mujale. Tänapäeval on see huvi noorte seast justkui kadunud. Kuhjade viisi raamatuid seisab riiulis ning ootab enda aega, kuid keegi neid kätte ei võta.\nNoored ei mõista lugemisoskuse tegelikku tähtsust. Tänapäeva digimaailmas, kus kogu eluks vajalik informatsioon, lõbustus ja rohkemgi, on pidevalt käe-jala ulatuses, ei teki noortel huvi tuhlata läbi raamatuid ning otsida neist meelelahutust. Paraku on lugemisoskus maailma mõistmise alus, sest kogu info liikumine ja talletamine käib siiani läbi tekstide ning üleskirjutiste. Lugemisoskuse tähtsust rõhutas enda avaldatud arvamusloos Tiit Hennoste „Lugemise harjumuse harjutus“, kus kerkis esile, et lugemisoskus pole pelgalt asi mida vaid eesti keele tunnis rakendatakse vaid see ulatub seinast seina. Nutiseadmetest küllastunud maailmas elades ei pea noored tähtsaks osata funktsionaalselt lugeda, mis võib neid tulevikus alt vedada, sest neil jääb suur osa maailmast mõistmata.\nNoortele tuleb teha lugemine atraktiivseks. Värvikirevas nutimaailmas ning pideva silmade stimuleerimise all olevad tänapäeva noored näitavad alatasa rohkem huvi üles asjade vastu, mis kergemini nende pilku püüavad. Hallid ning vanade kujundustega raamatud ei ole paraku väga silmatorkavad. Suurt rolli mängib samuti mitmekeelne ühiskond, kus vaid emakeele rääkimise asmelel segatakse sinna sisse veel muid keeli, sealhulgas ka inglise keelt. Tauno Vahteri arvamusloos „Peame leppima, noored lihtsalt ei loe“ tähendab Vahter, et mitmes riigis, muuhulgas Saksamaal tõlgitakse raamatute pealkirjad inglise keelde, kuigi sisu on neis saksakeelne, sest noored ostavad raamatuid ainult sellel viisil. Muutes raamatute kujunduse erksaks ning pealkirjad noorte jaoks atraktiivseks, on võimalus, et noored hakkavad rohkem lugema.\nNoortele tuleb õpetada, kuidas kujundada lugemisharjumusi. Digimaailmas, kus kõik on kliki kaugusel ning lugemisharjumust vaja pole, ei teki noortel vajadust harjutada end lugema. Noortel pole tahtmist teha endaga tööd ning mõelda mida lugemine neile annab. Tiit Hennoste artaklis „Lugemise harjumuse harjutus“ diskuteerib Hennoste, et lugemisharjumuse loomine algas iseendast ning see pole algul üldsegi kerge, kuid lõpuks peale harjumuse kujunemist enam ilma selleta ei saa. Õpetades ning selgitades noortel kuidas luua lugemisharjumusi ning mis head ja vead selle eesmärgiga kaasnevad võimaldab suurendada lugemist noorte seas. \nÕpetades noortele vajadust funktsionaalselt lugeda, teha see neile atraktiivseks ning seletada kuidas kujundada lugemisharjumusi, on hädavajalikud selleks, et noored jälle lugema hakkaks. Nende kolme tähtsa alustala puudumisel tekivad lugemises lüngad ning motivatsioon ja huvi kaovad. Prioritiseerides lugemist, kasvab ühiskond paremaks ning ühtsemaks, sest inimsed mõistavad teineteist ja ka maailma palju rohkem, kui ilma lugemisoskuseta.');
