INSERT INTO core.text(id, content)
VALUES ('a5c5aa39-5285-4b82-980f-3182c69f1542',
        'Tänapäeval suurem osa inimestest, kas on näinud  või vaatab üht suunamudiat, kellel on suur- või väikekuulsus. Mida tuntumad nad on seda rohkem on neil mõjutusvõimet teiste arvamuste jatarbimise suhtes. Seda saavad ärakasutada, kui tavainimene ei ole ettevaatlik ja lihtsalt jälgib käske mida neile antakse läbi video või muu tee.\nNiiöelda influencerid on igalpool, kas teevad kontsserte või teevad internetis videoid, nende arvukus on viimasel ajal tõusnid. Sellega on paljude noorte inimeste hoiakud ja arusaamad kujundatud nende lemmik suunamudija sarnaseks muutunud või mida kuulus isik ise tahab, et vaatajad arvaksid. Seda on ka väljatoodud allikast „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?“ räägib „Uuringutest on selgunud, et tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida ihaldada, mida põlastava pilguga vaadata, kuidas kellegiga suhelda.“ Sellest saab tuletada, et nendel on inimesi lihtne juhtida sinna, kus nad ise tahavad, mille tulemuseks võib hea või halb tulemus olla individuaalile.\nInterneti ajal on väga raske usaldada inimesi keda sa kohtasid arvuti teel.  Kunagi ei tea, mida nad tõeliselt teha proovivad või tahavad, kuna nad peidavad enda tõelist nägu ja isiksust ekraani taga. Näiteks juutuberid, kes on väga populaarsed võivad järsku oma miljonitele fännidele õelda, et ostke mingid nende tehtud toodet või kaupa ja saate rikkaks. Kuid oopis varastavad fännidelt raha ja jooksevad ära sellega. Sellest räägitakse ka allikast „Sotsiaalteadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir“ Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill kirjutab „Veebis tegutsevate petturite eesmärk on panna inimesi reageerima, olgu siis meelitamise või hirmutamise abil.“ Eelnevast kirjutatud on hea näha, et petturid kasutavad ükskõik, mis taktikat, et saada mida tahavad. \nKa häid tulemusi võib tulla suunamudijate poolt. Nad saavad aidata oma kuulsusega annetada vaesematele, tuua tähtsatele vähe arusaadud probleemidele tähelepanu näiteks eluohtlikute haigustega ja disabilititega inimesed. Ka loodusele saavad tähelepanu tuue nagu on kirjutatud allikas „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“. „Loomade eestkoste organisatsoon Loomus alustab tänasel rahvusvahelisel karusnahavabal reedel ja ostuvaba päeval kampaaniat #loomadesilmis, mis kutsub inemesi üles mitte soetama karusnahka.“ Seal on näha, et kuulsad inimesed ei pea kõike tegema oma pärast vaid saavad ka teisi aidata saavutada midagi suuremat.\nTänapäeval on kuulsaid isikuid publikule nähtav. Selle tulemusena on nende kombeid või arvamused sarnaseks muutuma oma lemmik talendiga. Sellega kaasnevad head ja halvad küljed, kus suunamudijad aitavad vaeseid ja õnnetuid isikuid, aga mõned kasutavad ära oma kuulsust, et ennast rikkamaks teha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
