INSERT INTO core.text(id, content)
VALUES ('0ace8652-f5a8-436a-a401-7628b88aea24',
        'Lugemise osakaal inimeste igapäeva elus on võrreldes eelmise sajandiga läbinud märkimisväärse allakäigu. Ühiskonnas on kasvanud nutiseadmete kasutamise osakaal ning paratamatult eelistatakse nii infot kui ka meelelahutust otsida just sealt. Selline teguviis on aga ääretult kurnav meie ajule ja ka psüühikale, muutes inimeste võimekust maailma mõista kui ka toimetuleku iseendaga üha keerulisemaks.\nNii noorte kui ka täiskasvanute seas on lugemine vaba aja sisustusena kaotanud oma väärtuse. Tunduvalt kergem on saada päevane dopamiiniannus paari minutiga telefonis või muus nutiseadmes aega veetes. Tiit Hennoste on Sirbis avaldatud arvamusartiklis toonud välja, kuidas ta ei usu, et raamatute tähtsuse langemist meie elus saab süüdistada pelgalt vaid piisava vaba aja tegevuste puudumisele. Olgugi et eelmisel sajandil, kui ühiskonna praegune generatsioon lapsevanemaid ja vanavanemaid olid noored, hinnati just lugemist hobina kõrgelt, oli ka sellel ajal muid võimalusi küllaga ning lisasks sellele ka noortel rohkem kohustusi. Ajaga on muutunud paberkandjal tekstide osakaal meie igapäevaelus, sest ühiskonna väärtushinnangud on liikunud edasi, tahtes jätta raamatud minevikku. \nInimkonna pidev areng ja üldine lugemuse vähenemine on toonud kaasa psüühilisemaid probleeme. Bioloogilise arengu jaoks on hädavajalik, et inimeste informatsiooni toidulaual oleks igapäev esindatud ka raamatud. Marju Lauristin on ÖÖÜlikooli raadiohäälingus toonud välja, kuidas lugemine annab võimaluse inimese iseloomule kasvada ja areneda. Võrreldes kirjapanduid tekste sotsiaalmeediaga, annab viimane koos tekstiga kohe ette ka pildi ja konteksti, mis muudab inimese aju info vastuvõtlikuse suhtes lihtsameelsemaks. Ka Tiit Hennoste on toonud välja, kuidas ühiskonnas on tõusuteel funktsionaalse lugemisoskuse puudulikkus, mis mõjutab tugevalt nii noorte kui ka täiskasvanute arusaama maailmast. Lugedes artikleid või muid kirjapandud pikemaid tekste areneb inimestel nii mõistmine maailmast kui ka silmaring ja lisaks on see väga stimuleeriv meie ajule. \nElame infoajastul, kus raamatud võivad aidata vähendada meie ümber lasuvat infomulli. Mõtteid, avastusi ja loomingut on kirja pandud aegade algusest. Kahjuks ei ole tänaseni kõik neist säilinud, ent sellegi poolest peitub tuhandeis miljonis raamatuis inimkonna jaoks haaramatu kogus teavet. Informatsiooni võib leida pea ükskõik mis valdkonnas ja seda nii laiendatult kui ka süvitsi. Raamatute lugemine toetab meie aju arengut pakkudes samal ajal puhkust liigsest stiimulist, mis meie ümber meedias pidevalt laiub ja meeli uputab. Inglismaa veebileht on tehtud vaatajaskonna uuringus leidnud, et keskmine täiskasvanu veedab 70% oma ärkvel oleku ajast kasutades nutiseadet. Selliste numbrite juures on äärmiselt oluline, et väärtustaksime ka bioloogiliselt oma keha toetamist ja seda just raamatute lugemise näol.\nRaamatute osakaal ja tähtsus arenenud ühiskonnas on langusteel ja jätkab sellist tendentsi ilmselt ka edaspidi. See tuleneb pidevast inimkonna arengust, mis muudab meie väärtushinnanguid, et saaksime uuenenud maailmas edukamalt toime tulla. Ometigi on lugemine oskus, mida ei tohiks jätta unarusse, vaid sellesse tuleks keskenduda ja pühenduda süvenenumalt, sest tegemist on oskusega, mis on psühholoogilise arengu seisukohast inimesele hädavajalik.');
