INSERT INTO core.text(id, content)
VALUES ('a23d6f60-e84f-4c87-b7d0-d8d37f1b3fb4',
        'Noorte seas on väga tähtsal kohal sotsiaalmeedia, sest sealt leidub neile sobilikku ja meeldivat sisu. Sisuloojad on need inimesed, kes kajastavad erinevaid teemasid ja üritavadki just inimeste huvi tõmmata enda sisule. Noored oskavad kasutada interneti, aga pettusi ja mõjutust soosivaid tegureid ei pruugita märgata.\nSuunamudijad suunavad noorte ostuvalikuid, pannes neid raha kulutama enda reklaamitud toodetele. Sotsiaalmeedia sisuloojate peamisteks tuludeks on sponsorid, reklaamid ja vaatamised, mida nad saavad oma jälgijate seast, kelleks on tihtipeale noored. Raha teenimiseks peab suutma reklaamiv isik toodet silmapaistvamaks ja tähtsamaks teha. Mingi toote reklaamimine ja kiitmine tähendab antud toote firma rahalist toetust, mis moonutab suunamudija arvamust. Juhan Hellerma tektstist ,,Sotsiaalteadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir’’ avaldub seoseid inimeste ja suunamudijate usaldusest. Tema sõnul on võimalus, et kuulsamad sisuloojad esitavad oma arvamusi mingist tootest ära ostetud arvamusega ning seda tuleb kontrollida. Suunamudijad suudavad müüa tooteid noortele enda arvamust jagades, aga selle usaldusväärsust mõjutab nende soov raha teenida.\nTulu saamine reklaamidest on suunamudijate üks tulu viis, aga teistsugune võimalus on muuta noorte mõtlemist oma arvamust avaldades. Erinevad algoritmid ja tehisintellekti võimalused abistavad noori leidma just seda teavet, mida nad soovivad, aga sellise sisu tarbimine muutub ühekülgseks ja moonutab reaalsust. Maria Murumaa Mengeli artiklist ,,Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?’’, tuuakse esile uuringute tulemusi, et noored saavad just sisuloolajetelt eeskuju enda arvamusteks ning seal on omadusi, mis mõjutavad teabe usaldamist. Noored hakkavad end seostama sisulooja teabe ja arvamusega ning see kahjustab tema võimet kontrollida fakte ja laiendada enda silmaringi. Influencer’i arvamused sotsiaameedias tungivad noorte mõttemaailma, mida nad ka omakorda omistavad.\nIgalühel ongi õigus avaldada enda arvamust, aga arvamuse tähtsust mõjutab inimese väärtused, milleks tavaliselt on kas kuulsus, intelligentsus või võimekus. Noorte otsuseid ühiskonnas mõjutavad sisuloojad just enda kuulsuse ja võimekusega. Mida rohkem jälgijaid või raha kellegil on, seda usaldusväärsem ja parem tundub ta noortele. Heas Kodanikus avaldatud uudises ,,Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama’’ räägitakse Eesti loomade eestkoste oganisatsioonist Loomus, mis kutsus inimesi üles karusnahka mitte soetama ning toetajate seas on mainitud erinevaid Eesti ja maailmakuulsaid suunamudijaid. On ka öeldud, et see kampaania on suunatud just noortele. Selline organisatsioon on küll heatahtlik, aga ikkagi on kasutatud mõjutavaks faktoriks kuulsuseid ja justnimelt netikuulsusi, et muuta kampaania usutavamaks ja vajalikuks. Noorte mõjutamiseks kasutatakse sotsiaalmeedia mõjuisikute väärtusi, et tagada mignisugune kasum või poolehoid.\nSotsiaalmeedia sisuloojate käes on see võimalus tungida noorte mõttemaailma ja avaldada mõju nende otsustele. Selleks kasutavad nad ära enda väärtusi, mis noortele silma paistavad, ning võivad oma arvamusi esitada suurele kuulajaskonnale. Kuulsus ja võimekus ei tähenda alati usaldusväärsust, sest võimaluste seas on ära ostetud arvamus.');
