INSERT INTO core.text(id, content)
VALUES ('e4e01092-2b67-4f5a-a797-468206b25301',
        'Suunamudijad on ülemaailma kuulsad ja nende mõju on tunda igal pool. Efekti võim ja vorm võib varieeruda, aga tulemuseks on ikka laps muudetud.\nTänapäeval on paljude noorte unistus saada ka suurteks suunamudijateks, kuid pole räägitud kui raske on seda täide viia. Netikuulsused on võrreldes suurte näitlejatega ja muude kuulsustega palju lähedasemad oma vaatajatega. See ka tagab neile suurema mõju nende arvamuste ja plaanide üle. Kui juutuuber näitab videos oma rikkust ja populaarsust, siis see mõjutab noori valima samasugust elu. Uurigud on näidanud, et tänapäeva noorte hulgast suur hulk tahab saada suunamudijaks. Probleem seisneb selles, et sisuloojad räägivad ainult tulemusest ja mitte vahepealsest. Suures osas on teemaks õnn, mida iga noor ei pruugi leida. Sellepärast peaksid mõjuisikud olema ausad ja läbipaistvad oma sõnadega.\nAusus on kahjuks vähem sage kui oleks arvata sotsiaalmeediakuulsuste seas. Kasutatakse valesid, et tõsta populaarsust või hoida oma mainet. Brian Johnson, tuntud kui LiverKing sotsiaalmeedias, oli kuulutanud pikka aega, et tema ürginimlik elustiil on hea ja andis talle oma praeguse välimuse ja tervise, kuid tegelikult kasutas ta steroide. Selline käitumine on ohtlik, sest noored võivad teda uskuda ja käituda tema moodi, riskides oma eluga. Kuid mõnikord ka väänatakse tõde enda kasu jaoks, ilma otsese valeta. Juutuuberid, Mr Beast, KSI ja Logan Paul, andsid välja produkti nimega Lunchly, mis oli nende versioon populaarsest tootest Lunchables. Nad väitsid, et nende variant on parem, sest nende konkurentide toode sisaldab pliid, aga tuleb välja et mõlemad tooted sisaldasid seda. Samuti väga ohtlik käitumine enda kasumi jaoks.\nMõjutus ei pea olema ainult halb, sest saab ka lihtsalt tuua tähelepanu suuremale probleemile või aidata millegi vastu võidelda. Loomus, milles osalevad ka kuulsad Eesti suunamudijad, toob fookusesse karusnaha tootmise ja selle ebainimlikuse. Noortele selle reklaamimine on hea viis, kuidas neid muuta tulevikkus hoolikamaks oma valikutega. Suured sisuloojad ülemaailma teevad sageli rahakogumis üritusi heategevuse jaoks, näiteks Sidemen Charity football. See võib samuti panna neid paremale rajale tulevikku suhtes.\nSuunamudijate mõju on suur ja lai, kuid kasutatakse seda jõudu erinevalt. Sisuloojad võivad noori mõjutada, ilma et nad seda isegi teaks, sellega et nad oma elu nii perfektselt näitavad. Ka on võimalik oma vaatajaid ära kasutada enda materjaalse kasu jaoks, isegi kui see ei ole eetiline. Kuid saab ka motiveerida noortel head teha, sellega kui sa annad neile võimaluse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
