INSERT INTO core.text(id, content)
VALUES ('85a58fbd-daa1-4cd8-99e7-48b05ccf387d',
        'Tänapäeva noored peavad käima koolis, kodus maja pidama ja ka soovikorral käia endale meelepärast spordiala harrastamas. See kõik toodab noorte peas stressi, millest on vaja kuidagi lahti saada ning see viib nad meelelahutuseni. Kuid kas põhjused piirduvad vaid meelelahutusega, või on ka mõni muu asjaolu, mis on raamatute lugemise ajast maha jätnud?\nMeelelahutus on kõige efektiivsem viis leevendada stressi ja meelemuresid. Paarsada aastat tagasi oli noorte peamine meelelahutamise viis raamatute lugemine ja kas sõprade või mingit sorti nukkudega mängimine. Tänapäeval on noored aga enamasti nutiseadmetes ja raamatud ei ole jäänud ainult tagaplaanile, vaid tehakse kõike, et nende lugemist vältida. Kõik see tuleneb tehnoloogia arengust, kuna nüüd on peaaegu et kõigil taskus telefon, kus saab mängida, naljakaid videosi vaadata ja uudiseid lugeda, on kõik hea ja huvitav meil käeulatuses. Lisaks mängib ka rolli asjaolu, et telefonis nähtud asju ei pea proovima mõista, lihtsalt vaatad ja saad aru, kusjuures raamatutes on vaja teksti ise tõlgendada ja enamasti pole ka pilti ees, et kõike illustreerida. Kõik see viib selleni, et raamatud on jäänud irrelevantseks ja moest välja langenud.\nRaamatute lugemise vähesuse eest tänapäeva ühiskonnas võib anda ka au äppidele nagu näiteks TikTok ja Instagram. Nendes rakendustes on võimalik leida igast teosest, olgu see siis raamat, film, video, mäng jms. kokkuvõtteid, tsitaate ja selgitusi. See kõik aitab tänapäeva noorukil tema enda väärtusliku aega säästa, et tegeleda asjadega mis tema elus tema silmis päriselt tähtsamad on. Säärastes rakendustes on ka tekst tehtud noore aju jaoks huvitavamaks, olgu see siis kas illustratsioonidega, muusikaga või seostamisega tema huvialadega.\nMuidugi ei saa ka nimetamata jätta seda, et paberkandjal raamat on ebamugav. Telefon on inimestel alati käepärast, aga raamat võib olla toa teises otsas riiuli peal. Isegi kui nooruk soovib lugeda, on telefonis selle tegemine kordades mugavam kui raamatus. Telefonis ei pea lehte kerima vaid lihtast korra või paar pöialt liigutama ja oledki juba järgmise tekstilõigu juures. Kui noor näiteks lamab voodis ja otsustab et tahab lugeda, kui hetkeses asendis on mugav, siis ei pea ta mugavustsoonist välja minema et seda teha, vaid saab teha seda kohe seal kus tahab.\nRaamatud on jäänud tänapäeval ajast maha, sest nendest on inimkonna ja tehnoloogia arenguga tekkinud nii palju paremaid variatsioone, et nende kasutamine on nüüdisaja noortele äärmiselt ebamugav. On tekkinud sama info koguse tarbimiseks palju kiiremaid viise, mis aitavad noorukitel ka paremini stressi leevendada, et raamatute lugemine on lihtsalt nende silmis aja raiskamine, eriti kui seda veel paberkandjal teha. Uus tehnoloogia viib uute viisideni lugemiseks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('85a58fbd-daa1-4cd8-99e7-48b05ccf387d', 'title', 'Miks on raamatud tänapäeva ühiskonnas ajast maha jäänud?');
