INSERT INTO core.text(id, content)
VALUES ('64f1fbba-b36a-4d05-b3da-7e8d4eecbccf',
        'Suunamudijad, sisuloojad, mõjuisikud – neid saab kutsuda mitut moodi. Kuid tihti ühendab neid üks läbiv märksõna „mõju“. Seega avaldavad sisuloojad inimestele, tihti just noortele mingisugust mõju. Siiski ei saa igaüks mõjuisikuks, tal on vaja kasutada teatud viise, mis inimesi teda jälgima meelitaks. Õpetajate Lehes välja toodud uurigute põhjal selgitatakse, et „tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pidada, mida ihaldada...“.\nSisuloojad, kes toodavad eksklusiivset sisu, mõjutavad ebaausalt noori elama üle enda rahaliste võimete, et noorte pealt kasu teenida. Tihti peale köidab noori elustiil, mida nad endale lubada ei saa. See võib olla põhjustatud sellest, et sisuloojad näitavad, kui glamuurne on omada kalleid riideid ja luksusautosid, tekitades noortes tunde, nagu nemad peaksid samamoodi selle peale raha kulutama. Samal ajal jätavad mõjuisikud rääkimata, et saavad neid asju tasuta. Eestis kuulus sisulooja Brigitte Susanne Hunt on üks neist, kes hindab väga tugevalt materjaalseid väärtusi. See on ka üks põhjus, miks ta on populaarne. Nimelt Go3’me poolt tehtud saates „Üks nädala Brigittega“ lasi Brigitte Susanne Hunt teha endast pilte väga kallis kleidis, mida ta ei kavatsenudki osta, et jätta mulje, nagu see oleks tema oma ja postitas pildi Instagrammi. Seega võivad suunamudijad mõjutada ebaausalt noori enda sisu tarbima, nii et noor soovib olla jälgitava moodi ning elab seetõttu üle enda rahaliste võimete.\nOsad suunamudijad, ertit elulist sisu tootvad, mõjutavad noori kasutades ausust, seejuures ei soovi ainult kasu teenida. Elulist sisu tootvad suunamudijad on tihti peale ausamad ning soovivad noorele ka midagi kasulikku pakkuda. Elulist sisu kajastades ollakse üldisemalt avatud. Kajastatakse lisaks ilusale ka elu valusamat poolt. Elulise sisuga on samuti lihtsam samastuda ning tihti antakse ka kasulikku nõu. Eestis tuntud sisulooja Maria Rannaväli on ise noor ning seetõttu jälgivad teda eelkõige noored inimesed. Ta julgeb jagada elu paremaid ja halvemaid külgi ning ka nõu anda. Ta on avameelselt rääkinud enda teekonnast tervislikuma eluviisi poole ja jaganud sellega kaasnevaid raskusi, samuti on andnud nõu vaimse tervise hoidmise osas ja kaasanud enda sisusse spetsialiste, mis muuda tema sisu usaldusväärsemaks. Seega saab mõjutada noori ka olles aus ja anda enda jälgijatele midagi kasulikku vastu.\nSisuloojad avaldavad tugevat mõju eelkõige noortele ning tahavad sisu pealt kasu teenida. Osad suunamudijad üritavad kasu teenida ebaausalt ehk tegelikult nende elu pole nii glamuurne, rõhutades eksklusiivsusele ja sellele, et noored tahavad nende eeskujul samuti elada kallimalt, aga see võib hoopis üle jõu käia. Samas on ka sisuloojaid, kes kajastavad enda elu ausalt ning toodavad elulist sisu, annavad nõu ja räägivad elu keerulisemast ning raskemast poolest, nende eesmärk pole ainult kasu teenida.');
