INSERT INTO core.text(id, content)
VALUES ('d3bd83dc-56d0-4b76-877b-01d89a92fd6a',
        'Interneti arenguga on avanenud võimalus inimestel avaldada oma ideid ja oskusi rahvusvaheliselt. Interneti kasutajatest on aga välja kujunenud uus ühiskonna kiht, kelle arvamused on jõudnud suuremale kuulajaskonnale ning on muutunud oma ala arvamusliidriteks – suunamudijad. Kuidas mõjutavad suunamudijad noorte, kes väga palju kasutavad interneti, arvamusi?\nSuunamudijad kujundavad noorte väärtushinnanguid. Noored on arengufaasis, milles võetakse välisteguritel sisendit ja kujundatakse selle järgi oma arusaam maailmast. Maria Murumaa Mengel on esile toonud parasotsiaalse suhte võime muuta noorte väärtushinnanguid. Parasotsiaalses suhtes arvab noor, et suunamudija on tema lähedane ning sellest tulenevalt on mudija arvamuste suhtes vastuvõtvam. Veel lisaks teismeliseeas, kus noore väärtushinnangud kujunevad kõige rohkem, veedab noor aega rohkem vanematest eemal ja koos tema lemmik suunamudijaga, mille ajal noor õpib jäljendama tema väärtushinnanguid, arvamusi ühiskondlikest probleemidest ja saab baasteadmiste kogumi. Kuna suunamudija mõjutab kõige rohkem noort tema kõige muutlikumas eas on noore väärtushinnangud väga suuresti toode suunamudija arvamustest.\nSisuloojad mõjutavad noorte tarbimisotsuseid. Sisuloojad peale oma väärtushinnangute jagavad ka oma toote eelistusi, sisulooja kuulajaskond hakkab seda toodet või teenust positiivsemalt vaatama. Rahvusvaheline meediastar Logan Paul koostöös teise sisuloojaga KSI lõid spordijoogifirma Prime, mida Paul reklaamis oma väga noorele kuulajaskonnale. Tulemuseks Prime-ist sai ülemaailmne fenomen noorte seas, kes nägid Prime-i staatussümbolina, toote jõudmisel üksikutesse Eesti poodidesse oli sisulooja joogi hind tunduvalt suurem, kui teised spordijoogid samas kategoorias selle suure nõudluse tõttu laste seas. Sisulooja loodud toote reklaamitud staatusest ja sellest tulenevast nõudlusest tuli miljoneid ostjaid, enamasti noored,  mida muidu poleks olnud, kui toode ei oleks sisuloojaga seotud – sisuloojatel on noorte ostude üle mõju.\nSuunamudijad saavad tuua ühiskonna probleemid noorte tähelepanusse. Suunamudijatel on lai kuulajaskond, keda saab üles kutsuda sotsiaalsele muutusele. Heas Kodanikus kirjutab loomade eestkoste organisatsioon Loomus nende karusnahkade tootmise vastasest kampaaniast, mis on leidnud laia kõlapinda reformimeelsete noorte seas tänu sisuloojate toetusele. Loomuse liige usub, et noored on muutumise ajend, mida vajatakse karusnahkade ebahumaanse tootmise peatamiseks ja nendeni on jõutud Eesti kuulsate sisuloojate abil. Tänu sisuloojate loodud probleemi kõlapinnale on probleem leidnud rahvusvahelist tähelepanu teistelt meediastaaritelt ja organisatsioonidelt. See kõik algas aga noortest, kes vastaisd üleskutsele, mis nende sisulooja esitas – suunamudijatel on mõju tõsta ühiskonnaprobleeme noorte tähelepanusse.\nSisuloojad on interneti osa ning nagu internet mõjutavad loojad noori laialdaselt, sest nad on suur osa nende arengufaasist. Sisuloojate mõjul kujunevad noore väärtushinnangud isegi rohkem kui vanemate mõjul ning peale hinnangute ka tarbimisharjumused läbi sisuloojate soovituste. Läbi sisuloojate saab ka uuendusmeelseid noori kutsuda üles ühiskonnas muutust tooma ja tuua tähelepanu probleemidele ühiskonnas – sisuloojad on noorte arvamusliidrid.');
