INSERT INTO core.text(id, content)
VALUES ('39fcfa04-3b16-4fc3-bd8d-a6d12bad3dfe',
        'Olen palju kuulnud vanematelt inimestelt, et oletatavalt noored ja eakaaslased loevad palju vähem kui nende ajal. Tõsi, minu klassiski võeti gümnaasiumis kahe raamatu samaaegne lugemine terava vastuseisuga võetud ning sotsiaalmeedias kuulsin aina rohkem probleeme noorte nn funktsionaalse kirjaoskamatusest. Kuigi taolised mured esinevad 20. sajandi algusest peale, tasuks siiski mõelda, mis täpselt iseloomustab praeguste noorte lugemisharjumusi, kui ta üldse on alles jäänud, ja kas nende tagajärjed on kasulikud ühiskonnale. \nKui noored loevadki midagi füüsiliselt, on raamatud valdavalt ingliskeelsed, üldjuhul leitud internetist (näiteks TikTokist ja Instagramist) ning loetakse vabatahtlikult. Suurem osa õpilasi viibib nutiseadmete taga märkimisväärselt palju aega, sellepärast levib informatsioon hetkel populaarsetest teostest just seal ja kuna internetist on kõige rohkem teavet inglise keeles, saavad vastavalt ingliskeelsete sõnadega teosed tuntumateks. Tauno Vahter mainib oma arvamusloos lisaks, et „poepidajate sõnul on ingliskeelse pealkirjaga raamatud pea ainsad, mida noored ostavad või loevad.“ Järelikult praegused lugemisharjumused on palju mõjutatut praegustest trendidest lääne kultuuriruumis.\nIngliskeelsed raamatud ei ole aga ainukesed teosed, mis eakaaslasi köidab. Interneti tulekuga on tulnud uus kirjandusliik, mis põhineb juba olemasoleva raamatu, filmi, mängu või telesarja põhjal uue loo kirjutamise, tihti samal tasemel kui professionaalsed kirjanikud – fanfiction. Lugude tegevustik võib imekombel tunduda palju huvitavamana, sest tegelased on lugejale juba teada, ja toestes mängitakse põhiliselt isikutevaheliste suhetega. Nii mõnigi minu tutvusringkonnast kui ka mina ise olen mitmeid nn fanfic’e näinud, mis olid kirjutatud animafilmi-, filmi-, koomiksitegelaste ja isegi päris elu inimeste kohta. Võib väita, et lugemine ei ole lõpuni kadunud, vaid kandus üle digikeskkonda sarnaste kirjandusžanrite näol.\nKuidas mõjutavad nimetatud harjumused tulevast elu? Kui inimesed loevad ainult neid huvitavaid raamatuid ning ei uuri muid liike, on tõenäosus, et maailmavaade jääb kitsaks. Tänapäeva ilukirjandus (nii füüsiline kui ka digitaalne) ei pruugi anda samamoodi keeruka keele, mis peaks seal esinema Tiit Hennoste arvamusloo järgi. Nende sisu võib jääda liiga pealiskaudseks või, veel hullem, teosed võivad hoopis julgustada mitte tegeleda teostega süvitsi. On risk, et täiskasvanueas võib välja areneda antiintellektualismi tunnusjooned, mille abil võivad osa poliitike pahatahtlikult mõjutada ühiskonda.\n21. sajandil loevad õnneks veel raamatuid, kuigi peamiselt vabatahtlikult. On tunda mõjutusi ingliskeelsest kultuuriruumist ja digitaliseerimisest, sest populaarsed teosed on tänapäeval põhiliselt inglise keeles ja kirjutatud internetiplatvormidel. Ehkki on võimalus tendentsile sisu lihtsustada, ei kaota loodetavasti noored enda lugemishuvi ja -harjumusi.');
