INSERT INTO core.text(id, content)
VALUES ('57fb2602-a17d-4f53-b405-d664ad38ab04',
        'Lugemine on põhioskus, mida iga inimene peaks valdama, sest me oleme iga päev ümbritsetud erinevat tüüpi tekstidest, millest arusaamine võiks olla elementaarne. Siiski on lugemisoskus vähenenud ning eriti paistab see silma noorte seas, sest enamikel neist pole välja kujunenud lugemisharjumust, mis aitaks arendada tekstide lugemise ja mõistmise pädevust. Miks aga ei ole suurel osal tänapäeva noortest tekkinud lugemisharjumust ja mis on selle puudumise võimalikud tagajärjed?\nViimaste aastate jooksul on aina rohkem levinud lastele varakult nutiseadmete soetamine, mis on tõenäoliselt noorte lugemisharjumuse puudumise üks põhjustest. Internet on kiire infoallikas ning ka meelelahutuslik ajaveetmise koht, seetõttu ei saagi noored tihtipeale aru, miks nad peavad lugema sadade lehekülgede kaupa teksti, kui lühike kokkuvõte on paari näpuliigutuse kaugusel. Kuna tänapäeval on suur roll ka AI-l, ei vaevu noored isegi neid lühikokkuvõtteid lugema, sest kirjandi, raamatututvustuse, faktiküsimused või muu taolise teeb õpilaste eest ära ChatGPT. Kõikide sarnaste tehnoloogiliste seadmete ja võtete tõttu on noortel kadunud vajadus lugemise järele ning ei saada aru, et hilisemas elus maksab mitte lugemine rängalt kätte, sest silmaring, sõnavara, grammatilised oskused on puudulikud.\nKuigi noored loevad tänapäeval vähe, pole lugemisharjumus veel täielikult kadunud, aga on raugenud huvi eestikeelse kirjanduse vastu. Inglise keel ja inglise keelne kirjandus on noorte elu üle võtnud ning ainus koht, kus nad veel eestikeelsete tekstidega kokku puutuvad, on kirjanduse tunnid koolis. Noorte endi vaatepunktist on inglisekeelsed raamatud paremad, sest originaalkeeles lugedes saab sisust paremini aru, hind on kaks korda odavam kui eestikeelsetel raamatutel ja oma emakeeles lugemist peetakse imelikuks. See on äärmiselt positiivne, et õpilased üldse enam loevad, aga ainult inglise keeles lugedes tekib probleem, et oma emakeele oskus aina kahaneb ja sõnavara jääb kesiseks. Kui paljud inimesed ei oska enam korrektset eesti keelt ega saa sellest aru, on meie keele säilimine suures ohus, sest minnakse üle nii-öelda lihtsamale võõrkeelele ja meie emakeel sureb välja. \nNoored ei oska sageli hinnata funktsionaalse lugemisoskuse osakaalu nende endi tulevikule, seega ei hakata ennast väsitama ka selle arendamisega. Kuna tekstide mõistmiseks tuleb pidevalt lugeda ja mõttega kaasas olla, näevad noored selles tüütut kohustust ja oma aja raiskamist, mitte selle positiivset mõju pikemas perspektiivis. Paljud uuringud on kindlaks teinud, nagu väidab Tiit Hennoste oma arvamusloos „Lugemise harjumuse harjutus“, et hea lugemisoskusega lapsel on tulevikus koolis paremad hinded, parem haridus, hea sissetulek ja vaimne tervis. Siiski ei tundu need faktid noori eriti motiveerivat ja tõenäoliselt ei hakka miski neid lugema innustama.\nHuvi lugemise vastu noorte seas on olemas, kuid kahjuks on see väike, sest ei mõisteta lugemisoskuse tähtsust ja tehnoloogia kiire areng vähendab raamatute lugemise olulisust. Isegi, kui noored loevad raamatuid, eelistatakse inglise keelset kirjandust, aga nii väheneb noorte oskus oma emakeeles ennast väljendada, keerulistest tekstidest aru saada ja huvi eesti keelt säilitada. Ainus lootus on, et noortel tekib tung lugeda hilisemas elus ning seda ikka eesti keeles.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('57fb2602-a17d-4f53-b405-d664ad38ab04', 'title', 'Noorte lugemisharjumused ja -oskused – kadunud või väärad?');
