INSERT INTO core.text(id, content)
VALUES ('958b55dd-e109-4646-a3e6-d6f73a3d03f2',
        'Noorte lugemisharjumused tänapäeval on väga erinevad võrreldes nende vanemate ja vanavanematega. Tänapäeva maailm on nii kiire ja kuhjaga tuleb peale uusi asju, mis üha enam eraldavad noored raamatutest. Telefonidel on suur mõju lugemishuviliste langustrendis, kuna seal olev maailm on nii sõltuvust tekitav ning noored kisutakse reaalsusest üha kaugemale. \nVähene lugemine tänapäeva ühiskonnas on küll murettekitav, aga tegelikult on ka neid inimesi, kes tõesti loevad. Lugemine on pidevas kasvutrendis, aga sellega kaasneb ka palju kriitikat. Noored on rohkem huvitatud inglise keelsest kirjandusest, mistõttu arendavad nad oma võõrkeele teadmisi ning emakeel jääb tagaplaanile. Seetõttu ongi tegemist aktuaalse teemaga, mida vanem generatsioon tihti esile toob. Asi ei ole selles, et on vähe noori, kes loevad, probleem seisneb selles, mida ja mis keeles loetakse. Vahter väidab, et tüdrukud loevad enamasti Tiktokis ja Instagramis nähtud ingliskeelseid romantilise ja fantaasiakirjanduse raamatuid. See väide on kuidagi negatiivse alatooniga, sest tähtis ei ole see, mida loetakse, vaid see, et loetakse.\nOn palju tegureid, mis soodustavad lugegmisharjumuse säilimist. Üheks peamiseks on kindlasti kohustuslik kirjandus koolis. Põhikoolist saati innustatakse noori lugema ja loetut analüüsima. See on väga positiivne, kuna noor pidevalt loeb ja samaaegselt viib end kurssi olulise kirjandusega. Selline kirjandus pole aga kõigile, kuna igal inimesel on oma eelistused. Hoolimata sellest tasub neid raamatuid ikkagi lugeda, kuna need on õpetlikud ja harivad. Näiteks gümnaasiumis loetakse Orwelli või Kafka teoseid, mis räägivad väga palju ühiskonnast ja selle negatiivsusest. Kohustuslik kirjandus on väga kasulik, aga iga õpilane peab ise vastutama, et ta seda ka loeks ja end seeläbi hariks. \nVahter leiab, et funktsionaalne lugemisoskus on põhiline tänapäeva maailmas elamise eeldus ja alus. See väide on väga tõetruu, kuna inimesed, kes ei ole harjunud lugema, ei suuda ka erinevaid koolitekste lugeda. Nad on harjunud infot kergelt kätte saama nutimaailmast, kus ei pea väga vaeva nägema ega mõtlema. Lugemise puhul on oluline sõnavara laiendamine, loetu mõistmine ning oskus seda analüüsida. Tuleb lugeda mõttega ja aega võtta, sest kiirustades teeme endale karuteene ja ei ole mõttega asja juures. Pideva praktika abil arendab inimene oma lugemisoskust ning samal ajal ka oma järjepidevust. Vahter ütles, et treenimine algab enda sundimisega, et harjumus tekiks, tuleb harjutada.\nLugeminsharjumus ei kao niipea ja noored teevad palju tööd, et seda säilitada. Väär on öelda, et tüdrukud loevad ainult teatud žanre, kui reaalsuses on nad avatud kõigele. Noorte lugemine tänapäeval on väga mitmekesine ja ei piirdu ainult lemmikžanridega. Tihti astutakse oma mugavustsoonist välja, lugedes näiteks kohustuslikku kirjandust või tuttava soovitatud raamatut, mis on harjumuspärasest erinev.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('958b55dd-e109-4646-a3e6-d6f73a3d03f2', 'title', 'Lugemine tänapäeval');
