INSERT INTO core.text(id, content)
VALUES ('2d16066f-e9fe-4959-a13d-80677f497868',
        'Olles esimene põlvkond, kes on sündinud koos tehnoloogiaga nt. telefonidega väiksest saati on see muutnud ka meie harjumusi ja tegevustee elistusi. Arvutid ja telefonid pakuvad nii palju teisi tegevusi, et lugemine on jäänud tagaplaanile. Mis on täpsemalt lugemisharjumuste muutumise põhjus?\nNoored valivad inglise keelseid raamatuid. Enamus noored veedavad mitu tundi päevas internetis, kus sisu on tavaliselt inglisekeelne ja see põhjustab noori valima samakeelseid raamatuid. Veel võib üks põhjus olla vähem populaarsete raamatute valik, millel ei pruugi olla eesti keelset tõlget veel olemas. Selle tagajärjed võivad olla nt. emakeele oskuste langemine, inglise keele segunemine eesti keelega ja võõrsõnade suurem osakaal igapäevakasutuses. Kas need on positiivsed või negatiivsed tagajärjed on vaieldavad, välja arvatud emakeele oskuse langemine. Keele säilimiseks ühiskonnas on vaja inimesi, kes oskavad adekvaatselt seda teatud keelt kõneleda.\nNoorte seas pole enam palju lugejaid. Telefonide ja muude nutiseadmete tõttu on lugemine muutunud vähem soositavaks tegevuseks, sest minu-ealised pigem mängiksid arvutis, kui loeksid raamatut. Videote vaatamine ja mängimine pole ajule nii kurnav tegevus võrreldes lugemisega ja sellepärast on jäänud lugejate arv vähemaks. Lugemise populaarsuse vähenemine on negatiivne, sest lugemine on hea viis saada rohkem teadmisi juurde ja lugemise vähenemine tähendab seda, et inimesed ei tea nii palju oma ümbrusest ja tekib kitsas silmaring. Kitsas silmaring tekitab raskusi inimestega vestlemisel ning teeb inimese ühepalgeliseks ja võõraks.\nTauno Vahteri artikklis on ka välja toodud sooline vahe lugejate seas – poisid loevad vähem kui tüdrukud. Kuigi lugejate arv väheneb mõlemal soopoolel, siis on see langus suurem poiste seas. Kui ainult üks sugupool loeb, siis on raske leida ühisi huvisi ja see võib takistada perede loomist. Kui ei teki uusi peresid, siis on ühiskonna arv languses ja ühiskond muutub väljasurevaks.\nRaamatute lugemine on tähtis ja sellepärast on vaja, et inimesed loeksid ja saaksid koguaeg uusi teadmisi. Lugemisharjumuse puudumine tekitab probleeme nagu: kitsas silmaring, perede arvu vähenemine, emakeele oskuse langus. Nooretele peab õpetama lugemise väärtust.');
