INSERT INTO core.text(id, content)
VALUES ('c285f12d-df89-4dee-9dc7-b05c8f70f962',
        'Tänapäeval leidub nii noori, kes armastavad lugeda, kui ka neid, kes ei suuda raamatut kättegi võtta. Kindlasti oleneb palju inimesest endast, milliseks ta oma suhte raamatutega kujundab ning millised huved tal on. Ka sõltub palju perest, milliseid väärtusi peetakse olulisteks ning millised võimalused kellelgi on. Vaatamata paljudest erinevatest teguritest, mängib koolis läbielatu suurt rolli noorte arvamuse ning edasiste lugemisharjumuste kujunemisel. Seega, kuidas mõjutab kool laste lugemisharjumisi?\nLugemisharjumus algab huvitavate raamatutega. Kaasealiste puhul, kellele ei meeldi kohustusliku kirjanduse lugemine, olen märganud, kuidas probleem ei pruugi ollagi raamatus, vaid puhtalt inimese enda suhtumises. Edasi pärides on tihtilugu tulnudki välja, et kuna põhikoolis loeti üsna üksluiseid teoseid, ei tekkinud kunagi huvi raamatute vastu ega häid lugemisharjumusi. Õnneks on üha enam hakatud tooma sisse kooli kohustusliku kirjandusena klassikute kõrvale kaasaegseid teoseid. Nii muutub raamatute valik järjest mitmekülgsemaks ning on noorte ajaga pidevalt kaasas. Kui juba väiksest saati antakse koolis eriilmelisi raamatuid lugeda, on suurem võimalus, et kõik leiavad enda jaoks midagi meelepärast ilma suurte pretensioonideta. Nii on juba väiksest saati raamatutesse suhtumine pigem positiivne ja on parem põhi all edasisteks analüüsideks raamatutega. \nPidev tähtajast-tähtajani lugemine võib soodustada pinnapealset lugemist. Elame maailmas, kus kõik liigub kiiresti, kus peame tegema kõike kiiresti. Tiit Hennostegi ütles, et mõttega lugemine võtab aega. Seega kiirlugemine, mis kipub juhtuma koolis tiheda ajagraafiku tõttu, ei aita kaasa nõudmisele, et on vaja hiljem analüüsida loetut, ning ei aita kaasa ka sellele, et noored õpiksid nautima raamatulugemist – suur osa heade lugemisharjumuste tekkimiseks on oskus nautida lugemisprotsessi. Pinnapealse lugemise tagajärg hiljemas elus on see, et ei osata enam mõttega olla kohal olulisi  dokumente lugedes ning nende põhjal otsusi tehes. Samuti ka, võib kaduda jällegi rõõm lugemise üle mõneks ajaks nagu juhtus omal ajal härra Hennostel ülikoolis. See ei tähenda, et tähtajaga lugemine oleks halb, vaid et tuleks anda mõistlikult aega lugemiseks.\nKoolis tuleks eraldi rõhku panna keeruliste tekstide mõistmisele. Kui noor on avara sõnavaraga ning oskab funktsionaalselt lugeda, ei pruugi see tähendada, et bürokraatliku tekstiga dokumendid, mida tihti elus ette tuleb, keerulised mõista oleks. Hennoste arvates on üks hea viis selliste tekstide mõistmiseks just nende lugemine ja läbi töötamine. Mis on tõsi – ainult harjutades saab paremaks. Seega just erinevate tekstide töötlemise ja eluks ettevalmistamise mõttes oleks igati kasulik koolis reaalselt võttagi dokument ette ja koos seda läbi lugeda.\nKool mängib võrdlemisi suurt rolli noorte lugemisoskuste- ja harjumuste kujunemisel. Olgu see kohustusliku kirjanduse raamatuvaliku esitamisel, lugemistähtaegade paika panemisel või otsustades, millele rõhku panna õpetamisel. Need valikud annavad õpilastele edasi sõnumi ning suuremal või väiksemal määral peegeldavad nende edaspidises elus harjumusi, oskusi või suhtumist raamatutesse.');
