INSERT INTO core.text(id, content)
VALUES ('f3503ccd-a866-4a97-bfc5-254fee5735e1',
        'Tänapäeva ühiskonnas on internet tõusnud olulisele kohale. Sotsiaalmeedias leidub suunamudijaid igal pool, seinast seina teemadega seoses, mistõttu puutuvad noored nendega tahes-tahtmata kokku, olgu see siis uudiseid või tootearvustusi otsides. Kuidas aga mõjutavad sisuloojad meie, noorte inimeste igapäevaelu ning maailmavaadet?\nNoored inimesed otsivad suunamudijatelt nõu erinevatel teemadel. Üks neist on poodlemine, kus vajatakse nõu mõne kindla toote või mängu suhtes, või otsitakse üleüldiselt ostusoovitusi. Tihti on erinevate toodete vahel raske valida, mistõttu uuritakse vastava eseme kohta veebis, loetakse ning kuulatakse erinevate teemat valdavate kuulsuste arvamusi või hinnanguid. Seejuures võib sisulooja eesmärk teiste aitamise asemel olla kasumi saamine: nad pakuvad oma jälgijatele tõelise arvamuse ning hinnangu asemel hoopis tootja poolt kinnimakstud reklaami. Reklaami tõelise hinnanguna esitamine ei ole jälgija suhtes aus. Enne ostude, eriti suurte, tegemist tuleks teha faktikontroll ning mitte pimesi uskuda mõjukate kuulsuste ütlemisi, nagu on järeldanud Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill. Seda on võimalik teha erinevaid allikaid jälgides ning sõpradelt toote kohta uurimise teel. \nTihti ei otsi noorukid uudiseid ajalehest või mõnest muust usaldatud allikast, vaid just sotsiaalmeediast. Sellises olukorras on suunamudijal mõjukas roll, sest tema väljaütlemised ning arvamused mõjutavad noorte jälgijate arusaama ja vaadet. Sisuloojal on võimalus oma vaatepunktist esitatud uudist jagada ning sellega jõuda paljude teismeliste ning muude kasutajateni. Kuna internetis on tihti keeruline vahet teha libauudiste või propaganda ning tõeliste uudiste vahel, tuleb lugejal olla eriti tähelepanelik ning kriitiline. Selline hindamine pole alati nii lihtne, eriti teismeliste jaoks, kelle kriitiline mõtlemine on tihti nõrgemal tasemel, kui täiskasvanutel. Teismeeas kasutajaid on lihtsam mõjutada erinevate trendide ning väärarvamustega, kui kogenud täiskasvanuid. Seega peakisd lapsevanemad ning koolid, oma võimete piires, aitama noortel arendada analüüsi ning läbimõtlemise oskust.\nMõjuisikutel on ka võimalus noorukeid positiivselt mõjutada ning seejuures ka ühiskonda muuta ja olla noortele eeskujuks. Sotsiaalmeediaplatvormidel nagu TikTok võib tihti näha erinevaid algatusi ning väljaütlemisi, mis on seotud näiteks meeste vaimse tervisega – kasutajaid kutsutakse üles rohkem tähelepanu pöörama just meeste vaimsele tervisele, sest tihti jäetakse see unarusse. Lisaks tehakse hulgaliselt postitusi ka sallivuse ning võrdsuse teemadel, kuna tänapäeva ühiskonnas on suhtumine teistesse ning teistsugustesse inimestesse muutunud ning paljud sisuloojad propageerivad mõistvat suhtumist. Paljuski on näha ka parema elustiiliga seotud postitusi, kus autor suunab jälgijaid keskkonnasõbralikkuse, taimetoitluse, sportliku eluviisi või isegi karusloomakasvanduste keelustamisele, nagu oli mainitud Hea Kodaniku avaldatud artiklis. Tuntud sisuloojad suudavad noori mõjutada positiivsemate harjumuste ning eluviiside poole tihti paremini, kui nende teismeliste enda vanemad. \nMeie ühiskonnas on sisuloojad olulisel kohal. Neil on võimalus mõjutada noori nii positiivselt kui ka negatiivselt, vaatamata sellele peab ikkagi noorel internetikasutajal olema olemas kriitiline mõtlemine ning usaldusväärsuse hindamisvõime.');
