INSERT INTO core.text(id, content)
VALUES ('6d902a9f-4fe4-40a8-83d8-a7ad52b401af',
        'Avaliku elu tegelased mõjutavad meid igapäevaselt, tihti ise arusaamata, et me oleme nende mõju all. Paljud neist on oma kasu peal väljas, kuid on ka neid, kes tõsiselt hoolivad oma tööst ja tahavad oma sisu teistega jagada. Kuidas nad seda teevad ja mis on nende eesmärgid?\nSuunamudija töö on mitmekülgne, esiteks on neil vaja leida tarbijaid, kes nende loodud sisu jälgiks ning seejärel neid meelelahutada, ükskõik mis viisil influencer ise vajalikuks peab. Maria Murumaa Mengel on oma artiklis („Mõjutamine (4): Kuidas suunamudijad meid mõjutavad“) kirjutanud, et sisuloojaid on nelja tüüpi. Kõige mõjuvõimsamad neist on need, kes suudavad publikuga samastuda. Kui sisulooja ei tundu autentne, siis ei ole enamus inimestel huvi ka teda jälgida. Lisaks sellele on suunamudijal vaja olla eriline - vaatajaid köidab, kui sisulooja on milleski osav või omab midagi ebatavalist. Nende omaduste omandamisel suudab influencer koguda suure vaatajaskonna, mida ta saab mõjutada.\nSuunamudijaid on üldiselt kahte tüüpi, need kes hoolivad kuulsusest ning need kellel on sellest ükskõik. Palju rohkem on neid, kes hoolivad suurest vaatajaskonnast ja teevad üksõik mida, et seda saavutada, võttes kasutusele võlts isiksuse. Tihti soovivad sellised sisuloojad teenida ka suures koguses raha ja asuvad kas mingit teenust või toodet reklaamima, ükskõik, kui ebaeetiline see on. Näiteks võib tihti kohata sotsiaalmeediaplatvormis „Twitch“ sisuloojaid kes mängivad hasart mänge ja reklaamivad seda alaealistele, teenides selle pealt tohutult summasid. Selline reklaamimine toob hasartmängu platvormidele veel rohkem mängijaid ning eriti palju ka noori. Juhan Hellerma on öelnud: „eriti kui mängu tulevad rahalised kohustused, tasub kodutöö ära teha ja mitte jälgida teatud mõjukuse saavutanud suunamudijate nõuandeid pimesi.“ Selliste sisiloojate juures tuleb olla skeptiline ning jälgida pingsalt, et neil mingeid salakavalaid motiive poleks.\nPeale kuulsus ahnete sisuloojate eksisteerib ka neid kes on siirad või keda kuulsus niivõrd palju ei huvita. Enamasti on need inimesed, kes on milleski osavad või soovivad oma teadmisi publikule edasi jagada, kuid mitte sellel põhimõttel, et ise selle pealt midagi teenida. Üheks näiteks võib tuua juutuuberi „Outdoorboys“, kellel on üle kümne miljoni jägija ning kes loob peamiselt matkamis- ja rändamis sisu. Tema peamine eesmärk on käia looduses ning jagada oma teadmisi vaatajatega. Tänu sellisele lihtsale põhimõttele on ta ka saavutanud massiivse vaatajaskonna, mis tõestab, et kuulsaks on võimalik saada ka tehes seda, mida inimene armastab. Kui ta peaks publikut kuidagi mõjtutama, siis see oleks eesmärgil, et inimesed käiksid rohkem väljas, avastamas loodust.\nSisuloojatel on oluline roll meie kõigi elude kujundamisel, kuid me ei tohiks lasta neil meid mõjutada üleliigselt. Tuleb osata vahet teha neil, kes hoolivad oma vaatajatest ja neil, kes mitte. Kui me seda oskust välja ei arenda, võime sattuda lõksu, millest lihtne välja rabeleda ei ole.');
