INSERT INTO core.text(id, content)
VALUES ('75a34de5-da03-49c4-901d-04c1eae0b4d1',
        'Noorte arvamus on kergesti mõjutatav, eriti kui mõju tuleb nende poolt idealiseeritud inimestelt, halvas või heas võtmes. Igapäevaselt keritakse tunide viisi netis, vaadates videosid ja pilte, mis tahes tahtmata jäävad meile pähe, positiivse või negatiivse emotsioonina. Olles see siis mõte, millist elu ise kunagi tahaks või ei tahaks või milline peaks välja nägema. Selles lastakse väga ennast mõjutada, aga ka suunamudijad ilustavad asja ja ei näita alati raskuseid.\nNoored võivad sisuloojatelt abi saada, kui nemad avalikult ja autentselt oma probleemist räägivad. Näidates end ,,päris’’ inimesena, kellel on ,,päris’’, mitte lavastatud probleemid, siis inimesed jälgivad teda ja samastuvad temaga. Pealtvaadates tundub Brigitte Susanne Hunt (BSH) täiesti perfektne ja võib rääkida, et ta tekitab noortes hoopis ebakindlust. Tegelikult ei näe piltidelt, mis toimub inimese sees, ja millega ta parasjagu tegeleb. BSH on pikalt oma instagrammis ja blogis jaganud protsessi oma kaalulangusest ja sellega kaasas käinud toitumishäiretest ehk kõik pole üldse nii lilleline kui tundub. Tänu sellele on temast kirjutatud mitmeid positiivseid artikleid ning tema blogi kommentaarium on täis noori naisi, kes tunnevad heameelt, et nad pole ainukesed, kes sarnast asja läbi elavad ja on tänulikud, et keegi oma lugu ja nippe julgeb jagada. \nInimesed ihkavad luksust. Teatud põhjus, miks teisi sotsiaalmeedias jälgitakse on nende eluviiside imetlemine või noortel tahe samasse kohta jõuda. Keili Sükijaineni telesaade ,,Kuldne pilet’’, avas uksed luksuslikku maailma. Seal näidati maailma kallimaid restorane, poode, maju jne – kõik, mis inimestes ihaldust pakub. Selline elustiil võib avada noorte silmad ja motiveerida neid samasse kohta jõudmaks, mis on justkui suunamudijate positiivne pool. Senikaua peab aga emotsiooni kogema läbi teiste seikluste.\nSotsiaalmeedia trikkide lõksu langemine on järjest rohkem päevakorras. Selle üheks suureks mõjutajaks on TikToki platvorm, kus tihti salaja peidetakse videosse ära promoklipp näiteks joogist või tootest. ,,Samas on aina raskem eristada, kas sisuloojale endale tõepoolest meeldib mõni film ja toode, või ta teeb seda reklaamina mingisuguse rahalise tasu või mõne muu hüve eest’’ on öelnud Kristjan Kikerpill. TikTokis tuntud Alix Earle testib päevast päeva uusi kosmeetikatooteid ja riidebrände, tänu millele äratab ka inimestes huvi. Hiljuti tegi noor naine koostööd brändiga, kus ta andis välja enda kehaligi teksapüksid, mis kunagi moes olid. Kommentaarium jagunes kahte laari – need, kes trendiga kaasa jooksid ja need, kes seda maha tegid. Keegi lõpuks ei tea, kas toode päriselt meeldib promojale või mitte, ja kas trendiga kaasamineja oleks ise sellise valiku teinud, kui poleks brändisaadiku eestvedamist.\nSotsiaalmeedia ja selle kasutamine on noortele õpetlik, kui osata filtreerida enda jaoks vajalik informatsioon. Praegused õpilased otsivad enne abi internetist, kui pöörduvad kohe päriselus kellegi poole. Tänu sotsiaalmeedias mõne suunamudija öeldule, võib keegi leida selle puuduoleva motivaatori, mis teda edasi lükkab või tulevikuks inspireerib. Siiski tuleks meeles pidada, et jääda iseendaks, teha asju, mis naeratuse näole toovad ja teha seda kõike ausalt ning mõeldes enda peale, mitte kuhu mass jookseb.');
