INSERT INTO core.text(id, content)
VALUES ('7afd7c0a-acd6-4a67-a07a-0070634d4fca',
        'Läbi aegade on muutuv tegur raamatud ning nende lugemine. Keskajal olid raamatud privileeg ning vaid jõukad said neid endale lubada, ühtlasi ka madalamad ühiskonnakihid ei olnud võimelised, et raamatuid lugeda, sest puudus lugemisoskus. Mida edasi aga aeg liikus seda kättesaadavamaks muutusid lugemispalad kõigile, kõigest paarkümmend aastat tagasi oli raamatute lugemine üks parim viis meelelahutuseks. Kuid tänapäeval on hakanud kõik liikuma allamäge.\nVarasemalt ülipopulaarne ning kõigile jõukohane tegevus, ehk raamatute lugemine pole tänapäeva noorte seas enam sugugi moes ning see on problemaatiline. Lugemise käigus omandab lugeja palju uut sõnavara, laieneb maailmavaade ja arusaam asjadest ning lisaks kõigele sellele areneb ka keskendumisvõime, mis on ülimalt oluline. Võttes arvesse kõike neid plusse, miks siiski noored otsustavad mitte lugeda. Nimelt, lugemine on vaevarikas töö, mis nõuab täielikku keskendumist ja pühendumist, kuid noortelt on seda palju tahta. Siinkohal muutuvad väga olulisteks mõjutajateks mobiiltelefonid ja muud nutiseadmed, sest tänu nendele avaneb pääs piiritusse veebimaailma. Internetist saavad noorukid nii huvitavat kui ka ebahuvitavat informatsiooni ning kõike seda väga palju ja väga lihtsalt, seetõttu on meeldivam netiavarustes tuuselda. Eriti marginaalselt mängivad rolli Instagram, TikTok ja muud sarnased rakendused, sest infolevik nendes äppides on meeletult kiire ja sisu on lõpmatult palju. Olles valiku ees, mida teha, kas lugeda või netiavarustes ringi rännata, valib enamik noori teise variandi. See kõik on väga nukker arvestades seda, mis oli mitukümmend aastat tagasi. Sellel teemal olen ka oma isaga vestelnud ning tema on rääkinud mulle, kuidas noorena ta luges salaja uneajast raamatuid tsakulambi valgusel, seda kõike teki all, et vanemad teada ei saaks. Tänapäeval tundub, et noored teevad sama, kuid raamatu asemel on mobiiltelefon.\nMida teha, et muuta noorte lugemisharjumusi? Kuna valikuid, kuidas vaba aega veeta on tuhandeid, siis tuleks nooremale põlvkonnale lugemine muuta atraktiivsemaks, nagu proovivad seda teha õpetajad, kes motiveerivad noorukeid hinnetega, mida saadakse kohustusliku kirjanduse vastamisel koolis. Mida edasi aeg on liikunud, seda rohkem on tunda, kuidas ka see pole piisav motivaator ning õpetajate üritused on läinud vett vedama. Üks meetoditest, mida kasutatakse on raamatu kokkuvõtte lugemine, seda tehakse ka minu klassis eriti palju, umbkaudu pooled lähevad lihtsamat teed mööda. \nSelle probleemiga tegelemine tundub lootusetu, kuid nõnda see pole, sest kõik sõltub noortest endist, kõige olulisem omadus, millest noored peavad võitu saama on laiskus. Vajalikke tegemisi, samamoodi nagu lugemisharjumuste alustamis lükatskse edasi, sest nii on lihtsam. Oluline on iseendast jagu saada ning teha raskeid asju, kui iga päev teha midagi rasket, siis lõpuks muutuvad need asjad lihtsaks. Seda seletab suurepäraselt lahti David Goggins oma raamatus „Ei saa mulle liiga teha“, rääkides, kuidas ta oma elu pimedamast august välja ronis, sest peale igat mõõna on tõus. Nii on igas eluvaldkonnas, olgu see sport, lugemine või õppimine. \nLugemisharjumused noorte seas on jäänud tahaplaanile, kuid asi pole lootusetu. Tohutult suurt rolli mängib laiskus, eriti tänapäeva noorte seas, just seetõttu on lugemine jäänud unarusse. Pöördepunktiks saab olema noorte enda tahe, sest uute heade harjumuste loomiseks on vaja lihtsalt alustada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7afd7c0a-acd6-4a67-a07a-0070634d4fca', 'title', 'Lugemisharjumused tänapäeva noorte seas');
