INSERT INTO core.text(id, content)
VALUES ('1a3fbae8-29a8-4516-9e1d-da0ba5993123',
        'Suunamudija, sisulooja, influencer – inimesed, kes iternetis oma arvamusi, hoiakuid või isegi igapäeva elu avalikult kõigiga jagavad ning sotsiaalmeedia kaudu mõjutavad oma jälgijate valikuid igapäevaelus. Olgu see siis seotud: toodete ostmisega, tervise valikutega või tõekspidamistega. Kõige rohkem mõjutab see meie tänapäeva noori ja nende maailmavaadet. Kas teistest mõjutatud olemine on halb või hea? Kas sisuloojate pool tulenev nõu on halb?\nSotsiaalmeedia on nüüdseks saanud suureks osaks meie elus, noored veedavad üha rohkem aega nutitelefonides jälgides tema elu ja järgides tema soovitusi. Mari Murumaa Mengeli artiklist tuleb välja mõte, et noored saavad just suundamudjatelt nõu, mida pidada normaalseks ja ebanormaalseks, mida ihaldada ja kuidas kellegiga suhelda. Kõik mida sa suunamudjatel õpid või kuuled on nende vaatenurk asjadele, nii nagu ka teiste sinu lähedal olevate inimeste arvamused. Kuulsuste hinnangud jõuavad lihtsalt ja kiiremini suuremale hulgale inimestele ning sellepärast võivad tekkida väärarvamused, kuna teie maailmapildid ei ole samasugused. Peale selle, et suunamudijad sotsiaalmeedias oma elu näitavad ja soovitusi jagavad on nad suureks  eeskujuks noortele inimestele. See pärast on kaasatud mitmeid kuulsusi erinevatesse heategevus projektidesse või kampaaniatesse. Loomade eeskoste organisatsioon Loomus kaasas oma kampaaniasse #loomadesilmis Eesti kuulsusi: Hanna Martinson, Liina Ariadne Peadnik, Marti Hallik ja teised. Kampaania oli suunatud eelkõige noortele, ning info noortee jõuab kohale läbi nende keda nad jälgivad.\nVeebis, nagu igalpool mujal, leidub pettureid, kes meelitavad inimesi valele teele. Raske on arusaada, kui tuntud inimene soovitab osta midagi, sest on tõepoolest hea või ta teeb seda reklaamina tasu eest. Tuleb olla skeptiline soovituste üle mida tehakse ja võimalusel tegema faktikontrolli. Mõte Mairi Murmaa Menegli artikklist, et meedia vahendusel tekib inimestel tunne, et meediastaar on lähedane tuttav kelle nõu tuleb kuulata, ning see tekitab arvamuse, et kõik mis sotsiaalmeedias näed on tõsi. Tuntud inimeste elu jägimine läbi iterneti jätab mulje nagu nende elus on kõik hästi ning tekitab vaatajas tunde nagu ta elaks oma elu valesti. Tuntud inimene, kui hea sõber paneb  alatihti tema soovitusi järgima ning usukam, et see mida ta soovitab on hea sinule.\nSisuloojate poolt tuleneva nõuga tuleb olla ettevaatlik, tuleb valmis olla, et toode või asi mis nad soovitasid tulenes lihtsalt tulu teenimise eesmärgil. Sotsiaalmeedia on osa meie elust ning sealt saab toetust ja nõu aga peame mõistma, vajadusel kontrollima, et kõik mida me veebis näeme ei ole alati nii hea kui tundub.');
