INSERT INTO core.text(id, content)
VALUES ('50b0a028-6cf6-4338-864d-e1be64e98c75',
        'Tänapäeval on väga aktuaalseks probleemiks saanud Eesti noorte lugemisharjumused. Paljud uuringud näitavad, et noored hakkavad järjest vähem lugema, mis seab küsimärgi alla nende edasises elus hakkamasaamise.\nAjalugu on näidanud, et noorte lugemisharjumused halvenevad pidevalt. Vaatamata sellele, et koolid endiselt kasutavad kohustusliku kirjanduse süsteemi, suudavad paljud õpilased lugemiskontrollidest läbi saada ka ilma raamatut päriselt lugemata. Peamiselt tehakse seda internetist sisukokkuvõtete läbilugemisel ja märkmete tegemisel. Noorte lugemisharjumuse halvenemise kohta kirjutati juba ka 1932. aasta Kaja ajalehes artikkel „Noorte lugemisoskus läheb tagurpidi“. See näitab, et tegemist ei ole mitte ainult tänapäeva noorte probleemiga, vaid on üleüldine probleem läbi aegade.\nKindlasti ei saa öelda, et käesoleva aja noortel puudub täielikult harjumus raamatuid lugeda. Statistiliselt loevad raamatuid peamiselt tüdrukud, kuid on ka poisse, kes lugemist naudivad. Siiski on peamised raamatud, mida noored loevad, inglisekeelne fantaasiakirjandus. Kui rääkida täna noortele A. H Tammsaare romaanist „Tõde ja õigus“, võin ma julgelt väita, et väga paljud eesti noored pole selle raamatuga kokku puutunud ega tunne isegi huvi selle vastu. Üks põhjus võib olla ka selles, et paksud ilma piltideta ja pikkade peatükkidega raamatud hirmutavad noored ära. Tauno Vahter mainib enda artiklis „Peame leppima, noored lihtsalt ei loe“, „inglise keel on üle võtnud noorte lugemise. Ka meil räägivad ammu nii lapsed kui täiskasvanud inglise keelest küllastunud keelt.“ Sellest võime järeldada, et kuna peamiseks keeleks on saanud inglise keel, ei jää noortel enam aega emakeelse kirjanduse lugemiseks. \nLugemisoskus on alus maailmas toimetulemises. Ilma lugemisoskuseta ei saa ühiskonnas hakkama, kuna ka kõige väiksemad elulised asjad on seotud lugemisega. Tiit Hennoste väidab enda artiklis „Lugemise harjumuse harjutus“, et ilma funktsionaalse lugemise oskuseta ei saa maailmas edukalt elada. Hea lugemisoskus ja lugemine oma vabal ajal aitab saada paremaid hindeid, parema hariduse, sissetuleku ning vaimse tervise. Ilma lugemisoskuseta ei saa ühiskonnas hakkama, kuna ka kõige väiksemad elulised asjad on seotud lugemisega, olgu see kas matemaatikaülesanne või mingi leping.\nNoorte lugemisharjumust mõjutavad suurel määral nutiseadmed. Tiktokis ja Instas lühivideoid vaadata on palju kergem, kui istuda maha ning reaalselt süveneda mõneks ajaks mõne kirjandusteose lugemiseks. Noorte ajud on harjunud lühikese ja lihtsa sisuga videote ja tekstide lugemisega, mistõttu väheneb tõsisemate ja raskemate tekstide lugemis- ja arusaamisoskus. Olles ise see noor inimene, kelle lugemisharjumus vajab parandamist, võin väita, et raamatute lugemine läks peale esimese nutitelefoni saamist palju keerulisemaks. \nNüüdisajal on noorte lugemisharjumused järjest halvemaks muutumas, mille tõttu kasvab järjest enam inimeste arv, kes ei saa ühiskonnas hakkama. Lugemisharjumusi mõjutab suurel määral ka nutiseadmete olemasolu ning üleliigne kasutamine.');
