INSERT INTO core.text(id, content)
VALUES ('64c85017-7a6a-4ed2-9974-b699b6ea0316',
        'Lugemine on aegade jooksul üha ebapopulaarsemaks muutuv hobi. Maailm, ühiskond ja elukeskkond on pidevas muutumises ning see, mis meie ümber toimub, mõjutab suurel määral meie harjumusi ja igapäeva tegevusi. Tänapäeva noorte lugemisharjumuste üle on juba kaua aega muret tuntud ja tuleb tõdeda, et olukord on üsna nukker. Kuidas selline olukord üldse tekkis ja mis mõjutab noorte lugemisharjumusi? Millised on vähese lugemise tagajärjed?\nNagu ütles Andrus Kivirähk saates Plektrumm, et tänapäeval on lugemine luksus. See tähendab siis seda, et lugemiseks peab olema aega ja jaksu ehk töö ja päevased tegevused ei tohiks nii ära väsitada, et pärast lugemiseks lihtsalt jõudu ei ole. See, mis toimub meie ühiskonnas ja igapäevases elus, loob lugemiseks väga ebasoodsad tingimused. Tiit Hennoste on öelnud, et meil valitseb kiirmaailm: kiirtoit, kiirkeel, kiirteadus, kiirseks, kiirlugemine. Iga sekund on arvel. Tohutu töö rabamine, kuna inflatsioon tõstab hindu ja alles iseseisvat elu alustavatel noortel on raske majanduslikult hakkama saada. Lisaks siia juurde veel õpingutele ja eneseteostusele kuluv aeg. Peale sellist päeva ei suudaks keegi võtta kätte raamatut ja süvenenult lugeda. See on täiesti inimlik, et aju ja silmad vajavad hoopis puhkust. Elukeskkonnal on väga suur mõju meie harjumustele ja tegevustele.\nHarjumusi ja väärtusi mõjutab ka kõik lapsepõlves kogetu. 1-7. eluaastani on laps nagu svamm. Nii palju kui suudame õppida sel lühiksel perioodil ei suuda me enam kunagi oma elu jooksul. Kõik nähtu salvestub alateadvusesse, mis meid eneselegi märkamata iga päev juhib. Siin kohal mängivad rolli lapsevanemad ja kasvatus. See on parim aeg kuna lapse väärtusi kujundada ja elukestvaid harjumusi luua. Olles eeskujuks lugemisel, et laps näeks kui vanemad loevad ja lugeda neile ka ette. Vaadates tänapäeva perekondi ja kasvatust siis see, mida lapsed näevad on hoopis midagi muud. Vanemad vaatavad ekraani ega pööra lastele tähelepanu- nutimanomaania. Kuidas siis peaks laps endale lugemisharjumuse saama ning selle kasulikkusest aru saama? Vanemad peaksid olema rohkem pühendunud laste kasvatamisele ja nende harimisele. Kõik saab siiski alguse kodust.\nLugemine on üks parim harimisviis.  Inimese alateadvus ei tee vahet tegelikkusel ja mitte tõestisündinud lugudel. Lugedes lugusid, näeme millised võivad olla mingite tegude tagajärjed ning ka see salvestub meile kogemusena ja aitab hiljem samu vigu vältida ning paremaid otsuseid langetada. Kujundab meie väärtused ja moraalinormid. Lugedes õpime õigekirja, laieneb sõnavara ja maailmapilt ning areneb info omandamise oskus. On uurimusi selle kohta, et hea lugemisoskus annab paremad hinded. Mitte lugemise tagajärjeks ongi halb kirjaoskus, kitsas silmaring ja halb lugemisoskus. \nMaailm muutub ja mõjutab meid igas võtmes. Noorte lugemisharjumus on tihedalt seotud koduga, kus nad kasvasid ning elustiiliga. Siin kohal ongi suur roll vanematel, et nad pühendaksid rohkem aega oma lastele ja õpetaksid neile, mis on oluline ja mis on neile hea, näidates samal ajal ka eeskuju.');
