INSERT INTO core.text(id, content)
VALUES ('c459e00c-b8aa-4455-b4a9-a5f375b8baa2',
        'Kõik rahva seas tuntud isikud omavad vähemal või rohkemal määral mõju inimestele. Ei erine ka tänapäeva suunamudijad rokkstaaridest ja filmi näitlejatest, ka neil on lai jälgijaskond ning inimkondlikult kõlama jääv hääl, mis võib mõjutada avalikkust. Kuid milliste viisidega ja kuidas on tänapäeva noori võimalik mõjutada?\nAvaliku elu tegelased suunavad noori tegema valikuid oma välimuses. Ühiskonnas, kus iga inimene on oma nägu, paistavad silma mitmed trendid, kus on kuulsuse jälgijaskond võtnud üle midagi, mis on tallle omapärane. Tuntud inimse stiili ülevõtmine võib tähendada fänni poolset toetust kuid ka soovi sarnaneda oma iidoliga. Kui Nublu oma algul aastatel Eestis populaarsust kogus, sai alguse temast, tänaseks tema kaubamärgiks saanud, prillide kandmise laine ning varsti kandsid Nubluga sarnasedi prille juba mitmed. Kui star tuleb välja omapärase välimusega, mis rahvale meeldib siis läheb rahvas sellega kaasa ning tekib trend.\nLaiemas ringkonnas teatud inimesed võivad mõjutada noorte valikuid. Inimesed on karjaloomad ning tunnevad end mugavalt kui saavad käia mõne karjajuhi järgi, eriti kui see karjajuht on temale sümpaatne. Kui noore inimese lemmik juutuuber on väga kallutatud arvamustega siis võtab noor inimene alateadlikult üle tema poolehoiu. Kuna ta on lummatud tema sisust siis tahab ta sarnaneda oma austatuga. Praegu Eesti populaarseim Twitchi sisulooja Istoprocent, kodanikunimega Kris Kärner, on tugeva parempoolse poliitilise arvamusega ning tema vaatajaskond on enamasti Isamaa või EKRE valijad. Kuigi inimene loob oma arvamuse ise, siis alateadlikult hakkab ta omastama talle meeldivate inimeste arvamusi.\nMõjuisikud saavad panna üldsust tegema teadlikumaid otsuseid. Seni kuni noor inimene ei tea, kuidas tema tegu võib mõjutada teisi ja ennast, seni ei oska ta ka käituda sellele omaselt. Kuid kui see sama inimene kuuleb mõnelt brändisaadikult, millised mõjud ja võimalused eksisteerivad, oskab ta ka kujundada oma käitumist. Andrei Zevakin tegi video, kus intervjueeris investoreid küsides, mida teha erinevates kogustes vaba rahaga. Mitmed noored, kes siiani olid kogunud ning mõelnud investeerimisest laiendasid oma teadmisi ning seega tegid pisikese sammu, et kindlustada oma tulevik. Noortel on tihti vaja vaid üht pisikest tõuget mõnelt sisuloojalt, või mõnelt teiselt eeskujult, et langetada oma otsus ning hakata tegutsema.\nIsegi kui inimene loob oma arvamuse ise siis ta on selle käigus väga mõjutatav kõrvaliste inimeste poolt. Inimest on võimalik kallutada mitmel moel - panna kandma riideid, et näidata üles oma toetust, tegema otsuseid kuna temale meeldiv isik ka teevab nii ning toimetama teadlikumalt kui arvamusliider on temas teadlikust tõstnud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
