INSERT INTO core.text(id, content)
VALUES ('c61978b9-e87a-44a5-9375-1789142c00b2',
        'Tänapäeval on üha suuremaks kasvavaks trendiks suunamudijad. Läbi aastate on nad ühiskonnas kõikide keskel eksisteerinud, kuid sel sajandil on neile hakatud rohkem tähelepanu suunama. Nad on noortele suureks eeskujuks. Aga kuidas avaliku elu tegelased mõjutavad noori? Antud kirjandis on arutletud just selle üle, kuidas avaliku elu tegelased positiivselt noori mõjutavad.\nÜheks punktiks on otsustamine. Tänu suunamudijatele on inimestel võimalik omast kodust näha palju rohkemat, kui kunagi eales. Telefonist on võimalik näha kalleid Prada kotte, Eiffeli torni või näha ülekannet presidendi vastuvõtust. Kõike on võimalik näha kodust diivanilt ilma raha kulutamata. Nagu 1. katkenist saab tsiteerida: „ Siin pakutakse inimestele infot asjade kohta, mis ei ole jälgijatele muidu kättesaadavad, näiteks kallid esemed, luksuslikud paigad, eksklusiivsed üritused.“ Heaks eluliseks näiteks on Martti ja Liina Hallik, kes kolisid Ameerikasse ja nüüd filmivad oma elu seal. See annab noortele hea ülevaate selle elu hüvedest ja pahedest. Noortel pole väga raha, et iseseisvalt reisida ja maailma avastada, kuid näiteks gümnaasiumi lõppedes soovivad osad noored tavapärasest rutiinist välja astuda ja näiteks teise riiki oma elu peale minna. Tänu nendele suunamudijatele saavadki noored näha, kas näiteks Austraaliasse minnes on kogu see dokumendi jama seda väärt või lähevad nad näiteks Soome ehitajaks. See annab noortele hea ülevaate, mis maailmas toimub, kuhu riiki minna ja miks üldse minna.\nTeiseks punktiks on igapäevaelu. Paljud noored puberteedieas tunnevad, et nad on täiesti omaette, nad ei sobitu kuhugi, keegi ei mõista neid. Kuid tegelikult on see täiesti vale, kuna noori on nii palju, et keegi ikka elab sama probleemi läbi, mis teine noor. Tsiteerides 1.katkendist: „...pakub elulisus „samastumise“ võimalust. Kui influencer räägib oma elust avatult ja autenselt, näitab end „päris“ inimesena, kellel on „päris“, mitte lavastatud probleemid, siis inimesed jälgivad teda ja samastavad ennast temaga.“.  Kajastades neid probleeme sotsiaalmeedias saavad noored näha ja kuulda, et nad ei ole tegelikult siin maailmas üksi nende probleemidega, keegi võitleb veel täpselt samade probleemidega. Näiteks tuntud Eesti tiktokker Mariliis Kaer on avalikult tiktokis postitanud enda suhete kohta. Tal on seal videoid suhteprobleemide kohta, miks lahku mindi ja samas jagab ta ka igapäevaprobleemide teemadest. See annab noortele hea ülevaate, mida ka teised läbi elavad. See mitte ainult ei aita samastuda, vaid õpetab neile ka kaastunnet. Nad võivad ka avastada, et probleem, mida nad ise läbi elavad ei pruugigi olla nii suur, kui nad ise arvasid seda olevat, sest kõrvaltvaatajana saadakse probleemist täiesti teistmoodi aru.\nTänapäeval on sotsiaalmeedia ja suunamudijad nii negatiivseks tembeldatud, kuid tegelikult leidub sellel olukorral ka positiivseid külgi. Suunamudijad saavad aidata otsust langetada, kuhu riiki edasi elama minna. Samuti on olemas ka suunamudijaid, kes postitavad oma probleemidest sotsiaalmeediasse, kuid tänu sellele saavad noored kellegagi samastuda ja ehk leiavad ka enda igapäevaprobleemidele sealt vastuseid.');
