INSERT INTO core.text(id, content)
VALUES ('42649e5f-a656-491e-af23-8af794d9ba01',
        'Raamatute lugemine on harjumus, mida hakatakse inimestele sisestama juba noorest east, lugedes juba laistaia ealistele jutte, kuniks nad juba ise selleks suutelised on. Tänapäeval on väga aktuaalne teema noorte lugemis harjumused ja kuidas noored ei ole lihtsalt harjumust lugeda ega teegi seda kui pole kästud. Paljudel praegustel noortel võib olla see lugemis pisik just sellepärast saamata, et vanemad ei aidanud nendel teha neid esimesi samme lugemis harjumuse poole. Aga mis nende lugemis harjumuste puudumine kaasa toob?\nNoorte tähelepanu keerleb suuresti tänapäeval selle ümber, mis toimub seal digimaailmas. Kõik sealsed algorütmid on mõeldud selleks, et tagada su pidev tähelepanu ja kõik, mis seal pakkutakse on kiire meelelahutus, millest su aju sõltuvusse satub. Seda kinnitab suuresti see, et need andmed on Jaan Aru doktoritöös välja toodud teduslike uuringute poolt kinnitatud. Kui moes on kiir tarbimine ja raamatute lugemine võttab kokku tunde, siis ei võta see geeniust arusaamaks, et tänapäeva noored ei loegi, sest nad lähevad lihtsmat vastupanu teed. \nMinu vanaema ikka rääkis, et kunagi raamatuid loeti meelelahutuseks ja teadmiste saamiseks, sest tol ajal polnud seda kuskilt mujalt saada. Tänapäeval aga kõik teadmised otsingumootorisse trükimise kaugusel. Tänu selle on raamat kaotanud oma väärtuse noorte silmis, kuna neil on tunne et Margaret Atwoodi tsitaat „ Raamtud on nagu aksnad mis lasevad valgust sisse“ ei vasta enam tõele ja sellepärast raamatute lugemis harjumus on pea olematu.\nMida aga see lugemise allakäik kaasa toob? esiteks nagu Tiit Hannoste oma Sirbi artikkliski on öelnud „ On piisavalt uurimusi selle kohta, et lapse hea lugemis oskus ja vabal ajal lugemine annab paremaid hindeid, parema hariduse, parema sissetuleku ja parema vaimse tervise.“ Kui sul pole harjumust lugeda, siis on väike tõenäosus, et sa oled hea lugeja, sest kõik oskused tulevad harjutades. Vajalike oskuste puudumisel, et saada parem haridus ja selle tagajärjel parem sissetulek, ei ole sa konkuresntisi võimeline tänapäeva konkureerivas maailmas. \nTeiseks enamikel oma elu jooksul on vaja sõlmida mõni leping või allkirjastada mõni muu õiguslik dokument. Vähe raamatuid lugedes pole sul laialdast  sõnavara ja võid ennast leida olukorrast, kus sa ei mõista dokumendi poolt sisugi, kuigi selle mõistmine on vajalik teadamaks millele sa oma allkirjaga loa annad. Ma olen Tiit Hannostega samale järeldusele jõudnud „Lugemisoskuse allakäiguga aina  kasvab inimeste hulk, kes ei saa enam ühiskonnas hakama: ei suuda läbi lugeda tekste, millele nad alla kirjutavad; ei saa aru sellest, mida riik ja ühiskond neile teada annab.“ \nKokkuvõttes  võiks öelda, et  tänapäeva noorte lugemis harjumused pea olematud ja lugemis harjumuste puudumine röövib noortelt võimaluse olla konkuretsi võimelised haridus ja töötur vallas. Lisaks puudub valmidus allkirjatad tähtsaid dokumente mille mõistmine on vajalik.');
