INSERT INTO core.text(id, content)
VALUES ('2d2b19af-effb-4d30-be9f-2e5c8d0222f3',
        'Kujutagu ette tänapäeva Eesti kirjanduse klassi, mille sisse piiludes leiad klassitäis noori. Need ei ole õpilased, kes iga õhtu enne magama minekut 20 lehekülge Bulgakovi või Ristikivi endasse sisendavad, vaid need on sellised, kes eelistavad oma aju asemel hoopis arvutiprotsessorit. Järgnevad lõigud arutlevad noorte lugemisharjumuse ja tehisintellekti seoste ning nende tagajärgedest.\nNoorte ebatihedad lugemisharjumused ja tehisintellekti kasutusvõtt tapavad loovuse. Kui noor täidab ülesande näiteks juturoboti ChatGPT või uhiuue Deepseek abiga, siis vastus tuleb andmebaasist, kus peitub juba kellegi teise arvamus ja loovus. Eesti õnneks puuduvad nendel robotitel andmed, et Eesti kirjandusest kokkuvõtteid teha, aga need proovivad ikkagi ja mitteteadlikud Eesti noored esitavad neid väär vastuseid. Kui kõik koostatu põhineb juba kellegi teise tehtul, kas noore loovusel on üldse mingit enda osa? Ei, ei ole ja ilma loovuseta ei saa mõista ka keerukaid tekste. Nagu Tiit Hennoste kord väitis „Keerukas keel on olemas ja jääb ka alatiseks olema“, ning selleks, et kompleksses maailmas õitseda või vähemalt eksisteerida riigina on vaja loovaid kodanikke. Loovus eristab inimesi ja tekitab unikaalsust. Seega, noorte lugemisharjumuste, nutisõltuvuste ja tehisintellekti mugavuste värbamine võib tuua riigi ja rahvuse vundamentaale lõhkuvaid tagajärgi. \nNoorte elu muutub liiga mugavaks, mille tagajärjel väheneb inimese kannatus, patriootlikkus, tänulikkus jne. Kõik hea tuleb vaid kannatuse, vaeva või valuga – see ongi mõnu või edu hind, aga digitaliseeritud maailmas on kõik kättesaadav: informatsioon, meelelahutus, hobid, töö ja isegi toit.  Kuigi keskmine eestlane ei saa kõike seda oma mõnuks ära kasutada, siis võimalus on siiski olemas. Võrdleme tänapäeva noori näiteks X-generatsiooniga: noored ei ole elanud teise riigi võimu all, võtnud osa ühestki sõjast ega üle elanud ühtegi retsessiooni. See generatsioon ja nendest vanemad on Eesti edu vundamendid, sest nad on läbi kogenud halva ja teavad kõike, mis on hea. Nüüd Eesti on paradiis ja nagu kirjanik Tõnu Õnnepalu ütles, siis Euroopa on paradiis, sest meil jääb aega, et asjade üle vinguda. Noor saab vinguda raamatu üle, aga vähemalt on tal võimalus raamatut lugeda. Seega, lugemise vältimise ja teiste mugavuste tagajärjel nõrgeneb isik ja ka tema isiksus. \nKokkuvõttes tehisintellekti ilmumisega suureneb mugavusharjumus ning nõrgeneb noore lugemisharjumus, mille tagajärjel sureb ka noore loovus ja tema isiku unikaalsus. Lõpuks on iga tänapäeva inimene standardne, tuim ja korduv – justkui elu Nõukogude Liidus. Tauno Vahter kord väitis: „võitlus noorte lugemisharjumuste pärast on kõigest pidurdav kaitselahing“, kuid see ei tähenda, et me ei võiks proovida probleemi leevendada või raamatutele kasvõi loovaid, aga huvitavaid alternatiive leida.');
