INSERT INTO core.text(id, content)
VALUES ('c13b993c-1d42-4f1d-b08c-d7e3ff8fb9f5',
        'Väiksena oli minu ja mu suurema venna unistus saada juutuuberiteks. Mis muutus? Mõistsime, et see ala ei ole meie jaoks. Me ei talunud neid negatiivseid kommentaare. Saime aru, et kui me peaksime populaarseks saama, siis me ei suudaks kontrollida seda, mida me ütleme. Suunamudijate töö võib tunduda lihtne, kuid tegelt see võib olla üsna raske ja väga paljud asjad võivad minna valesti.\nSuunamudijad tekitavad vaatajatele ajakadu ning keskendumishäireid. Ühiskond ei mõista vahest, et on olemas vaid üks elu. Nad ei mõista, et seda elu ei saa tagasi ning nad ei mõista, et nad raiskavad aega. Just seda teevad suunamudijad, postitades neid postitusi, mida vaatajad ootavad näha ja seejärel vaatavad. Vaatajad on nagu zombid. Kui video postitatakse, siis nad peavad kohe seda vaatama ja kaotavad täielikult ajataju ning nende aju põhimõtteliselt lülitub välja. Olen seda ise kogenud, kus olen päev läbi videoid vaadanud ning olulised sündmused päiselus maha maganud. Selline populaarsus, mis mõndadel suunamudijatel on, seda on liiga palju. Kui sisuloojad ei postita, siis vaatajatel tekkib keskendumishäired. Nad ei saa igapäeva tegevusi teha ilma, et nad ei mõtleks sellele, et: „mida teeks minu lemmik suunamudija sellises olukorras“ või „millal ... postitab uue video?“ Inimesed kaotavad enda ratsionaalse mõtlemise ning ainult mõtlevad oma suunamudijate peale. Noored enam ei mõtle, mis on normaalne ja mis ebanormaalne oma peaga. Hea näide on selline juutuuber nagu Istoprotsent. Istoprotsent on Eesti juutuuber, kes on pikka aega teinud videoid noorematele vaatajaskonnale ning Istol on tekkinud hiiglaslik fännimeeskond, kes teda igalpool kaitseb kommentaariumites kui Isto on midagi öelnud, mida inimesed peavad valeks, kuid Isto vaatajaskond mitte, sest Isto on nii mõjukas juutuuber.\nSuunamudijad teevad ajupesu vaatajate otsustele ja valikutele. Nagu juba mainitud, siis suunamudijatel on liialt palju võimu, kui nad on populaarsed. Populaarsusega kaasneb ego ning sisuloojad hakkavad arvama, et nende ütlemised on ainult õiged. Pettused on väga suur probleem tänapäeva ühiskonnas, olgu see siis telefonikõnedega, maksupettustega või isegi suunamudijatega. On sisuloojaid, kes teevad raha ja investeerimis kontenti ning vaatajad näevad, et see isik elab eksklusiivset elu ning ilmselt teab, mida räägib seega inimesed usaldavad teda. Kuid rahvas unustab ära ühe hea lause: „usalda, kuid kontrolli.“ Logan Paul, kes on Ameerika juutuuber ja kes sai kuulsaks postitades naljakaid lühiklippe, oli teinud video või öelnud oma vaatajatele, et ostke memecoine, mis on siis interneti rahaühik, ja et see teeb teid rikkaks. Kuna Loganil on väga suur vaatajaskond ning väga palju Youtube tellijaid, siis just niimoodi tema vaatajad tegidki. Tänu sellele jäid paljud tema vaatajad vaeseks kaasaarvatud ka Logan, kes kaotas palju raha, ning seejärel tegi Logan oma Youtube kanalile vabandus video ning hakkas raha andma oma vaatajatele, kes kuulasid tema nõuannet. Muidugi vaatajad tegid oma valiku, et ostsid seda valuutat, kuid see juhtus ainult Logan Pauli soovituste pärast.\nLõpetuseks tahan öelda, et piirake oma interneti kasutusaega. Ärge jääge ekraani sisse kinni ning ärge unustage ära ka elu väljaspool internetti. Tahan veel öelda, et vali hoolega, kelle nõuannet kuulda võtad. Tee oma uuringuid ennem, kui tormama hakkad.');
