INSERT INTO core.text(id, content)
VALUES ('81ccbe53-02fa-4552-98e8-93795b3e0ea2',
        'Maailm on muutumas üha enam infoühiskonnaks, mis tähendab, et paljude noorte tähelepanu pälvivad meedias tegutsevad arvamusliidrid – kutsugem neid antud kirjandis sisuloojateks. Meedia ja seal kajastatav sisuloome võivad ühest küljest anda edasi palju ühiskonna jaoks olulist infot ning väga aktuaalseid teemasid ja sellega noori harida. Küll aga peame olema kursis seal valitsevatest ohtudest ning halvimal juhul ka nendega vahel silmitsi seisma.\nOn oluline kajastada meedias väga aktuaalset infot erinevate ühiskonnas esinevate probleemide kohta. Heas Kodanikus on avaldatud arikkel selle kohta, kuidas tuntud Eesti sisuloojad on vastu karusnahkade tootmisele ning müügile. Loomuse liige Hanna Martinson on öelnud: „Kampaania #loomadesilmis on suunatud eelkõige noortele tarbijatele, et tõsta teadlikkust karusloomafarmide kulissidetagusest elust...“. Loomus on loonud ka kampaania, kus koguvad allkirju puurikanade keelustamisele. Sellega propageerivad nad ka puurikanade munade mittetootmist ning -ostmist. Esineb inimesi, kes juba praegu müüvad mahekanade munasid ning aitavad sellega peatada puurikana munade tootmist. Saaremaal on tuntuim Salmel mahekanade munade müüja Tanel. Selline reklaam noorte seas on vajalik, et laiendada nende silmaringi ja suunata neid tegema tulevikus ühiskonnale kasulikke otsuseid.\nEi saa taganeda ohust, mis noori sotsiaalmeedias surfates piirab. Võttes kinni eelmises sisulõigus mainitud allkirjade kogumisest legaalsel eesmärgil, tuleb tõdeda, et veebis tegutsevatest petturitest kaitsud pole keegi. Mõnigi tegu või žest petturi poolt võib sarnaneda sisuloojate omaga. See nende kavalus ongi – näha välja ehtne. Seda järeldab ka Tartu Ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill oma uurimistöös. „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid „kuulajatele meeldib“, siis on see probleem.“ sõnas Kikerpill. Samuti tuletab ta meelde, et võimalusel tuleks alati kasutada faktikontrolli. Petturite eesmärk võib olla finantsiline, kuid ka lihtsalt häkkida huviorbiidis oleva isiku kontodele sisse ning sealt saadavaid andmeid kuritarvitada. Noorte naiivsust ning ka ehk pisukest kärsitust teades, võivad nad kergesti jagada oma andmeid teadmata, kuhu või kellele need lähevad. Petturid lähenevad ka tuttava nime alt, mis tähendab, et on suur võimalus langeda ohvriks. Tehakse kontod tuttava sisulooja nime alt ja luuakse erinevaid loosimänge. Tooksin näite selle kohta kui paar aastat tagasi loodi sisulooja ja reality-tegelase Ada-Marie Nelke nimega konto. Õnneks keegi teadaolevalt selle ohvriks ei langenud.\nKokkuvõttes on noortele meedias aktuaalsetest teemadest kajastamine tähtis, see avardab silmaringi ja paneb noori mõtlema nii enda kui ka teiste tulevikule. Kuid selle kõrval sama vajalik on valitsevatest ohtudest teavitamine. Petturid muutuvad kavalamaks, mis tähendab, et on oluline olla teadlik ümbritsevatest riskidest.');
