INSERT INTO core.text(id, content)
VALUES ('45298b1c-8100-4330-88d2-a4eecff7adec',
        'Tänapäeval on internet ja sellega kaasas käivad sisuloojad väga suur osa inimeste, eriti noorte elu suur osa. Erinevate seal tegutsevate kuulsuste jälgimine ja nendelt eeskuju võtmine on kohati uus, kuid aina rohkem populaarsust koguv trend. Loomulikult tahetakse samasugust elu nagu populaarsetel inimestel internetis, kus uhkustatakse kallite majade, autode ja üleüldse kalli eluviisiga. Jäädakse justkui pimedaks kõige muu suhtes ja ollakse internetis, selles keskkonnas lukus. Sellest tulenevalt sooviksin arutleda selle üle, kuidas täpselt suunamudijad tänapäeva noorte igapäevaelu, otsuseid ja valikuid mõjutavad.\nEsmalt räägiksin sellest, kuidas internetikuulsused võivad kohati noore jaoks kujuneda tähtsamaks, kui näiteks nende vanemad. Miks peaks kuulama vanema soovitusi või nõuandeid, kui nutiseadmes olev sisulooja räägib palju targemat juttu: miks muidu on tal tuhandeid jälgjaid, võib tuua põhjenduseks. Internetikuulsust uurinud Crystal Abidin on nimelt välja toonud neli peamist omadust või trikki kuidas kuulsused endale tähelepanu saavad, millest tooks välja mõned tähtsamad. Esmalt pakutaksegi inimestele infot asjade kohta mis on tavaliselt neile kättesaamatud. See võib alata näiteks kõige uuema nutitelefoni näitamisest ja lõppeda mingisuguse eksootilise ja vahva koha tutvustamisega. Teiseks võiks välja tuua selle, et enamus tipus olevatest suunamudijatest on tõenäoliselt oma ala meistrid, näiteks oskus mängida arvutimänge ning olles selles tunduvalt paremad kui nende jälgjad. Sellest tulenevalt võibki tavalisel inimesel jääda mulje, et kui kõik need, keda jälgin on nii tuntud ja rikkad, siis miks mitte ka mina. Minu arvamus siinkohal on, et see võimalus saada rikkaks ja tuntuks on nii väikene, millest teinekord ei pruugita aru saada on, et internetis olevad inimesed ja just nimelt tipus on enamus rikkad, kuid see kogus on vähem järjel olevate inimestega niivõrd väikene ja sellepärast nad seal internetis tegutsevadki, eltakse justkui võlts seltskonnas.\nTeiseks arutaksin selle üle, kuidas võivad teatud tulevased kuulsused siis sinna tippu jõuda ning kuidas see võib teinekord seotud olla varjatud hüvedega sisulooja jaoks. Enamus juhtudel tuleb sisuloojate ja avaliku elu tegelastega ette seda, et midagi reklaamitakse. Harvematel juhtudel võib välja kujuneda see, et meie lemmik staari ja internetis tegutsevate kelmide vahel on raske teha eristust, nagu on järeldanud Tartu ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpill oma hiljutises uurimustöös. Väga tavaline on see, et ostetakse midagi, mida on nähtud reklaamist või jälgitavalt sisuloojalt ja ei ole kontrollitud toote või teenuse tausta. Sellega tahaksingi siin rõhutada seda, et eriti noored kontrolliksid oma kasutatavat sisu, mille alla võib kuuluda ükskõik mis, enne kui hakatakse kulutama oma raha ei tea kelle või mille peale.\nKokkuvõtteks ütleksingi, et tänapäeva noored võivad teinekord olla justkui pimestatud sellest, mis toimub nende ümber ja keskendutakse ainult sellele, mis toimub internetis või nende lemmik sisuloojaga. Arvan, et eriti teismelistele, kui ka vanematele peaks teadvustama seda, et suur osa internetis toimusvast on tegelikult võlts ja kõik see kättesaamatu on toodud lihtsalt rohkemate inimeste silme ette, mis varem ei olnud nii kättesaadav. Noored ei tohiks sellest lähtuvalt seada endale valesid ettekujutusi.');
