INSERT INTO core.text(id, content)
VALUES ('0c52b786-9e10-4c4e-94c8-5396f5dcb981',
        'Eesti on maailmas üks riikidest kellel on kõige suuremad lugemisoskused. See-eest on aga märgata ühte trendi, mis on nii ülejäänud maailmas, kui ka Eestis. Nimelt noored loevad aina vähem. Interneti ja tehnoloogia areng on kaasa toonud muudatuse noorte inimeste lugemisharjumustes. Kui nad ka midagi loevad, siis tavaliselt on tegu hoopis audioraamatutega. Aga kas see on üldse uus muudatus ja miks üldse noored nii vähe loevad? Mis võivad olla tagajärjed?\nKuidas aeg edasi, seda rohkem tundub nagu noored pea üldse raamatuid ei loe. Olgu nad siis peamiselt arvutis või muudes seadetes, ennemini kui nad hakkaksid midagi produktiivsemat tegema. Siiski, ei ole tegemist täiesti uue suunaga noorte tegutsemises. Nagu on toonud Tauno Vahter välja oma arvamusloo „Peame leppima, noored lihtsalt ei loe“ sissejuhatuses, juba eelmise sajandi kolmekümne teisel aastal kurdeti sarnase teema üle Kaja artiklis „Noorte lugemisoskus läheb tagurpidi“. Seega ei ole tegemist täiesti uue sündmusega – ka varem on noored vähem lugenud ja maailm pole otsa lõppenud. Mõned need samad inimesed kes täna kurdavad, et noored ei loe, on ka see sama generatsioon kelle kohta see artikkel käis.\nSiiski teeb ka Tauno Vahtrile hirmu see, et tänapäeva poed müüvad aina rohkem inglise keele raamatuid. Teda tsiteerides: „Inglise keel on üle võtnud noorte lugemise. Ka meil räägivad juba ammu nii lapsed kui täiskasvanud inglise keelest küllastunud keelt“. Inimesed – nii noored kui ka täiskasvanud, loevad tänapäeval rohkem inglise keelseid tekste kui eesti keelseid. Seega muutub ka nende sõnavara. Kui Eesti keelseid tekste enam ei loeta, hääbub ka Eesti keel minevikku, Liivi keele kõrvale.\nAga miks veel noored nii vähe loevad? Tegemist võib olla mentaliteediga. On juba teada et pahurpidi psühholoogia on midagi mille järgi noored tegutsevad – kui minul kästakse ühte asja teha, siis ma pigem teen teist asja. Seega võib olla üks põhjus, et miks noored nii vähe loevad, selles et sunnitakse peale ja lausa rõhutakse seda, et lugema kindlasti peab. Koolis on kohustuslik kirjandus, ja nagu Tiit Hennoste on välja toonud oma arvamusloos „Lugemise harjumuse harjutus“, siis harjumuse lugemisest algab iseendast. Ta lausa väidab et kirjandusõpetajad mängisid rolli lugemise allakäigus tema klassis, vähemalt mingil määral. Sealt võib oletada et kõige parem tekitada harjumust lugemiseks on alustada iseendast. See on treening, ja treeninguga tegeled sina ise, täpselt nagu kehaline võimlemine. Kui sul on endal piisavalt motivatsiooni ennast treenida, siis lähevad su oskused ka märksa paremaks.\nLugemisoskuse allakäik ei ole midagi uut, kuigi see on tänapäeval märgatavam tänu sellele, et on rohkem teisi asju mida oleks võimalik teha lugemise asemel. Siiski päris lugemisoskus ära ei kao, sest suur osa inimesi loevad ikka tekste inglise keeles, ja nende numbrid ainult tõusevad. Nii võib kaduda ära Eesti keel. Kui aga hakata noortele peale suruma lugemist, siis nendel võib hoopis hakata tööle refleks mis paneb neid vastupidiselt käituma. Seega peaks püüdma noorte huvi lugemise vastu säilitada, mitte maha suruda.');
