INSERT INTO core.text(id, content)
VALUES ('8f041b82-170b-4e0a-89ce-dea093addc58',
        'Sotsiaalmeedias on lugematu arv sisuloojaid, kes on saanud oma teatud oskuste või strateegiatega kuulsaks ning keda noorema põlvkonna inimesed, kes usinasti kogu aeg internetis aktiivsed on, võtavad just kui eeskujudena.  Tänapäeval on pidevalt juttu sellest, et kuna sotsiaalmeediakuulsuste eesmärgiks on raha teenimine, mõjuvad nad pisematele halvasti, sest ei mõelda laste vaimsele tervisele. Kuigi, kas suunamudijate mõju on noortele ilmtingimata alati halb, või võib leida laps meediast ka endale midagi positiivset?\nSotsiaalmeedias on väga populaarne ebatervisliku eluviiside jagamine. Laste seas kuulsad juutuuberid KSI ja Logan Paul avalikustasid koostööna energiajoogi „Prime“. See uudis tekitas noorte seas suurt heameelt ja ootust, kuna nad on kahte kuulsust kaua jälginud ja toode oli nendele väga ahvatlevalt reklaamitud. Peamiseks probleemiks ilmnes joogi ebatervislikkus. Lapsed, kes olid suuresti mõjutatud kahe juutuuberi poolt, tarvitasid Prime’i liialt palju ning see tekitas vanematele muresid, et nende pojad ja tütred sisestavad enda kehasse väga palju ebatervislikke koostisosi. Tervisele kahjuliku brändi avalikustamine ning samal ajal olles noorte seas väga populaarsed ei ole hea kombinatsioon laste tervisele, kuna lapsed idoliseerivad neid juutuubereid ja on nõus tegema ükskõik mida kuulsused parasjagu enda kasuks õigeks peavad.\nNoortele on sotsiaalmeedias kättesaadaval ka inimesi motiveerivate eesmärkidega sisu. Viimasel ajal Instagramis ja Tiktokis kuulsaks saanud kunagine USA mereväelane David Goggins on noortele silma paistnud enda inimesi motiveerivate videotega. Nimelt, on kuulsaks saanud jutuvestluste klipid, kus Goggins räägib enda raskest lapsepõlvest, mereväe raskustest, enese ületamisest ja arendamisest. Viimasel ajal on aktuaalseks teemaks saanud noorte laiskus ja pidev nutiseadmetes olemine, kuid nende videote vaatamisel leiavad noored oma nutiseadmetest mõtteid, millega motiveerida ennast ületama takistusi, mis eelnevalt tundusid võimatud. Vaatajad saavad samastuda sisulooja mineviku olukordadega ja võtta kaasa tarkuseteri, millega enda toimetulekut abistada. Kui noored võtavad ennast kätte, hakates treenima, ennast muud moodi harima jne. saab õelda, et nutiseadmetest oli kasu ja väheneb ka nende kasutamine.\nJälgides õigeid sisuloojaid saab noor end sotsiaalmeedias ka harida. Pikka aega kuulus olnud ameerika astrofüüsik Neil deGrasse Tyson on viimasel ajal hakanud tegema internetis videosi kirjeldades astronoomiat ja füüsikat noorematele arusaadavas võtmes. Neid videosi vaadates saavad lapsed paremini aru, kuidas neid ümbritsev maailm ja kosmos töötavad.  Saades sotsiaalmeediast lisaks koolile tarkusi, saab neid saadud informatsioon aidata nii koolis, eraelus või võib ka avada uusi karjääriuksi, mida noor ei oleks ise suutnud avada. Tarkust omandades saavad inimesed olla kasulikud mitte ainult endale, vaid ka neid ümbritsevale ühiskonnale.\nSisuloojad ei ole lastele alati halva mõjuga. Suunamudijad võivad aidata inimesi ning samuti ka neid harida. Oluline on lapsevanemana see, et ennetavalt suudaksid nad noort suunata õigete valdkondade juurde, kust neid negatiivselt mõjutada on raskem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
