INSERT INTO core.text(id, content)
VALUES ('00039c9e-8651-4866-ac9a-c28c90e26be4',
        'Tänapäeval on enamus noored inimesed ainult telefonis, selle asemel, et raamatuid lugeda. Nad näevad raamatute lugemist rohkem kui kohustust, mitte vaba aja veetmis võimalust. Selline elustiil ei ole ainult võõrriikides vaid ka suurel määral Eestis, sest Eesti on ikkagi e-riik. Mis on siis tagajärjed järgides sellist rammatuid mitte kaasavat elustiili?\nÜks põhilisi asju, mis ära kaob raamatute puudumisel on funktsionaalne lugemisoskus. Funktsionaalne lugemisoskus on see, mille abil saab igapäeva elus paremini hakkama ning ilma milleta on väga raske elada. See aitab inimest peaaegu igal moel. Näiteks saab võtta ühe tsitaadi Tiit Hennoste artiklist „Lugemis harjumuse harjutus“, mis läheb niimoodi: „Kõik käib läbi lugemise, koolimatemaatika ülesannetest kuni pangalepinguteni.  On piisavalt uurimusi selle kohta, et lapse hea lugemisoskus ja vabal ajal lugemine annab paremad hinded, parema hariduse, parema sissetuleku ja parema vaimse tervise.“ Siit saab järeldada seda, et kui raamatud puuduvad inimese elustiilist, siis tuleb sellega kaasa saamatus ehk ei olda võimelised läbi lugema tekste, millele alla kirjutatakse ning ei saada aru sellest, mida riik või ühiskond üritab neile öelda.\nTeiseks, raamatute lugemine õpetab inimestele kannatust. Õpetab neid aru saama, et kõik head teadmised või oskused ei tule kiiresti või ühe pöidla liigutusega.  Enamus asju liigub tänapäeval nii kiiresti ehk on toimumas kiirmaailma valitsus. Toit, keel, teadus, seks ja lugemine on kõik kiiresti kättesaadav ainult ninapidi telefonis istudes.  Üks tsitaat Tiit Hennoste artiklist „Lugemis harjumuse harjutus“ on järgmine: „Mõttega lugemine on aeglane tegevus.“  Sellest tsitaadist saab välja lugeda seda, et arenemine võtab aega ning selle jaoks on vaja kannatust. Areng ei teki sõrmenipsu pealt vaid see kestab aastaid. \nViimaseks on harjumuste mitte välja kujunemine. Harjumus luuakse harjutamisega.  Harjumus tekib ainult siis, kui on piisavalt tahet ning soovi, et seda kindlat tulemust saada. Jällegi üks tsitaat Tiit Hennoste artiklist „Lugemis harjumuse harjutus“: „On palju räägitud sellest, kuidas treenimine algab enda sundimisega ja peagi saabub hetk, kus inimene tunneb ennast halvasti, kui pole saanud oma igapäevast treeningannust. Seesama kehtib ka lugemise puhul.“ Antud tsitaadi põhjal saab järeldada seda, et kui inimesel pole piisavalt tahet, et tekitada endale igapäevane lugemisharjumis, siis ei ole ta ka suuremtõenäoliselt võimeline tekitama teistel aladel harjumusi.\nKokkuvõtteks võib öelda, et kui järgida elustiili, kus ei loeta vabatahtlikult raamatuid puhtalt huvi või teadmiste saamise pärast, siis peamised asjad, mis inimesel ära kaovad on fuktsionaalne lugemisoskus. Sealhulgas ka võime olla kannatlik kuna mõttega rammatute lugemine on aeglane ja tekib ka harjumuste mitte välja kujunemine.');
INSERT INTO core.text_property(text_id, property_name, property_value)
