INSERT INTO core.text(id, content)
VALUES ('36ae6e2e-cd2e-4dcc-9ee8-e6444385d468',
        'Noorte lugemine on olnud juba aastakümneid langustrendis, kas tõesti on selle taga vaid digiseadmed või on siinkohal mängus ka muud faktorid? Kuidas on mõjutatud Eesti ning, mida näevad Eesti noored enda raamaturiiulitel ja raamatupoodides, kas tõesti on Eesti lugemistulevik inglise keelne?\nAlustades digiseadmetest ja ekraanidesse, on õige väita, et noorte lugemisahrjumused on langustrendis, suur osa vabast ajast veedetakse nutitelefonis, tappes oma aju ja keskendumisvõimet Kui juba on tekkinud nutisõltuvus on sellest raske lahti saada, veel enam on raske ennast sundida tegema midagi, mis nõuab mõttega koha olemist ja tähelepanu kauemaks kui mõni lühivideo, nagu Tiit Hannoste on oma arvamusloos „Lugemise harjumuse harjutus“ öelnud: „Mõttega lugemine on aeglane tegevus.“ Noored ei suuda keskenduda lugemisele, ja sellele, mida neile proovitakse ridadevahelt ette sööta, sest nad on nii hajunud saama uut infot kiiresti ja ilma suure vaevata.\nSiinkohal ei saa süüdistada lugemise allakäigus vaid digiseadmeid. Noorena mõistan isegi, et vahel on muud teha kui lugeda. Näiteks on vaja sõpradega välja minna või on tarvis muud ette võtta ja lugemiseks palju aega ei jää. Sellegipoolest ei tohiks ajanappus ja tegevuste rohkus olla ainsaks põhjuseks, miks mitte lugeda. Nagu Tiit Hannoste eelmainitud arvamusloos väitis, et põjuhseks ei saa olla üleküllaldane tegevuste hulk, sest vabaaja tegevusi, mis ei hõlmanud lugemist, oli ka eelmisel sajandil, kuid siiski loeti tol ajal rohkem. Selle mõtte taustal on siiski passlik tunnistada et lisaks vabaajal veetmisele sõpradega, telefoni kasutusele, koolile ja muudele tegevustele vahel tõesti ei jagu päevas ruumi lugemiseks, või kui jaguks on pea juba nii väsinud, et isegi parima tahtmise juured ei veeriks aju sõnu paberil välja.\nKindlasti ei saa käsitlemata jätta ingliskeele ülevõttu kirjanduses. Tauno Vahter oma arvamusloos „Peame leppima, noored lihtsalt ei loe“ ütleb: „Noortele suunarud teemades on raamatu kaanel pealkiri üksnes inglise keeles, kuigi tõlge on siiski saksa keeles.“ Kuigu Tauno Vahter räägib siin Saksamaast on selline inglisekeelne pealkirjastamine probleemiks üle maailma, enda kogumusest saab tuua näiteks Poola. Kuna olen ise sellel teemal patune ning loen sageli inglisekeelseid raamatuid, olin üpris elevil, kui märkasin Poola raamatupoes ingliskeelseid pealkirju, kuid raamatu avamisel nägin poola keelset teksti. Sellist fenomeni, kus peubutatakse inimest lugema inglise keelse pealkirjaga, ma Eestis veel täheldanud ei ole, kuid on vaid ajaküsimus, millal hakatakse nii tegema ka siin.\nNoorte lugemishimu on langemas, seda mitmetel põhjustel, kuid tuleb siin siiski olla optimistlik ja loota, et mingil hetkel astub see jälle kasvutrendi. Täiesti aus olles, ei ole tegelikult vahet, mis keeles noor loeb, kas eesti, inglise, saksa või mõnes muus keeles, oluline on see, et noor loeb, arendab oma aju ning funktsionaalse lugemise oskust.');
