INSERT INTO core.text(id, content)
VALUES ('6ca7f354-f0dc-4aa8-893e-657e788dc556',
        'Tänapäeva ühiskonnas muutub sotsiaalmeedia iga päevaga aina tähtsamaks. On palju erinevaid kanaleid, kus inimesed saavad luua just seda sisu, mida nad ise tahavad ja sellega kuulsaks sisuloojaks saada. Osad influencerid on saavutanud kuulsuse luues naljakat sisu, tehes midagi head ühiskonna jaoks või olles lihtasalt teistest erinev. Sellega seoses tekivad neil oma austajad, kes soovivad olla nende moodi, et saada kuulsaks ja olla sama lahe. Kuid kas selline olukord on noortele kasulik või peaksid noored proovima elada nii nagu nad ise tahaksid?\nPaljud noored jälgivad oma lemmikuid sisuloojad iga päev ja proovivad nendega sarnased olla. Siiski võib esineda ka negatiivseid külgi, mis jääb inimestele märkamatuks. Veel võivad erinevad mõjuisikud rääkida lugusid, mis ei põhine mitte ühelgi faktil. Tartu ülikooli ühiskonnateaduste instituudi ektor Kristjan Kikerpill on öelnud, et võimalusel tuleks alati kasutada faktikontrolli, et teha kindlaks, kas räägitud jutt vastab tõele või on tegu väljamõeldisega. Veel esineb internetis palju erinevaid väljakutseid, mis võivad seada noorte elud väga ohtlikusse olukorda. Näiteks saab tuua kunagi internetis levinud mängu „Sinivaal“, kus noortel kästi sõitvate autode eest võimalikult lähedalt läbi joosta. Just selliseid mänge mängides kaotasid paljud lapsed oma elud. Ka paljudel noortel tekib oma lemmikute kuulsuste tõttu alaväärsuskompleks. Selle põhjusena hakkavad paljud noored enda välimust või käitumist muutma, et olla enda iidoliga võimalikult sarnane.\nKuigi on palju influencereid, kes teevad kõike vaid omakasupüüdlikuse eesmärgil, on ka olemas sisuloojaid, kes tahavad aidata oma toetajaid. Nad võivad jagada oma isiklikke kogemusi, et noored saaksid samu vigu vältida. Seda on teinud ka paljud Eesti kuulsad isikud, kes on rääkinud ära oma loo, et noored sama vigu ei teeks. Üheks parimaks näiteks saab tuua näitleja Märt Avandi, kes rääkis oma loo kokaiinisõltuvusest, kuidas sellistest asjadest eemale hoida ja sellest millist mõju see tema elule avaldas. Veel saavad sisuloojad tõsta noorte teadlikust erinevatest valikutest, mis neid elus ees ootavad. Näiteks juutuuber Andrei Zevakin on teinud reklaami erinevatele Eesti ülikoolidele nagu näiteks Eesti Mereakadeemia, käies ise kooli ühe õppejõu ja mitmete õpilastega merel. See tõstab noorte teadlikust nende valikutest ja näitab neile ülikoolide häid ja halbu külgi.\nMaailmas on olemas miljoneid erinevaid sisuloojad, kes mõjutavad noori igapäevaselt. Tuleb teha vahet kas nad on heatahtlikud või soovivad vaid endale parimat. Selle jaoks tuleb nende räägitud fakte kontrollida. Tuleb ka aru saada kus jookseb noorte inimeste jaoks mõistlikuse piir ja kas kõikidest väljakutsetest tasub osa võtta. Ka vanemtale tasub jälgida, keda nende lapsed internetis jälgivad, kuna leidub inimesi, kes proovivad teha inimestele head, kuid on ka neid, kes võivad seada noorte elu ohtlikusse olukorda.');
