INSERT INTO core.text(id, content)
VALUES ('5c0f5b2c-b04d-4f4b-9ac8-c6f17eee43e2',
        'Suunamudimine on uudset tüüpi nähtus, mis on välja kujunenud viimase 15-20 aasta jooksul. Suunamudijad on kujunenud lahutamatuks osaks sotsiaalmeediat kasutavate inimeste elus. Nende postitusi jälgivad inimesed igast vanusegrupist, kuid enamus neist on nooremad ergo kergemini mõjutatavad. Suunamudijate peamine ülesanne on inimesi mõjutada, olgu see tooteid reklaamides või tegevusi propageerides. See tekitab ohtliku olukorra, milles inimesed käituvad enda tahtmiste vastu, et rahuldada sotsiaalmeedias propageeritud „õiget“  arusaama.\nMaria Murumaa Mengel mainis, et juba 1956. aastast on parasotsiaalsete suhete teooria kohaselt inimestes kerge tekitada illusioon, et kuulsus on neile lähedane tuttav. Suunamudijad kultiveerivad seda suhet enda elu parimaid ning halvimaid hetki jagades. Jälgijatel tekib võlts usaldus suunamudijasse, sest ainult usaldusväärne ja lähedane isik jagaks sellist isiklikku informatsiooni. Seda usaldust saab sisulooja enda heaksarvamise järgi ära kasutada.\nEnamasti kasutatakse seda usaldust ära kasumi teenimiseks. Firmad ja isikud peavad toodete või ideede jagamiseks reklaami tegema. Suunamudijad on nende jaoks kuldsed haned, sest neil on loodud jälgijate ehk tarbijatega vastastikune suhe. Inimesed võivad tootele reageerida täiesti erinavalt olenevalt sellest, kelle käest nad kiidusõnu kuulevad. Firma saab edukalt tooteid müüa, suunamudija teenib raha, kuid kahjuks on üldjuhul tehing jälgijale ehk tarbijale kahjulik. Reeglina ei lähe tarbijal seda toodet või ideed vaja või toote kvaliteet on kehvem kui reklaamitud. Mõlemal juhul kulub ostja raha ebavajalikule tootele.\nArtiklis „Sotsiaalteadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir“ mainiti, et alati tuleks rahaliste kohustuste puhul uurida toodet, mitte jälgida pimesi suunamudijate nõuandeid. Viimase paari aasta jooksul on sisuloojate seas populaarseks kujunenud krüptovaluutade loomine. Jälgijatele lubatakse, et nad saavad selle krüpovaluuta ostmisega rikkaks, kuid alati juhtub vastupidine. Järjepidevalt tuleb iga kuu või kahe tagant välja uus skandaal, kuidas suunamudija tegi krüptoraha, inimesed ostsid seda ja kergitasid selle väärtust ning seejärel müüs influencer kõik oma osakud ja teenis suure kasumi, jättes enda jälgijad rahaliselt miinusesse.\nÕnneks on vahel hetki kui suunamudijad kasutavad enda võimu, et maailma parandada nagu sai lugeda Hea Kodaniku artiklist „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“. Karusnahafarmidel ei ole ühtegi positiivset tegurit. Sellele peab tähelepanu juhtima, et tarbijad oleksid teadlikumad ning selle jaoks on suunamudijad perfektsed. Nad saavad enda mõjuvõimuga taunida vääri ideid ja ülistada positiivset, eriti kui see langeb kokku nende enda vaadetega nagu näiteks loomakaitsjad Brian May ja Brigitte Bardot.\nSuunamudijatel on paratamatult oluline roll inimeste harjumuste kujundamisel. Mõlemal osapoolel on tähtis analüüsida ja kritiseerida olukorda, et pimesi ei öeldaks või tehtaks endale või teistele midagi kahjulikku.');
