INSERT INTO core.text(id, content)
VALUES ('ac5a6f55-d9ac-471c-b63f-f0278520c95d',
        'Tänapäevl võib märkama, et noored ei loe väga palju.See on väga nähtav ja paljud pöörduvad selle teemale oma tähelepanu. Olid need, kes arvavad, et see on väga suur probleem ja midagi peaks tegema noorte lugemisharjumusega.Võib palju räägida selle teemal , kuid tahakse arutleda konkretse küsimuse, konktetselt milline on tänapäeva noorte lugemisharjumus, selle võimalikud tagajärged ja millised põhjused sellest?\nJuba 1932. aastal oli kirjutanud, et noorte lugemisoskus läheb tagurpidi.Tänapäeval võib seda veelgi eredamalt näha, kuid sellele võivad olla järgmised seletused. Tiit Hennoste ütles, et lugemine oli tema jaoks vaba aja veetmise ja õhtu veetmise viis.Tänapäeval on meil veidi teistsugune pilt. Noortel on palju võimalusi ja viise oma aega huvitavalt ja erksalt veeta mimg sageli ei äirata lugemine nende huvi.Samuti Tiit Hennos ütles järgmised sõnad : „Mu arust on kaks olulist asja. Üks on nutimonomaania. ... Teine on kiirmaailma valitsus: kiirtoit, kiirkeel, kiirteadus, kiirlugemine. Mõttega lugemine on aeglane tegevus“ . Osaliselt võib temaga nõustada.Praeguse põlvkonna jaoks on tehnoloogia ajastul teave kiiresti kättesaadav ja selle nimel ei pea kõvast vaeva nägema.Kõigel on kiire  ja sageli ei ole piisavalt aega maha istuda ja lihtsalt midagi mõistlikult lugeda, sest ülesandeid on nii palju. Ja see on tingitud ka sellest, et ei osata seda õigesti teha. \nVõib ka öelda, et ilukirjandusekeel on raskesti mõistetav keel, tuleb teha jõupingutusi, et aru saada, mida sealt öelda tagavad. Sellele võib esitada Tiit Hennos, kes ütles, et ilukirjanduses hoopis tegelikult kõige keerukam keel , seal on kõige ebatavalisem ja laiem sõnavara , rasken lausekonstruktsioonid ja palju muid, aga keerukas keel on olemas ja jääb alatiseks olema. „Seda peab valdama, et maailmas hakkama saada, mõista keerulist, ebatavalist sõnavara, mõista pikki, keerukaid lauseid.“ Elu ei ole lihtne asi, kogu aeg peab midagi lahendada ja ületada raskusi.\nNoorte lugemisharjumuste puudumine võivad olla tõsised tagajärjed. Esiteks vähendab see kirjaoskust ja võimet end selgelt väljendada, mis raskendab suhtumist ja ametialast arengut.Teiseks, ilma lugemiseta aheneb nende silmaring, väheneb kriitiline mõtlemine ja vüime teavet analüüsida.Lisaks areneb lugemine kujutusvõimet ja emotsionaalset intelligentsust ning aitab arendada sügavamat arusaamist teistest inimestest. Ilma selleta võivad noored muutuda vähem empaatiliseks ja sallivaks. Pikemas perspektiivis võib lugemisharjumuste puudumine mõjutada ühiskonna arengut tervikuna: kultuuritase langeb, väheneb teaduse ja tehnoloogia arengu kriis kui spetsialistide arv väheneb.\nLugemine ei ole mitte ainult teadmiste allikas, vaid ka mõtlemise, kujutlusvõime ja suhtlemisoskuse arendamise vahend, Ilma selleta kaotavad noores võime kriitiliselt mõelsa, tõhusalt suhelda ja mõista ümbritsevat maailma. Lugemine on oluline isikliku arengu ja ühiskondliku arengu jaoks.');
