INSERT INTO core.text(id, content)
VALUES ('3ca527e2-a2c3-4405-b48a-08c64bd66cf0',
        'Tänases ühiskonnas igal on vähemalt mittu inimest, keda nad vaatavad, kas on see mingi poliitik, näitleja või minge lihtne mees, kes mängib igal reedel mingi arvutimängu ja transleerib seda. Nad on nii nimetatud „suunamudijad“. Nad on eeskujud oma vaatajatele, kas positiivned või neghatiivned, igal juhul nad mõjuvad oma vaatajat. Aga, kas ei ole probleemi, et mingi tundatu inimene internettist hakkab noorte põlvkondadele käitumist ja väärtusi kujundama.\nPeamiseks on vaja arusaada, et kõik inimesed keda sa näed, bõi kelle kohta sa kuulad kuidagi sind mõjutavad. Nad võivad näidata kuidas käituda on vaja, või vastupidi. Kuidas riietuda, mis muusikat kuulama, kuidas on vaja teistega käituda. Meie aju näeb kõike, mis toimub meie ümber, see kuidagi mõjutab temast, kas natukene või vastupidi pöörab meie arvamust 180 kraadi poole. See mõju võib ola positiivne, aidata kuidagi inimestele midagi arusaama, või areneda, või normaliseeruda midagi halba. Suunamudijad mõjutavad seda tugevam. Kui inimene, kellele sa oled automaatselt hästi suunatud hakkab midagi sulle öelda, siis selle informatsioon sa võttad lihtsam.\nAga esiteks peame rääkida selles, et see asi on juba päris vana. Vanasti noored võtsid endale eeskijuks mida nad nägid, lugesid või kuulsid. Sõltus see tavaliselt ühiskonnast, mis ümbritses inimesi. Kui sa elad vaeses kohas, kus oli normaalne varastada, siis varastamine muutub temale oluliseks asjaks. Kui inimest õppetati, et ta peab käituda õigesti, siis saab temale õiguskäitus oluliseks. Kõige tugevasti töötab see, kui seda hakkab teha nende eeskuju. Kuna nendele see eeskuju on just mingi näide kuidas on vaja käituda. Aga see asi töötab ka inimestega kes on vanem. Vanasti olid nad tuttavad inimesed, nagu isa või ema, või mingi raamatu tegelane. Praegu see eeskujusaamine lihtsustas, aga töötab just sama moodi. \nSuunamudija saatumine sai lihtsam kui oli enne, see põhjustas selle olukorra, kus teie last saab lihtsalt mõjutada mingi inimene internetist, kes ütleb et alkohol ja narkotikumid on hea, valetada on normalne, ja te ei pea arvestada teiste inimeste tunnetega, ja temale selle eest mitte midagi ei tule. Muidugi tekkib soov kõike seda kinni panna, aga kas ei ole see vanemate vastupidevus, segitada oma lastele mis on hea ja mis on paha, et temast ei saa nii lihtsalt manipuleerida. Peaaegu sama asi töötab ka täikasvanu inimestega, kuna te olete juba täiskasvanud, te peate juba mingi asja arusaama, ja kuidagi tsensureerida infot, mis teile sattub.\nLõppude lõppuks on loogiline, et teised inimesed saavad meid kuidagi mõjutada, ja internett väga lihtsustas seda, aga see ei ole nii halb asi, kuna kedagi teise arvamus saab meid positivses suunad mõjutada. Lihtsalt ühiskonnale on vaja arusaama, et nad peavad õppima kuidagi tsensureerida ja ise arusaama infot, mida neile räägivad.');
