INSERT INTO core.text(id, content)
VALUES ('86253e29-0b47-4bf1-ac8d-3fd266fb232c',
        'Tänapäeva ühiskonnas on olemas mitu probleemi mis on seotud noortega. Noored võtavad vastu informatsiooni kiiresti ja põnevusega, aga on olemas üsna suur probleem, mis puudutab just tänapäeva noori, ja see probleem on telefonide kasutus. Vanasti, selleks, et teada saada mis ja kus toimub, võiks olla lihtsalt vaadata ajalehti ja telerid, kui ta oli, aga nüüd on olemas väike seadme, mis hoiab ennas tuhandeit allikaid. Mis on selle tagajärg?  \n Räägites Eesti ühiskonnast on nähtav see, et paljud noored kasutavad telefonid kustahes, kas koolis või voodis lamades. See võtab palju aega nende igapäevaelust, mis võiks selle asemel minna raamatute lugemisele. Raamatute lugemine on harjutus mis aitab arendama igasuguseid aju oskusi nagu tähelepanelikkus ja deduktiivsus. Telefonis on liiga palju positiivsust kui ka negatiivsust, aga räägites raamatest, negatiivsed küljed kaotavad. Ainuke koht kus paljud noored loevad raamatuid on kool ja isegi seal mõned kasutavad trikke, et neid raamatuid mitte lugeda. Raamatud olid nagu vaba aja täitmine ja nüüd seda aega täitavad telefonid. Võib öelda, et Eestis, kui arenenud riigis see probleem on rohkem levinum kui näiteks Süürias, sest seal elaval inimesel on probleemi. Võib ka öelda, et see probleem tuleb magusast elust, kuna meie probleemid on väiked võrreldes teistega.\n„Kus luuakse lugemise harjumus? Kindlasti kodus“. See tsitaat hästi näitab seda, et luua lugemise harjumust koolis ei ole võimalik, kuna laps ikka veedab rohkem aega kodus ja õues kui koolis. Umbes kõik lapse harjumused tulevad mitte koolist ja just selle sellepärast on oluline midagi muuta midagi meie kooli süsteemis, sest kui kõik jääb nagu praegu, tulevikus ilmuvad täiskasvanud, mis olid kasvatatud telefoni ja interneti abil, mille tagajärjena on raamatute populaarsuse kahanemine või isegi nende kadumine. \nLõpuks võib öelda, et raamatute populaarsuse kahanemine ja see, et lapsed on kasvatatud telefonide abil tulevad välja nagu suured tagajärjed. Tore asi on see, et on veel võimalik midagi muuta, täpselt koolides ja kooli prograamides. Kõik on meie kätes.');
