INSERT INTO core.text(id, content)
VALUES ('98d4363d-7b9d-4c82-b292-5c86ba20f7fe',
        'Tänapäeval paljud noored ei loe tavalisi raamatuid, aga lihtsal skrollivad internetis. Pärast arvutite arendamist paljud noored hakkasid kasutama arvuti meele lahutuseks, nagu mängud ja internet portaalid. Kas noored hakkasid lugema vähem või nad teevad seda lihtsalt teist mooodi?\nEsiteks, noored hakkasid vähem lugeda tavalisi raamatuid, sest praego filmid või mingid videod internetis on põnevam kui vana kunstikirjandus. Ausal öeldes eestis on probleem uutega estikeelsetega ramatutega, need raamatud mida saaksid armastada noored. Inglese ja venekeelel on väga palju ramatuid mis on minevad ja paljud noorid kuulasit nendest. Näiteks praegu eesti koolides nooredu lugevad sellist raamatud nagu „ussisõnad“ mida kirjutas Andrus Kivirähk ja sellest raamatust oli palju uudisi Facebook’is, et sellist raamatud on vaja lugeda mitte noortele vaid täiskasvanutele. See näitab, et kool ei saa pakkuda seda mis on põnev noortele.\nTeiseks, praegu internetis on väga palju põnevaid lugusid, et kuidas inimesed elavad ja millised probleemid on nendel, paljud noored kasutavad „Twitter“, „Facebook“ ja „Redit“ need äppid on tehtud selleks, et inimesed rohkem lugeksid ja saaksid teada kuidas teised elavad. Need äppid teevad palju selleks, et nooed hakkaksid lugem ja kirjutama oma utusid.\nViimaseks, uudis portaalid kus noored istuvad iga päeva ja komiksid inglise keles. Praegu suur osa nooretest palju teavad poliitikast ja majandusest, sest praegu on populaarsed erialad ülikoolides. Kõige roohkem nooned kasutavad „ERR“, „Postimees“ ja inglisekeelsed nagu „BBC“, „Financenews“ ja teised. Sellest kijutas postimees artiiklis mida lugevad noored. \nNoortel ei ole probleemi lugemisharjumusega, lihtsalt praegu ilmusid uued võimalused lugeda. On mõned probleemid eesti raamatutega mis sobiksid noorte jaoks, aga nad ssavad hakkama ilma nendeta. Noored kasutavad uudisportaalid ja sotsiaalmeedia selleks, et saada lugemis praktikad. Ühiskod lihtsalt läheb tulevikku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('98d4363d-7b9d-4c82-b292-5c86ba20f7fe', 'title', 'Lugemisharjumus täna');
