INSERT INTO core.text(id, content)
VALUES ('913d0d7e-5ed3-4839-bc2b-99793b80509e',
        'Ajal, kus elasid meie vanemate vanemad, infoallikaks olid ainult raamatud ning suhtlemiseks ainult reaalne kohtumine. Praegu meil on internet, kus meie otsime vajalikut infot ja jagame oma elu sotsiaalmeedias. Põlvkondadel olid erinevad viisid infoleidmiseks, seega nendel on lugemisharjumus, kuid meil see on puudu. Seos sellega, et erinevate põlvkonna väärtused muutuvad, muutuvad ka nende harjumused.\nEi saa öelda, et noored üldse ei loe. Nad loevad, kuid teevad seda ainult tol ajal, kui seda vajavad, ja ainult seda infot, mis nendele huvi pakkub. Ajal, kui elasid meie vanemate vanemad, meellahutuseks enamasti olid igasugused, kodus olevad, raamatud. Kõik lugesid ühe ja sama ning puudus suur valiku võimalus. Meie ajal on suur hulk erinevate meelelahutusi, mida me saame teha kodust mitte väljudes. On ka filmid, mis on tehtud raamatute alusel, seega me valime filmi vaatamine. Film on huvitav ning ei le vaja kasutada enda oma kujutlusvõime. Kõik on tehtud inimese elu lihtsustamiseks, milleks seda siis raskemaks teha?\nTänapäeval progreseerib tehisintellekt, mis on suur proobleem noorte arenemisel. Nad ise ei kirjuta kirjandid ja ei loe terve raamatut, vaid loevad lühema ümbejutustust. Sotsiaalmeedia arenes väga palju ja see pakkub huvi noortele, sest see on midagi uus, mis jätkab oma arenemist igapäev. Z-põlvkond ei elanud päeva internetita maailmas, seega nendele see on väga tuttav. Iga inimene kasutab interneti erinevatel viisidel. Erinevates veebides ja erinevates žanrites.\nNoored ikkagi loevad, aga loevad seda, mis pakkub neile huvi ja nad tahavad seda lugeda. Meie väga austame vabadust ja valiku võimalust, seega kooli raamatuid me ei loe. Ei loe mitte selle pärast, et ei taha, aga sest meid piinavad ja ei annavad võimalust valida seda, mis rohkem huvi pakkub. Tik Tokis ja Instas paljud bloogerid propagandeerivad raamatute lugemine ning hindavad ja soovitavad raamatuid, mida ise lugesid. Vaadates probleemile selles vaatenurgast siis probleemi ei ole ja lugemisharjumus ei kadus.\nVõrrelda X- ja Z-põlvkonda on sama asi kui võrrelda kala ja kilpkonna. Nad on omavahel natuke seotud ja samasugused, kuid eluviisid on erinevad. Z-põlvkond teab rohkem informatsiioni digitaalses keskkonnas. Lugemisharjumus ei kadunud, aga nad täiesti muutusid.');
