INSERT INTO core.text(id, content)
VALUES ('608fc864-6048-4215-9c58-c9ecf7c09682',
        'Tänapäeva maailmaas on avaliku elu tegelastel ja sotsiaalmeedia mõjuisikutel noorte elu kujundamisel tohutu roll. Nad mõjutavad noorte otsuseid, nende väärsuseid ja isegi eluviisi, pakkudes ja reklaamides erinevaid eeskujusid, tooteid ning kujundades arusaama edust ja õnnest. Nende mõju motiveerib inimest ja nad hakkavad teha inspireerimaid tegevusi, kuigi mitte alati see mõju toob head tagajärgi. \nEsiteks pakuvad sotsiaalmeedia mõjutajad noortele eeskuju ning kujundavad nende arusaama sellest, milline peaks olema elu. Nad jagavad hetki, kus võib näha nende „päris“ elu, kus neil on samagused probleemid, nagu tavalistel inimestel. Ka nad jagavad oma arvamust ning näitavad oma „heategevus“ ühiskonnale. Paljud neist annavad raha loomade aitamisel. Näiteks allikas :“Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“ räägitakse, et kampaanias osalesid seitse suunamuudijad, kes kutsusid inimest mitte soetama karusnahka. Nende mõju pärast kampaania sai populaarseks ning aastate jooksul toetust avaldanud 70 erinevate valdkondade ettevõtet ja kõik siinsed loomakaitseorganisatsioonid. Kui noored näevad oma lemmikud suunamudijat, siis neil tekkib huvi ja nad uurivad, kus tema „eeskuju“ osaleb ja tahab ka selles osalemist võtta. Ka nad motiveerivad noored saada tulevikus nagu ńemad ja treha samased heategevused ühiskonnale. Se on hea näide, kuidas sotsiaalmeedia mõjuisikud mõjutavad inimest teha head tegevusi. \nTeiseks mõjutavad sotsiaalmeedia tegelased noorte tarbimisharjamusi. Paljud mõjutajad reklaamivad erinevaid tooteid ja teenuseid, mis võivad tunduda noortele meeldivad. Kuna reeklaamid teevad nende „eeskujusid“ eriti raske aru saada, kas nad tõesti seda toode soovivad või see on sotsiaalmeedia mõju, näiteks palju reklaami vaadet näitavad, et toode on hea ja seda peab osta. Allikas: „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad“ oli kirjutatud, et suunamudijad mõjutavad inimesi konkreetsete toodete ostmisel, tervisega seotud valikuid tehes ( dieedid, iluoperatsioonid jne). See kõik võib viia tarbimis süvenemiseni, kus noored soovivad pidevalt osta uusi toodeid, uskudes, et see kõik teeb elu paremaks nagu suunamudijatel, kuid samas võib see tekitada ka ebarealistlikke ootusi ja rahuolematust oma igapäevaeluga. \nKokkuvõttes on avaliku elu tegelastel ja sotsiaalmeedia  mõjuisikutel suur roll noorte igapäevaelu otsuste kujundamisel.  Nende mõju võib olla nii positiivne kui ka negatiivne. Ühelt poolt võivad nad inspireerida teha teadlikumaid tegevusi, kuid teiselt võivad nad tekitada ebarealistlikke ootusi ja teenida raha liigsete tarbimise tõttu. Seega on oluline, et noored oskaksid eristada reaalsust soltsiaalmeedia maailmast  ning säilitada oma arusaama elust ning mõtlemisest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('608fc864-6048-4215-9c58-c9ecf7c09682', 'title',
        'Avaliku elu tegelaste ja sotsiaalmeedia mõjuisikute mõju noorte elu');
