INSERT INTO core.text(id, content)
VALUES ('3cd70691-3fcc-4483-9af1-aad77764707e',
        'Tänapäeva ühiskonnas mängivad avaliku elu tegelased ja sotsiaalmeedia mõjutajad olulist rooli noorte igapäevaelus. Nende kaudu jõuavad noorteni mitte ainult trendid ja elustiilivalikuid, vaid ka hoiakud ja väärtushinangud. Aga see mõju võib olla nii positiivne, kui ka negatiivne ja ohtlik, mis vajab tähelepanu ühiskonna poolt.\nÜks probleem, mida ajalehes Õpetajate Leht artikklis „Mõjutamine (4): Kuidas suunamudijad meid mõjutavad?“ käsitletakse noorte eraldumine lähedastest, sest nad tõepoolest arvavad, et sisuloojad saavad nendest aru parem, annavad noortele teadmisi ja annavad neile paremad soovitusi kui nende vanemad või sõbrad. Allika autor märgib: „Uuringutest on selgunud, et tihti saavad noored just suunamudijatelt nõu, mida normaalseks või ebanormaalseks pindada, mida ihaldada, mida põlastava pilguga vaadata, kuidas suhelda. Suunamudijate kaudu jõuab noorteni ka mitmeid baasteadmisi ja tüvitekste, sisuloojad isegi kujundavad neid.“. See näitab, et noored kuulavad mimg küsivad abi ja nõu influencer´itel, vaid mitte vanemate juures.\nTeine negatiivne aspekt on see, et suunamudijatel on suur mõju noortele ja neid usutakse, millest on kirjutatud „Sotsiaalteadlane: suunamudijate ja veebikelmide vahel jookseb õrn piir“ tekstis. Selle teksti autor toob esile, et mõjuisikud võivad teadlikult või tahtmatult manipuleerida oma jälgijatega, esialgu noortega, seades esikohale oma soove ja kasu. Sellised olukorrad panevad noored ohtu, kuna nad võivad teha otsuseid, mis pole nende enda huvides. Tekstis on lühidalt kirjeldatud paljude unfluencer´ite rahateenimisvõimalused, mille põhiidee on sisendada oma jälgijatedele, et see on hea, kasulik ja toode ning nad peavad seda osta, kuid tegelikult teha seda ainult raha teenimise eesmärgil ja müüa madala kvaliteediga tooteid ja sellega petta oma usaldavat auditooriumi.\nMa mainisin alguses, et suunamudijate mõju võib olla ka positiivne. Blogijad saavad motiveerida vanainimesi ja noori teha häid tegevusi, muuta maailma ning panna alus millelegi kasulikule. Näiteks ajalehes Hea Kodanik avaldatud uudis „Seitse populaarset Eesti suuna,udijat kutsuva inimesi üles karusnahka mitte soetama“ toob esile, kuidas influincer´id suunavad noori tegema keskkonnasõbralikumaid ja parimaid valikuid. Lisaks, see algatus annab noortele teadmisi loomade heaolekust ja keskkonnaprobleemidest, mis on tänapäeva maailmas väga olulised teemad ja suured probleemid, mis vajavad lahendusi ja rohkem toetajad. See uudis peab motiveerida meie riigi elanike, sealsuhtes noored; teha loodusesõbralikumaid valikuid. See ongi näide, mis toetab järeldust, et meedia ja netikuulsused saavad mõjutada noored positiivselt. \nJälgijate ja sotsiaalmeedia mõjutajate vahel on õrn piir ja suunamudijate mõju noortele on täitsa mitmekesine. Positiivse poole pealt võivad nad inspireerida ja tõsta teadlikkust olulistes küsimustes, samas kui ebatavaliste nõuannete ja tegevuste ignoreerimine võib viia petmisteni ja mõtlematute otsusteni. Seetõttu peaks ühiskond rohkem mõelda noorte tunnetest, probleemidest ja toetada neid, et eristada ohtlike ja traumerivate olukordi.');
