INSERT INTO core.text(id, content)
VALUES ('49c15ecf-e176-482d-b3d0-4e385a00e882',
        'Meie ühiskond areneb väga kiiresti, eriti viimastel aastatel on areng kiirustanud geomeetrilise jadaga, aga areng ühes kohas mõnikord tähendab halvenemist teises. Niimoodi juhtus lugemisega. Nutiseadmed olid alguses suurepäraseks arengu abivahendiks, aga viimasel ajal on näha ka takistusi. Üks neist on lugemise harjumuse kadumine. Noored ei suhtu lugemisesse nagu ajaveetmise viisisse, vaid peavad seda kohustuseks või isegi karistuseks. Mida see ohustab ja mis saab praegu teha?\nMina olen ise noor ja tunnen selle probleemi tõsist, sest enda karval näen, et tehnoloogiad võtsid mind üle ja valiku tegemisel ma ei läheks vabatahtlikuna lugeda, kuid eelistaks midagi lihtsamat ja pingetumat. Miks niimoodi juhtus? Kõik tuleb lapsepõlvest. Mäletan oma esmisest iPad`i ja emaga kokkulepet, et pooltundi lugemist annab mulle aega mängimiseks. Mul ei tekkinud sisemotivatsiooni lugeda, see oli keerulisem, on vaja pingutada ja kasutada oma kujutlusvõimet, et saada aru kogu loost. Oletan, et ma ei ole ainuke näide, olen nagu kogu minu põlvkond. Meil oli liiga palju alternatiive, millistega võrreldes on lugemine nähtavalt alla jäänud. Kuidas seda siis ära lahendada? Harjumusi omandamine on aega võttev protsess, aga oled kord harjumust võtnud, siis on kohta enda arendamiseks. Alustamiseks tuleb vastata endale: milleks ma seda teen? Kas see on minu tõeline soov või keegi mind sunnib? Sisemotivatsioonita ei tule midagi head välja. Teiseks on oma lemmikžanri leidmine, kuna kui teema sind päriselt köidab, siis rahuldamiseni on pool sammu. \nLugemisprobleem on laiali levinud, aga kui alustada kohe, siis kõik on teie käes.');
