INSERT INTO core.text(id, content)
VALUES ('28983b1d-bf96-47b3-9479-20e4143ecb68',
        'Tänapäeva noored on harjunud lugema ainult siis kui see on kohustus. Näiteks kohustuslik kirjandus. Sellestki proovitakse mööda põigata; vaadatakse filme, loetakse internetist raamatu kokkuvõtteid või küsitakse sõbralt, kes raamatut luges, et mis seal toimus. Muidugi ei käi see kõigi õpilaste kohta ja on ka erandeid. Kuid pean nõustuma Tauno Vaheri väitega; „et tõsiselt häid tulemusi noorte lugemisharjumuse suurendamisel ei ole ja pigem ka ei tule.“.\nEnda kogemusele põhinedes julgen väita, et suurem lugemine hakkab hiljem elus. Olgu see siis gümnaasiumis, ülikoolis või lausa pensioni eas. Gümnaasiumi õpilasena ootab kirjanduse õpetaja, et sa loeksid vähemalt ühe raamatu kuus, aga kuna muu õppekoormus on nii suur ja eksisteerivad ka kohustused väljaspool kooli, vaatan ka mina pigem filmi kui loen raamatut. Tihti on ka kohustuslik kirjandus miski, mis ei köida õpilast ja see tõttu õpilasel on seda keerulisem lugeda.„Millalgi vahetus vabatahtliku lugemise ajastu suurele osale noortest käsu peale lugemise ajastuga“- Tiit Hennoste, nõustun selle väitega ja olen tundnud seda ise kogu oma elu. \nMuidugi me teame, et lugemine aitab arendada keele oskust ja aitab ka meid tulevikus karjääri redelil. Kuid kuna lugemine on jäänud noortele nii kautseks ja me elame nuttiajastus ei kahtle ma, et tulevikus meilid kollegidelt on kõige lihtsamate kirjavigadega. Muidugi on meil ka tänapäeval AI, kes kirjutab juba algklasside õpilaste tekste nende eest, või täidab nende lugemispäevikut. Õnneks ei ole AI veel nii tark ja õpetaja saab aru kui AI ütleb, et näiteks kevades ei olnud Teele vaid hoopis Tuuli.\nNõustun ka Tiit Hennostega teemal, et lugemisest tuleks teha harjumus. Just lugemisharjumuse peaks juba väike lastele sisse juurima, et neil tulevikus kergem oleks. Lugemisharjumuse tekket võib ka soodustada nuttitelefoni ja muude segavate faktorite piiramisel, eriti ennem magama minekut.\nKuidas me saaksime noorte lugemisharjumust tõsta ja lugematuse tagajärgi vältida? Minu arvates peaks õpilane saama lugeda raamatut, mis teda huvitavad. Muidugi peab ka teadma Eesti tähtsaid kirjandus teoseid nagu „Tõde ja Õigus“, aga me peaksime andma õpilasele vabamad käed valida ise raamat. Tehes lugemine õpilastele huvitavaks ja meelepäraseks paraneb nende grammatika ja väheneb oht teha lihtsaid kirjavigu. Loodan, et lastele tulevikus muutub lugemine harjumuseks ja, et kohustlik kirjandus köidaks õpilast nii palju, et ta ka päriselt loeb seda raamatut mitte ei vaata filmi.');
