INSERT INTO core.text(id, content)
VALUES ('11323718-a16a-48bc-8e18-0a6cf6506931',
        'Sisuloojad on suured mõjutajad Eesti  ühiskonnale, nad tegelevad igapäevaselt kas reklaamimisega või meelelahutusega.\nReklaamimisega seoses on tekkinud mitmeid probleeme millel võivad olla rasked tagajärjed nt: sisulooja reklaamib toodet mis talle endale tegelikult üldse ei sobi, seda reklaami näevad inimesed ja muidugi tahavad nad seda osta kui toodet reklaamib kuulus influencer. Enamus reklaamides ei mainita kuidas toode on valmistatud ja mis koostisosi see sisaldab.\nTihtipeale kasutatakse suunamudijaid kui info allikana, mis tähendab, et kogu info saadakse neilt, enamik juhtudel osutub neilt saadud info valeks. Paljud noored küsivad neilt nõu, mis muidugi võib probeemil aidata lahendust leida, aga on ka võimalus, et see süvendab probleemi.\nVeebis tegutsevad ka igasugused petturid, nad oskavad sõnastada oma juttu nii, et inimesed sellele kohe reageeriks.\nPaljud petturid sotsiaalmeedias kasutavad ära just nooremaid lapsi või vanemaid inimesi, ei ole välistatud, et ka keskeas inimesed puutumatuks jäävad. Enamasti pettetakse inimestel välja raha, kuid saab ka muul moel. Tänapäeval on petturid juba nii arenenud, et jutu käigus suudavad saada sinu andmed, et neid siis hiljem kurjasti ära kasutada. Mõndadel juhtudel on nõus inimesed ise raha andma/kandma, nii tuleb välja TikTokist, piisab ainult kurvemast näost ja juba saadetakse raha teele.\n   „Populaarsemate suunamudijate sõnumid jõuavad väga paljude inimesteni. Kui see on siiras ja võib-olla inimene lihtsalt arvab midagi, millega me ei nõustu, siis on tegemist mõtte- ja sõnavabaduse alla kuuluvaga. Kui aga mängus on varjatud hüved, siis on põhjust olla rohkem murelik.“ Sotsiaalmeedias levib info tohutult kiiresti, tänu sellele, et inimesed seda näevad ja teistega jagavad. Paljud inimesed jagavad petturite videoid ja sõnumeid peaaegu igapäev, enamus teeb nende üle nalja, kuid on ka inimesi kes satuvad nende petturite mõju alla ja seejärel jäävad nende lõksu. Meedias toimub ks palju konflikte, mis tõttu tekib suuremat sorti “draama“, tänu sellele valivad, siis inimesed kelle poolt nemad on, mida kurvem on lugu, seda rohkem inimesed usuvad ja nii lihtsasti ongi võimalik inimest mõjutada.\n   “Usume, et noored hoolivad loomadest ja tahavad päriselt maailma muuta“. Tänapäeva generatsioonile on pandud palju usku, muidugi on nad võimelised tulevikus maailma muutma. Tänapäeva noored on entusiastlikud ja hakkajad, kindel on see, et asjad hakkavad muutuma.\nPraegune suur püstitaud probleem seoses loomadega on karusloomafarmid. On keelustatud ning kinni pandud paljusid farme, erinevad ettevõtted on kogunud allkirju, sealhulgas on selle vastu erinevad artistid, näitlejad, kirjanikud jne. On tehtud paljusid ettevõtteid, sealhulgas ka Fur Free Retailer, mis ei kasuta karusloomade nahka ega karva enda toodetel, nemad on leidnud võimaluse mitte kasutada karusnahka. Tegutseb ka maailma populaarseim loomakaitseorganisatsioon PETA.');
