INSERT INTO core.text(id, content)
VALUES ('3d3a6c53-be40-4672-a2bd-19e67f463aef',
        'Sotsiaalmeedia mõjuisikud suunavad tänapäeval noorte elusid. Ei ole kahtlust, et neil on oma mõju olemas, aga küsimus on selles milline see täpsemalt on. Need mõjuisikud võivad olla igast vanusest, maailmanurgast ja ühiskonnakihist isikud, kellel on pealehakkamist ja midagi, mida noortele edasi anda. Üldreeglina peab olema netikuulsusel, mingi eripära, mis tallle edu toob, selleks võib saada sisulooja erakordsus, eksootilisus, eksklusiivsus või just elulisus. Igal juhul, kui mõjuisik on oma publiku tähelepanu köitnud on tal võimalus hakata nende mõtlemist ja tegusid suunama. Nüüd on tema otsustada, kuhu suunas ta oma vaatajad, lugejad või kuulajad viib, rahvas on tema ja teiste sama eluala esindajate kätes.\nTihti eeldame, et suunamudijad on siirad ja heatahtlikud ja nad soovivad oma publikut suunata avastama neile endile sümpaatseid kultuuriaardeid. Nad näiteks jagavad oma postitustes soovitusi filmi-, maalikunsti, muusika ja kirjanduse vallas. Samas võivad nad ka mõnda teost kritiseerida ja soovitada noortel seda vältida. Kristjan Kikerpuu on kirjutanud järgnevalt: „Kui see on siiras, ja võib-olla inimene lihtsalt arvab midagi, millega me ei nõustu, siis on tegemist mõtte- ja sõnavabaduse alla kuuluvaga. Kui aga mängus on varjatud hüved, siis on põhjust olla rohkem murelik.“ Nii on tihti raske vahet teha inimese ausa ja heasüdamliku soovituse ja kellegi poolt ostetud arvamusavalduse vahel, kus on mängus tarbijaeest peidetud hüved.\nSamamoodi on ka erinevate mõtteviiside ja ideedega, suunamudijad reklaamivad ka neid ja meie kui tarbijad ei oska alati ära mõistatada varjatud motiive nende tegevuse taga. Maria Murumaa Mengel on kirjutanud enda artiklis uuringutest, kust on selgunud, et noored saavad tihti just suunamudijatelt nõu, selle kohta mida normaalseks või ebanormaalseks pidada, mida ihaldada, mida põlastava pilguga vaadata, kuidas kellessegi suhtuda.  Sama artikli sõnul on ka kindlaks tehtud, et suunamudijad mõjutavad inimesi toodete ostmisel, tervisega seotud valikud tehes, parteide ja poliitikute toetamisel ja muudes eluvaldkondades. Seega on netikuulsuste mõju tohutu. Noorte suunamise taga olevad motiivid on aga tihti teadmata.\nMainitu põhjal on ilmselge, et suunamudijad kujundavad noorte maailmapilti igast küljest, olgu see siis nende endi suva järgi või millegi muu ajendil, mis jääb tihti varjatuks. Igasugu juutuuberid, instagrammerid, tiktokkerid, blogijad ja teised  suunavad noori ostma, mõtlema, tarbima ja tegutsema väga erinevates suundades. Noortel jääb vaid üle targasti nende sisu tarbida ja teha valikud, mis neile paistavad sobivat, sest võimalusi on tänapäevases infoühiskonnas lõpmatu hulk. Tuleb vaid ettevaatlik olla seal, kus on mängus varjatud hüved, sest nendes kohtades on niiditõmbajatel, kes hüvesid suunamudijatele pakuvad suuremad ja olulisemad eesmärgid silmas.');
