INSERT INTO core.text(id, content)
VALUES ('6bb1ef73-e310-4e3a-a9bc-81c0bb1b0cb0',
        'Tänapäeva ühiskonna mure on pealetuleva põlvkonna suutmatus keskenuda pikkadele info edastustele, nende aju nõuba kiiret ja viivitamatut info saamist. Tänapäeval süüdistatakse selles Tik Tok-i ja Instagram-i, kuid tegelik probleemi iva on saanud juba alguse märksa varasemalt. On märgatud et alates 90-nendates kuni 2000 aatate vahel on noorukite lugemus komeedina langenud. Oleme jõudnud tänapäeva kus lugemine on noorte seas äärmiselt ebapopulaarne ning seda asendavad teised meelelahutus võimalused. Aga siiski, milleks noortele lugemine, miks on see siiski äärmiselt vajalik?\n Mälestusi minu oma kooliajast põhikoolis. Mäletan kuidas lugemine oli üks viimaseid asju mida soovisin teha kõigi teiste toredate tegevuste kõrvalt, olgu need kas siis mängimine või videote vaatamine. Sama seis on ka tänapäeval. Ise ei alustaks ilmselt mitte ühegi raamatu lugemist kui seda just kirjanduse tunnijaoks vaja ei ole. Kurb kui see ka pole siis tänapäeva maailmas ei ole raamatute lugemine konkurentsi võimeline teiste meelelahutus võimalustega mis noortele kättesaadav on. Alati on midagi muud mis selle üle trumpab. Isegi võttes arvesse et paljud raamatud on ju tegelikult vägagi huvitavad siis on populaarseimatest teosetest tehtud juba filmid. Näitena võib tuua kas Harry Potteri raamatud või siis Sõrmuste isanda ja Kääbiku lood Tolkeni raamatutest.\n Miks siiski meil noortel seda paganam lugemist vaja on? Olen kindel et iga noor suudab endale teadvustada et lugemine ei ole ju tegelikult halb vaid hoopis kasulik. Mis  võiksid siis olla mõned lugemise plussid mida tuleks arvesse võtta? Kindlasti on üks teada tundtumaid fakte see et lugemine on ajule kasulik ning soodustab mõtlemist. Sammuti avardab lugemine ka tarbija silmaringi ja sõnavara. Minu arvates on viimane just üks olulisemaid tegureid lugemise puhul. \nVõttes teatavaks kõike eelmainutud, milleks noortele siis lugemine ikkagi vajalik on? Nooruki aju on alles arengu faasis nign selle pärast oleksiki just kasulik stimuleerida aju materjaliga mis talle tööd pakub. Pikemad raamatud ja teksdid ongi just selleks ülesandeks pastlikud. Kui nüüd uuseti näitena tuua Harry Potter on too just selle tõttu healugemine kuna raamatud on pikad ning vajavad meenutamist. Raamatu lõppedes saan tervikpildi alles siis kokku panna kui olen kogu teose läbi töötlenud. Ja et seda teha peab aju informatsiooni talletama.\nLõpetuseks on lugemine üks olulisemaid osasid inimese aju arengus. Õpimegi ju tähti tundma läbi teksdide lugemise. Sammuti on raamatud ka head õpetajad. Võttes aluseks ükskõik millise Inglis keelse raamatu avadad sa tänu selle oma keele oskust. Uueks lugemise motoks peakski võib-olla saama Kreisiraadio repertuaarist tuntud väljend „Keeled suu ja Euroopase“.');
INSERT INTO core.text_property(text_id, property_name, property_value)
