INSERT INTO core.text(id, content)
VALUES ('be4d72ce-c5e0-4847-a749-650d4f793689',
        'Sotsiaalmeedia ja sisuloojad ümbritsevad meid meie elus pea iga päev. Tihti just noored on need kes nende tegevusi jälgivad ja neist eeskuju võtavad. Kuidas ja kas nad seda läbi sotsiaalmeedia teevad?\nNoori on kahte tüüpi: neid kes lasevad ennast ümbritsevast mõjutada ja on neid kes ei lase. Tihtipeale me ei saa arugi, kuidas sotsiaalmeedia meid mõjutab. Sisuloojad saavad seda teha mitut moodi: eksklusiivsed kaubad, erakordsed juhtumused ja päriselu. Võtame näiteks hetkel kõige kõmulisema suunamudija Brigitte – Susanne Hundi. Ta kajastab oma igapäeva elu nii nagu see tegelikult on. Ta räägib väga avameelselt oma elu ümberpööramisest, kuidas ta loobus alkoholist ja muudest mõjuainetest, pidutsemisest ning kuidas ta alustas trenni tegemisega ja hakkas tervislikult toituma.\nTa teeb ka mitmete tuntud brändidega koostööd, kus ta promob asju mida talle on saadetud. Nagu ta on ka ise öelnud teeb ta koostööd ainult nende brändidega, mis talle ise ka päriselt meeldivad, näiteks trenni ja ilukaubad ning talle ei meeldi kui teised mõjuisikud teevad koostöid ainult raha pärast, isegi kui see toode või teenus neile päriselt ei meeldi. Ta nimetab seda jälgijate petmiseks. Teda jälgivad väga paljud noored ja niipalju kui mina olen läbi sotsiaalmeedia aru saanud siis on osad, kes tema tegemistele kaasa elavad ja temast õppust võttavad, aga on ka neid kellele ta ei lähe üldse korda. Seega võib öelda, et tal on just noorte ja teismeliste üle, kes pole veel seda oma rada leidnud, mõju.\nIga päev näeme kuidas üks või teine midagi sotsiaalmeedias, kas siis instagramis võik tiktokis reklaamib. Tihti me ei saagi aru, et see meid kasvõi mingil määral mõjutab ja me suundumegi kohe seda ostma. See toode ei pruugi meile üldsegi meeldida, aga siit tuleb välja see ühiskonna surve, et teistel on ja minul peab see ka olema. Liis Velsker promob sageli oma instagrammis Nike brändi ja ma olen aus, ka mina olen temast mingil määral mõjutatud, sest olen ostnud just neid tosse, mida tema oma storydes reklaaminud on. Õnneks pole mina petta saanud ja mulle on kõik asjad seni meeldinud. On ka mitmeid juhuseid kus inimesed on petta saanud ja asju enam tagastada ei saa ja nad jäävad oma rahast ilma.\nPaljud kasutavad ka oma sotsiaalmeedia platvormi ka heategevuse otstarbel. Liina Ariandne pedanik on loonud endale mitme aasta jooksul suure jälgiaskonna ja ta propageerib loomade päästmist ja veganlust. Ta on teinud mitmeid koostöid loomade varjupaikadega ja osaleb ka organisatsioonis Loomus. Sellega ta suunab inimesi loomi päästma ja olema heatahtlikud.\nSuunamudijad saavad meid mõjutada, mitmel moel olgu see, siis enda hüvanguks või maailmajaoks. Siinkohal saame me ise otsustada, kas ja millisel moel me laseme ennast mõjutada. Siiski tuleb meeles pidada, et kõik mida internetis näed ei pruugi alati tõsi olla.');
