INSERT INTO core.text(id, content)
VALUES ('affb2c3b-eead-48f7-94a3-d0e1a974d3bd',
        'Lugemine on olnud aegade algusest saadiks suur osa eestlaste elus. Raamatute kaudu saame me teada Eesti ajaloost ning ka rohkem Eesti kultuuri kohta. Kuid tänapäeval on see muutunud, noored ei taha raamatut kätte võtta ja seda lugema hakata. Ka tänapäeva noorte lugemisharjumused on muutunud, ning sellele on ka tagajärjed. \nPaljud noored inimesed eelistavad lugemise asemel Tiktokis videoid vaadata või sõpradega väljas käia. Tänapeva noored on leidnud uue viisi kuidas lugeda, aga samal ajal mitte raamatu lehti keerata. Noored loevad raamatuid veebikeskkondades, näiteks Eesti Raamat internetikeskkonnas. Sel viisil saavad nad lugeda, kuid samal ajal telefoni või Ipadi mitte käest ära pannes. Nagu ka igal heal asjal on ka sellel omad tagajärjed ja paha pool, millega tuleb arvestada näiteks: silmad jäävad kiiremini haigeks eriti kui loed palju korraga, kiiremini tulevad peavalud.\nEriti raske on noorteseas see kui keegi käsib neil raamatut lugeda ja nad ei saa oma valitud teost lugeda. Näiteks koolis kohustuslikuskirjanduses antakse noorele inimesele raamat, mis räägib sõjast ja raskest ajast inimese elus, kas üheksanda,- kümnenda,- üheteistkümnenda -või kaheteistkümnenda klassi õpilast huvitab selline teema? Tavaliselt mitte, leidub ka erandeid mõnda teismelist huvitabki ajalugu, aga rohkem on neid, kes pigem viskaksid selle raamatu kapi peale ja enne ei vaataks isegi selle poole kui õpetaja ühtesid hakkab ekooli või stuudiumisse panema. Noored tahaksid pigem lugeda krimi- või armastusteoseid, mitte ajaloo kohta või sõdade. Tagajärgi sellele on mitu; esimene tagajärg on see, et noorte hinded langevad tänu sellele, et õpetajad annavad neile raamatuid lugeda, mis on nende jaoks igavad, teine tagajärg on see, et noorte teadmised ajaloo või sõdade või muu tähtsa kohta on üleaegade langenud, sest neid lihtsalt ei huvita need nii palju, et selle kohta piisavalt uurida. \nKolmandaks eesti noored ei taha lugeda Eesti kirjanike, neile meeldivad rohkem väliskirjanikud. Näiteks Colleen Hoover, kes kirjutab armastus- ja draamaromaane. Tüdrukute seal kõige levinum žanr ongi armastus- ja draama, sest tüdrukud on hingelt natuke rohkem romantikud, muidugi mitte kõik, aga paljud. Poistele rohkem meeldivad fantaasia -või krimi žanrid, sest poisid on natuke rohkem huvitatud sellisest maailmast, kui tüdrukud. Mitte kõik poisid ja mitte ka kõik tüdrukud. Inimesed on kõik erinevad. tagajärjeks on see, et Eesti kirjanike hakatakse aina vähem lugema ja lõpuks nende raamatud kaovad poeriiulitelt. \nKokkuvõtteks on tänapäeva noorte seast lugemine kaduma hakanud, neid ei huvita raamatud, nii palju kui kunagi huvitasid raamatud inimesi. Alati on parem võtta kätte raamat ja lehti keerata, kui oma silmi rikkuda ja pead valutama ajada.');
