INSERT INTO core.text(id, content)
VALUES ('c4dea1a0-b124-4e28-afc3-5525f60dd952',
        'Lugemisoskusel on oluline roll ühiskonna toimimise juures. Kirja teel edastame me suurema osa infost, õppematerjalid, dokumendid, teatmeteosed – kõik nad edastavad olulist teavet, mida me inimestena tänu lugemisoskusele mõistame. Lugema õpime me juba varajases lapseeas, kuid vanuse kasvades ja sõnavara laienedes, suudame me tarbida üha keerukamaid tekste, lugeda funktsionaalselt ning see arendab inimest ennast, kui ka tema silmaringi. Mis põhjustab lugemisharjumuse vähenemist? Milliseid probleeme see endaga kaasa toob? Kas sotsiaalmeedia mõjutab lugemise harjumust?\nÜheks suurimaks probleemiks tänapäeva ühiskonnas on lugemisharjumuse vähenemine. Aja möödudes on inimeste elutempo muutunud kiiremaks ning aega lihtsalt maha istumiseks ei leita. Vaba aja veetmiseks kasutatakse raamatu asemel sageli nutitelefoni ja sotsiaalmeediat – sealne info on kiiremini ja kergemini tarbitav. Ka Tiit Hennoste ütleb oma arvamusloos, et ,,Mõttega lugemine on aeglane tegevus“, see nõuab aega ja püsivust, mida tänapäeva inimesel tihti ei ole.\nLugemisharjumuse vähenemist põhjustab ka kodune kasvatus. Lugemise harjumus luuakse just seal, väiksena raamatuid ettelugedes, hiljem koos õppides, kui ka ise eeskujuks olles. Kahjuks tuleb ka siin mängu nutimaailm, aja puuduse tõttu ei leita piisavalt aega ka oma laste jaoks. Nendega koos mängimine ja õppimine on jäänud tahaplaanile ning lihtsaks ja mugavaks lahenduseks on saanud nutiseadmed, kus laps saab vaadata erinevaid videoid. See toob kaasa nutisõltuvuse ning laste vähese huvi raamatutesse, sest koolis saab tihtipeale raamatutest hoopis kohustus ning laste huvi kaob.\nLugemisharjumuse vähenemine toob endaga kaasa suuri probleeme. Arvamusloos ,,Lugemise harjumuse harjutus“ on samuti öeldud, et lugemisoskuse allakäiguga kasvab inimeste hulk, kes ei saa enam ühiskonnas hakkama. Võib öelda, et lugemisoskus on hea elu eelduseks ja aluseks. Lugemisoskus tagab meile hea hariduse ja head suhted, sest me mõistame inimesi, infot mida nad meile edastavad ja pabereid millele me alla kirjutame. Selle puudumine ja halvenemine on allakäik kogu ühiskonnale. \nSamuti võib see kaasa tuua vaimse tervise probleeme. Vabal ajal raamatu lugemise asemel lahutatakse oma meelt sotsiaalmeedias, seal näeb enamasti aga ideaalset elu, kalleid reise, eksklusiivseid üritusi ja töödeldud pilte, kus inimestel on perfektne näonahk ja meik. See mõjutab noorte enesehinnangut ja võib kaasa tuua erinevaid vaimse tervise probleeme. Samal ajal raamatut lugedes saaks noored uusi teadmisi, rikastaks oma sõnavara ja lugedes eneseabi õpikuid saaks abi ka vaimse tervise probleemide korral.\nLugemisharjumus on aastate jooksul vähenenud tänu kiirele elutempole ja nutisõltuvuse suurenemisele. Kodudes pööratakse raamatute lugemisele vähem tähelepanu ja huvi raamatute vastu on kadumas. See kõik toob endaga kaasa aga suuri probleeme ühiskonnas. Lugemisoskus on vajalik ja silmaringi avardav ning ilma selleta ühiskond ei saaks toimida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c4dea1a0-b124-4e28-afc3-5525f60dd952', 'title', 'Lugemisoskuse vähenemine kui allakäik ühiskonnale');
