INSERT INTO core.text(id, content)
VALUES ('ddae1dd4-48f6-4c1a-b9e4-684c9d9387af',
        'Tänapäeval on suureks osaks meelelahustuseks saanud just sotsiaalmeedias teiste inimeste jälgimine. Inimesed veedavad enamus oma ajast just Instagrammis, TikTokis või mõnel muul vabas vormis sotsiaalmeedia lehel. Pahaaimamatult aga mõjutavad sealsed sisuloojad suuresti nende jälgijaid, mis mõni kord võib lõppeda väga halvasti. Keda need suunamudijad ka mõjutavad? Kuidas need sisuloojad siiski teisi mõjutavad? Kas on ka mõni hea aspekt sisuloomisel?\nPeamiselt näeme just noori mõju all olemas. Kauplused upuvad põhikooli ealistest ning satub tihti ette lapsi, kellel on kohutavalt kallid riided seljas ning uhke meik näos. TikTokis näeb sageli tüdrukuid, kes meigivad end kõige kallimate toodetega ning lähevad sedasi kooli. Nii on ka tavaelus, kus on näha, et üks täiesti tavaline noor neiu on maalinud endale uhke näo pähe ja rahumeeli koolipinki läinud. Sageli leiab noori, kedagi jäljendamas ning kui vaadata, keda laps internetis jälgib, siis ei ole raske järeldusi teha, kust eeskuju on saadud.\nKõige enam näeme me internetis reklaame sisuloojate poolt. Tihti on nende taga tegelikult koostööd ehk instagrammer teeb reklaampostituse ning selle eest saab raha. See ongi suunamudijate elatis, praktiliselt oleme meie nende tuluallikas. Sisuloojad kiidavad mingi toote nii heaks, lisavad ka e-poe lingi, kust antud toodet saab tellida ning tuleb ka ette, kui kogu ladu ostetakse vaid paari tunniga tühjaks. Kuuaja möödudes saavad ilmselt enamus inimesed aru tellitud toote mõttetusest ning paraku jääb asi sahtlisse seisma. See omakorda tekitab raha kulutamise, süütunde, et inimene reklaamiohvriks sattus ning keskkonna mõttes suures hulgas raiskamist. Puhtalt üks väike reklaampostitus võib tekitada nii suurt mõju, millest inimesed alles hiljem aru saavad.\nMallu Mariann Treimann, Eesti kuulsaim blogija, kirjutas raamatu „Salapäevik kõigile lugemiseks“. Seal kirjutabki Mallu oma reaalsusest, kuidas kõik ei olegi nii hea, kui piltidelt võib tunduda. See on Murumaa näide elulisusest. Inimest köidab raamat just see tõttu, et saavad sealt lohutust oma kurbusele. Paljud noored tüdrukud vaevlevad vähemalt korra südamevaluga ning üksnes raamatu lugemine võib parandada selle valu. Nähes, kui hull oli kellegi teise olukord annab see lugejale mõista, et pole tema elul midagi viga. Samas aitab ka valule samastumine. Teadmine, et kellelgi on olnud sama valus ja sai sellest üle, annab jõudu edasi püüelda. Suunamudijatel on ka hea mõju inimestele, kasvõi raamatu lugemine aitab valu korral.\nPeamisteks sisuloojate ohvriteks on just noored tüdrukud, kes tundide viisi internetis üles meigitud neidusid näevad. Võiks öelda, et need tiktokkerid on justkui iidolid noortele. Kõige tüüpilisem nähtus digi-maailmas on reklaamiohverdus. Inimesed ostavad koju sadade eurode väärtuses tooteid, mis lihtsalt seisma jäävad. Samas on mõnes osas sisuloojatel ka positiivne mõju, elulisus näitab jälgijatele, et nende uhkete influencer’ ite elu ei ole midagi nii lillelist.');
