INSERT INTO core.text(id, content)
VALUES ('75c1d552-7707-44ce-9d5b-e0b81a81db89',
        'Raamatute ja teiste ajakirjalike paberite lugemine on läbi ajaloo olnud üks tähtsamaid aspekte inimaju arengus. Lugemine aitab kaasa rääkimisega, kirjutamisega ja mõtlemisega. Lugedes leiad mitmeid uusi sõnu mida enne ei teadnudki, neid oma korda saad kasutada kas pikka ja väsitava kirjandi kirjutamises või kui lihtsalt vestled oma sõpradega. Mida rikkam on sinu mõtlemismaht seda lihtsamaks muutuvad pikkade kirjandite kirjutamine.\nAga miks loetakse üldsegi nii vähe?\nOn väga hästi näha, et lihtinimene loeb ja kirjutab üldiselt vähe. Sellele viitab üks asi, nutitelefon ja interneti kasutusele tulek. Internetti võib kiiresti sõltuvusse jääda, kuna on leida palju ajule huvi tekitavaid asju, näiteks Youtube või Tik Tok. Aga kõik internetis ei ole halb ajule, kui piiravas kogus oleme internetis, siis võivad mõned mängud meie koordinatsiooni ja reaktsiooni kiirust suurendada. Samuti on paljuid kes loevad või kirjutavad teistega interneti kaudu, mis arendab lugemis ja rääkimis oskusi. Aga kui ollakse arvutis ja telefonis liigselt kaua, siis võivad tekkida tervise probleemid. Näiteks liigutakse vähem, kaua ekraani vahtimine kahjustab silmi ja magamis rutiini. \nKuidas saada lapsi ja noorukeid rohkem lugema?\nVanemad või õpetajad peaksid küsima ja tutvuma rohkem mida nende lastele huvi pakub ja siis arutama temaga, et millised raamatud talle sobiks. Siis tuleks sobidada raamatu lugemine päevasesse rutiini, näiteks loed enne kooli, koolist kojue tulles ja ennem magama minekut. Nagu tekstis tuuakse välja: „Alguses on raske, aga paari kuu pärast on asi sealmaalm et vajan oma igaõhtust lugemise annust.“ Kui last piisavalt harjutatakse lugemisega, hakkab ta huvi tundama isegi raamatutesse mis on väljaspool huvi ringi. Nendest kogub ta teadvust ja uusi huvisi teiste asjade vastu. \nKuidas tõsta eesti keelsete raamatute populaarsust?\nOn teada, et lastele väga meeldib õppida ja rääkida inglis keeles, kuid see ei peaks olema ainuke keel mida kõneleda. Et meelitada inimesi rohkem õppima eesti keelt, tuleks raamatuid arendada mis sobib tänapäeva lastele. Pealkirjad raamatu kaantel tuleks kirjutada inglise keeles, et see pakuks rohkem huvi noorukitele. Samuti õeldakse seda tekstis nagu: „mõne aastaga on juhtunud see, et noortele suunatud teemades on raamatu kaanel pealkiri üksnes inglise keeles, kuigi tõlge on siiski saksa keeles.“. Kindlasti on mõningaid kellele üldsegi huvi ei paku inglise keel ja kes tahab ainult eesti keelt õppida, aga me peame vaatama rohkem tulevikku. Inglis keele on maailma universaal keel ja sellega peab harjuma. Peab tegema olulisi samme ja otsusi, et teha eesti keelsed raamatud taas huvitavaks lastele ja et inglise keel jääb ikkagiks teiseks keeleks.\nLõpp');
