INSERT INTO core.text(id, content)
VALUES ('d19001c5-fe93-4981-bf84-f0e26967119a',
        'Teada on, et inimese igapäevaelu ja väljavaateid kujundavad enim inimesed nende ümber. Sotsiaalmeedia annab inimestele võimaluse olla pidevalt üksteisega kontaktis, vahendada kiirelt infot ning jälgida kasvõi võhivõõraste igapäevaelu. Tänu inimese loomusele teistega sarnaneda ja kuhugi kuuluda, hakkavad nad otsima eeskujusid, kuid avaliku elu tegelastel on mitu erinavat pahet. \nSuunamudijad propageerivad ennast enamasti internetis. Nad jagavad igapäevaelust postitusi, avaldavad isiklikku arvamust ning on trendide rajajad. Tänapäeval tahab iga inimene kuuluda kuhugi gruppi ning tunda ennast, nagu nende arvamus loeb. Seetõttu on tuntumad isikud isiksuste ja arvamuste teede rajajaks. Kui inimesel on palju jälgijaid ja sõpru, peetakse teda juskui liidriks. Nagu on ka öeldud Õpetajate Lehes, artiklis „Mõjutamine: Kuidas suunamudijad meid mõjutavad?“: „Juba 1956. aastast pärit parasotsiaalsete suhete teooria kohaselt tekib meedia vahendusel illusioon, et meediastaar on nende lähedane tuttav, keda tasub kuulata.“.\nTema järgi kujunevad isiklikud vaated, igapäevane elu ning põhilised vaated elule. \nKuigi internetis on palju head, ei välista see pahatahtlike kavatsustega inimesi. Ei tunta ekraani taga istuvat tegelast ning tema motiive. Olles ettevaatamatu võid sattuda skeemide ja petturite ohvriks, mis on tänapäeval kujunenud juba normaalseks nähtuseks. Ei tasu uskuda kõike, mida näed ja kuuled. Samuti mängib suunamudijate elus tähtsat rolli raha ja tuntus, osade jaoks ongi see justkui kõige tähtsam aspekt. Näiteks propageeritakse tervist kahjustavaid tooteid ning jagatakse valeinfot. Nende petuskeemide ohvriks langedes, ei pruugi olla lihtne nendest välja tulla. Samuti võivad neil olla ka eluohtlikud tagajärjed.\nOn teada et sotsiaalmeedial on nii häid kui ka halbu pooli. See võib olla justkui kõige lähedasemaks sõbraks, kelle nõuandeid saad kuulata. Selle sisu võib enesehinnangut tõsta ning pakkuda kindlust ja lähedust. Kuid internet võib olla tihtipeale kahepalgeline. Kuna on tuntumad just rikkad ja kuulsad, maalitakse inimestele maailmast vale arusaam. Propageeritakse eksklusiivset ja rikkalikku elu, mida tavainimene ei saa endale lubada. Kuid õnneks on ka suunamudijaid, kes on reaalsed ja ausad. Nad jagavad oma igapäevaelu reaalseid tegevusi ja arvamusi, mistõttu on keegi, kellega samastuda. Samuti võivad heatahtlikud inimesed tänu sotsiaalmeediale ühendada jõud ning teha kõik koos midagi head. Nagu on ka kirjutatud Heas Kodanikus, artiklis „Seitse populaarset Eesti suunamudijat kutsuvad inimesi üles karusnahka mitte soetama“, on tehtud midagi revolutsioonilist. Organisatsioon Loomus algatas kampaania #loomadesilmis, mis kutsub inimesi üles mitte soetama karusnahka. Selle iikumisega ühinesid ka paljud teised organisatsioonid ja tuntud inimesed, mistõttu jõuab info kiiresti edasi ning inimesed parandavad oma halbu harjumusi.\nInternetis on palju positiivset kui ka negatiivset – seda tuleb õppida nägema. Avaliku elu tegelased, keda me igapäevaselt jälgime, kujundavad meie arvamust, hoiakut ja enesehinnangut. Just sellel põhjusel on tähtis olla sotsiaalmeedias turvaline, pöörata tähelepanu allika õigsusele ning jälgida pingsalt, mida uskuda.');
