INSERT INTO core.text(id, content)
VALUES ('33445be0-bc08-4cc8-a5a1-16fa066c5b17',
        'Kõik inimesed puutuvad elujooksul kokku lugemisega, olgu selleks siis kas lasteaed, gümnaasium, ülikool või töökoht. Eriti tuleb lugemist, õpilaste jaoks rohkem tuntud kui kohustuslik kirjandus, ette põhikoolis ja gümnaasiumis, mis tekitab palju peavalu. Tänapäeva noorte jaoks on lugemine kui tabu ning asi, millel ei pruugi olla mõtet. Aga miks lugemisharjumus noorte seas ajaga aina hääbub ning mis on selle kõige tagajärg?\nVanasti, kui meie vanemad ja vanavanemad veel meie vanused olid, oli peamine ajaviide lugemine või üksteise seltsis aja veetmine. Puudusid arvutid ning nutitelefonid, kus tundide kaupa erinevaid videoid ja netiportaale sirvida sai. Me aga elame ajas, kus tehnoloogia on pidevalt arengus ning mõjutab suuresti kõike. Tänapäeva elu on vägagi lihtne igasuguse AI või interneti abiga. Võime tuua ühe lihtsa näite. Gümnaasiumis tuleb läbi lugeda Eesti ajaloo üks kõige vajalikum ning ajalugu edasi andev teos – „Tõde ja Õigus“, mille on kirjutanud Anton Hansen Tammsaare. Võin omast käest öelda, et huvitav seda lugeda ei ole ning on kohati väga julm ning ka sellepärast paljud valivad raamatu lugemise asemel filmi või otsivad lihtsalt internetist kokkuvõtteid. Mõni on lausa nii laisk, et küsib AI käest ning loodab töö ajal selle peale.\nKiire tehnoloogia arenguga maailmas tuleb ka endal tempot hoida. Tänapäeva inimestel on kõigil koguaeg kuskile kiire. Vahel on lausa selline tunne, nagu oleks maailma lõpp tulemas. Nagu ütles ka Tiit Hennoste, on meil peaaegu nagu kiirmaailma valitsus: kiirtoit, kiirkeel, kiirteadus, kiirseks, kiirlugemine. Kellegil ei ole aega mõttega raamatuid lugeda. Raamatute lugemise asemel kuulatakse audioraamatuid või podcaste, et maailmauudistega kursis olla või ennast harida päevakajaliste teemadega.\nViimaseks probleemiks võime tuua inglise keele mõju. Palju suhtlust, isegi meie oma kodumaal, käib läbi rahvusvahelise suhtluskeele juba. Enamus lapsi oskavad ennem inglisekeelt kui seda üldse õppima on hakanud.\nLugemisokskuse halvenemine ning harivate kirjandusteosete mitte lugemine toob kaasa palju. Tuues näiteks Tiit Hennoste teksi, saame kõik noortena nõustuda, et vanemad kodus või õpetajad koolis ikka räägivad kuidas raamatuid mitte lugedes, pole meil piisavalt head sõnavara, kuidas raamatud annavad meile hariduse, parema tuleviku ja sissetuleku ning omakorda parema tervise. Paraku reaalsus on aga see, pole vahet palju õpetajad meile raamatuid lugeda annavad, tänapäeva noored ei loe ja suure tõenäosusega ei hakka ka lugema. \nVõime öelda ja ilmselt ka kõik nõustuda, et sellises tehnoloogiamaailmas elades, tuleb meil lihtsalt leppida teadmisega, et kirjandus järk-järgult hävib. Uued teadmised ja võimalused tulevad peale ning kes teab, võib-olla kahekümne aasta pärast on meil kogu kirjandus võimalik kätte saada juba vaid otsingusse sisestamisest.');
