INSERT INTO core.text(id, content)
VALUES ('8c066cc0-5f76-4c28-9ff5-875f8eed6f61',
        'Suunamudijad ehk influencer’id mängivad tänapäeva netiavarustes suurt rolli tegutsedes erinevatel sotsiaalmeedia platformidel. Kuigi esmapilgul võivad suunamudijad tunduda kui lihtsalt ühed kuulsad ja rikkad inimesed, kes oma tegevusega, milleks on üldiselt videote postitamine, kopsakat raha teenivad, ei tohi alahinnata nende mõju noorte igapäevaelule, otsustele ja valikutele. \nMaailmas on palju erinevaid inimesi ning alati ei ole lihtne eristada, kes oma kavatsustega soovib teistele head või on ainult oma kasu peale väljas. Nii on ka suunamudijatega, kes võivad teadlikult või kogemata levitada oma jälgijate hulgas valearvamusi- või infot. Tartu ülikooli ühiskonnateaduste instituudi lektor Kristjan Kikerpilli on öelnud: „Arvamus on vaba, aga kui tulemus on täielik käojaan, mis ei põhine faktidel, kuid „kuulajatele“ meeldib, siis see on probleem. Halvemal juhul võib selle tulemusel kuskil suuremaks kakluseks ja rüüstamiseks minna.“ Ka toote reklaami puhul võib olla keeruline aru saada, kas netikuulsus seda tegelikult heaks ja vajalikuks peab või reklaamib seda kõigest sponsorite rahalise tasu eest. Samuti müüvad ja kiidavad influencer’id enda loodud tooteid, mis tegelikkuses ei pruugi osutuda kvaliteetseteks ning halvimal juhul hoopis tervist kahjustavateks. Jake Paul on üle maailma tuntud suunamudija, kes lõi oma joogibrändi, mis on praeguseks jõudnud paljude riikide poelettidele. Sellest hoolimata, on selgunud, et tema joogid sisaldavad aineid, mis võivad pikemas perspektiivis organismile halvasti mõjuda. Tuntud suunamudija aga ise reklaamib oma toodet tihti ning ei ole potentsiaalsete terviseriskide osas midagi ette võtnud. Seepärast peab influencer’ite tooteid, eriti jooke ja sööke, ostes olema ettevaatlik ning tegema taustakontrolli, et vältida pettust või tervisekahjustusi. Kõik suunamudijad ei pea eelkõige silmas oma jälgijate heaolu. \nKuigi paratamatult on influencer’eid, kes kasutavad oma kuulsust ja mõju puhtalt kasumi teenimiseks, on siiski olemas ka neid, kes kasutavad seda heategevuseks. Oma populaarsuse toel kutsuvad nad oma jälgijaid üles annetama ja osalema heategevusüritustel. Tihti postitakse ka videosid, mille pealt teenitud kasum läheb ülenisti heategevusorganisatsioonidele, kes seda rahasummat tegutsemiseks vajavad. 2019. aastal toimus Eestis kampaania #loomadesilmis, millest võtsid osa Eesti tuntud suunamudijad Hanna Martinson, Liis Velsker, Liina Ariadne Pedanik, Martti Hallik, Mick Pedaja, Alisa Tsitsernova ja Juhani Särglep. Nende eesmärk oli tõstatada noorte tarbijate seas karusnahkade tootmise ja karusloomafarmide teema ning seeläbi suunata neid valima looma- ja keskkonnasõbralikke tooteid ja vähendada karusnahkade ostmist. Eesti suunamudijate tegevus aitas koguda allkirju rahvusvahelisele petitsioonile, et keelustada karusloomakasvandused. See on kõigest üks olukord mitmest, kus influencer’ite kuulsus aitab kaasa heategevusele ning pole suunatud isiklikule tulu teenimisele. Niimoodi tegutsedes aitavad nad kaasa parema maailma loomisele ja tekitavad seejuures ka noortes arusaama, et teiste aitamine on parem kui üüratu rahasumma teenimine.\nTänapäeval on sotsiaalmeedias palju influencer’eid, kes mõjutavad noorte elu ja arusaamu ning nii mõnigi neist kasutab oma mõju ja kuulsust teadlikult ära. Levitatakse arvamusi, mis ei põhine faktidel ja on seeõttu valearusaamad ning reklaamitakse enda või sponsorite tooteid ka siis, kui need ei ole tegelikult kvaliteetsed. Siiski saab netikuulsustel olla noortele ka positiivne mõju. Paljud suunamudijad võtavad osa heategevusesüritustest ja annatevad oma raha heategevusorganisatsioonidele, mistõttu suunavad nad ka oma jälgijaid tegema sama ning looma teiste aitamise mentaliteeti.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8c066cc0-5f76-4c28-9ff5-875f8eed6f61', 'title', 'Suunamudijad –  mis on nende mõju?');
